// ===========================================================================
//  medals.js — the Maker Medals model on the web (Gamification Layer 1).
//
//  A FAITHFUL port of the native pure-core model `src/core/game/MakerMedals.{h,cpp}`:
//  the SAME eight-milestone catalog + STABLE persistence keys, the SAME idempotent
//  earned-state (award() reports NEW strikes only), and a BYTE-COMPATIBLE
//  serialize/deserialize (a newline-separated list of earned keys, catalog order).
//
//  PURE + DOM-FREE + framework-free so it unit-tests in Node (web/verify.js imports it
//  and asserts parity with the native format) and drives the web shelf unchanged. The
//  chrome convex-mirror render lives in medalart.js; WHEN a medal is earned is wired by
//  main.js to the real making events. award() returns whether the medal was NEWLY struck
//  — the single fact the earn celebration + the +200 score strike need (never re-fire on
//  a persisted reload). The web build persists the serialized text in its OWN IndexedDB
//  slot; the native dev-box `.medals` file is never touched.
//
//  Native cross-reference (do not drift): cyclo::game::Medal / kCatalog keys /
//  MakerMedals::{award,serialize,deserialize}. Identity colours mirror laf/MedalArt.h
//  medalColour(); the celebration mapping mirrors app/CelebrationLayer.h Kind (the SIX
//  weird per-challenge celebrations — FirstBeat + CodePeeker strike with no celebration).
// ===========================================================================

// The eight Layer-1 milestones, in shelf order (matches the native Medal enum). Each maps
// to a real capability, so earning is honest. Keep the order stable (it is the shelf order
// AND the serialize order).
export const Medal = {
  FirstBeat: 0,
  HumCatcher: 1,
  KeyFinder: 2,
  GrooveMaker: 3,
  CodePeeker: 4,
  TimeTraveler: 5,
  GrainGardener: 6,
  ShipIt: 7,
};
export const MEDAL_COUNT = 8;

// The immutable catalog — STABLE persistence key + shelf copy + identity colour + glyph.
//  - key   : the persistence token (NEVER rename a shipped key — byte-matches native kCatalog).
//  - color : the medal's LED-style identity hue (mirrors laf/MedalArt.h medalColour()) — the
//            coloured light an EARNED dome catches so its chrome reads as treasure.
//  - glyph : the lab's emblem (docs/design-lab/maker-medals.html MEDALS[].glyph).
export const CATALOG = [
  { id: Medal.FirstBeat,     key: 'first_beat',     title: 'First Beat',     sub: 'tap a pad, the loop starts', color: '#ff6a55', glyph: '●'  },
  { id: Medal.HumCatcher,    key: 'hum_catcher',    title: 'Hum Catcher',    sub: 'hum a tune into a melody',   color: '#3aa8ff', glyph: '♪'  },
  { id: Medal.KeyFinder,     key: 'key_finder',     title: 'Key Finder',     sub: 'let a sound find its key',    color: '#8b6bff', glyph: '♯'  },
  { id: Medal.GrooveMaker,   key: 'groove_maker',   title: 'Groove Maker',   sub: 'swing or humanize a beat',    color: '#3ad29f', glyph: '≈'  },
  { id: Medal.CodePeeker,    key: 'code_peeker',    title: 'Code Peeker',    sub: 'edit your song as code',      color: '#ffb03a', glyph: '</>'     },
  { id: Medal.TimeTraveler,  key: 'time_traveler',  title: 'Time Traveler',  sub: 'restore an old version',      color: '#2fd4d4', glyph: '↺'  },
  { id: Medal.GrainGardener, key: 'grain_gardener', title: 'Grain Gardener', sub: 'grow a grain garden',         color: '#a7e34a', glyph: '✦'  },
  { id: Medal.ShipIt,        key: 'ship_it',        title: 'Ship It',        sub: 'export your first track',     color: '#ff5f9e', glyph: '▲'  },
];

export function medalInfo(m) { return CATALOG[m]; }
export function medalColour(m) { return CATALOG[((m % MEDAL_COUNT) + MEDAL_COUNT) % MEDAL_COUNT].color; }
export function medalForKey(key) {
  for (const mi of CATALOG) if (mi.key === key) return mi.id;
  return -1;
}

// The SIX weird per-challenge celebrations (mirrors app/CelebrationLayer.h Kind). Six of the
// eight medals fire a bespoke celebration; FirstBeat + CodePeeker strike with only the medal's
// light-sweep (there is no CelebrationLayer::Kind for them in native either).
export const Celebration = {
  None: 'none',
  ShipIt: 'shipit',
  HumCatcher: 'hum',
  KeyFinder: 'keyfinder',
  GrooveMaker: 'groovemaker',
  TimeTraveler: 'timetraveler',
  GrainGardener: 'graingardener',
};

// Which celebration a medal's FIRST strike fires (parity with native awardMedal->playCelebration).
export function celebrationForMedal(m) {
  switch (m) {
    case Medal.ShipIt:        return Celebration.ShipIt;
    case Medal.HumCatcher:    return Celebration.HumCatcher;
    case Medal.KeyFinder:     return Celebration.KeyFinder;
    case Medal.GrooveMaker:   return Celebration.GrooveMaker;
    case Medal.TimeTraveler:  return Celebration.TimeTraveler;
    case Medal.GrainGardener: return Celebration.GrainGardener;
    default:                  return Celebration.None;   // FirstBeat, CodePeeker
  }
}

// The inverse (celebration -> its medal) so a celebration can draw in its medal's IDENTITY colour
// straight from this ONE shared catalog — no per-celebration hardcoded hex to drift (P1-b).
export function medalForCelebration(kind) {
  switch (kind) {
    case Celebration.ShipIt:        return Medal.ShipIt;
    case Celebration.HumCatcher:    return Medal.HumCatcher;
    case Celebration.KeyFinder:     return Medal.KeyFinder;
    case Celebration.GrooveMaker:   return Medal.GrooveMaker;
    case Celebration.TimeTraveler:  return Medal.TimeTraveler;
    case Celebration.GrainGardener: return Medal.GrainGardener;
    default:                        return -1;
  }
}

// The identity colour a celebration paints in — the SAME hue as its medal's dome (CATALOG.color).
// celebrations.js uses this instead of a private hardcoded palette so the trophy + its celebration
// can never drift. KeyFinder's tonic-tint has its own key-derived colour; this is only its fallback.
export function celebrationColour(kind) {
  const m = medalForCelebration(kind);
  return m < 0 ? '#8b6bff' : CATALOG[m].color;
}

// The earned-state collection: which medals have been struck. A faithful port of
// cyclo::game::MakerMedals.
export class MakerMedals {
  constructor() { this.earned_ = new Array(MEDAL_COUNT).fill(false); }

  isEarned(m) { return !!this.earned_[m]; }

  // Strike a medal. Returns true iff it was NEWLY earned (fire the celebration + the +200 score
  // strike); false if it was already earned (idempotent — re-awarding is a no-op, so triggers can
  // be dumb + fire every time without ever double-awarding).
  award(m) {
    if (this.earned_[m]) return false;
    this.earned_[m] = true;
    return true;
  }

  earnedCount() { let n = 0; for (const e of this.earned_) if (e) ++n; return n; }
  static totalCount() { return MEDAL_COUNT; }

  // ---- persistence — byte-compatible with native MakerMedals::serialize ----
  // A newline-separated list of the earned medals' STABLE keys, in catalog order. Empty when
  // nothing is earned. Deterministic (order-stable) so it diffs cleanly.
  serialize() {
    let out = '';
    for (const mi of CATALOG) if (this.isEarned(mi.id)) out += mi.key + '\n';
    return out;
  }

  // Replace earned-state from serialized text. Tolerant by design (mirrors native): splits on any
  // whitespace/comma, ignores blank + UNKNOWN tokens (forward-compatible — a file written by a
  // newer build that added medals loads cleanly). Full replace, so load == restore.
  deserialize(text) {
    this.earned_.fill(false);
    if (typeof text !== 'string') return;
    for (const tok of text.split(/[\s,]+/)) {
      if (!tok) continue;
      const m = medalForKey(tok);
      if (m >= 0) this.earned_[m] = true;
    }
  }
}
