// ===========================================================================
//  celebrations.js — the SIX weird per-challenge CELEBRATIONS (Gamification Layer 2).
//
//  A FAITHFUL port of native `src/app/CelebrationLayer.h`: a single, non-interactive
//  full-window canvas overlay that plays ONE short (~1.7 s), surreal, medal-SPECIFIC
//  flourish then removes itself. The owner's brief: "push it stranger" — each moment
//  DRAMATIZES the exact thing the maker just did, never a generic confetti burst.
//
//  Constraints honoured (parity with native):
//   • Cheap + on-device — pure 2D-canvas vector drawing; a bounded rAF loop that STOPS the
//     instant the moment ends (zero per-frame cost after it clears, nothing on the audio path).
//   • Non-blocking + zero-tap — the layer is pointer-events:none; the instrument keeps playing
//     under it (and a tap anywhere dismisses it early via the host).
//   • Locked flat design bar — chrome appears ONLY on a genuine reward OBJECT (the vinyl disc);
//     every other mark is a flat mark in the medal's identity hue. Grey PLAY pads untouched.
//   • Reduced-motion aware — holds one payoff still instead of animating.
//
//  DETERMINISTIC by design: paint() is a pure function of (kind, t in 0..1). The same t always
//  renders the same frame, so renderStatic(kind, t) grabs a repeatable frame for a contact strip
//  (the __cyclo.renderCelebration hook the headless harness uses to capture the 6 mid-animation).
//
//  Native cross-reference (do not drift): CelebrationLayer::{paintShipIt,paintHum,paintKeyFinder,
//  paintGrooveMaker,paintTimeTraveler,paintGrainGardener}, kDurationSec 1.7, kPayoffStill 0.62.
// ===========================================================================

import { Celebration, celebrationColour } from './medals.js';

const kDurationSec = 1.7;
const kPayoffStill = 0.62;
const kPi = Math.PI;
const kTwoPi = Math.PI * 2;

// ---- tiny deterministic maths (mirror native) ----
const clamp01 = (x) => (x < 0 ? 0 : x > 1 ? 1 : x);
const ease = (x) => { x = clamp01(x); return x * x * (3 - 2 * x); };
function h01(i) {
  let x = (i >>> 0) * 2654435761 + 1013904223;
  x = x >>> 0;
  x ^= x >>> 15; x = Math.imul(x, 2246822519) >>> 0; x ^= x >>> 13;
  return (x & 0xffffff) / 0x1000000;
}
const waveAmp = (u) =>
  0.62 * Math.sin(u * 37.0) * (0.55 + 0.45 * Math.sin(u * 6.3)) + 0.24 * Math.sin(u * 91.0 + 1.3);

// ---- colour helpers ----
function hexToRgb(hex) { const s = hex.replace('#', ''); return [parseInt(s.slice(0, 2), 16), parseInt(s.slice(2, 4), 16), parseInt(s.slice(4, 6), 16)]; }
const clampByte = (v) => (v < 0 ? 0 : v > 255 ? 255 : v);
function rgba(rgb, a) { return `rgba(${clampByte(rgb[0]) | 0},${clampByte(rgb[1]) | 0},${clampByte(rgb[2]) | 0},${a === undefined ? 1 : a})`; }
function brighter(rgb, amt) { return rgb.map((c) => clampByte(c + (255 - c) * amt)); }       // toward white
function darker(rgb, amt) { return rgb.map((c) => clampByte(c / (1 + amt))); }               // JUCE darker
function mulBright(rgb, f) { return rgb.map((c) => clampByte(c * f)); }
const WHITE = [255, 255, 255], BLACK = [0, 0, 0];
function hsvToRgb(h, s, v) {
  const i = Math.floor(h * 6), f = h * 6 - i, p = v * (1 - s), q = v * (1 - f * s), t = v * (1 - (1 - f) * s);
  let r, g, b;
  switch (i % 6) { case 0: r = v, g = t, b = p; break; case 1: r = q, g = v, b = p; break; case 2: r = p, g = v, b = t; break; case 3: r = p, g = q, b = v; break; case 4: r = t, g = p, b = v; break; default: r = v, g = p, b = q; }
  return [r * 255, g * 255, b * 255];
}
const PC_NAMES = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
const pcName = (pc) => PC_NAMES[((pc % 12) + 12) % 12];

// ---- canvas drawing helpers (JUCE Graphics -> 2D canvas) ----
function fillEllipse(ctx, x, y, w, h) { ctx.beginPath(); ctx.ellipse(x + w / 2, y + h / 2, w / 2, h / 2, 0, 0, kTwoPi); ctx.fill(); }
function strokeEllipse(ctx, x, y, w, h, lw) { ctx.lineWidth = lw; ctx.beginPath(); ctx.ellipse(x + w / 2, y + h / 2, Math.max(0, w / 2), Math.max(0, h / 2), 0, 0, kTwoPi); ctx.stroke(); }
function fillRect(ctx, x, y, w, h) { ctx.fillRect(x, y, w, h); }
// Justification: 'centre' (centred box) or 'topLeft'
function drawText(ctx, text, x, y, w, h, just, font) {
  ctx.font = font;
  if (just === 'topLeft') { ctx.textAlign = 'left'; ctx.textBaseline = 'top'; ctx.fillText(text, x, y); }
  else { ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText(text, x + w / 2, y + h / 2); }
}
const monoFont = (sz, bold) => `${bold ? '700' : '400'} ${Math.round(sz)}px ui-monospace, "Cascadia Mono", Consolas, monospace`;
const sansFont = (sz, bold) => `${bold ? '700' : '400'} ${Math.round(sz)}px system-ui, -apple-system, "Segoe UI", sans-serif`;
const roundFont = (sz) => `800 ${Math.round(sz)}px system-ui, "Segoe UI", Roboto, sans-serif`;

export class CelebrationLayer {
  constructor(canvas) {
    this.cvs = canvas;
    this.ctx = canvas.getContext('2d');
    this.kind = Celebration.None;
    this.t = 0;
    this.notes = [];
    this.keyRootPc = -1;
    this.keyMinor = false;
    this.raf = 0;
    this.startMs = 0;
    this.reduce = false;
    this.onDone = null;
    this.w = 0; this.h = 0;
  }

  _size() {
    const dpr = Math.min((window.devicePixelRatio || 1), 2);
    const w = window.innerWidth, h = window.innerHeight;
    this.w = w; this.h = h;
    this.cvs.width = Math.round(w * dpr);
    this.cvs.height = Math.round(h * dpr);
    this.cvs.style.width = w + 'px';
    this.cvs.style.height = h + 'px';
    this.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }

  _setKind(kind, melody) {
    this.kind = kind;
    this.notes = (melody && melody.length) ? melody.slice() : [0.15, 0.42, 0.30, 0.62, 0.85, 0.55, 1.0];
  }

  // Fire a celebration for real (from a medal's FIRST strike).
  play(kind, opts = {}) {
    this._size();
    this._setKind(kind, opts.melody);
    this.keyRootPc = opts.keyRootPc == null ? -1 : opts.keyRootPc;
    this.keyMinor = !!opts.keyMinor;
    this.reduce = !!opts.reduceMotion;
    this.onDone = opts.onDone || null;
    this.cvs.classList.remove('hidden');
    if (this.raf) cancelAnimationFrame(this.raf);
    if (this.reduce) {
      this._paint(kPayoffStill);
      this._holdUntil = performance.now() + 700;
      this.raf = requestAnimationFrame(() => this._holdTick());
      return;
    }
    this.startMs = performance.now();
    this.raf = requestAnimationFrame(() => this._tick());
  }

  _holdTick() {
    if (performance.now() >= this._holdUntil) { this._finish(); return; }
    this.raf = requestAnimationFrame(() => this._holdTick());
  }

  _tick() {
    const t = (performance.now() - this.startMs) / (1000 * kDurationSec);
    if (t >= 1.0) { this._paint(1.0); this._finish(); return; }
    this._paint(t);
    this.raf = requestAnimationFrame(() => this._tick());
  }

  _finish() {
    if (this.raf) cancelAnimationFrame(this.raf), (this.raf = 0);
    this.ctx.clearRect(0, 0, this.w, this.h);
    this.cvs.classList.add('hidden');
    const cb = this.onDone; this.kind = Celebration.None; this.onDone = null;
    if (cb) cb();
  }

  // Dismiss early (a tap, or the host closing it).
  dismiss() { if (this.kind !== Celebration.None) this._finish(); }

  // Freeze at progress t01 for a screenshot — no loop, no motion (the capture hook).
  renderStatic(kind, t01, opts = {}) {
    if (this.raf) cancelAnimationFrame(this.raf), (this.raf = 0);
    this._size();
    this._setKind(kind, opts.melody);
    this.keyRootPc = opts.keyRootPc == null ? -1 : opts.keyRootPc;
    this.keyMinor = !!opts.keyMinor;
    this.cvs.classList.remove('hidden');
    this.t = clamp01(t01);
    this._paint(this.t);
  }

  _paint(t) {
    this.t = t;
    const ctx = this.ctx;
    ctx.clearRect(0, 0, this.w, this.h);
    ctx.save();
    switch (this.kind) {
      case Celebration.ShipIt:        this._paintShipIt(ctx); break;
      case Celebration.HumCatcher:    this._paintHum(ctx); break;
      case Celebration.KeyFinder:     this._paintKeyFinder(ctx); break;
      case Celebration.GrooveMaker:   this._paintGrooveMaker(ctx); break;
      case Celebration.TimeTraveler:  this._paintTimeTraveler(ctx); break;
      case Celebration.GrainGardener: this._paintGrainGardener(ctx); break;
      default: break;
    }
    ctx.restore();
  }

  _minDim() { return Math.min(this.w, this.h); }
  // this celebration's identity colour — the SAME hue as its medal's dome, from the ONE shared
  // catalog (medals.js celebrationColour), so the trophy + its celebration can never drift (P1-b).
  _col() { return hexToRgb(celebrationColour(this.kind)); }
  _keyTint() {
    if (this.keyRootPc >= 0) return hsvToRgb((((this.keyRootPc % 12) + 12) % 12) / 12.0, 0.60, 1.0);
    return this._col();
  }

  // ==================================================================== SHIP IT — vinyl-press stamp
  _paintShipIt(ctx) {
    const t = this.t, w = this.w, h = this.h, cx = w * 0.5, restY = h * 0.44, R = this._minDim() * 0.30;
    const label = this._col();   // Ship It pink — from the shared medal catalog
    const pDesc = clamp01(t / 0.34), pImpact = clamp01((t - 0.34) / 0.22), pSettle = clamp01((t - 0.40) / 0.18);
    const pStamp = clamp01((t - 0.58) / 0.20), pSweep = clamp01((t - 0.72) / 0.28), pFade = clamp01((t - 0.88) / 0.12);

    let shX = 0, shY = 0;
    if (t >= 0.34 && t < 0.54) { const k = 1 - clamp01((t - 0.34) / 0.20); const amp = 9 * k * k; shX = Math.sin(t * 220) * amp; shY = Math.cos(t * 190) * amp * 0.6; }
    ctx.save(); ctx.translate(shX, shY);

    if (pDesc < 1.0) {
      const suck = ease(pDesc);
      for (let r = 0; r < 5; r++) {
        const baseY = h * (0.60 + r * 0.085), y = baseY + (restY - baseY) * suck, a = (1 - suck) * 0.55;
        if (a <= 0.01) continue;
        ctx.strokeStyle = rgba(label, a); ctx.lineWidth = 2;
        ctx.beginPath();
        const x0 = cx + (w * -0.42) * (1 - suck), x1 = cx + (w * 0.42) * (1 - suck), amp = 16 * (1 - suck), N = 44;
        for (let i = 0; i <= N; i++) { const u = i / N, xx = x0 + (x1 - x0) * u, yy = y + Math.sin(u * 22 + r) * amp; i === 0 ? ctx.moveTo(xx, yy) : ctx.lineTo(xx, yy); }
        ctx.stroke();
      }
    }

    let discY;
    if (t < 0.34) { const u = Math.pow(pDesc, 1.4); discY = -R * 0.5 + (restY - (-R * 0.5)) * u; }
    else { const b = Math.exp(-pSettle * 6) * Math.abs(Math.sin(pSettle * 3 * kPi)); discY = restY - b * R * 0.22; }

    if (t < 0.34 && pDesc > 0.12) {
      for (let s = 1; s <= 4; s++) { const gy = discY - s * R * 0.34; ctx.fillStyle = rgba([154, 160, 168], 0.09 * (5 - s)); fillEllipse(ctx, cx - R, gy - R, R * 2, R * 2); }
    }

    const discA = 1 - pFade;
    if (discA > 0.01) this._drawDisc(ctx, cx, discY, R * (1 - pFade * 0.12), label, discA, pStamp, pSweep);

    if (t >= 0.34 && pImpact < 1.0) {
      const sw = ease(pImpact), rr = R * (1 + sw * 2.4), a = (1 - sw) * 0.6;
      ctx.strokeStyle = rgba(WHITE, a); strokeEllipse(ctx, cx - rr, restY - rr, rr * 2, rr * 2, 3 * (1 - sw) + 1);
      const rr2 = R * (1 + sw * 1.5); ctx.strokeStyle = rgba(label, a * 0.7); strokeEllipse(ctx, cx - rr2, restY - rr2, rr2 * 2, rr2 * 2, 2);
    }
    if (t >= 0.32 && t < 0.46) { const fa = (1 - clamp01((t - 0.32) / 0.14)) * 0.5; ctx.fillStyle = rgba(WHITE, fa); fillRect(ctx, 0, 0, w, h); }

    if (pSettle > 0 && t < 0.86) {
      const life = clamp01((t - 0.40) / 0.44);
      for (let i = 0; i < 8; i++) {
        const side = i % 2 === 0 ? -1 : 1, seed = h01(i * 7 + 3), lp = clamp01(life * 1.3 - seed * 0.5);
        if (lp <= 0 || lp >= 1) continue;
        const pxx = cx + side * R * (0.55 + seed * 0.5), pyy = restY + R * 0.55 - lp * R * (0.7 + seed * 0.6), pr = R * (0.06 + lp * 0.20 + seed * 0.05);
        ctx.fillStyle = rgba(WHITE, (1 - lp) * 0.5); fillEllipse(ctx, pxx - pr, pyy - pr, pr * 2, pr * 2);
      }
    }
    ctx.restore();
  }

  _drawDisc(ctx, cx, cy, R, label, alpha, stampP, sweepP) {
    const labelR = R * 0.34;
    // chrome body radial
    let grd = ctx.createRadialGradient(cx - R * 0.4, cy - R * 0.5, R * 0.05, cx, cy, R * 1.3);
    grd.addColorStop(0, rgba([244, 246, 248], alpha)); grd.addColorStop(0.35, rgba([199, 204, 210], alpha));
    grd.addColorStop(0.62, rgba([107, 112, 120], alpha)); grd.addColorStop(0.85, rgba([58, 62, 69], alpha)); grd.addColorStop(1, rgba([43, 47, 54], alpha));
    ctx.fillStyle = grd; fillEllipse(ctx, cx - R, cy - R, R * 2, R * 2);

    const grooves = 46;
    for (let i = 0; i < grooves; i++) {
      const u = i / grooves, gr = labelR + (R * 0.97 - labelR) * u, gc = i % 2 === 0 ? [233, 237, 241] : [35, 38, 43];
      ctx.strokeStyle = rgba(gc, 0.5 * alpha); strokeEllipse(ctx, cx - gr, cy - gr, gr * 2, gr * 2, 0.9);
    }

    if (sweepP > 0 && sweepP < 1) {
      ctx.save();
      ctx.beginPath();
      ctx.ellipse(cx, cy, R * 0.98, R * 0.98, 0, 0, kTwoPi);
      ctx.ellipse(cx, cy, labelR, labelR, 0, 0, kTwoPi, true);   // even-odd annulus (hole at label)
      ctx.clip('evenodd');
      const ang = kTwoPi * sweepP, spectral = [[255, 77, 141], [88, 224, 138], [91, 142, 212]], env = Math.sin(sweepP * kPi);
      for (let s = 0; s < 3; s++) {
        const a2 = ang + s * 0.22, dx = Math.cos(a2), dy = Math.sin(a2);
        const gr = ctx.createLinearGradient(cx - dx * R, cy - dy * R, cx + dx * R, cy + dy * R);
        gr.addColorStop(0, rgba(spectral[s], 0)); gr.addColorStop(0.5, rgba(spectral[s], 0.5 * env * alpha)); gr.addColorStop(1, rgba(spectral[s], 0));
        ctx.fillStyle = gr; fillEllipse(ctx, cx - R, cy - R, R * 2, R * 2);
      }
      ctx.restore();
    }

    // centre label
    let lg = ctx.createLinearGradient(cx, cy - labelR, cx, cy + labelR);
    lg.addColorStop(0, rgba(brighter(label, 0.15), alpha)); lg.addColorStop(1, rgba(darker(label, 0.25), alpha));
    ctx.fillStyle = lg; fillEllipse(ctx, cx - labelR, cy - labelR, labelR * 2, labelR * 2);
    ctx.strokeStyle = rgba(WHITE, 0.5 * alpha); strokeEllipse(ctx, cx - labelR, cy - labelR, labelR * 2, labelR * 2, 1.2);

    if (stampP > 0) {
      const sa = ease(stampP);
      const rowY = (yc) => cy + labelR * yc;
      ctx.fillStyle = rgba(BLACK, 0.35 * sa); drawText(ctx, 'CYCLO REC', cx - labelR + 0.6, rowY(-0.62) + 0.6, labelR * 2, labelR * 0.5, 'centre', monoFont(Math.max(9, R * 0.11), true));
      ctx.fillStyle = rgba(WHITE, 0.95 * sa); drawText(ctx, 'CYCLO REC', cx - labelR, rowY(-0.62), labelR * 2, labelR * 0.5, 'centre', monoFont(Math.max(9, R * 0.11), true));
      ctx.fillStyle = rgba(BLACK, 0.9 * sa); drawText(ctx, 'CYC-001', cx - labelR, rowY(-0.12), labelR * 2, labelR * 0.5, 'centre', monoFont(Math.max(12, R * 0.17), true));
      ctx.fillStyle = rgba(WHITE, 0.75 * sa); drawText(ctx, 'FIRST PRESSING', cx - labelR, rowY(0.40), labelR * 2, labelR * 0.35, 'centre', sansFont(Math.max(7, R * 0.07), true));
    }

    const sp = R * 0.045; ctx.fillStyle = rgba([20, 22, 26], alpha); fillEllipse(ctx, cx - sp, cy - sp, sp * 2, sp * 2);

    // specular sheen (clipped)
    ctx.save(); ctx.beginPath(); ctx.ellipse(cx, cy, R, R, 0, 0, kTwoPi); ctx.clip();
    let sh = ctx.createRadialGradient(cx - R * 0.45, cy - R * 0.5, R * 0.02, cx - R * 0.45, cy - R * 0.5, R * 0.95);
    sh.addColorStop(0, rgba(WHITE, 0.42 * alpha)); sh.addColorStop(1, rgba(WHITE, 0));
    ctx.fillStyle = sh; fillEllipse(ctx, cx - R, cy - R, R * 2, R * 2); ctx.restore();

    ctx.strokeStyle = rgba(BLACK, 0.4 * alpha); strokeEllipse(ctx, cx - R, cy - R, R * 2, R * 2, 1.5);
    ctx.strokeStyle = rgba(WHITE, 0.5 * alpha); strokeEllipse(ctx, cx - R + 1.5, cy - R + 1.5, R * 2 - 3, R * 2 - 3, 1);
  }

  // ==================================================================== HUM CATCHER — hum -> bird
  _paintHum(ctx) {
    const t = this.t, w = this.w, h = this.h, blue = this._col();   // Hum Catcher blue — shared catalog
    const P0 = { x: w * 0.22, y: h * 0.72 }, P1 = { x: w * 0.52, y: h * 0.02 }, P2 = { x: w * 1.14, y: h * 0.10 };
    const bez = (u) => { const v = 1 - u; return { x: v * v * P0.x + 2 * v * u * P1.x + u * u * P2.x, y: v * v * P0.y + 2 * v * u * P1.y + u * u * P2.y }; };
    const pGather = clamp01(t / 0.18), uFly = (t - 0.18) / 0.68;

    if (pGather < 1.0) {
      const col = ease(pGather), y0 = h * 0.82, xL = w * 0.10, xR = w * 0.90, N = 96;
      ctx.strokeStyle = rgba(blue, 0.85 * (1 - col * 0.35)); ctx.lineWidth = 2.4; ctx.lineJoin = 'round';
      ctx.beginPath();
      for (let i = 0; i <= N; i++) { const u = i / N, sx = xL + (xR - xL) * u, sy = y0 - waveAmp(u) * h * 0.10, gx = sx + (P0.x - sx) * col, gy = sy + (P0.y - sy) * col; i === 0 ? ctx.moveTo(gx, gy) : ctx.lineTo(gx, gy); }
      ctx.stroke();
    }
    if (t < 0.14) return;

    const nn = this.notes.length;
    for (let i = 0; i < nn; i++) {
      const uNote = 0.10 + 0.80 * (i / Math.max(1, nn - 1));
      if (uFly < uNote - 0.02) continue;
      const age = clamp01((uFly - uNote) / 0.9), bp = bez(uNote), by = bp.y - this.notes[i] * h * 0.10 - h * 0.02;
      const rr = this._minDim() * (0.014 + 0.010 * (1 - age)), a = (1 - age) * 0.9;
      ctx.fillStyle = rgba(blue, a * 0.35); fillEllipse(ctx, bp.x - rr * 2, by - rr * 2, rr * 4, rr * 4);
      ctx.fillStyle = rgba(WHITE, a); fillEllipse(ctx, bp.x - rr, by - rr, rr * 2, rr * 2);
      ctx.strokeStyle = rgba(blue, a); strokeEllipse(ctx, bp.x - rr * 1.6, by - rr * 1.6, rr * 3.2, rr * 3.2, 1.4);
    }

    if (uFly < 1.10) {
      const pos = bez(Math.min(uFly, 1.08)), pos2 = bez(Math.min(uFly + 0.02, 1.10));
      const head = Math.atan2(pos2.y - pos.y, pos2.x - pos.x), flap = Math.sin(uFly * 26.0), birdA = 1 - clamp01((uFly - 1.0) / 0.10);
      if (birdA > 0.01) this._drawBird(ctx, pos, head, flap, blue, birdA);
    }

    if (t > 0.84) {
      const sp = clamp01((t - 0.84) / 0.14), pos = bez(Math.min(0.98 + sp * 0.10, 1.08));
      for (let i = 0; i < 10; i++) {
        const a = h01(i * 3 + 1) * kTwoPi, d = sp * this._minDim() * (0.10 + h01(i * 5) * 0.08), rr = this._minDim() * 0.008 * (1 - sp), aa = (1 - sp) * 0.9;
        ctx.fillStyle = rgba(i % 2 ? blue : WHITE, aa); fillEllipse(ctx, pos.x + Math.cos(a) * d - rr, pos.y + Math.sin(a) * d - rr, rr * 2, rr * 2);
      }
    }
  }

  _drawBird(ctx, pos, head, flap, blue, alpha) {
    const S = this._minDim() * 0.13, cell = Math.max(3, S * 0.14);
    ctx.save(); ctx.translate(pos.x, pos.y); ctx.rotate(head - 0.12);
    const px = (lx, ly, rgb, a) => { ctx.fillStyle = rgba(rgb, (a === undefined ? 1 : a) * alpha); ctx.fillRect(lx - cell * 0.5, ly - cell * 0.5, cell, cell); };
    const wing = (dir, bright) => {
      const wa = -0.55 + flap * 0.85 * dir;
      for (let d = cell; d <= S * 0.52; d += cell) { const wx = -S * 0.02 - d * 0.55, wy = -S * 0.05 + d * Math.sin(wa), sh = 0.5 + 0.5 * waveAmp(d / S); px(wx, wy, mulBright(blue, 0.85 + 0.4 * sh), bright); }
    };
    wing(0.75, 0.6);
    for (let lx = -S * 0.42; lx <= S * 0.34; lx += cell) {
      const nx = (lx + S * 0.42) / (S * 0.76), half = Math.sin(nx * kPi) * S * 0.30 + S * 0.05;
      for (let ly = -half; ly <= half; ly += cell) { const shade = 0.5 + 0.5 * waveAmp(nx * 0.7 + (ly / S + 0.5) * 0.3); px(lx, ly, mulBright(blue, 0.7 + 0.55 * shade)); }
    }
    for (let t2 = 0; t2 < 3; t2++) px(-S * 0.46 - t2 * cell * 0.4, (t2 - 1) * cell, mulBright(blue, 0.8));
    px(S * 0.40, -S * 0.02, hexToRgb('#ffb03a')); px(S * 0.46, -S * 0.02, hexToRgb('#ff8a2a')); px(S * 0.28, -S * 0.10, WHITE);
    ctx.fillStyle = rgba(BLACK, alpha); fillEllipse(ctx, S * 0.28 - cell * 0.16, -S * 0.10 - cell * 0.16, cell * 0.32, cell * 0.32);
    wing(1.0, 1.0);
    ctx.restore();
  }

  // ==================================================================== KEY FINDER — tuning-fork ting
  _paintKeyFinder(ctx) {
    const t = this.t, w = this.w, h = this.h, cx = w * 0.5, cy = h * 0.40, tint = this._keyTint();
    const washA = ease(clamp01(t / 0.13)) * (1 - ease(clamp01((t - 0.55) / 0.42)));
    if (washA > 0.01) {
      const wg = ctx.createRadialGradient(cx, cy, 0, cx, cy, this._minDim() * 0.95);
      wg.addColorStop(0, rgba(tint, 0.30 * washA)); wg.addColorStop(1, rgba(tint, 0.04 * washA));
      ctx.fillStyle = wg; fillRect(ctx, 0, 0, w, h);
    }
    const Rmax = this._minDim() * 0.66;
    for (let r = 0; r < 6; r++) {
      const ts = r * 0.055, age = (t - ts) / 0.60;
      if (age <= 0 || age >= 1) continue;
      const rad = ease(age) * Rmax, a = (1 - age) * 0.55 * (1 - r * 0.13);
      if (a <= 0.01) continue;
      ctx.strokeStyle = rgba(tint, a); strokeEllipse(ctx, cx - rad, cy - rad, rad * 2, rad * 2, 2.4 * (1 - age) + 0.6);
    }
    const forkA = 1 - ease(clamp01((t - 0.30) / 0.24));
    if (forkA > 0.01) {
      const F = this._minDim() * 0.16, tw = F * 0.34, shiver = Math.sin(t * 120) * F * 0.05 * (1 - clamp01(t / 0.40));
      ctx.lineJoin = 'round'; ctx.lineCap = 'round';
      ctx.beginPath();
      ctx.moveTo(cx - tw - shiver, cy - F); ctx.lineTo(cx - tw, cy + F * 0.15);
      ctx.moveTo(cx + tw + shiver, cy - F); ctx.lineTo(cx + tw, cy + F * 0.15);
      ctx.moveTo(cx - tw, cy + F * 0.15); ctx.quadraticCurveTo(cx, cy + F * 0.55, cx + tw, cy + F * 0.15);
      ctx.moveTo(cx, cy + F * 0.40); ctx.lineTo(cx, cy + F * 0.85);
      ctx.strokeStyle = rgba(tint, 0.85 * forkA); ctx.lineWidth = Math.max(2, F * 0.10); ctx.stroke();
      ctx.strokeStyle = rgba(WHITE, 0.5 * forkA); ctx.lineWidth = Math.max(0.8, F * 0.03); ctx.stroke();
    }
    const rootPc = this.keyRootPc >= 0 ? this.keyRootPc : 2, third = this.keyMinor ? 3 : 4;
    const pcs = [rootPc, rootPc + third, rootPc + 7], rowY = cy + this._minDim() * 0.34, letA = 1 - ease(clamp01((t - 0.82) / 0.18));
    for (let i = 0; i < 3; i++) {
      const birth = 0.24 + i * 0.07, rise = ease(clamp01((t - birth) / 0.34));
      if (rise <= 0.001) continue;
      const bx = cx + (i - 1) * this._minDim() * 0.20, ly = cy + (rowY - cy) * rise, sz = this._minDim() * (0.055 + 0.055 * rise), age = clamp01((t - birth) / 0.34);
      const pulse = Math.sin(clamp01(age) * kPi), hr = sz * (0.9 + 1.6 * pulse);
      ctx.strokeStyle = rgba(tint, 0.35 * pulse * letA); strokeEllipse(ctx, bx - hr, ly - hr, hr * 2, hr * 2, 2);
      ctx.fillStyle = rgba(darker(tint, 0.6), 0.8 * letA); drawText(ctx, pcName(pcs[i]), bx - sz + sz * 0.06, ly - sz + sz * 0.06, sz * 2, sz * 2, 'centre', roundFont(sz * 1.5));
      ctx.fillStyle = rgba(WHITE, 0.96 * letA); drawText(ctx, pcName(pcs[i]), bx - sz, ly - sz, sz * 2, sz * 2, 'centre', roundFont(sz * 1.5));
    }
  }

  // ==================================================================== GROOVE MAKER — the swung wave
  _paintGrooveMaker(ctx) {
    const t = this.t, w = this.w, h = this.h, mint = this._col();   // Groove Maker mint — shared catalog
    const lifeA = ease(clamp01(t / 0.10)) * (1 - ease(clamp01((t - 0.82) / 0.18)));
    if (lifeA <= 0.01) return;
    const gw = this._minDim() * 0.60, gh = gw, gx = w * 0.5 - gw * 0.5, gy = h * 0.54 - gh * 0.5, gap = gw * 0.05, cell = (gw - gap * 3) / 4, lift = cell * 0.42;
    const swing = 0.34, passes = 2.0, wp = (t * passes) % 1.0;
    const colPhase = (c) => (c + (c % 2 === 1 ? swing : 0)) / 4.0;
    const wrapDist = (a, b) => { const d = Math.abs(a - b); return Math.min(d, 1 - d); };
    for (let c = 0; c < 4; c++) {
      const d = wrapDist(wp, colPhase(c)), env = Math.exp(-(d * d) / (2 * 0.075 * 0.075));
      for (let rIx = 0; rIx < 4; rIx++) {
        const re = clamp01(env - rIx * 0.06), px = gx + c * (cell + gap), py = gy + rIx * (cell + gap) - re * lift, corner = cell * 0.22;
        this._roundRect(ctx, px, py, cell, cell, corner);
        ctx.fillStyle = rgba(mint, 0.10 * lifeA); ctx.fill();
        this._roundRect(ctx, px, py, cell, cell, corner);
        ctx.strokeStyle = rgba(mint, (0.22 + 0.5 * re) * lifeA); ctx.lineWidth = 1.6; ctx.stroke();
        if (re > 0.02) {
          const glowR = cell * (0.7 + re * 0.5), ccx = px + cell / 2, ccy = py + cell / 2;
          const gl = ctx.createRadialGradient(ccx, ccy, 0, ccx, ccy, glowR);
          gl.addColorStop(0, rgba(mint, 0.5 * re * lifeA)); gl.addColorStop(1, rgba(mint, 0));
          ctx.fillStyle = gl; fillEllipse(ctx, ccx - glowR, ccy - glowR, glowR * 2, glowR * 2);
          this._roundRect(ctx, px + cell * 0.16, py + cell * 0.16, cell * 0.68, cell * 0.68, corner * 0.7);
          ctx.fillStyle = rgba(brighter(mint, 0.3), 0.55 * re * lifeA); ctx.fill();
          this._roundRect(ctx, px + cell * 0.34, py + cell * 0.34, cell * 0.32, cell * 0.32, corner * 0.5);
          ctx.fillStyle = rgba(WHITE, 0.5 * re * re * lifeA); ctx.fill();
        }
      }
      if (env > 0.35) {
        const base = gy - lift;
        for (let m = 0; m < 3; m++) {
          const seed = h01(c * 13 + m * 7), up = (t * 1.7 + seed) % 1.0, mx = gx + c * (cell + gap) + cell * (0.2 + seed * 0.6), my = base - up * cell * 1.4, mr = cell * 0.07 * (1 - up);
          ctx.fillStyle = rgba(mint, (1 - up) * env * 0.8 * lifeA); fillEllipse(ctx, mx - mr, my - mr, mr * 2, mr * 2);
        }
      }
    }
  }

  _roundRect(ctx, x, y, w, h, r) {
    const rr = Math.min(r, w / 2, h / 2);
    ctx.beginPath(); ctx.moveTo(x + rr, y);
    ctx.arcTo(x + w, y, x + w, y + h, rr); ctx.arcTo(x + w, y + h, x, y + h, rr);
    ctx.arcTo(x, y + h, x, y, rr); ctx.arcTo(x, y, x + w, y, rr); ctx.closePath();
  }

  // ==================================================================== TIME TRAVELER — VHS rewind
  _paintTimeTraveler(ctx) {
    const t = this.t, w = this.w, h = this.h, cyan = this._col();   // Time Traveler cyan — shared catalog
    const snap = clamp01((t - 0.86) / 0.09), rewA = 1 - snap;
    const wob = (Math.sin(t * 47) + 0.4 * Math.sin(t * 113)) * w * 0.006 * rewA;
    ctx.save(); ctx.translate(wob, 0);
    if (rewA > 0.01) {
      ctx.fillStyle = rgba(BLACK, 0.34 * rewA); fillRect(ctx, 0, 0, w, h);
      for (let y = 0; y < h; y += 3) { ctx.fillStyle = rgba(BLACK, 0.20 * rewA); fillRect(ctx, -w * 0.05, y, w * 1.1, 1.4); }
      const slices = 26;
      for (let s = 0; s < slices; s++) {
        const y0 = h * s / slices, sh = h / slices + 1, j = h01(s * 5 + ((t * 22) | 0)) - 0.5, shove = j * w * 0.06 * rewA;
        if (Math.abs(shove) < 1) continue;
        ctx.fillStyle = rgba(cyan, 0.16 * rewA); fillRect(ctx, -w * 0.05 + shove - 3, y0, w * 1.1, sh);
        ctx.fillStyle = rgba([255, 58, 122], 0.13 * rewA); fillRect(ctx, -w * 0.05 + shove + 3, y0, w * 1.1, sh * 0.5);
      }
      const bandC = h * (1.15 - ((t * 2.2) % 1.3)), bandH = h * 0.14;
      const bg = ctx.createLinearGradient(0, bandC - bandH, 0, bandC + bandH);
      bg.addColorStop(0, rgba(WHITE, 0)); bg.addColorStop(0.5, rgba(WHITE, 0.35 * rewA)); bg.addColorStop(1, rgba(WHITE, 0));
      ctx.fillStyle = bg; fillRect(ctx, 0, bandC - bandH, w, bandH * 2);
      ctx.fillStyle = rgba(cyan, 0.30 * rewA);
      for (let i = 0; i < 40; i++) { const rx = h01(i * 3 + ((t * 30) | 0)) * w, ry = bandC + (h01(i * 7) - 0.5) * bandH, rw = 6 + h01(i * 11) * 26; fillRect(ctx, rx, ry, rw, 1.6); }
      const counter = ((1 - t) * 8888) | 0, cs = 'REW <<   ' + String(counter).padStart(4, '0');
      const font = monoFont(Math.max(12, this._minDim() * 0.045), true), bx = w * 0.06, by = h * 0.06;
      ctx.fillStyle = rgba([255, 58, 122], 0.7 * rewA); drawText(ctx, cs, bx - 2.4, by, 0, 0, 'topLeft', font);
      ctx.fillStyle = rgba(cyan, 0.7 * rewA); drawText(ctx, cs, bx + 2.4, by, 0, 0, 'topLeft', font);
      ctx.fillStyle = rgba(WHITE, 0.92 * rewA); drawText(ctx, cs, bx, by, 0, 0, 'topLeft', font);
    }
    ctx.restore();
    if (snap > 0) {
      ctx.fillStyle = rgba(WHITE, (1 - snap) * 0.85); fillRect(ctx, 0, 0, w, h);
      const tagA = ease(clamp01((snap - 0.2) / 0.5)) * (1 - clamp01((t - 0.985) / 0.015));
      if (tagA > 0.01) { ctx.fillStyle = rgba(cyan, 0.9 * tagA); drawText(ctx, '> PLAY', w * 0.06, h * 0.06, 0, 0, 'topLeft', monoFont(Math.max(12, this._minDim() * 0.05), true)); }
    }
  }

  // ==================================================================== GRAIN GARDENER — bloom -> flower
  _paintGrainGardener(ctx) {
    const t = this.t, w = this.w, h = this.h, cx = w * 0.5, cy = h * 0.42, lime = this._col();   // Grain Gardener lime — shared catalog
    const fade = 1 - ease(clamp01((t - 0.88) / 0.12));
    if (fade <= 0.01) return;
    const scatterP = ease(clamp01(t / 0.32)), settleP = ease(clamp01((t - 0.34) / 0.50)), burst = clamp01(t / 0.22);
    if (burst < 1.0) {
      const br = ease(burst) * this._minDim() * 0.34;
      ctx.strokeStyle = rgba(lime, (1 - burst) * 0.6 * fade); strokeEllipse(ctx, cx - br, cy - br, br * 2, br * 2, 3 * (1 - burst) + 1);
      const fr = (1 - burst) * this._minDim() * 0.12; ctx.fillStyle = rgba(WHITE, (1 - burst) * (1 - burst) * 0.5 * fade); fillEllipse(ctx, cx - fr, cy - fr, fr * 2, fr * 2);
    }
    const NSEED = 66, NPET = 6, Rf = this._minDim() * 0.24;
    for (let i = 0; i < NSEED; i++) {
      const pet = i % NPET, idxIn = (i / NPET) | 0, within = (idxIn + 0.5) / (((NSEED + NPET - 1) / NPET) | 0);
      const petAng = pet / NPET * kTwoPi, lobe = Math.sin(within * kPi), rr = Rf * (0.22 + 0.78 * lobe), ang = petAng + (h01(i) - 0.5) * 0.55 * lobe;
      const tx = cx + Math.cos(ang) * rr, ty = cy + Math.sin(ang) * rr;
      const sa = h01(i * 3) * kTwoPi, sd = this._minDim() * (0.30 + 0.22 * h01(i * 7)), scx = cx + Math.cos(sa) * sd, scy = cy + Math.sin(sa) * sd;
      const mx = cx + (scx - cx) * scatterP, my = cy + (scy - cy) * scatterP, posx = mx + (tx - mx) * settleP, posy = my + (ty - my) * settleP;
      if (settleP > 0.45) {
        const grow = clamp01((settleP - 0.45) / 0.55), rtx = posx + (cx - posx) * 0.30 * grow, rty = posy + (cy - posy) * 0.30 * grow;
        ctx.strokeStyle = rgba(darker(lime, 0.2), 0.5 * grow * fade); ctx.lineWidth = Math.max(1, this._minDim() * 0.004);
        ctx.beginPath(); ctx.moveTo(posx, posy); ctx.lineTo(rtx, rty); ctx.stroke();
      }
      const br2 = 0.5 + 0.5 * settleP, sr = this._minDim() * (0.007 + 0.006 * lobe);
      ctx.fillStyle = rgba(lime, 0.30 * br2 * fade); fillEllipse(ctx, posx - sr * 2.4, posy - sr * 2.4, sr * 4.8, sr * 4.8);
      ctx.fillStyle = rgba(WHITE, 0.85 * br2 * fade); fillEllipse(ctx, posx - sr, posy - sr, sr * 2, sr * 2);
    }
    const heartP = ease(clamp01((t - 0.62) / 0.30));
    if (heartP > 0.01) {
      const pulse = 0.85 + 0.15 * Math.sin(t * 20), S = this._minDim() * 0.075 * heartP * pulse, glowR = S * 2.6;
      ctx.fillStyle = rgba(lime, 0.45 * heartP * fade); fillEllipse(ctx, cx - glowR, cy - glowR, glowR * 2, glowR * 2);
      ctx.beginPath();
      for (let k = 0; k < 8; k++) { const a = k / 8 * kTwoPi - kPi * 0.5, rad = k % 2 === 0 ? S : S * 0.34, xx = cx + Math.cos(a) * rad, yy = cy + Math.sin(a) * rad; k === 0 ? ctx.moveTo(xx, yy) : ctx.lineTo(xx, yy); }
      ctx.closePath();
      ctx.fillStyle = rgba(WHITE, 0.95 * heartP * fade); ctx.fill();
      ctx.strokeStyle = rgba(brighter(lime, 0.3), 0.9 * heartP * fade); ctx.lineWidth = Math.max(1, S * 0.10); ctx.stroke();
    }
  }
}
