// ===========================================================================
//  store.js — durable + portable Cyclo songs on the web.
//
//  Memory cyclo-platform-strategy: "storage can evict a bus-sketch; the coin/text is its
//  own backup; own-recording songs need a bundle to travel." This module is that safety net:
//
//    1. AUTOSAVE (IndexedDB) — the current document + BPM + the session's user samples are
//       persisted (debounced) so a reload lands exactly where you left off, samples intact.
//       IndexedDB (not localStorage) because sample PCM is far too big for localStorage.
//    2. NAMED PROJECTS (IndexedDB) — save / list / open / delete named projects, each a full
//       snapshot (doc + bpm + samples). Mirrors native ProjectStore / ProjectBrowser intent.
//    3. .cyclo FILE + BUNDLE — a downloadable, shareable single file:
//         • code-only  -> a plain-text `.cyclo` (the document text; human-readable, byte-for-byte
//           the same coin native writes) for songs that use only built-in/synth sounds.
//         • bundle     -> a `.cyclobundle` (an fflate zip) packing the doc text + every referenced
//           USER sample as a 16-bit WAV, so a song built on your OWN recording travels as one file
//           (OS share sheet / download). This closes the "own-recording songs can't be saved/shared"
//           gap — the share LINK stays for code-only songs; sample-bearing songs steer to a bundle.
//       readCycloFile() imports either back (detects a zip by its `PK` magic vs plain text).
//
//  The bundle codec (makeBundle / readBundle / WAV encode+decode) is PURE — it imports only fflate,
//  touches no `window` / `indexedDB` / `document`, and runs in Node — so web/verify.js proves the
//  round-trip headlessly. The IndexedDB half is browser-only and is only called from the bundle.
// ===========================================================================
import { zipSync, unzipSync, strToU8, strFromU8 } from 'fflate';

export const BUNDLE_FORMAT = 'cyclo-bundle/1';
const DB_NAME = 'cyclo';
const DB_VERSION = 2;
const STORE_PROJECTS = 'projects';   // key = project name -> { name, doc, bpm, samples[], savedAt }
const STORE_META = 'meta';           // key = 'autosave' -> { doc, bpm, samples[], savedAt }
const STORE_LIBRARY = 'library';     // key = sound name -> { name, channels, rate, pcm, slices, savedAt }
                                     //   the persistent, CROSS-PROJECT sound library (native SoundLibrary):
                                     //   keepers that any project can pull in. Its OWN store, separate from
                                     //   per-project autosave/projects — a "kept" sound outlives every project.
const AUTOSAVE_KEY = 'autosave';
const SCORE_KEY = 'score';           // key = 'score' -> { text } (the Maker Score serialized state)
const MEDALS_KEY = 'medals';         // key = 'medals' -> { text } (the Maker Medals earned-state)
const HISTORY_KEY = 'history';        // key = 'history' -> { text } (the local version-history shelf)
const FEED_KEY = 'feed';              // key = 'feed' -> { text } (the LIVE FEED activity ring, JSON)
const DAILY_KEY = 'daily';            // key = 'daily' -> { text } (the Daily Challenge completion state)
const WELCOMED_KEY = 'welcomed';      // key = 'welcomed' -> { text:'1' } (the first-run welcome has been seen)

// A "sample" record everywhere in this module is: { name, channels, rate, pcm:Float32Array }
// where pcm is INTERLEAVED (mono = 1 ch, stereo = L,R,L,R). IndexedDB structured-clones a
// Float32Array losslessly, so autosave/projects keep the raw floats (no WAV re-encode); only the
// portable .cyclobundle re-encodes to WAV so the file is a standard, openable container.

// ---------------------------------------------------------------------------
//  WAV (16-bit PCM) encode / decode — pure, no DOM. Used ONLY by the portable bundle
//  (autosave/projects keep raw Float32 in IndexedDB). 16-bit is plenty for a shareable
//  sound file and keeps the bundle small; decode reads exactly what we write.
// ---------------------------------------------------------------------------
export function encodeWav(sample) {
  const { channels, rate, pcm } = sample;
  const frames = Math.floor(pcm.length / channels);
  const blockAlign = channels * 2;
  const dataLen = frames * blockAlign;
  const buf = new ArrayBuffer(44 + dataLen);
  const dv = new DataView(buf);
  const ws = (off, s) => { for (let i = 0; i < s.length; i++) dv.setUint8(off + i, s.charCodeAt(i)); };
  ws(0, 'RIFF'); dv.setUint32(4, 36 + dataLen, true); ws(8, 'WAVE');
  ws(12, 'fmt '); dv.setUint32(16, 16, true); dv.setUint16(20, 1, true);
  dv.setUint16(22, channels, true); dv.setUint32(24, rate, true);
  dv.setUint32(28, rate * blockAlign, true); dv.setUint16(32, blockAlign, true); dv.setUint16(34, 16, true);
  ws(36, 'data'); dv.setUint32(40, dataLen, true);
  let off = 44;
  for (let i = 0; i < pcm.length; i++) {
    // round-to-nearest at a single 32768 scale (clamp the +full-scale to the int16 max) so the
    // decode (/32768) round-trip error stays under 1 LSB — a faithful 16-bit sample file.
    let v = Math.round(Math.max(-1, Math.min(1, pcm[i])) * 32768);
    if (v > 32767) v = 32767; else if (v < -32768) v = -32768;
    dv.setInt16(off, v, true);
    off += 2;
  }
  return new Uint8Array(buf);
}

// Decode a 16-bit PCM WAV (as this module writes) back to { channels, rate, pcm:Float32Array }.
// Tolerant of extra chunks: it scans for `fmt ` + `data` rather than assuming a fixed 44-byte header.
export function decodeWav(bytes) {
  const u8 = bytes instanceof Uint8Array ? bytes : new Uint8Array(bytes);
  const dv = new DataView(u8.buffer, u8.byteOffset, u8.byteLength);
  const tag = (off) => String.fromCharCode(u8[off], u8[off + 1], u8[off + 2], u8[off + 3]);
  if (tag(0) !== 'RIFF' || tag(8) !== 'WAVE') throw new Error('not a WAV file');
  let channels = 1, rate = 48000, bits = 16, dataOff = -1, dataLen = 0;
  let p = 12;
  while (p + 8 <= u8.length) {
    const id = tag(p), size = dv.getUint32(p + 4, true);
    if (id === 'fmt ') {
      channels = dv.getUint16(p + 10, true);
      rate = dv.getUint32(p + 12, true);
      bits = dv.getUint16(p + 22, true);
    } else if (id === 'data') {
      dataOff = p + 8; dataLen = size; break;
    }
    p += 8 + size + (size & 1);   // chunks are word-aligned
  }
  if (dataOff < 0 || bits !== 16) throw new Error('unsupported WAV (need 16-bit PCM)');
  const n = Math.floor(dataLen / 2);
  const pcm = new Float32Array(n);
  for (let i = 0; i < n; i++) pcm[i] = dv.getInt16(dataOff + i * 2, true) / 0x8000;
  return { channels: channels || 1, rate: rate || 48000, pcm };
}

// ---------------------------------------------------------------------------
//  .cyclo FILE + BUNDLE — the portable, single-file save/share format. PURE.
// ---------------------------------------------------------------------------

// A single downloadable file for a song. `samples` is the list of USER samples the doc references
// (empty for a code-only song). Returns { filename, mime, bytes|text, isBundle }.
//   - no samples -> code-only `.cyclo`: the raw document text (the coin), exactly like native.
//   - samples    -> `.cyclobundle`: an fflate zip { song.cyclo, manifest.json, samples/<name>.wav }.
export function makeCycloFile(name, doc, bpm, samples) {
  const safe = fileStem(name);
  if (!samples || samples.length === 0) {
    return { filename: safe + '.cyclo', mime: 'text/plain;charset=utf-8', text: doc, bytes: null, isBundle: false };
  }
  return { filename: safe + '.cyclobundle', mime: 'application/zip', text: null, bytes: makeBundle(name, doc, bpm, samples), isBundle: true };
}

// Pack a doc + its user samples into a zip container (Uint8Array). One self-contained file.
export function makeBundle(name, doc, bpm, samples) {
  const files = {};
  files['song.cyclo'] = strToU8(String(doc));
  const manifest = { format: BUNDLE_FORMAT, name: String(name || 'song'), bpm: bpm || null, samples: [] };
  for (const s of samples || []) {
    const file = 'samples/' + fileStem(s.name) + '.wav';
    files[file] = encodeWav(s);
    // carry the sound-editor slice regions so s("name:k") survives a bundle round-trip too
    manifest.samples.push({ name: s.name, file, rate: s.rate, channels: s.channels, slices: s.slices || [] });
  }
  files['manifest.json'] = strToU8(JSON.stringify(manifest, null, 2));
  return zipSync(files, { level: 6 });
}

// Inverse of makeBundle: unzip -> { doc, bpm, name, samples:[{name,channels,rate,pcm}] }.
export function readBundle(bytes) {
  const files = unzipSync(bytes instanceof Uint8Array ? bytes : new Uint8Array(bytes));
  const manRaw = files['manifest.json'];
  const manifest = manRaw ? JSON.parse(strFromU8(manRaw)) : { samples: [] };
  const doc = files['song.cyclo'] ? strFromU8(files['song.cyclo']) : '';
  const samples = [];
  for (const entry of manifest.samples || []) {
    const wav = files[entry.file];
    if (!wav) continue;
    const dec = decodeWav(wav);
    samples.push({ name: entry.name, channels: dec.channels, rate: dec.rate, pcm: dec.pcm, slices: entry.slices || [] });
  }
  return { doc, bpm: manifest.bpm || null, name: manifest.name || 'song', samples };
}

// Import EITHER a code-only `.cyclo` (plain text) OR a `.cyclobundle` (zip), auto-detected by the
// zip local-file-header magic (`PK\x03\x04`). `bytes` is the raw file bytes (Uint8Array/ArrayBuffer).
export function readCycloFile(bytes) {
  const u8 = bytes instanceof Uint8Array ? bytes : new Uint8Array(bytes);
  const isZip = u8.length >= 4 && u8[0] === 0x50 && u8[1] === 0x4b && u8[2] === 0x03 && u8[3] === 0x04;
  if (isZip) return readBundle(u8);
  return { doc: strFromU8(u8), bpm: null, name: 'song', samples: [] };
}

// A filesystem-safe stem for a project/sound name (letters, digits, dash, underscore, space->-).
export function fileStem(name) {
  const s = String(name || '').trim().replace(/\s+/g, '-').replace(/[^A-Za-z0-9._-]/g, '');
  return s || 'song';
}

// ---------------------------------------------------------------------------
//  IndexedDB — autosave + named projects. Browser-only (guards indexedDB presence).
// ---------------------------------------------------------------------------
export function idbAvailable() {
  return typeof indexedDB !== 'undefined' && indexedDB !== null;
}

let dbPromise = null;
function openDb() {
  if (!idbAvailable()) return Promise.reject(new Error('IndexedDB unavailable'));
  if (dbPromise) return dbPromise;
  dbPromise = new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(STORE_PROJECTS)) db.createObjectStore(STORE_PROJECTS, { keyPath: 'name' });
      if (!db.objectStoreNames.contains(STORE_META)) db.createObjectStore(STORE_META, { keyPath: 'key' });
      // v2: the persistent cross-project sound library (keyed by the sanitized sound name)
      if (!db.objectStoreNames.contains(STORE_LIBRARY)) db.createObjectStore(STORE_LIBRARY, { keyPath: 'name' });
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error || new Error('IndexedDB open failed'));
  });
  return dbPromise;
}

// Run one store operation in its own transaction and resolve with the request's result. `op`
// returns the IDBRequest (e.g. store.get(k)); the promise resolves once the request succeeds AND
// the transaction commits, so a write is durable before we report success (matters for autosave).
function run(storeName, mode, op) {
  return openDb().then((db) => new Promise((resolve, reject) => {
    const t = db.transaction(storeName, mode);
    const store = t.objectStore(storeName);
    let value;
    let req;
    try { req = op(store); } catch (e) { reject(e); return; }
    if (req) req.onsuccess = () => { value = req.result; };
    t.oncomplete = () => resolve(value);
    t.onerror = () => reject(t.error || new Error('IndexedDB transaction failed'));
    t.onabort = () => reject(t.error || new Error('IndexedDB transaction aborted'));
  }));
}

// ---- autosave (single recovery slot) ----
export async function saveAutosave(snapshot) {
  await run(STORE_META, 'readwrite', (store) => store.put({ key: AUTOSAVE_KEY, ...snapshot, savedAt: Date.now() }));
}
export async function loadAutosave() {
  const rec = await run(STORE_META, 'readonly', (store) => store.get(AUTOSAVE_KEY));
  return rec || null;
}
export async function clearAutosave() {
  await run(STORE_META, 'readwrite', (store) => store.delete(AUTOSAVE_KEY));
}

// ---- Maker Score (Gamification L3) — the score/streak state, persisted like native's global
// `.score` prefs file but in this build's OWN IndexedDB (the dev-box .score is never touched).
// Stored as the serialized text (byte-compatible with the native codec) so persistence is parity.
export async function saveScore(text) {
  await run(STORE_META, 'readwrite', (store) => store.put({ key: SCORE_KEY, text: String(text), savedAt: Date.now() }));
}
export async function loadScore() {
  const rec = await run(STORE_META, 'readonly', (store) => store.get(SCORE_KEY));
  return rec && typeof rec.text === 'string' ? rec.text : null;
}
export async function clearScore() {
  await run(STORE_META, 'readwrite', (store) => store.delete(SCORE_KEY));
}

