// ---- first-run WELCOME "seen" flag (native ProjectStore::isFirstRun / markWelcomed) — persisted
// in this build's OWN IndexedDB meta slot. Set once the user dismisses the welcome (any exit); a
// returning visitor then skips it. clearAllStorage() wipes it too, so a cleared profile is "fresh"
// and greets again (the headless first-run test relies on this). ----
export async function saveWelcomed() {
  await run(STORE_META, 'readwrite', (store) => store.put({ key: WELCOMED_KEY, text: '1', savedAt: Date.now() }));
}
export async function loadWelcomed() {
  const rec = await run(STORE_META, 'readonly', (store) => store.get(WELCOMED_KEY));
  return !!(rec && rec.text);
}
export async function clearWelcomed() {
  await run(STORE_META, 'readwrite', (store) => store.delete(WELCOMED_KEY));
}

// ---- small dismissible-UI flags (a dismissed one-off hint, etc.) — one meta record per flag,
// namespaced under `ui:` so they never collide with the reserved slots above. clearAllStorage()
// wipes them with the store (a fresh profile sees the hint again). ----
export async function saveUiFlag(name, on) {
  const key = 'ui:' + String(name);
  await run(STORE_META, 'readwrite', (store) => on
    ? store.put({ key, text: '1', savedAt: Date.now() })
    : store.delete(key));
}
export async function loadUiFlag(name) {
  const rec = await run(STORE_META, 'readonly', (store) => store.get('ui:' + String(name)));
  return !!(rec && rec.text);
}

// ---- named projects ----
export async function saveProject(name, snapshot) {
  const rec = { name: String(name), ...snapshot, savedAt: Date.now() };
  await run(STORE_PROJECTS, 'readwrite', (store) => store.put(rec));
  return rec;
}
export async function listProjects() {
  const all = await run(STORE_PROJECTS, 'readonly', (store) => store.getAll());
  return (all || []).sort((a, b) => (b.savedAt || 0) - (a.savedAt || 0));
}
export async function loadProject(name) {
  const rec = await run(STORE_PROJECTS, 'readonly', (store) => store.get(String(name)));
  return rec || null;
}
export async function deleteProject(name) {
  await run(STORE_PROJECTS, 'readwrite', (store) => store.delete(String(name)));
}
export async function clearAllStorage() {
  await run(STORE_PROJECTS, 'readwrite', (store) => store.clear());
  await run(STORE_META, 'readwrite', (store) => store.clear());
  try { await run(STORE_LIBRARY, 'readwrite', (store) => store.clear()); } catch (e) {}
}

// ---------------------------------------------------------------------------
//  PERSISTENT SOUND LIBRARY (native src/engine/SoundLibrary + BankBrowser) — the cross-project
//  "keepers". A user sample's PCM is copied into this OWN IndexedDB store so it is available in
//  EVERY project (unlike per-project autosave/projects, which snapshot one session). A record is
//  { name, channels, rate, pcm:Float32Array (interleaved), slices, savedAt }. IndexedDB
//  structured-clones the Float32Array losslessly, so a keeper stays bit-faithful across projects.
//  keepLibrarySound() saves; listLibrary() enumerates (newest-first); deleteLibrarySound() removes.
//  Rehydrating a library sound into a project is the SAME addSample bridge the record/import path
//  uses (see main.js useLibrarySound) — a library sound becomes a first-class bank sound again.
// ---------------------------------------------------------------------------

// Save (or overwrite) a keeper. `rec` = { name, channels, rate, pcm:Float32Array, slices? }.
// The name is the key, so re-keeping the same name updates it in place (no duplicates).
export async function keepLibrarySound(rec) {
  if (!rec || !rec.name || !rec.pcm || !rec.pcm.length) throw new Error('bad library sound');
  const stored = {
    name: String(rec.name),
    channels: rec.channels || 1,
    rate: rec.rate || 48000,
    pcm: rec.pcm instanceof Float32Array ? rec.pcm : Float32Array.from(rec.pcm),
    slices: rec.slices || [],
    savedAt: Date.now(),
  };
  await run(STORE_LIBRARY, 'readwrite', (store) => store.put(stored));
  return stored;
}

// Every keeper, newest-first — each a full record (name, channels, rate, pcm, slices, savedAt).
export async function listLibrary() {
  const all = await run(STORE_LIBRARY, 'readonly', (store) => store.getAll());
  return (all || []).sort((a, b) => (b.savedAt || 0) - (a.savedAt || 0));
}

// Whether a keeper with this exact name exists (so the UI can show a "KEPT" tag).
export async function libraryHas(name) {
  const rec = await run(STORE_LIBRARY, 'readonly', (store) => store.get(String(name)));
  return !!rec;
}

// Remove one keeper from the library (the project copy, if any, is untouched).
export async function deleteLibrarySound(name) {
  await run(STORE_LIBRARY, 'readwrite', (store) => store.delete(String(name)));
}
