// ===========================================================================
//  Cyclo web — the SOUND EDITOR (open a sound and edit its audio).
//
//  The web port of native src/app/SoundEditor.h. Opening a sound shows the CORRECT type,
//  exactly as native does on open (never on the pad): a SAMPLE (your recording/import) opens
//  as a WAVEFORM editor — drag two handles to trim, tap NORM / REV, drag GAIN, and SLICE it
//  into transient regions; a SYNTH VOICE opens as its RECIPE (editable `voice NAME=` code) and
//  routes you to edit it in the CODE view (the coin), which already works via globals.
//
//  Every edit op runs the SHARED C++ DSP through the WebEngine bridge (web/web_engine.h):
//    trim      -> WebEngine.trimSample      (cyclo::edit::extractRegion)
//    normalize -> WebEngine.normalizeSample (cyclo::edit::normalize, target 0.99)
//    reverse   -> WebEngine.reverseSample   (cyclo::edit::reverse)
//    gain      -> WebEngine.gainSample      (shared applyGain)
//    slice     -> WebEngine.sliceSample     (core TransientDetector, == native autoSlice)
//  Each writes the result back into the ONE shared SampleBank, so pads + s("name") + s("name:k")
//  play the edited sound immediately — nothing about the audio is re-done in JS. Slices persist
//  (autosave/bundle) so s("name:2") survives a reload. Built-in kit voices are non-destructive
//  (they route to code); a user recording is the user's to edit.
//
//  INPUT-AGNOSTIC (docs/web-interaction.md): the trim handles grab the NEARER handle from a pointer
//  drag anywhere on the waveform (mouse/touch/pen + capture) with the shared occlusion-safe bubble
//  ABOVE the finger, and each handle is keyboard-focusable (arrow keys nudge, visible focus ring);
//  the GAIN + SLICE rows reuse the shared attachValueDrag gesture; every button is a real <button>
//  (pointer + Enter/Space). No action is hover-gated.
// ===========================================================================
import { attachValueDrag, attachActivate, showValueBubble, hideValueBubble } from './gesture.js';
import { AMBER, CYAN, PHOS_RGB } from './palette.js';
import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

const SAMPLE_COLOR = AMBER;   // native's SAMPLE type tint (col::amber) — the shared token
const VOICE_COLOR  = CYAN;    // native's SYNTH VOICE type tint (col::cyan) — the shared token

function el(tag, cls) { const e = document.createElement(tag); if (cls) e.className = cls; return e; }
const clamp01 = (x) => Math.max(0, Math.min(1, x));

// Read a user sample's PCM back OUT of the shared bank (the source of truth). Interleaved; we
// downmix to a mono peak per column for drawing. Copy the WASM view out immediately.
function loadPcm(engine, name) {
  let info = { channels: 1, rate: 48000, frames: 0 };
  try { info = JSON.parse(engine.userSampleInfo(name)); } catch (_) {}
  const inter = Float32Array.from(engine.userSampleData(name));
  const ch = info.channels || 1;
  const frames = info.frames || Math.floor(inter.length / ch);
  return { ch, frames, rate: info.rate || 48000, inter };
}
function loadSlices(engine, name) {
  try { return JSON.parse(engine.sampleSlices(name)) || []; } catch (_) { return []; }
}

// opts: { host, name, engine, onApplied, onEditAsCode(name, recipe), onClose, setStatus }
export function createSoundEditor(opts) {
  const { host, engine, name } = opts;
  const isSample = engine.isUserSample(name);
  const isVoice = !isSample && engine.hasVoiceRecipe(name);

  const scrim = el('div', 'se-scrim');
  const card = el('div', 'se-card');
  card.style.setProperty('--se', isSample ? SAMPLE_COLOR : VOICE_COLOR);
  scrim.appendChild(card);

  // header
  const head = el('div', 'se-head');
  const dot = el('span', 'se-dot');
  const titles = el('div', 'se-titles');
  const h = el('div', 'se-title'); h.textContent = name.toUpperCase();
  const sub = el('div', 'se-sub'); sub.textContent = isSample ? 'SAMPLE · WAVEFORM' : 'SYNTH VOICE · RECIPE';
  titles.appendChild(h); titles.appendChild(sub);
  const close = el('button', 'fx-close'); close.type = 'button'; close.textContent = '×';
  close.setAttribute('aria-label', 'close');
  head.appendChild(dot); head.appendChild(titles); head.appendChild(close);
  card.appendChild(head);

  let cleanup = [];
  if (isVoice) buildVoice(); else buildSample();
  host.appendChild(scrim);

  // Open/close/scrim/Escape via the ONE shared overlay manager (overlay.js): header ×, release-close
  // scrim-tap (press-vs-release guarded), central Escape stack.
  const overlay = registerOverlay(scrim, {
    panel: card,
    closeButtons: [close],
    label: name + ' — sound editor',
    onClose: () => { teardown(); if (opts.onClose) opts.onClose(); },
  });
  overlay.open();

  // ---------------------------------------------------------------------------
  //  SYNTH VOICE — show the recipe (read-only phosphor) + route to edit-as-code.
  // ---------------------------------------------------------------------------
  function buildVoice() {
    const recipe = (engine.voiceRecipeText(name) || '').trim();
    const screen = el('pre', 'se-recipe');
    screen.textContent = 'voice ' + name + ' =\n  ' + recipe.replace(/\)\./g, ')\n  .');
    card.appendChild(screen);

    const note = el('div', 'se-hint');
    note.textContent = 'this sound is a synth voice — a recipe you can read + tweak as code';
    card.appendChild(note);

    const edit = el('button', 'se-primary'); edit.type = 'button'; edit.textContent = 'Edit as code ›';
    attachActivate(edit, () => { if (opts.onEditAsCode) opts.onEditAsCode(name, recipe); overlay.close(); });
    card.appendChild(edit);
  }

  // ---------------------------------------------------------------------------
  //  SAMPLE — the waveform editor (trim handles + norm/rev/gain + slice).
  // ---------------------------------------------------------------------------
  function buildSample() {
    let pcm = loadPcm(engine, name);
    let slices = loadSlices(engine, name);
    // begin/end are normalized 0..1 across the CURRENT buffer; a fresh edit resets them to the ends.
    let begin = 0, end = 1;

    const wrap = el('div', 'se-wavewrap');
    const canvas = el('canvas', 'se-wave');
    wrap.appendChild(canvas);
    // two visual + keyboard-focusable handles (arrow keys nudge; the pointer drag grabs the nearer)
    const hBegin = el('button', 'se-handle'); hBegin.type = 'button';
    hBegin.setAttribute('aria-label', 'trim start'); hBegin.setAttribute('role', 'slider');
    const hEnd = el('button', 'se-handle'); hEnd.type = 'button';
    hEnd.setAttribute('aria-label', 'trim end'); hEnd.setAttribute('role', 'slider');
    wrap.appendChild(hBegin); wrap.appendChild(hEnd);
    card.appendChild(wrap);

    const readout = el('div', 'se-readout');
    card.appendChild(readout);

    // EDIT ops row: TRIM (apply the handles), NORM, REV, then a GAIN drag-row + apply
    const ops = el('div', 'se-ops');
    const trimBtn = mkBtn('TRIM', 'trim to the selected region', () => {
      const b = Math.round(begin * pcm.frames), e = Math.round(end * pcm.frames);
      const n = engine.trimSample(name, b, e);
      if (n > 0) { reload(); applied('trimmed to ' + fmtSecs(n / pcm.rate)); }
    });
    const normBtn = mkBtn('NORM', 'normalize to full, even volume', () => {
      if (engine.normalizeSample(name, 0.99)) { reload(); applied('normalized'); }
    });
    const revBtn = mkBtn('REV', 'play the sound backwards', () => {
      if (engine.reverseSample(name)) { reload(); applied('reversed'); }
    });
    ops.appendChild(trimBtn); ops.appendChild(normBtn); ops.appendChild(revBtn);
    card.appendChild(ops);

    // GAIN — a drag-row (pending factor 0.25x..4x), applied on release / Enter (never compounding mid-drag)
    let gainNorm = 0.5;                                 // 0.5 == x1 (log-mapped)
    const gainDenorm = (t) => Math.pow(4, (t - 0.5) * 2);   // 0->x0.25, .5->x1, 1->x4
    const gainRow = el('div', 'se-row'); gainRow.tabIndex = 0; gainRow.setAttribute('role', 'slider');
    gainRow.setAttribute('aria-label', 'gain');
    const gFill = el('div', 'se-row-fill'); const gLab = el('span', 'se-row-label'); gLab.textContent = 'GAIN';
    const gVal = el('span', 'se-row-val');
    gainRow.appendChild(gFill); gainRow.appendChild(gLab); gainRow.appendChild(gVal);
    const applyGainBtn = mkBtn('APPLY', 'apply the gain', () => applyGain());
    const gainWrap = el('div', 'se-gainwrap'); gainWrap.appendChild(gainRow); gainWrap.appendChild(applyGainBtn);
    card.appendChild(gainWrap);
    function refreshGain() { gFill.style.width = (gainNorm * 100).toFixed(1) + '%'; gVal.textContent = 'x' + gainDenorm(gainNorm).toFixed(2); }
    function applyGain() {
      const f = gainDenorm(gainNorm);
      if (Math.abs(f - 1) < 1e-3) { status('gain: nothing to do (x1)'); return; }
      if (engine.gainSample(name, f)) { gainNorm = 0.5; refreshGain(); reload(); applied('gain x' + f.toFixed(2)); }
    }
    attachValueDrag(gainRow, {
      getNorm: () => gainNorm, setNorm: (t) => { gainNorm = clamp01(t); refreshGain(); },
      width: () => gainRow.getBoundingClientRect().width,
      format: (t) => 'x' + gainDenorm(t).toFixed(2),
      onEnd: () => applyGain()
    });
    refreshGain();

    // SLICE — a sensitivity drag-row + SLICE (transient) + GRID (even). Slices become playable chips.
    let sens = 0.5;
    const sliceRow = el('div', 'se-row'); sliceRow.tabIndex = 0; sliceRow.setAttribute('role', 'slider');
    sliceRow.setAttribute('aria-label', 'slice sensitivity');
    const sFill = el('div', 'se-row-fill'); const sLab = el('span', 'se-row-label'); sLab.textContent = 'SLICE';
    const sVal = el('span', 'se-row-val');
    sliceRow.appendChild(sFill); sliceRow.appendChild(sLab); sliceRow.appendChild(sVal);
    const sliceBtn = mkBtn('CHOP', 'slice at transients (SLICE = sensitivity)', () => doSlice());
    const gridBtn = mkBtn('GRID 8', 'slice into 8 equal steps', () => doGrid(8));
    const sliceWrap = el('div', 'se-slicewrap');
    sliceWrap.appendChild(sliceRow); sliceWrap.appendChild(sliceBtn); sliceWrap.appendChild(gridBtn);
    card.appendChild(sliceWrap);
    function refreshSens() { sFill.style.width = (sens * 100).toFixed(1) + '%'; sVal.textContent = sens.toFixed(2); }
    attachValueDrag(sliceRow, {
      getNorm: () => sens, setNorm: (t) => { sens = clamp01(t); refreshSens(); },
      width: () => sliceRow.getBoundingClientRect().width, format: (t) => t.toFixed(2)
    });
    refreshSens();

    const chips = el('div', 'se-chips');
    card.appendChild(chips);

    const coin = el('div', 'se-coin');
    card.appendChild(coin);
    const hint = el('div', 'se-hint');
    hint.textContent = 'drag the handles to trim · drag · scroll · arrow keys — pull away to fine-tune';
    card.appendChild(hint);

    function doSlice() {
      const n = engine.sliceSample(name, sens);
      if (n > 0) { reload(); applied('sliced into ' + n + ' — tap a chip, or use s("' + name + ':0..' + (n - 1) + '")'); }
    }
    function doGrid(c) {
      const n = engine.sliceSampleEven(name, c);
      if (n > 0) { reload(); applied('sliced into ' + n + ' equal steps'); }
    }

    function buildChips() {
      chips.innerHTML = '';
      if (!slices.length) { coin.textContent = 's("' + name + '")'; return; }
      slices.forEach((_, k) => {
        const c = el('button', 'se-chip'); c.type = 'button'; c.textContent = k;
        c.setAttribute('aria-label', 'play slice ' + k);
        attachActivate(c, () => {
          if (opts.ensureAudio) opts.ensureAudio();
          engine.triggerSlice(name, k);
          c.classList.remove('hit'); void c.offsetWidth; c.classList.add('hit');
          setTimeout(() => c.classList.remove('hit'), 220);
        });
        chips.appendChild(c);
      });
      coin.textContent = 's("' + name + ':0..' + (slices.length - 1) + '")  · ' + slices.length + ' slices';
    }

    // reload the PCM + slices after an edit (the buffer may have changed length), reset handles.
    function reload() {
      pcm = loadPcm(engine, name);
      slices = loadSlices(engine, name);
      begin = 0; end = 1;
      buildChips();
      layoutHandles();
      draw();
      if (opts.onApplied) opts.onApplied();
    }
    function applied(msg) { status(msg); }
    function status(msg) { readout.textContent = msg; if (opts.setStatus) opts.setStatus(msg); }

    // ---- waveform drawing ----
    function draw() {
      const dpr = Math.min(2, window.devicePixelRatio || 1);
      const w = canvas.clientWidth, hh = canvas.clientHeight;
      if (!w || !hh) return;
      if (canvas.width !== w * dpr || canvas.height !== hh * dpr) { canvas.width = w * dpr; canvas.height = hh * dpr; }
      const ctx = canvas.getContext('2d');
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.clearRect(0, 0, w, hh);
      const mid = hh / 2, frames = pcm.frames, ch = pcm.ch;
      const bx = begin * w, ex = end * w;
      for (let x = 0; x < w; x++) {
        const i0 = Math.floor(x / w * frames), i1 = Math.max(i0 + 1, Math.floor((x + 1) / w * frames));
        let mx = 0;
        for (let i = i0; i < i1 && i < frames; i++)
          for (let c = 0; c < ch; c++) { const a = Math.abs(pcm.inter[i * ch + c]); if (a > mx) mx = a; }
        const barH = mx * (mid - 3);
        const inSel = x >= bx && x < ex;
        ctx.strokeStyle = inSel ? `rgba(${PHOS_RGB},.85)` : 'rgba(120,130,140,.32)';
        ctx.beginPath(); ctx.moveTo(x + 0.5, mid - barH); ctx.lineTo(x + 0.5, mid + barH); ctx.stroke();
      }
      // slice boundaries — amber ticks
      if (slices.length) {
        ctx.strokeStyle = 'rgba(255,178,69,.7)';
        for (const [b] of slices) {
          const px = (b / frames) * w;
          ctx.beginPath(); ctx.moveTo(px, 0); ctx.lineTo(px, 7); ctx.moveTo(px, hh - 7); ctx.lineTo(px, hh); ctx.stroke();
        }
      }
    }

    function layoutHandles() {
      hBegin.style.left = (begin * 100) + '%';
      hEnd.style.left = (end * 100) + '%';
      const b = Math.round(begin * pcm.frames), e = Math.round(end * pcm.frames);
      hBegin.setAttribute('aria-valuetext', fmtSecs(b / pcm.rate));
      hEnd.setAttribute('aria-valuetext', fmtSecs(e / pcm.rate));
    }

    // ---- trim handles: grab the NEARER handle on a pointer drag (native SoundEditor::mouseDown) ----
    let dragging = 0;   // 0 none, 1 begin, 2 end
    const normFromEvent = (e) => {
      const r = canvas.getBoundingClientRect();
      return clamp01((e.clientX - r.left) / Math.max(1, r.width));
    };
    const setHandle = (which, t, clientX, clientY) => {
      if (which === 1) begin = Math.min(t, end - 0.001);
      else end = Math.max(t, begin + 0.001);
      begin = clamp01(begin); end = clamp01(end);
      layoutHandles(); draw();
      const frames = pcm.frames;
      const secs = (which === 1 ? begin : end) * frames / pcm.rate;
      if (clientX != null) showValueBubble(clientX, clientY, fmtSecs(secs));
      status('trim ' + fmtSecs(begin * frames / pcm.rate) + ' – ' + fmtSecs(end * frames / pcm.rate));
    };
    const onDown = (e) => {
      if (e.button != null && e.button !== 0) return;
      const t = normFromEvent(e);
      dragging = Math.abs(t - begin) <= Math.abs(t - end) ? 1 : 2;
      try { wrap.setPointerCapture(e.pointerId); } catch (_) {}
      e.preventDefault();
      setHandle(dragging, t, e.clientX, e.clientY);
    };
    const onMove = (e) => { if (dragging) setHandle(dragging, normFromEvent(e), e.clientX, e.clientY); };
    const onUp = (e) => { if (!dragging) return; dragging = 0; try { wrap.releasePointerCapture(e.pointerId); } catch (_) {} hideValueBubble(); };
    wrap.addEventListener('pointerdown', onDown);
    wrap.addEventListener('pointermove', onMove);
    wrap.addEventListener('pointerup', onUp);
    wrap.addEventListener('pointercancel', onUp);
    // keyboard: focus a handle, arrows nudge it (Shift = coarser)
    const handleKey = (which) => (e) => {
      let d = 0;
      if (e.key === 'ArrowRight' || e.key === 'ArrowUp') d = 1;
      else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') d = -1;
      else return;
      e.preventDefault();
      const step = (e.shiftKey ? 0.05 : 0.005) * d;
      setHandle(which, (which === 1 ? begin : end) + step, null, null);
    };
    hBegin.addEventListener('keydown', handleKey(1));
    hEnd.addEventListener('keydown', handleKey(2));

    buildChips();
    layoutHandles();
    // draw after layout (clientWidth needs the element in the DOM); a rAF settles the size
    requestAnimationFrame(() => { draw(); layoutHandles(); });
    const onResize = () => { draw(); layoutHandles(); };
    window.addEventListener('resize', onResize);
    cleanup.push(() => window.removeEventListener('resize', onResize));

    function mkBtn(label, tip, fn) {
      const b = el('button', 'se-key'); b.type = 'button'; b.textContent = label; b.title = tip;
      attachActivate(b, fn);
      return b;
    }
  }

  function fmtSecs(s) { return s >= 1 ? s.toFixed(2) + 's' : Math.round(s * 1000) + 'ms'; }

  let torn = false;
  function teardown() {
    if (torn) return; torn = true;
    cleanup.forEach((fn) => { try { fn(); } catch (_) {} });
    if (scrim.parentNode) scrim.parentNode.removeChild(scrim);
  }
  const destroy = () => overlay.close();

  return { destroy, kind: isSample ? 'sample' : (isVoice ? 'voice' : 'none') };
}
