// ===========================================================================
//  melodic.js — the KEYS strip + CHORDS ribbon (the melodic/harmonic front doors).
//
//  The web twins of native src/app/PadGrid (KEYS mode) + src/app/ChordRibbon. Both are pure
//  INPUT surfaces: a tap plays a PITCHED note/chord NOW through the SHARED engine
//  (WebEngine.triggerPadPitched) and quantizes into a machine-managed `## KEYS` / `## CHORDS`
//  code section — THE COIN — exactly like finger-drumming writes `## LIVE`. "Graphics and code
//  are two views of ONE document."
//
//  Nothing musical lives in JS: the note->pitch mapping (Scale.degreeToSemitone), the chord
//  voicing (ChordVoicing) and the touch<->code codec (Coin.formatKeysBody / spliceSection /
//  parseKeysBody) are the SHARED pure-core headers, reached through the WASM bridge
//  (M.noteToSemitone / M.chordStripsJson / M.keysBodyFor / M.spliceDocSection / M.parseKeysBodyJson
//  / M.sectionBodyOf). So the web plays + writes byte-identically to native.
//
//  Input-agnostic (docs/web-interaction.md): every strip/key/chip goes through the shared
//  attachActivate (pointer press AND keyboard Enter/Space, ghost-click/zoom suppressed) with big
//  ~44px+ targets and a visible focus ring. A pointer-drag across the ribbon STRUMS (auditions the
//  crossed strips); the tap is what commits — one clean chord per step, no runaway doc churn.
// ===========================================================================
import { attachActivate } from './gesture.js';
import { qwertyNoteIndex } from './keymap.js';

// The 7 strip hues — byte-match native ChordRibbon::HUES (colour-as-light, never colour-alone).
const HUES = ['#5b8ed4', '#33b3ac', '#57c06a', '#c9b24a', '#e0913f', '#d46a86', '#a077d4'];
const NOTE_NAMES = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
// The KEYS scale cycle (value -> chip label). "" = chromatic (grid stores semitones); a named scale
// stores DEGREES and the coin writes `.n("...","scale")`, exactly as native keysScale drives the coin.
const SCALES = [
  { value: '', label: 'CHRM' },
  { value: 'major', label: 'MAJ' },
  { value: 'minor', label: 'MIN' },
  { value: 'majpent', label: 'PENT' },
];

const noteName = (pc) => NOTE_NAMES[((pc % 12) + 12) % 12];

// grid <-> the bridge's "step=note,note;step=note" wire format (see web/bridge.cpp parseGridSpec).
function gridObjFromSpec(spec) {
  const g = {};
  if (!spec) return g;
  for (const entry of spec.split(';')) {
    if (!entry) continue;
    const eq = entry.indexOf('=');
    if (eq < 0) continue;
    const step = parseInt(entry.slice(0, eq), 10);
    const notes = entry.slice(eq + 1).split(',').filter((t) => t.length).map((t) => parseInt(t, 10));
    if (notes.length) g[step] = notes;
  }
  return g;
}
function gridSpecFromObj(g) {
  return Object.keys(g)
    .map((k) => parseInt(k, 10))
    .filter((k) => g[k] && g[k].length)
    .sort((a, b) => a - b)
    .map((k) => k + '=' + g[k].slice().sort((a, b) => a - b).join(','))
    .join(';');
}

// Build the KEYS + CHORDS surfaces into the two host elements. `opts`:
//   module()        -> the WASM module M (the coin + voicing + scale bridge)
//   engine()        -> the live WebEngine (triggerPadPitched + currentCycle)
//   getDoc()        -> current editor document text
//   applyDoc(text)  -> write the new doc (dispatch into CM + hot-swap/play) — main.js owns it
//   ensurePlaying() -> Promise; start audio + the transport (native auto-plays on the first note)
//   padNames()      -> the ordered bank sound names (for the SOUND chip cycle)
//   setStatus(s)    -> a status line
//   onKeyFound(pc, minor) -> the honest Key Finder trigger (user locked their music to a key)
export function createMelodic(opts) {
  const M = opts.module, eng = opts.engine;

  const state = {
    keysSound: 'guitar', keysScaleIdx: 1 /* MAJ */, keysOctave: 0,
    chordsSound: 'guitar', keyIdx: 0 /* C */, minor: false, voices: 3,
    keyChosen: false,          // the user has actively picked a key (arms the Key Finder earn)
  };

  const keysEl = document.createElement('div');
  keysEl.className = 'melodic keys-surface';
  const chordsEl = document.createElement('div');
  chordsEl.className = 'melodic chords-surface';

  // ---- shared helpers ------------------------------------------------------
  function firstBankSound() { const n = opts.padNames(); return n.length ? n[0] : 'guitar'; }
  function cycleSound(cur) {
    const n = opts.padNames();
    if (!n.length) return cur;
    let i = n.indexOf(cur); if (i < 0) i = -1;
    return n[(i + 1) % n.length];
  }
  function stepNow() {
    const cyc = eng() ? eng().currentCycle() : 0;
    const frac = cyc - Math.floor(cyc);
    return (((Math.round(frac * 16)) % 16) + 16) % 16;
  }
  // Read a section back from the doc: {sound,scale,grid} or null when hand-edited (audition only).
  function readSection(name, fallbackSound) {
    const body = M().sectionBodyOf(opts.getDoc(), name);
    if (!body) return { sound: fallbackSound, scale: '', grid: {} };
    const js = M().parseKeysBodyJson(body);
    if (js === 'null') return null;
    const o = JSON.parse(js);
    return { sound: o.sound || fallbackSound, scale: o.scale || '', grid: gridObjFromSpec(o.grid) };
  }
  function writeSection(name, sound, scale, gridObj) {
    const spec = gridSpecFromObj(gridObj);
    const body = M().keysBodyFor(sound, scale, spec);
    opts.applyDoc(M().spliceDocSection(opts.getDoc(), name, body));
  }

  // ---- chip builder (KEY / SCALE / VOICES / SOUND / OCTAVE) -----------------
  function chip(label, valueFn, onTap, extraClass) {
    const b = document.createElement('button');
    b.type = 'button';
    b.className = 'mchip' + (extraClass ? ' ' + extraClass : '');
    b.tabIndex = 0;
    const cap = document.createElement('span'); cap.className = 'mchip-cap'; cap.textContent = label;
    const val = document.createElement('span'); val.className = 'mchip-val';
    b.appendChild(cap); b.appendChild(val);
    b._val = val;
    b._render = () => { val.textContent = valueFn(); };
    attachActivate(b, () => { onTap(); });
    b._render();
    return b;
  }

  // ========================================================================
  //  KEYS — a playable scale strip (one octave + the octave root above).
  // ========================================================================
  function keysScale() { return SCALES[state.keysScaleIdx].value; }
  function keysStepsPerOctave() {
    // chromatic = 12 semitones; a named scale's "octave" is its degree count (bridge-consistent).
    const sc = keysScale();
    if (!sc) return 12;
    // ask the core: degree == stepsPerOctave maps to +12 semitones, so find where it wraps.
    // (major/minor = 7, pentatonic = 5) — derive by probing noteToSemitone until it hits 12.
    for (let d = 1; d <= 12; d++) if (M().noteToSemitone(sc, d) >= 12) return d;
    return 12;
  }
  function keyCount() { return keysStepsPerOctave() + 1; }   // one octave + the root above
  function keyOctaveBase() { return state.keysOctave * keysStepsPerOctave(); }

  function playKeysNote(keyIndex) {
    const sound = state.keysSound;
    const scale = keysScale();
    const noteVal = keyIndex + keyOctaveBase();            // a semitone (chromatic) or a scale degree
    const semi = scale ? M().noteToSemitone(scale, noteVal) : noteVal;
    if (eng()) eng().triggerPadPitched(sound, Math.pow(2, semi / 12));   // instant pitched audition
    opts.ensurePlaying().then(() => {
      const parsed = readSection('KEYS', sound);
      if (parsed === null) { opts.setStatus('KEYS is hand-edited — the keys audition only'); return; }
      const step = stepNow();
      // additive overdub (native keysGrid[step].insert): stack near-simultaneous taps into a chord
      const prev = parsed.grid[step] || [];
      if (!prev.includes(noteVal)) parsed.grid[step] = prev.concat([noteVal]);
      writeSection('KEYS', sound, scale, parsed.grid);
    }).catch(() => {});
  }

  function buildKeys() {
    keysEl.innerHTML = '';
    const bar = document.createElement('div'); bar.className = 'msurf-bar';
    const title = document.createElement('div'); title.className = 'msurf-title'; title.textContent = 'Keys';
    bar.appendChild(title);
    const chips = document.createElement('div'); chips.className = 'mchips';
    const soundChip = chip('SOUND', () => state.keysSound.toUpperCase(),
      () => { state.keysSound = cycleSound(state.keysSound); refreshKeys(); }, 'wide');
    const scaleChip = chip('SCALE', () => SCALES[state.keysScaleIdx].label,
      () => { state.keysScaleIdx = (state.keysScaleIdx + 1) % SCALES.length; refreshKeys(); });
    const octDown = chip('OCT', () => '−',
      () => { state.keysOctave = Math.max(-2, state.keysOctave - 1); refreshKeys(); }, 'oct');
    const octVal = chip('', () => (state.keysOctave > 0 ? '+' : '') + state.keysOctave,
      () => {}, 'octval');
    const octUp = chip('OCT', () => '+',
      () => { state.keysOctave = Math.min(2, state.keysOctave + 1); refreshKeys(); }, 'oct');
    chips.appendChild(soundChip); chips.appendChild(scaleChip);
    chips.appendChild(octDown); chips.appendChild(octVal); chips.appendChild(octUp);
    bar.appendChild(chips);
    keysEl.appendChild(bar);

    const strip = document.createElement('div'); strip.className = 'keys-strip';
    const scale = keysScale();
    const n = keyCount();
    for (let i = 0; i < n; i++) {
      const noteVal = i + keyOctaveBase();
      const semi = scale ? M().noteToSemitone(scale, noteVal) : noteVal;
      const key = document.createElement('button');
      key.type = 'button'; key.className = 'keycell'; key.tabIndex = 0;
      // black/white styling for the chromatic layout (a real keyboard look); scales are flat cells.
      const pc = ((semi % 12) + 12) % 12;
      if (!scale && [1, 3, 6, 8, 10].includes(pc)) key.classList.add('accidental');
      if (i === n - 1) key.classList.add('octaveup');   // the root an octave up (the "home" key)
      key.style.setProperty('--tint', HUES[i % HUES.length]);
      const lbl = document.createElement('span'); lbl.className = 'keylbl';
      lbl.textContent = noteName(pc);
      key.appendChild(lbl);
      key.setAttribute('aria-label', 'play ' + noteName(pc));
      const led = document.createElement('span'); led.className = 'keyled'; key.appendChild(led);
      attachActivate(key, () => { flash(key); playKeysNote(i); });
      strip.appendChild(key);
    }
    keysEl.appendChild(strip);

    // HUM A TUNE — the hum-to-melody front door (native HumMelody). Opens the hum-capture sheet;
    // a hummed take runs the SHARED pitch tracker and lands as a ## KEYS melody, right here.
    if (opts.onHum) {
      const humBtn = document.createElement('button');
      humBtn.type = 'button'; humBtn.className = 'hum-open'; humBtn.tabIndex = 0;
      humBtn.innerHTML = '<span class="hum-open-glyph">♪</span> Hum a tune';
      humBtn.setAttribute('aria-label', 'hum a tune into a melody');
      attachActivate(humBtn, () => { opts.onHum(state.keysSound); });
      keysEl.appendChild(humBtn);
    }

    const hint = document.createElement('div'); hint.className = 'mhint';
    hint.textContent = 'tap a note — pitched, writes ## KEYS · or HUM A TUNE and we turn your voice into notes';
    keysEl.appendChild(hint);
  }
  function refreshKeys() {
    if (state.keysSound === 'guitar' && !opts.padNames().includes('guitar')) state.keysSound = firstBankSound();
    buildKeys();
  }

  // ========================================================================
  //  CHORDS — the diatonic chord ribbon (7 scale-locked strips).
  // ========================================================================
  function chordState() {
    return JSON.parse(M().chordStripsJson(state.keyIdx, state.minor, state.voices));
  }
  function playChord(degree, commit) {
    const cs = chordState();
    const sound = state.chordsSound;
    const semis = cs.strips[degree].semis;
    for (const s of semis) if (eng()) eng().triggerPadPitched(sound, Math.pow(2, s / 12));
    if (!commit) return;   // a strum-crossing auditions only; the tap commits
    opts.ensurePlaying().then(() => {
      // the honest Key Finder earn: the user actively chose a key AND is playing music locked to it.
      if (state.keyChosen && opts.onKeyFound) opts.onKeyFound(cs.keyPc, state.minor);
      const parsed = readSection('CHORDS', sound);
      if (parsed === null) { opts.setStatus('CHORDS is hand-edited — the ribbon auditions only'); return; }
      const step = stepNow();
      parsed.grid[step] = semis.slice();     // one chord per step (native chordsGrid[step] = notes)
      writeSection('CHORDS', sound, '', parsed.grid);   // absolute semitones (chord tones are exact)
    }).catch(() => {});
  }

  function buildChords() {
    chordsEl.innerHTML = '';
    const cs = chordState();
    const bar = document.createElement('div'); bar.className = 'msurf-bar';
    const title = document.createElement('div'); title.className = 'msurf-title';
    title.textContent = state.voices === 1 ? 'Melody' : 'Chords';
    bar.appendChild(title);
    const chips = document.createElement('div'); chips.className = 'mchips';
    const soundChip = chip('SOUND', () => state.chordsSound.toUpperCase(),
      () => { state.chordsSound = cycleSound(state.chordsSound); refreshChords(); }, 'wide');
    const keyChip = chip('KEY', () => chordState().key,
      () => { state.keyIdx = (state.keyIdx + 1) % 7; state.keyChosen = true; refreshChords(); });
    const scaleChip = chip('SCALE', () => (state.minor ? 'min' : 'maj'),
      () => { state.minor = !state.minor; state.keyChosen = true; refreshChords(); });
    const voicesChip = chip('VOICES', () => String(state.voices),
      () => { state.voices = state.voices >= 5 ? 1 : state.voices + 1; refreshChords(); });
    chips.appendChild(soundChip); chips.appendChild(keyChip);
    chips.appendChild(scaleChip); chips.appendChild(voicesChip);
    bar.appendChild(chips);
    chordsEl.appendChild(bar);

    const ribbon = document.createElement('div'); ribbon.className = 'chord-ribbon';
    cs.strips.forEach((st, d) => {
      const strip = document.createElement('button');
      strip.type = 'button'; strip.className = 'chordstrip'; strip.tabIndex = 0;
      strip.dataset.degree = String(d);
      strip.style.setProperty('--tint', HUES[d % HUES.length]);
      const rn = document.createElement('span'); rn.className = 'chord-roman'; rn.textContent = st.roman;
      const nm = document.createElement('span'); nm.className = 'chord-name'; nm.textContent = st.name;
      const dots = document.createElement('span'); dots.className = 'chord-dots';
      for (let k = 0; k < state.voices; k++) { const dot = document.createElement('i'); dots.appendChild(dot); }
      const pipe = document.createElement('span'); pipe.className = 'chord-pipe';
      strip.appendChild(rn); strip.appendChild(nm); strip.appendChild(dots); strip.appendChild(pipe);
      strip.setAttribute('aria-label', 'play ' + st.name + ' (' + st.roman + ')');
      attachActivate(strip, () => { flash(strip); playChord(d, true); });
      ribbon.appendChild(strip);
    });
    // STRUM: dragging across the ribbon auditions the crossed strips (touch-first; a tap commits).
    attachStrum(ribbon);
    chordsEl.appendChild(ribbon);

    // the coin head — what the ribbon writes (native ChordRibbon's code bar)
    const coin = document.createElement('div'); coin.className = 'chord-coin';
    coin.innerHTML = '<span class="coin-head">s("' + escapeHtml(state.chordsSound) + '").note(</span>' +
                     '<span class="coin-body">"…"</span><span class="coin-head">)</span>';
    chordsEl.appendChild(coin);
    const hint = document.createElement('div'); hint.className = 'mhint';
    hint.textContent = 'tap a strip — it loops in key · VOICES 1 = melody … 5 = lush 9th · KEY locks your song';
    chordsEl.appendChild(hint);
  }
  function refreshChords() {
    if (state.chordsSound === 'guitar' && !opts.padNames().includes('guitar')) state.chordsSound = firstBankSound();
    buildChords();
  }

  // pointer-drag strum: audition each strip the pointer crosses (never commits — the tap does that).
  // Routed through the shared drag pattern (docs/web-interaction.md R1): Pointer Events +
  // setPointerCapture on the ribbon, so a strum that drifts OFF the ribbon mid-drag keeps tracking
  // (the moves still arrive at the captured ribbon) instead of silently dying — the ONE raw drag that
  // used to skip capture. elementFromPoint still resolves which strip is under the pointer.
  function attachStrum(ribbon) {
    let last = -1, activeId = null;
    const stripAt = (x, y) => {
      const el = document.elementFromPoint(x, y);
      const s = el && el.closest ? el.closest('.chordstrip') : null;
      return s && ribbon.contains(s) ? parseInt(s.dataset.degree, 10) : -1;
    };
    // record the current strum position (test hook: prove capture keeps tracking off-ribbon)
    const mark = (d) => { last = d; ribbon.dataset.strumLast = String(d); ribbon.dataset.strumN = String((parseInt(ribbon.dataset.strumN || '0', 10)) + 1); };
    ribbon.addEventListener('pointerdown', (e) => {
      activeId = e.pointerId;
      try { ribbon.setPointerCapture(e.pointerId); } catch (_) {}
      const d = stripAt(e.clientX, e.clientY);   // the strip button's own attachActivate commits this one
      if (d >= 0) mark(d);
    });
    ribbon.addEventListener('pointermove', (e) => {
      if (activeId === null || e.pointerId !== activeId) return;
      const d = stripAt(e.clientX, e.clientY);
      if (d >= 0 && d !== last) { mark(d); playChord(d, false); }   // crossed a new strip -> strum audition
    });
    const end = (e) => {
      if (activeId !== null) { try { ribbon.releasePointerCapture(activeId); } catch (_) {} }
      activeId = null; last = -1;
    };
    ribbon.addEventListener('pointerup', end);
    ribbon.addEventListener('pointercancel', end);
  }

  function flash(el) {
    el.classList.remove('lit'); void el.offsetWidth; el.classList.add('lit');
    clearTimeout(el._litT); el._litT = setTimeout(() => el.classList.remove('lit'), 300);
  }
  function escapeHtml(s) { return String(s).replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c])); }

  // DESKTOP QWERTY notes (progressive enhancement, docs/web-interaction.md): a physical key on the
  // KEYS surface plays the matching strip cell — Ableton-style (chromatic strip = the piano layout,
  // a scale strip walks its degrees). Reuses the SAME playKeysNote path a tap/Enter takes (pitched
  // audition + the ## KEYS coin), flashing the cell so it reads. Returns true if a note fired. This
  // is only ever called by main.js's keymap when KEYS is the active surface and focus isn't typing.
  function playKeyByChar(char) {
    const idx = qwertyNoteIndex(char, !keysScale());
    if (idx < 0 || idx >= keyCount()) return false;
    const cell = keysEl.querySelectorAll('.keycell')[idx];
    if (cell) flash(cell);
    playKeysNote(idx);
    return true;
  }

  // Public: (re)build both surfaces from the current bank (called on show + when the bank changes).
  function refresh() { refreshKeys(); refreshChords(); }
  refresh();

  return { keysEl, chordsEl, refresh, state, playKeyByChar };
}
