// ===========================================================================
//  Cyclo web — the shared INPUT-AGNOSTIC control gesture.
//
//  The web build is the ONLY Cyclo skin that serves BOTH mouse (desktop) and touch
//  (mobile) from one UI (memory cyclo-web-input-agnostic), so every value control must
//  work with a fat fingertip AND a mouse AND a keyboard — no action gated behind hover,
//  right-click, or the scroll-wheel. This is the ONE gesture every web param control
//  reuses (the FX drag-rows today; any future knob/slider tomorrow), so the behaviour is
//  identical everywhere. See docs/web-interaction.md for the full spec.
//
//  What it gives every control it is attached to:
//    - ONE Pointer-Events code path (pointerdown/move/up + setPointerCapture) — mouse,
//      touch and pen are the same code, and a drag that leaves the element still tracks.
//    - Press-to-position (one-tap coarse set) + relative refine on drag (touch economy).
//    - Touch precision WITHOUT a wheel: pull the pointer perpendicular to the control and
//      the resolution shrinks ("drag further away = finer") — the classic mobile trick.
//    - An OCCLUSION-SAFE floating readout BUBBLE that renders ABOVE the contact point,
//      never under the finger (the #2 mouse-vs-touch gotcha).
//    - Desktop progressive enhancement: mouse-wheel fine-tunes; ArrowLeft/Right/Up/Down
//      nudge the focused control (Shift = coarser page step). None is the ONLY way in.
//
//  The value OUTCOME is identical across input: a value reached by finger-drag, wheel or
//  arrow key lands on the same number. The PURE maths (fineFactor/applyDelta) import
//  nothing and run in Node, so web/verify.js asserts the resolution mapping headlessly.
// ===========================================================================

export const RES_FLOOR = 0.12;    // finest resolution multiplier — a control is never fully frozen
export const RES_FALLOFF = 90;    // px of perpendicular travel that roughly halves the resolution

// perpendicular distance (px) from the control's track -> a resolution multiplier in [RES_FLOOR, 1].
// 0 px away = 1:1 (coarse, fast); the further you pull the pointer away, the finer the control gets.
export function fineFactor(perp) {
  const f = 1 / (1 + Math.max(0, perp) / RES_FALLOFF);
  return Math.max(RES_FLOOR, f);
}

const clamp01 = (x) => Math.max(0, Math.min(1, x));

// advance a normalized value by a horizontal pixel delta, scaled by the fine-resolution factor.
// At perp 0 the accumulated deltas equal an absolute position map (so a straight horizontal drag
// to some X lands on that X's value regardless of modality — mouse == touch == identical outcome).
export function applyDelta(norm, dxPx, perpPx, widthPx) {
  const w = Math.max(1, widthPx);
  return clamp01(norm + (dxPx / w) * fineFactor(perpPx));
}

// ---- the shared occlusion-safe readout bubble (browser only) -------------------
let sharedBubble = null;
function bubbleEl() {
  if (sharedBubble) return sharedBubble;
  const b = document.createElement('div');
  b.className = 'gesture-bubble';
  b.setAttribute('aria-hidden', 'true');
  document.body.appendChild(b);
  sharedBubble = b;
  return b;
}
// Render the live value ABOVE the contact point (offset up by 40px) — never under the fingertip.
function showBubble(x, y, text) {
  const b = bubbleEl();
  b.textContent = text;
  b.style.left = x + 'px';
  b.style.top = (y - 40) + 'px';
  b.classList.add('show');
}
function hideBubble() { if (sharedBubble) sharedBubble.classList.remove('show'); }

// Exposed so bespoke controls (e.g. the sound-editor trim handles, which grab the NEARER of two
// handles rather than mapping one value across a track) can reuse the SAME occlusion-safe bubble —
// one shared readout that always floats ABOVE the finger, never a second implementation.
export function showValueBubble(x, y, text) { showBubble(x, y, text); }
export function hideValueBubble() { hideBubble(); }

// Attach the gesture to a control element.
//   opts.getNorm()  -> the control's current normalized value [0,1]
//   opts.setNorm(t) -> apply a new normalized value (the control re-renders + emits)
//   opts.format(t)  -> the string shown in the floating bubble for norm t
//   opts.width()    -> the control's usable pixel width (defaults to el's client width)
//   opts.keyStep / opts.wheelStep -> nudge sizes (sensible defaults)
// Returns { detach } to unwire it.
export function attachValueDrag(el, opts) {
  const width = opts.width || (() => el.getBoundingClientRect().width);
  const fmt = opts.format || ((t) => Number(t).toFixed(2));
  const keyStep = opts.keyStep ?? 0.02;
  const wheelStep = opts.wheelStep ?? 0.03;
  let dragging = false, lastX = 0, cy = 0, wheelHideT = 0;

  const apply = (t, clientX, clientY) => {
    const c = clamp01(t);
    opts.setNorm(c);
    if (clientX != null) showBubble(clientX, clientY, fmt(c));
  };

  const onDown = (e) => {
    if (e.button != null && e.button !== 0) return;      // ignore right/middle mouse buttons
    dragging = true;
    const rect = el.getBoundingClientRect();
    cy = rect.top + rect.height / 2;
    lastX = e.clientX;
    try { el.setPointerCapture(e.pointerId); } catch (_) {}
    e.preventDefault();
    // press-to-position: jump to the tapped X (coarse, one tap gets you close), then drags refine
    apply((e.clientX - rect.left) / Math.max(1, width()), e.clientX, e.clientY);
    if (opts.onStart) opts.onStart();
  };
  const onMove = (e) => {
    if (!dragging) return;
    const dx = e.clientX - lastX; lastX = e.clientX;
    const perp = Math.abs(e.clientY - cy);               // pull away from the control -> finer
    apply(applyDelta(opts.getNorm(), dx, perp, width()), e.clientX, e.clientY);
  };
  const onUp = (e) => {
    if (!dragging) return;
    dragging = false;
    try { el.releasePointerCapture(e.pointerId); } catch (_) {}
    hideBubble();
    if (opts.onEnd) opts.onEnd();
  };
  // desktop wheel-over fine-tune (never the only way to set a value)
  const onWheel = (e) => {
    e.preventDefault();
    const dir = e.deltaY < 0 ? 1 : -1;
    const step = (e.shiftKey ? wheelStep * 0.25 : wheelStep) * dir;
    opts.setNorm(clamp01(opts.getNorm() + step));
    showBubble(e.clientX, e.clientY, fmt(opts.getNorm()));   // occlusion-safe readout for the wheel too
    clearTimeout(wheelHideT); wheelHideT = setTimeout(hideBubble, 650);
  };
  // keyboard nudge on the focused control (Shift = coarser page step)
  const onKey = (e) => {
    let d = 0;
    if (e.key === 'ArrowRight' || e.key === 'ArrowUp') d = 1;
    else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') d = -1;
    else return;
    e.preventDefault();
    const step = (e.shiftKey ? keyStep * 5 : keyStep) * d;
    opts.setNorm(clamp01(opts.getNorm() + step));
  };

  el.addEventListener('pointerdown', onDown);
  el.addEventListener('pointermove', onMove);
  el.addEventListener('pointerup', onUp);
  el.addEventListener('pointercancel', onUp);
  el.addEventListener('wheel', onWheel, { passive: false });
  el.addEventListener('keydown', onKey);

  return {
    detach() {
      el.removeEventListener('pointerdown', onDown);
      el.removeEventListener('pointermove', onMove);
      el.removeEventListener('pointerup', onUp);
      el.removeEventListener('pointercancel', onUp);
      el.removeEventListener('wheel', onWheel);
      el.removeEventListener('keydown', onKey);
    }
  };
}

// A universal "activate" wiring for momentary controls (pads, tiles, icon buttons) so a press
// works from pointer (mouse/touch/pen) AND keyboard (Enter/Space) — never pointer-only. The
// pointer path fires on pointerdown (instant, on press not release) with the synthetic mouse /
// scroll / double-tap-zoom suppressed; the keyboard path fires on Enter/Space.
export function attachActivate(el, fn, opts = {}) {
  const onPointer = (e) => { if (e.button != null && e.button !== 0) return; e.preventDefault(); fn(e); };
  // Enter/Space activate; a MODIFIED combo (⌘/Ctrl/Alt+Enter, etc.) is NOT a plain activate — leave
  // it to the desktop keymap (e.g. ⌘+Enter = evaluate), so a focused pad/tab never double-fires it.
  const onKey = (e) => {
    if (e.ctrlKey || e.metaKey || e.altKey) return;
    if (e.key === 'Enter' || e.key === ' ' || e.key === 'Spacebar') { e.preventDefault(); fn(e); }
  };
  el.addEventListener('pointerdown', onPointer);
  el.addEventListener('keydown', onKey);
  // kill the ghost-mouse + scroll/zoom that touch would otherwise synthesise on the element
  if (opts.touch !== false) el.addEventListener('touchstart', (e) => { e.preventDefault(); }, { passive: false });
  return { detach() { el.removeEventListener('pointerdown', onPointer); el.removeEventListener('keydown', onKey); } };
}
