// ===========================================================================
//  trackrack.js — the COMPOSE channel strips (the web twin of native src/app/TrackRack.h).
//
//  Native's TrackRack puts, beside every `## NAME` section's clip lane, a channel strip:
//  MUTE / SOLO tags, a LEVEL fader, and a PAN control. The web COMPOSE view already carries the
//  clip/timeline half (compose.js); THIS is the channel-strip half — one strip per section, shown
//  in COMPOSE whether or not there is a `song =` arrangement (native shows a strip for every track
//  always). It sits above the arrangement timeline as the MIXER.
//
//  The coin / mapping (follows native EXACTLY):
//    • LEVEL + PAN are the CODE coin — a fader/knob writes `.gain(x)` / `.pan(x)` INTO that
//      section's body (removed at unity/centre) via the SHARED pure-core MixCoin (WASM bridge
//      setSectionGain / setSectionPan), byte-preserving every other section. The engine hot-swaps,
//      so a level/pan move is HEARD immediately AND is plain editable code (native AutomationCoin).
//    • MUTE + SOLO are a SEPARATE mix model (native RackItem::muted/soloed, not code): the host
//      holds the {muted,soloed} sets, the engine's WebEngine::setMix filters which sections
//      compile (solo overrides the arrangement), and the model is persisted + captured in history.
//
//  Input-agnostic (docs/web-interaction.md): the LEVEL fader + PAN control reuse the shared
//  attachValueDrag (pointer/touch/pen + capture, occlusion-safe bubble ABOVE the finger, wheel +
//  arrow-key fine-tune with a focus ring, pull-away=finer, touch-action:none, identical outcome
//  across input). MUTE / SOLO are real focusable <button>s (attachActivate: pointer + Enter/Space),
//  44px targets. colour-is-light — each strip glows its own hue.
// ===========================================================================
import { attachValueDrag, attachActivate } from './gesture.js';
import { PAD_TINTS as TINTS } from './palette.js';

// The section tint palette — colour-is-light (native rack hues), matched to compose.js's lanes.
// The ONE shared ramp (./palette.js).

// Build the channel-strip rack into one host element. `opts`:
//   module()        -> the WASM module M (the SHARED MixCoin bridge + composeModel section list)
//   getDoc()        -> current editor document text
//   applyDoc(text)  -> write the new doc (dispatch into CM + hot-swap when playing) — main.js owns it
//   getMix()        -> { muted:Set<string>, soloed:Set<string> } (the mute/solo model, lowercased keys)
//   toggleMute(name)/toggleSolo(name) -> flip a section's mute/solo (host updates the engine + persists)
//   setStatus(s)    -> a status line
export function createTrackRack(opts) {
  const M = opts.module;
  const el = document.createElement('div');
  el.className = 'trackrack';

  let sections = [];       // [{ name, editable }] from composeModel (all sections, in doc order)
  const gainMax = () => { try { return M().mixGainMax(); } catch (e) { return 1.5; } };

  // ---- read the section list from the SHARED core (the same parse the engine/COMPOSE use) ----
  function readSections() {
    try {
      const model = JSON.parse(M().composeModel(opts.getDoc()));
      sections = (model.sections || []).map((s) => ({ name: s.name, editable: !!s.editable }));
    } catch (e) { sections = []; }
    return sections;
  }

  // a lowercased key for the mute/solo model (native matches section names case-insensitively)
  const key = (name) => String(name).toLowerCase();
  function isMuted(name) { const m = opts.getMix(); return m && m.muted && m.muted.has(key(name)); }
  function isSoloed(name) { const m = opts.getMix(); return m && m.soloed && m.soloed.has(key(name)); }
  function anySolo() { const m = opts.getMix(); return m && m.soloed && m.soloed.size > 0; }
  // native RackModel::audible: not muted, and (no solo anywhere OR this one soloed)
  function isAudible(name) { return !isMuted(name) && (!anySolo() || isSoloed(name)); }

  // ========================================================================
  //  Rendering — one strip per section.
  // ========================================================================
  let list, empty;

  function build() {
    el.innerHTML = '';
    const bar = document.createElement('div'); bar.className = 'trackrack-bar';
    const title = document.createElement('div'); title.className = 'trackrack-title'; title.textContent = 'Mixer';
    const hint = document.createElement('div'); hint.className = 'trackrack-hint';
    hint.textContent = 'mute · solo · level · pan — each section';
    bar.appendChild(title); bar.appendChild(hint);
    el.appendChild(bar);

    empty = document.createElement('div'); empty.className = 'trackrack-empty';
    empty.textContent = 'add a section in CODE — each one shows up here';
    el.appendChild(empty);

    list = document.createElement('div'); list.className = 'trackrack-list';
    el.appendChild(list);
  }

  function render() {
    readSections();
    const has = sections.length > 0;
    empty.classList.toggle('hidden', has);
    list.classList.toggle('hidden', !has);
    list.innerHTML = '';
    sections.forEach((sec, i) => list.appendChild(strip(sec, i)));
  }

  function strip(sec, i) {
    const name = sec.name;
    const tint = TINTS[i % TINTS.length];
    const row = document.createElement('div');
    row.className = 'tstrip';
    row.style.setProperty('--tint', tint);
    row.classList.toggle('inaudible', !isAudible(name));

    // colour chip + name
    const head = document.createElement('div'); head.className = 'tstrip-head';
    const chip = document.createElement('span'); chip.className = 'tstrip-chip';
    const label = document.createElement('span'); label.className = 'tstrip-name'; label.textContent = name; label.title = name;
    head.appendChild(chip); head.appendChild(label);

    // MUTE / SOLO — real focusable buttons (pointer + keyboard), 44px targets
    const tags = document.createElement('div'); tags.className = 'tstrip-tags';
    const mute = tagButton('M', 'mute ' + name, isMuted(name), 'tmute');
    const solo = tagButton('S', 'solo ' + name, isSoloed(name), 'tsolo');
    attachActivate(mute, () => { opts.toggleMute(name); });
    attachActivate(solo, () => { opts.toggleSolo(name); });
    tags.appendChild(mute); tags.appendChild(solo);

    // LEVEL fader — writes .gain(x) into the section (SHARED coin), removed at unity
    const level = faderControl('tlevel', name, {
      read: () => sectionGain(name),
      norm: (mul) => mul / gainMax(),
      fromNorm: (t) => t * gainMax(),
      write: (mul) => opts.applyDoc(M().setSectionGain(opts.getDoc(), name, mul)),
      label: (mul) => (Math.abs(mul - 1) < 0.03 ? '0 dB' : dbText(mul)),
      value: (mul) => Math.abs(mul - 1) < 0.03 ? '' : dbText(mul),
      unityNorm: 1 / gainMax(),
      caption: 'LEVEL',
    });

    // PAN control — writes .pan(x) into the section (SHARED coin), removed at centre
    const pan = faderControl('tpan', name, {
      read: () => sectionPan(name),
      norm: (p) => p,
      fromNorm: (t) => t,
      write: (p) => opts.applyDoc(M().setSectionPan(opts.getDoc(), name, p)),
      label: (p) => (Math.abs(p - 0.5) < 0.03 ? 'centre' : panText(p)),
      value: (p) => (Math.abs(p - 0.5) < 0.03 ? '' : panText(p)),
      unityNorm: 0.5,
      caption: 'PAN',
    });

    // FX — open the effect-chain RACK console for this section (native FxRackView door)
    let fxBtn = null;
    if (opts.openRack) {
      fxBtn = document.createElement('button');
      fxBtn.type = 'button'; fxBtn.className = 'tstrip-fx';
      fxBtn.textContent = 'FX'; fxBtn.title = 'FX rack — ' + name;
      fxBtn.setAttribute('aria-label', 'open the FX rack for ' + name);
      fxBtn.tabIndex = 0;
      attachActivate(fxBtn, () => { opts.openRack(name); });
    }

    row.appendChild(head);
    row.appendChild(tags);
    row.appendChild(level.el);
    row.appendChild(pan.el);
    if (fxBtn) row.appendChild(fxBtn);
    return row;
  }

  function tagButton(txt, aria, on, cls) {
    const b = document.createElement('button');
    b.type = 'button'; b.className = 'tstrip-tag ' + cls + (on ? ' on' : '');
    b.textContent = txt; b.title = aria; b.setAttribute('aria-label', aria);
    b.setAttribute('aria-pressed', String(!!on));
    b.tabIndex = 0;
    return b;
  }

  // A compact horizontal fader/knob-track that reads/writes a section value live from the doc, so it
  // stays correct without a rack rebuild during its own drag (getNorm reads the doc each frame).
  function faderControl(cls, name, spec) {
    const wrap = document.createElement('div'); wrap.className = 'tstrip-ctl ' + cls;
    const cap = document.createElement('span'); cap.className = 'tstrip-cap'; cap.textContent = spec.caption;
    const track = document.createElement('div'); track.className = 'tstrip-track';
    track.tabIndex = 0;
    track.setAttribute('role', 'slider');
    track.setAttribute('aria-label', spec.caption + ' ' + name);
    const unity = document.createElement('span'); unity.className = 'tstrip-unity'; unity.style.left = (spec.unityNorm * 100) + '%';
    const fill = document.createElement('span'); fill.className = 'tstrip-fill';
    const knob = document.createElement('span'); knob.className = 'tstrip-knob';
    const val = document.createElement('span'); val.className = 'tstrip-val';
    track.appendChild(unity); track.appendChild(fill); track.appendChild(knob);
    wrap.appendChild(cap); wrap.appendChild(track); wrap.appendChild(val);

    const paint = () => {
      const raw = spec.read();
      const t = Math.max(0, Math.min(1, spec.norm(raw)));
      fill.style.width = (t * 100) + '%';
      knob.style.left = (t * 100) + '%';
      val.textContent = spec.value(raw);
      track.setAttribute('aria-valuetext', spec.label(raw));
      track.setAttribute('aria-valuenow', String(Math.round(t * 100)));
    };

    attachValueDrag(track, {
      getNorm: () => Math.max(0, Math.min(1, spec.norm(spec.read()))),
      setNorm: (t) => { spec.write(spec.fromNorm(t)); paint(); },
      format: (t) => spec.label(spec.fromNorm(t)),
      width: () => track.getBoundingClientRect().width,
    });
    paint();
    return { el: wrap, paint };
  }

  // ---- the SHARED-core reads (native readGainMul / readPan / gainDbText / panText) ----
  function sectionGain(name) { try { return M().sectionGain(opts.getDoc(), name); } catch (e) { return 1; } }
  function sectionPan(name)  { try { return M().sectionPan(opts.getDoc(), name); } catch (e) { return 0.5; } }
  function dbText(mul)  { try { return M().gainDbTextOf(mul); } catch (e) { return ''; } }
  function panText(pan) { try { return M().panTextOf(pan); } catch (e) { return ''; } }

  build();
  render();

  return {
    el,
    refresh: () => render(),
    // verification hooks (headless drive)
    _sectionNames: () => sections.map((s) => s.name),
    _audible: (name) => isAudible(name),
    _stripFor: (name) => list.querySelectorAll('.tstrip')[sections.findIndex((s) => s.name === name)] || null,
  };
}
