// ===========================================================================
//  scorecard.js — the shareable SCORE CARD, rendered ON-DEVICE to a canvas.
//
//  A faithful port of the native `src/app/ScoreCard.h` poster: a static, braggable 4:5
//  image (1080x1350 — the social ratio) the maker renders in the browser and hands to the
//  OS share sheet / downloads. ZERO hosting cost (memory cyclo-zero-hosting-cost): no
//  server, no hosted leaderboard — the card IS the shareable trophy.
//
//  Content + spirit match native: a dark studio ground with a phosphor bloom + scanlines, the
//  cyclo wordmark, the hero MAKER SCORE, a DAY STREAK / BEST / EDITS stat strip, a TROPHIES row
//  (the Maker Medal coins — earned = coloured treasure, locked = a dim slug), and a CODE peek of
//  the maker's own track (the coin renders CODE).
//
//  The TROPHIES row draws the ONE shared medal catalog (name + glyph + identity colour) imported
//  from medals.js — the SAME source the in-app medals shelf renders, so the trophy on the card can
//  never drift from the trophy you earned (P1-b). The card's phosphor is the tokenized --phos.
//
//  Kept browser-only (needs a 2D canvas) and proven via the headless harness (render + share
//  fires); the ECONOMY it visualises is the node-tested pure module (score.js).
// ===========================================================================

import { PHOS, AMBER, PHOS_RGB } from './palette.js';         // the ONE phosphor + amber (shared token palette)
import { CATALOG as MEDAL_CATALOG } from './medals.js';       // the ONE shared medal catalog (glyph + identity colour)

export const CARD_W = 1080;
export const CARD_H = 1350;

// phosphor as an rgba() string at alpha `a` — the tokenized --phos (never the old stray hex).
const ph = (a) => `rgba(${PHOS_RGB},${a})`;

// thousands-grouped integer (tabular, glanceable): 12,845 — matches native group()
export function group(n) {
  n = Math.round(n);
  const neg = n < 0;
  const s = String(Math.abs(n));
  let out = '', c = 0;
  for (let i = s.length - 1; i >= 0; --i) {
    out = s[i] + out;
    if (++c % 3 === 0 && i > 0) out = ',' + out;
  }
  return (neg ? '-' : '') + out;
}

function streakStr(s) { return s + (s === 1 ? ' day' : ' days'); }

// Draw the recessed-LCD screen backing used for stat tiles + the code well (native paintRecessedScreen).
function recessedScreen(g, x, y, w, h, r) {
  g.save();
  roundRect(g, x, y, w, h, r);
  g.fillStyle = 'rgba(0,0,0,0.34)';
  g.fill();
  g.lineWidth = 1.2;
  g.strokeStyle = ph(0.14);
  g.stroke();
  g.restore();
}

function roundRect(g, x, y, w, h, r) {
  const rr = Math.min(r, w / 2, h / 2);
  g.beginPath();
  g.moveTo(x + rr, y);
  g.arcTo(x + w, y, x + w, y + h, rr);
  g.arcTo(x + w, y + h, x, y + h, rr);
  g.arcTo(x, y + h, x, y, rr);
  g.arcTo(x, y, x + w, y, rr);
  g.closePath();
}

function statTile(g, x, y, w, h, label, value, ps) {
  recessedScreen(g, x, y, w, h, ps(0.018));
  g.textBaseline = 'alphabetic';
  g.textAlign = 'left';
  g.fillStyle = ph(0.5);
  g.font = `700 ${ps(0.019)}px ${MONO}`;
  g.fillText(label, x + ps(0.022), y + ps(0.016) + ps(0.024));
  g.fillStyle = PHOS;
  g.font = `700 ${ps(0.05)}px ${MONO}`;
  g.fillText(fit(g, value, w - ps(0.044)), x + ps(0.022), y + h - ps(0.03));
}

// Shrink a string's rendered form only by trusting the caller's fonts; here we just clip via measure.
function fit(g, text, maxW) {
  // values are short; if a huge number ever overflows, trim gracefully.
  if (g.measureText(text).width <= maxW) return text;
  let t = text;
  while (t.length > 1 && g.measureText(t).width > maxW) t = t.slice(0, -1);
  return t;
}

const MONO = 'ui-monospace, "SF Mono", "JetBrains Mono", Menlo, Consolas, monospace';
const ROUND = 'system-ui, "Segoe UI", Roboto, sans-serif';

// hex "#rrggbb" -> [r,g,b]
function hexRgb(hex) { const s = hex.replace('#', ''); return [parseInt(s.slice(0, 2), 16), parseInt(s.slice(2, 4), 16), parseInt(s.slice(4, 6), 16)]; }
function shade(rgb, f) { return rgb.map((c) => Math.max(0, Math.min(255, Math.round(f < 1 ? c * f : c + (255 - c) * (f - 1))))); }
function rgbStr(rgb, a) { return `rgba(${rgb[0]},${rgb[1]},${rgb[2]},${a === undefined ? 1 : a})`; }

// The centre glyph size: multi-char emblems (</>) shrink so they fit the coin like the single glyphs.
function glyphFont(glyph, r) { return `700 ${(glyph.length > 1 ? r * 0.62 : r * 0.95)}px ${ROUND}`; }

// A locked trophy slug (a dim punched coin) — matte grey, dim glyph. Mirrors native's locked slug:
// the coloured reward appears ONLY on earning, so earned-vs-locked reads at a glance.
function lockedSlug(g, cx, cy, r, glyph) {
  g.save();
  g.beginPath();
  g.arc(cx, cy, r, 0, Math.PI * 2);
  const grd = g.createRadialGradient(cx - r * 0.3, cy - r * 0.35, r * 0.1, cx, cy, r);
  grd.addColorStop(0, '#232a28');
  grd.addColorStop(1, '#141917');
  g.fillStyle = grd;
  g.fill();
  g.lineWidth = 2;
  g.strokeStyle = ph(0.10);
  g.stroke();
  // a dim centre glyph
  g.fillStyle = 'rgba(180,200,190,0.22)';
  g.font = glyphFont(glyph, r);
  g.textAlign = 'center';
  g.textBaseline = 'middle';
  g.fillText(glyph, cx, cy + r * 0.04);
  g.restore();
}

// An EARNED trophy coin — a glossy convex disc in the medal's IDENTITY colour with an embossed
// glyph (the 2D-canvas twin of native laf/MedalArt.h::drawGlossyMedal). Chrome is REWARD-ONLY:
// this is only ever drawn for a genuinely earned medal.
function earnedCoin(g, cx, cy, r, glyph, color) {
  const mc = hexRgb(color);
  g.save();
  // soft cast shadow — the coin floats a touch proud
  g.beginPath(); g.arc(cx, cy + r * 0.06, r, 0, Math.PI * 2);
  g.fillStyle = 'rgba(0,0,0,0.34)'; g.fill();
  // coloured convex belly: lit top-left -> base colour -> shaded base
  g.beginPath(); g.arc(cx, cy, r, 0, Math.PI * 2);
  const belly = g.createLinearGradient(cx - r * 0.5, cy - r * 0.7, cx + r * 0.55, cy + r);
  belly.addColorStop(0, rgbStr(shade(mc, 1.35)));
  belly.addColorStop(0.5, rgbStr(mc));
  belly.addColorStop(1, rgbStr(shade(mc, 0.45)));
  g.fillStyle = belly; g.fill();
  // top-left specular sheen (the studio softbox on the dome), clipped to the disc
  g.save(); g.clip();
  const sx = cx - r * 0.22, sy = cy - r * 0.28, sr = r * 1.1;
  const sheen = g.createRadialGradient(sx, sy, r * 0.03, sx, sy, sr);
  sheen.addColorStop(0, 'rgba(255,255,255,0.7)');
  sheen.addColorStop(1, 'rgba(255,255,255,0)');
  g.fillStyle = sheen; g.fillRect(cx - r, cy - r, r * 2, r * 2);
  // inner base shade grounds the sphere
  const base = g.createLinearGradient(cx, cy, cx, cy + r);
  base.addColorStop(0, 'rgba(0,0,0,0)');
  base.addColorStop(1, 'rgba(0,0,0,0.34)');
  g.fillStyle = base; g.fillRect(cx - r, cy - r, r * 2, r * 2);
  g.restore();
  // bright rim catch-light + crisp outer edge
  g.beginPath(); g.arc(cx, cy - 0.6, r - 1.4, 0, Math.PI * 2);
  g.lineWidth = 1.8; g.strokeStyle = 'rgba(255,255,255,0.9)'; g.stroke();
  g.beginPath(); g.arc(cx, cy, r - 0.6, 0, Math.PI * 2);
  g.lineWidth = 1.2; g.strokeStyle = rgbStr(shade(mc, 0.3), 0.55); g.stroke();
  // embossed emblem: a light top bevel then the dark relief, so it reads as struck INTO metal
  g.textAlign = 'center'; g.textBaseline = 'middle';
  g.font = glyphFont(glyph, r);
  g.fillStyle = 'rgba(255,255,255,0.5)'; g.fillText(glyph, cx, cy + r * 0.04 + 1.2);
  g.fillStyle = rgbStr(shade(mc, 0.28), 0.75); g.fillText(glyph, cx, cy + r * 0.04);
  g.restore();
}

// The eight milestone slots — DERIVED from the ONE shared medal catalog (medals.js), so name +
// glyph + identity colour are identical to the in-app shelf and can never drift again (P1-b).
export const MEDAL_SLOTS = MEDAL_CATALOG.map((mi) => ({
  id: mi.id, name: mi.title.toUpperCase(), glyph: mi.glyph, color: mi.color,
}));

// Render the score card into a canvas at full resolution. `data` = {total,best,streak,edits,
// projectName,codeSnippet,dateStr,earned}. `earned` is an 8-bool array (catalog order) marking
// which medals are struck. Returns the canvas.
export function renderScoreCard(canvas, data) {
  canvas.width = CARD_W;
  canvas.height = CARD_H;
  const g = canvas.getContext('2d');
  const W = CARD_W, H = CARD_H;
  const px = (u) => u * W;
  const py = (v) => v * H;
  const ps = (u) => u * W;
  const earned = Array.isArray(data.earned) ? data.earned : [];
  const earnedCount = earned.filter(Boolean).length;

  g.save();
  roundRect(g, 0, 0, W, H, W * 0.035);
  g.clip();

  // ---- dark studio ground ----
  const bg = g.createLinearGradient(0, 0, 0, H);
  bg.addColorStop(0, '#10201a');
  bg.addColorStop(0.5, '#0a1512');
  bg.addColorStop(1, '#05090b');
  g.fillStyle = bg;
  g.fillRect(0, 0, W, H);

  // soft phosphor bloom off the top (studio key light)
  const glow = g.createRadialGradient(W / 2, py(0.05), 0, W / 2, py(0.05), py(0.45));
  glow.addColorStop(0, ph(0.16));
  glow.addColorStop(1, ph(0));
  g.fillStyle = glow;
  g.fillRect(0, 0, W, H);

  // faint scanline texture (a screen readout, on brand)
  g.fillStyle = 'rgba(255,255,255,0.014)';
  for (let yy = 0; yy < H; yy += 4) g.fillRect(0, yy, W, 1);

  // inner hairline frame
  g.lineWidth = 1.5;
  g.strokeStyle = ph(0.22);
  roundRect(g, ps(0.02), ps(0.02), W - ps(0.04), H - ps(0.04), ps(0.02));
  g.stroke();

  // ---- header: wordmark + tagline ----
  g.textAlign = 'left';
  g.textBaseline = 'alphabetic';
  g.fillStyle = PHOS;
  g.font = `800 ${ps(0.052)}px ${ROUND}`;
  g.fillText('cyclo', px(0.066), py(0.093));
  g.fillStyle = AMBER;
  g.font = `800 ${ps(0.026)}px ${ROUND}`;
  g.fillText('●', px(0.066) + g.measureText('cyclo').width + ps(0.006), py(0.086));

  g.textAlign = 'right';
  g.fillStyle = ph(0.55);
  g.font = `700 ${ps(0.021)}px ${MONO}`;
  g.fillText('MAKER SCORE CARD', px(0.934), py(0.088));

  // ---- the hero: MAKER SCORE ----
  g.textAlign = 'left';
  g.fillStyle = ph(0.6);
  g.font = `700 ${ps(0.028)}px ${MONO}`;
  g.fillText('MAKER SCORE', px(0.066), py(0.185));

  g.fillStyle = PHOS;
  g.font = `700 ${ps(0.17)}px ${MONO}`;
  g.save();
  g.shadowColor = ph(0.45);
  g.shadowBlur = 34;
  g.fillText(group(data.total), px(0.062), py(0.315));
  g.restore();

  // baseline rule
  g.fillStyle = ph(0.3);
  g.fillRect(px(0.066), py(0.40), W * 0.868, 2);

  // ---- three stat tiles: DAY STREAK · BEST · CODE EDITS ----
  {
    const ty = py(0.435), th = ps(0.135), gap = ps(0.02);
    const tw = (W * 0.868 - 2 * gap) / 3;
    statTile(g, px(0.066), ty, tw, th, 'DAY STREAK', streakStr(data.streak), ps);
    statTile(g, px(0.066) + tw + gap, ty, tw, th, 'BEST SESSION', group(data.best), ps);
    statTile(g, px(0.066) + 2 * (tw + gap), ty, tw, th, 'CODE EDITS', group(data.edits || 0), ps);
  }

  // ---- the TROPHIES row (the shared Maker Medal catalog: earned coins vs locked slugs) ----
  g.textAlign = 'left';
  g.fillStyle = ph(0.55);
  g.font = `700 ${ps(0.022)}px ${MONO}`;
  g.fillText('TROPHIES', px(0.066), py(0.61));
  g.fillStyle = ph(0.32);
  g.font = `700 ${ps(0.016)}px ${MONO}`;
  g.textAlign = 'right';
  g.fillText(earnedCount > 0 ? earnedCount + '/' + MEDAL_SLOTS.length + ' EARNED' : 'EARN THEM IN THE APP', px(0.934), py(0.61));
  {
    const cols = 4;
    const area = W * 0.868;
    const coin = ps(0.118);
    const cellW = area / cols;
    const rowH = ps(0.148);
    const gx = px(0.066);
    const gy = py(0.625);
    for (let i = 0; i < MEDAL_SLOTS.length; ++i) {
      const cxc = gx + (i % cols) * cellW + cellW * 0.5;
      const cyc = gy + Math.floor(i / cols) * rowH + coin * 0.5;
      const slot = MEDAL_SLOTS[i];
      if (earned[i]) earnedCoin(g, cxc, cyc, coin * 0.5, slot.glyph, slot.color);
      else lockedSlug(g, cxc, cyc, coin * 0.5, slot.glyph);
      g.fillStyle = earned[i] ? rgbStr(shade(hexRgb(slot.color), 1.35), 0.92) : 'rgba(255,255,255,0.30)';
      g.font = `600 ${ps(0.016)}px ${ROUND}`;
      g.textAlign = 'center';
      g.fillText(slot.name, cxc, cyc + coin * 0.5 + ps(0.026));
    }
  }

  // ---- the CODE peek: the maker's own track as code (the coin) ----
  {
    const wx = px(0.066), wy = py(0.872), ww = W * 0.868, wh = ps(0.088);
    recessedScreen(g, wx, wy, ww, wh, ps(0.02));
    g.textAlign = 'left';
    g.fillStyle = ph(0.5);
    g.font = `700 ${ps(0.017)}px ${MONO}`;
    g.fillText('// ' + String(data.projectName || 'untitled').toLowerCase(), wx + ps(0.028), wy + ps(0.033));
    g.fillStyle = ph(0.92);
    g.font = `400 ${ps(0.02)}px ${MONO}`;
    const lines = String(data.codeSnippet || '').split('\n').map((l) => l.trim()).filter(Boolean);
    let shown = 0, ly = wy + ps(0.062);
    for (const ln of lines) {
      if (shown >= 2) break;
      g.fillText(ln.slice(0, 46), wx + ps(0.028), ly);
      ly += ps(0.026);
      ++shown;
    }
  }

  // ---- footer ----
  g.textAlign = 'center';
  g.fillStyle = ph(0.4);
  g.font = `700 ${ps(0.018)}px ${MONO}`;
  g.fillText('made with cyclo   /   ' + (data.dateStr || ''), W / 2, py(0.99));

  g.restore();
  return canvas;
}
