// ===========================================================================
//  daily.js — the Daily Challenge on the web (Gamification, the DAY-STREAK driver).
//
//  One on-device creative dare per day (the "Daily Groove" model) — the opt-in delight that
//  motivates coming back to extend the Maker Score's DAY STREAK. A faithful twin of the native
//  pure core:
//    * The DARE ROTATION (which dare shows on a given calendar day) is a DETERMINISTIC pure
//      function of the day index, reused via WASM from src/core/game/DailyChallenge.h — the
//      64-bit splitmix64 deck-shuffle is NOT re-implemented in JS. main.js reads it through
//      M.dareForDayJson(day) / M.dareCatalogJson(); this module holds only the completion state.
//    * The COMPLETION STATE (this class) mirrors native cyclo::game::DailyChallenge EXACTLY:
//      it remembers ONLY which day was last completed (forward-only, idempotent per day) plus a
//      lifetime count, so the card shows a done-state and never double-counts a day. The STREAK
//      itself lives in MakerScore (score.js) and advances there when the app awards ChallengeDone
//      — single source of truth, no duplicated streak math.
//
//  PURE + DOM-FREE + framework-free so it unit-tests in Node (web/verify.js) and drives the UI
//  unchanged. Persisted (serialized text, byte-compatible with native) in this build's OWN
//  IndexedDB slot — the native dev-box `.daily` prefs file is never touched.
//
//  Native cross-reference (do not drift): cyclo::game::DailyChallenge::{isCompletedOn, complete,
//  serialize, deserialize}; the dare catalog + kinds live in src/core/game/DailyChallenge.h.
// ===========================================================================

import { PHOS, AMBER, BLUE, CYAN } from './palette.js';   // shared accent tokens (node-safe: hex fallbacks)
import { Action } from './score.js';                     // the scored making events (node-safe: pure)

// The six creative dispositions (native cyclo::game::DareKind order). A card navigates by the
// icon + colour so a non-reader (the binding-constraint 8-year-old) reads it with no words.
export const DareKind = { Spark: 0, Build: 1, Polish: 2, Remix: 3, Listen: 4, Flow: 5 };
export const DARE_KIND_COUNT = 6;

// ---- P1-a: which REAL making events honestly complete a dare of each KIND -----------------------
// A dare is ARMED on "Do it now" (the card's button), NOT completed. It completes only when the
// maker actually performs a making move matching the day's disposition — one of these scored events
// (score.js Action ids, the SAME honest hooks the medals strike from). Nothing is faked: tapping the
// button just points you at the making surface; the +24 + streak fire on the DOING. If a dare's
// exact micro-event isn't detectable on web yet, the KIND still completes on a disposition-matching
// real action (never on the tap), so the loop stays honest AND completable every day.
//
// Detectability today (all six kinds are completable through a real scored event):
//   Spark  → a pad tap (TAP) or a caught hum (HUM)
//   Build  → a pad tap or a genuine code edit (lay down / stack structure)
//   Polish → a groove (SWING), a found key (TUNE), or a genuine code edit (SHAPE a clause)
//   Remix  → a genuine code edit (TWIST) or a version restore (REMIX/ROLL back)
//   Listen → a grown grain garden (GROW) or a pad tap (audition texture)
//   Flow   → a genuine code edit (CODE) or an export (SHIP)
// (Record/import a sound isn't a scored Action yet, so RECORD/FIND lean on TAP/HUM within Spark —
//  honest: a real new-sound gesture still completes them. When record earns a score, add it here.)
export const DARE_KIND_EVENTS = {
  [DareKind.Spark]:  [Action.PadTap, Action.HumCaught],
  [DareKind.Build]:  [Action.PadTap, Action.CodeEdit],
  [DareKind.Polish]: [Action.GrooveMade, Action.KeyFound, Action.CodeEdit],
  [DareKind.Remix]:  [Action.CodeEdit, Action.VersionRestored],
  [DareKind.Listen]: [Action.GrainGrown, Action.PadTap],
  [DareKind.Flow]:   [Action.CodeEdit, Action.Export],
};

// The real making events that complete a dare of `kind` (empty array = not yet detectable → honest
// arm-but-never-fake). Used by main.js to complete an ARMED dare only when a matching action fires.
export function dareEventsForKind(kind) { return DARE_KIND_EVENTS[kind] ? DARE_KIND_EVENTS[kind].slice() : []; }

// A stable ASCII name per kind (matches native dareKindName) — for glyph/colour lookup + tests.
export function dareKindName(kind) {
  return ['SPARK', 'BUILD', 'POLISH', 'REMIX', 'LISTEN', 'FLOW'][kind] || '';
}

// The identity colour family the card + live-feed draw per kind (mirrors native
// DailyChallengeCard::kindColour — amber / fader-blue / cyan / violet / phosphor / pink).
export function dareKindColour(kind) {
  return [
    AMBER,     // Spark  — amber
    BLUE,      // Build  — fader / settings blue
    CYAN,      // Polish — cyan
    '#b07cff', // Remix  — violet
    PHOS,      // Listen — phosphor
    '#ff73b3', // Flow   — pink
  ][kind] || PHOS;
}

// The persistent completion state — a faithful port of native cyclo::game::DailyChallenge.
// It remembers ONLY the last completed day (so the card shows "done today" and never awards the
// same day twice) + a lifetime count. The DAY STREAK lives in MakerScore and is advanced there.
export class DailyChallenge {
  constructor() {
    this.lastCompletedDay_ = -1; // day index of the last completed dare (persisted)
    this.totalCompleted_ = 0;    // lifetime dares completed (persisted)
  }

  // Has the dare for `day` already been completed? (day < 0 -> unknown -> false.)
  isCompletedOn(day) { return day >= 0 && this.lastCompletedDay_ === day; }

  // Mark `day`'s dare complete. Returns true only on a NEW completion (idempotent per day, and
  // forward-only so a rolled-back clock can't "re-open" an already-finished earlier day). The
  // caller advances the streak via MakerScore only when this returns true.
  complete(day) {
    if (day < 0 || day <= this.lastCompletedDay_) return false;
    this.lastCompletedDay_ = day;
    ++this.totalCompleted_;
    return true;
  }

  lastCompletedDay() { return this.lastCompletedDay_; }
  totalCompleted() { return this.totalCompleted_; }

  // ---- persistence (byte-compatible with native serialize; tolerant, forward-compatible) ----
  serialize() {
    return 'lastday=' + this.lastCompletedDay_ + '\n' + 'total=' + this.totalCompleted_ + '\n';
  }

  deserialize(text) {
    this.lastCompletedDay_ = -1;
    this.totalCompleted_ = 0;
    if (typeof text !== 'string') return;
    for (const rawLine of text.split('\n')) {
      const eq = rawLine.indexOf('=');
      if (eq < 0) continue;
      const key = rawLine.slice(0, eq).trim();
      const val = rawLine.slice(eq + 1).trim();
      if (!key) continue;
      const n = parseInt(val, 10);
      if (!Number.isFinite(n)) continue; // a malformed number never corrupts the rest of the load
      if (key === 'lastday') this.lastCompletedDay_ = n;
      else if (key === 'total') this.totalCompleted_ = n;
      // unknown keys ignored (forward-compatible)
    }
  }
}
