// ===========================================================================
//  welcome.js — the first-run WELCOME + the FACTORY EXAMPLES picker (native src/app/Welcome.h +
//  src/app/ProjectBrowser.h). The web twin of native's "no blank page" front door: a newcomer or
//  an 8-year-old lands somewhere inviting and hears music in ONE tap, without reading a word.
//
//  The hero is ONE giant green PLAY button (the universal "hear it now" symbol — native's IconButton
//  FAB), loading a built-in demo. Below it a clear path to either OPEN AN EXAMPLE (the factory picker)
//  or START FROM SCRATCH — mirroring native's three quieter verbs. The examples are the SHARED-core
//  cyclo::factoryExamples() read via WASM (exampleName / exampleDoc / exampleBpm) — never retyped in
//  JS, so the browser ships the exact canonical set the native app + tests/test_examples.cpp cover.
//
//  Gating (first-run-only) + the load/play wiring live in main.js; this module is presentation +
//  the picker. It is input-agnostic (every control is a real focusable <button>, pointer + keyboard),
//  dismissible (Escape / tap-scrim / Start fresh), and un-annoying (one screen, one tap to sound).
// ===========================================================================

import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

// Build the welcome overlay (kept hidden until show()). `examples` is [{ name, caption }] derived
// from the SHARED core (name = exampleName(i); caption = the doc's first `//` line). The callbacks
// do the real work in main.js; every exit path calls onSeen() so the welcome never nags again.
export function createWelcome({ host, examples, onDemo, onLoadExample, onStartFresh, onSeen }) {
  const ex = Array.isArray(examples) ? examples : [];
  let seenFired = false;
  const fireSeen = () => { if (!seenFired) { seenFired = true; try { onSeen && onSeen(); } catch (e) {} } };

  const scrim = document.createElement('div');
  scrim.className = 'sheet-scrim welcome-scrim hidden';
  scrim.setAttribute('role', 'dialog');
  scrim.setAttribute('aria-modal', 'true');
  scrim.setAttribute('aria-label', 'welcome to cyclo');

  const sheet = document.createElement('div');
  sheet.className = 'sheet welcome-sheet';
  scrim.appendChild(sheet);

  // ---- HOME screen: wordmark + tagline + the giant green PLAY hero + verbs ----
  const home = document.createElement('div');
  home.className = 'welcome-screen';
  home.innerHTML = `
    <div class="welcome-word">cyclo<span class="grain">●</span></div>
    <div class="welcome-tag">Make weird music, real quick.</div>
    <div class="welcome-sub">A tiny coding instrument. Press play — then change a number and hear it move.</div>`;
  // the hero: a big green PLAY FAB (a green triangle is the one control every human already knows
  // means "start / hear it"). One tap to music — native's Welcome hero.
  const heroWrap = document.createElement('div');
  heroWrap.className = 'welcome-hero';
  const hero = document.createElement('button');
  hero.type = 'button';
  hero.className = 'welcome-play';
  hero.setAttribute('aria-label', 'play a demo beat');
  hero.innerHTML = '<span class="welcome-play-tri" aria-hidden="true"></span>';
  const heroCap = document.createElement('div');
  heroCap.className = 'welcome-hero-cap';
  heroCap.textContent = 'Play a demo beat';
  heroWrap.appendChild(hero);
  heroWrap.appendChild(heroCap);
  home.appendChild(heroWrap);

  // the two quieter verbs (native's icon+word column): open an example, or start empty
  const openBtn = document.createElement('button');
  openBtn.type = 'button';
  openBtn.className = 'sheet-key welcome-verb';
  openBtn.innerHTML = '<span class="sheet-glyph">♪</span> Open an example';
  const freshBtn = document.createElement('button');
  freshBtn.type = 'button';
  freshBtn.className = 'sheet-key welcome-verb';
  freshBtn.innerHTML = '<span class="sheet-glyph">＋</span> Start with a beat';
  home.appendChild(openBtn);
  home.appendChild(freshBtn);
  sheet.appendChild(home);

  // ---- EXAMPLES screen: the factory picker (native ProjectBrowser's DEMO rows) ----
  const picker = document.createElement('div');
  picker.className = 'welcome-screen welcome-picker hidden';
  const pTitle = document.createElement('div');
  pTitle.className = 'sheet-title';
  pTitle.textContent = 'Pick an example';
  const pSub = document.createElement('div');
  pSub.className = 'sheet-sub';
  pSub.textContent = 'A few songs to start from. Tap one to load it and hear it.';
  const list = document.createElement('div');
  list.className = 'ex-list';
  list.setAttribute('aria-label', 'built-in examples');
  ex.forEach((e, i) => {
    const row = document.createElement('button');
    row.type = 'button';
    row.className = 'ex-row';
    row.dataset.index = String(i);
    row.innerHTML =
      `<span class="ex-main"><span class="ex-name">${escapeHtml(e.name)}</span>` +
      `<span class="ex-caption">${escapeHtml(e.caption || '')}</span></span>` +
      `<span class="ex-tag">DEMO</span>`;
    row.addEventListener('click', () => pick(i));
    list.appendChild(row);
  });
  const backBtn = document.createElement('button');
  backBtn.type = 'button';
  backBtn.className = 'sheet-cancel';
  backBtn.textContent = 'Back';
  picker.appendChild(pTitle);
  picker.appendChild(pSub);
  picker.appendChild(list);
  picker.appendChild(backBtn);
  sheet.appendChild(picker);

  // ---- behaviour ----
  let origin = 'welcome';   // 'welcome' -> Back returns home; 'menu' -> Back closes (opened standalone)

  function showScreen(which) {
    home.classList.toggle('hidden', which !== 'home');
    picker.classList.toggle('hidden', which !== 'examples');
  }

  (host || document.body).appendChild(scrim);

  // Open/close/scrim/Escape via the ONE shared overlay manager (overlay.js): release-close scrim-tap
  // (marks the welcome seen), the central Escape stack. Welcome keeps its bespoke bottom-"Back" verb
  // and its two-screen (home / examples) flow; onEscape steps examples -> home before it closes.
  const overlay = registerOverlay(scrim, {
    panel: sheet,
    label: 'welcome to cyclo',
    restoreFocus: false,
    onEscape: () => { if (examplesShown() && origin === 'welcome') { showScreen('home'); return true; } return false; },
    onClose: () => { fireSeen(); },
  });

  function show() { overlay.open(); showScreen('home'); setTimeout(() => hero.focus(), 20); }
  function hide() { overlay.close(); }
  function isShown() { return overlay.isOpen(); }
  function examplesShown() { return isShown() && !picker.classList.contains('hidden'); }

  function showExamples(from) {
    origin = from === 'menu' ? 'menu' : 'welcome';
    overlay.open();                 // idempotent — a no-op when the home screen is already up
    showScreen('examples');
    setTimeout(() => { const r = list.querySelector('.ex-row'); if (r) r.focus(); }, 20);
  }
  function pick(i) {
    hide();                         // fireSeen runs in the overlay onClose
    try { onLoadExample && onLoadExample(i); } catch (e) {}
  }

  hero.addEventListener('click', () => { hide(); try { onDemo && onDemo(); } catch (e) {} });
  openBtn.addEventListener('click', () => showExamples('welcome'));
  freshBtn.addEventListener('click', () => { hide(); try { onStartFresh && onStartFresh(); } catch (e) {} });
  backBtn.addEventListener('click', () => { if (origin === 'menu') hide(); else showScreen('home'); });

  return {
    el: scrim,
    show, hide, isShown, showExamples, examplesShown,
    pickExample: pick,
    exampleNames: () => ex.map((e) => e.name),
    destroy: () => { try { scrim.remove(); } catch (e) {} },
  };
}

function escapeHtml(s) {
  return String(s == null ? '' : s).replace(/[&<>"]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
}
