// ===========================================================================
//  reference.js — the LANGUAGE REFERENCE OVERLAY (native src/app/ReferenceOverlay.h + HelpCard.h).
//
//  The in-app browsable, SEARCHABLE language manual: every token / transform / combinator / signal /
//  keyword grouped by category (PATTERN | TRANSFORM | SIGNAL | GLOBAL), each showing its NAME, its
//  SIGNATURE/SYNTAX, a one-line SUMMARY and a real EXAMPLE — and tapping an entry INSERTS that example
//  into the code at the caret (native's "one touch from reading to hearing"). The data is the SHARED
//  core cyclo::languageReference() read via WASM (M.referenceJson()) — the SAME single source of truth
//  the completions + the syntax highlighter + tests/test_reference.cpp use, so it can never drift and
//  there is no hand-maintained JS copy.
//
//  Input-agnostic (docs/web-interaction.md): a real text <input> filter + every entry a focusable
//  <button> (pointer AND keyboard Enter/Space), 44px+ targets, arrow-key list navigation, scrim-tap /
//  Escape close, `touch-action:manipulation` + `overscroll-behavior:contain`. Design-bar phosphor
//  styling (the recessed dark "data screen" language — name in phosphor, syntax in amber, example in cyan).
// ===========================================================================
import { attachActivate } from './gesture.js';
import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

// ---- pure filter logic (DOM-free, node-testable in web/verify.js) --------------------------------
// A live filter matches an entry when the query (case-insensitive) appears anywhere in its name,
// syntax, summary OR category — byte-identical to native ReferenceOverlay::rebuild's haystack test
// (`name + " " + syntax + " " + summary + " " + category`, containsIgnoreCase).
export function refMatches(entry, query) {
  const q = String(query == null ? '' : query).trim().toLowerCase();
  if (!q) return true;
  const hay = (
    (entry.name || '') + ' ' + (entry.syntax || '') + ' ' +
    (entry.summary || '') + ' ' + (entry.category || '')
  ).toLowerCase();
  return hay.includes(q);
}

// Filter a reference array to those entries matching `query` (order preserved). The whole search model.
export function filterReference(entries, query) {
  return (Array.isArray(entries) ? entries : []).filter((e) => refMatches(e, query));
}

// ---- the overlay -------------------------------------------------------------------------------
// `module` is the WASM module (for M.referenceJson()); `onInsert(example, isGlobal)` drops an entry's
// example into the editor (globals prepend, chains insert at the caret — main.js does the coin work);
// `onClose` returns focus to the code. Built once, kept hidden until show().
export function createReference({ host, module, onInsert, onClose }) {
  let entries = [];
  try { entries = JSON.parse(module.referenceJson()); } catch (e) { entries = []; }

  const scrim = document.createElement('div');
  scrim.className = 'ref-scrim hidden';
  scrim.setAttribute('role', 'dialog');
  scrim.setAttribute('aria-modal', 'true');
  scrim.setAttribute('aria-label', 'language reference');

  const card = document.createElement('div');
  card.className = 'ref-card';
  scrim.appendChild(card);

  // ---- head: title + close ----
  const head = document.createElement('div');
  head.className = 'ref-head';
  const titles = document.createElement('div');
  titles.className = 'ref-titles';
  titles.innerHTML = '<div class="ref-title">Language reference</div>' +
    '<div class="ref-sub">TAP AN ENTRY TO DROP ITS EXAMPLE INTO YOUR CODE</div>';
  const closeBtn = document.createElement('button');
  closeBtn.type = 'button';
  closeBtn.className = 'ref-close';
  closeBtn.setAttribute('aria-label', 'close');
  closeBtn.innerHTML = '&times;';
  head.appendChild(titles);
  head.appendChild(closeBtn);
  card.appendChild(head);

  // ---- the filter field (a recessed dark screen, the deck's DATA language) ----
  const filter = document.createElement('input');
  filter.type = 'text';
  filter.className = 'ref-filter';
  filter.setAttribute('autocomplete', 'off');
  filter.setAttribute('spellcheck', 'false');
  filter.setAttribute('aria-label', 'filter the reference');
  filter.placeholder = 'filter… (e.g. chop, rand, song)';
  card.appendChild(filter);

  // ---- the scrollable list ----
  const list = document.createElement('div');
  list.className = 'ref-list';
  list.setAttribute('role', 'listbox');
  list.setAttribute('aria-label', 'language entries');
  card.appendChild(list);

  // A live count / empty state under the list — honest feedback while filtering.
  const foot = document.createElement('div');
  foot.className = 'ref-foot';
  card.appendChild(foot);

  // A friendlier heading per raw category (the native categories are terse; keep them for matching).
  const CAT_LABEL = {
    PATTERN: 'PATTERN — what goes inside s("…")',
    TRANSFORM: 'TRANSFORM — chained after s(…) with a dot',
    SIGNAL: 'SIGNAL — put one where a number goes',
    GLOBAL: 'GLOBAL — lines above the first section',
  };

  let entryButtons = [];   // the flat, in-order list of the currently-rendered entry buttons

  function rebuild() {
    const q = filter.value;
    const shown = filterReference(entries, q);
    list.innerHTML = '';
    entryButtons = [];
    let lastCat = null;
    for (const e of shown) {
      if (e.category !== lastCat) {
        lastCat = e.category;
        const h = document.createElement('div');
        h.className = 'ref-cat';
        h.setAttribute('role', 'presentation');
        h.textContent = CAT_LABEL[e.category] || e.category;
        list.appendChild(h);
      }
      const b = document.createElement('button');
      b.type = 'button';
      b.className = 'ref-entry';
      b.setAttribute('role', 'option');
      b.dataset.name = e.name;
      b.dataset.category = e.category;
      // name (phosphor) + signature (amber) on the top line; summary (prose) + example (cyan) below.
      const l1 = document.createElement('div');
      l1.className = 'ref-entry-l1';
      const nm = document.createElement('span');
      nm.className = 'ref-entry-name';
      nm.textContent = e.name;
      const sig = document.createElement('span');
      sig.className = 'ref-entry-sig';
      sig.textContent = e.syntax;
      l1.appendChild(nm); l1.appendChild(sig);
      const sum = document.createElement('div');
      sum.className = 'ref-entry-sum';
      sum.textContent = e.summary;
      const ex = document.createElement('div');
      ex.className = 'ref-entry-ex';
      ex.textContent = (e.example || '').replace(/\n/g, ' ');
      b.appendChild(l1); b.appendChild(sum); b.appendChild(ex);
      // tap / Enter / Space inserts the example (pointer + keyboard, one path — native's onTap)
      attachActivate(b, () => insert(e));
      list.appendChild(b);
      entryButtons.push(b);
    }
    const n = shown.length, total = entries.length;
    foot.textContent = q.trim()
      ? (n ? `${n} of ${total} — matching “${q.trim()}”` : `no entries match “${q.trim()}”`)
      : `${total} entries · sources, transforms, signals, globals`;
    foot.classList.toggle('warn', q.trim() !== '' && n === 0);
  }

  function insert(e) {
    hide();
    try { onInsert && onInsert(e.example, String(e.category).toUpperCase() === 'GLOBAL'); } catch (err) {}
  }

  // ---- keyboard list navigation (arrows move focus between entries; Home/End jump) ----
  function focusedIndex() {
    const a = document.activeElement;
    return entryButtons.indexOf(a);
  }
  function focusEntry(i) {
    if (!entryButtons.length) return;
    const j = Math.max(0, Math.min(entryButtons.length - 1, i));
    entryButtons[j].focus();
  }
  list.addEventListener('keydown', (ev) => {
    const i = focusedIndex();
    if (ev.key === 'ArrowDown') { ev.preventDefault(); focusEntry((i < 0 ? 0 : i + 1)); }
    else if (ev.key === 'ArrowUp') { ev.preventDefault(); focusEntry((i < 0 ? 0 : i - 1)); }
    else if (ev.key === 'Home') { ev.preventDefault(); focusEntry(0); }
    else if (ev.key === 'End') { ev.preventDefault(); focusEntry(entryButtons.length - 1); }
  });
  // Down-arrow from the filter field drops focus into the first entry (keyboard flow, no mouse needed).
  filter.addEventListener('keydown', (ev) => {
    if (ev.key === 'ArrowDown') { ev.preventDefault(); focusEntry(0); }
  });

  filter.addEventListener('input', rebuild);

  rebuild();
  (host || document.body).appendChild(scrim);

  // Open/close/scrim/Escape via the ONE shared overlay manager (overlay.js): header ×, release-close
  // scrim-tap (press-vs-release guarded), the central Escape stack. Focus lands in the search field.
  const overlay = registerOverlay(scrim, {
    panel: card,
    closeButtons: [closeBtn],
    label: 'language reference',
    initialFocus: filter,
    onOpen: () => { filter.value = ''; rebuild(); },
    onClose: () => { if (onClose) onClose(); },
  });
  function show() { overlay.open(); }
  function hide() { overlay.close(); }
  function isOpen() { return overlay.isOpen(); }

  return {
    el: scrim,
    show, hide, isOpen,
    destroy: () => { try { scrim.remove(); } catch (e) {} },
    // ---- verification hooks (drive the REAL surface headlessly) ----
    _entries: () => entries.slice(),
    _count: () => entries.length,
    _setSearch: (q) => { filter.value = q == null ? '' : String(q); rebuild(); },
    _visibleNames: () => entryButtons.map((b) => b.dataset.name),
    _visibleCount: () => entryButtons.length,
    _categoriesShown: () => {
      const seen = [];
      for (const b of entryButtons) if (!seen.includes(b.dataset.category)) seen.push(b.dataset.category);
      return seen;
    },
    _entryFor: (name) => entries.find((e) => e.name === name) || null,
    _tapEntry: (name) => {
      // find the RENDERED button (proves the entry is actually on screen), then run the SAME
      // insert path a pointer/Enter would (attachActivate listens to pointerdown/keydown, not the
      // synthetic click event, so we invoke the handler directly with the entry's real data).
      const b = entryButtons.find((x) => x.dataset.name === name);
      if (!b) return false;
      const e = entries.find((x) => x.name === name);
      if (e) insert(e);
      return true;
    },
  };
}
