// ===========================================================================
//  score.js — the Maker Score economy on the web (Gamification Layer 3).
//
//  A FAITHFUL, line-for-line port of the native pure-core model
//  `src/core/game/MakerScore.{h,cpp}` — the SAME base points per action, the SAME
//  super-linear soft-capped code-edit multiplier, the SAME Duolingo-style daily streak,
//  and a byte-compatible serialize/deserialize. Editing code is worth the MOST and it
//  counts EXPONENTIALLY (the owner's firm steer): each code edit in a session is worth
//  more than the last, saturating toward an 8x ceiling so a spammer's per-edit award
//  tops out rather than running away.
//
//  PURE + DOM-FREE + framework-free so it unit-tests in Node (web/verify.js imports it and
//  asserts the curve matches the native formula) and drives the web UI unchanged. The web
//  build persists the serialized text in IndexedDB (its own store — the native `.score`
//  dev-box file is never touched); the economy itself is identical to native.
//
//  Native cross-reference (do not drift):
//    econ::kBase* / kMedalBonus / kMaxMult / kCurveP / kHalf / kStreakStep / kStreakDayCap
//    codeEditMultiplier(n) = 1 + (kMaxMult-1)*n^P/(n^P + kHalf^P)   // = 1 + 7*n^2/(n^2+144)
//    streakMultiplier(streak) = 1 + kStreakStep*clamp(streak-1, 0, kStreakDayCap)
// ===========================================================================

// The making actions that earn points — each maps to a real event hook (the SAME sites the
// Maker Medals strike from), so earning is honest. Order MATCHES the native Action enum.
export const Action = {
  PadTap: 0,
  CodeEdit: 1,
  KeyFound: 2,
  GrooveMade: 3,
  HumCaught: 4,
  GrainGrown: 5,
  VersionRestored: 6,
  Export: 7,
  ChallengeDone: 8,
};

// ---- the economy's tunable constants — identical to native `econ::` ------------------------
export const econ = {
  kBasePadTap: 4,
  kBaseCodeEdit: 12,
  kBaseKeyFound: 18,
  kBaseGrooveMade: 22,
  kBaseHumCaught: 22,
  kBaseGrainGrown: 16,
  kBaseVersionRestored: 8,
  kBaseExport: 35,
  kBaseChallengeDone: 24,

  kMedalBonus: 200,      // a struck medal is a chunky one-off bonus (the splash; the score is the drip)

  kMaxMult: 8.0,         // per-edit multiplier ceiling (8x the base)
  kCurveP: 2.0,          // exponent — >1 makes the early ramp super-linear
  kHalf: 12.0,           // edits at which f is halfway to the ceiling

  kStreakStep: 0.02,     // +2% per consecutive day beyond the first
  kStreakDayCap: 15,     // caps the streak bonus at +30%
};

// The immutable catalog, in Action order: stable persistence key + scoreboard label + base points.
// Keys are STABLE tokens (never rename a shipped key — it is what persists) and byte-match native.
export const CATALOG = [
  { id: Action.PadTap,          key: 'pad_tap',   label: 'Pad taps',          base: econ.kBasePadTap },
  { id: Action.CodeEdit,        key: 'code_edit', label: 'Code edits',        base: econ.kBaseCodeEdit },
  { id: Action.KeyFound,        key: 'key_found', label: 'Keys found',        base: econ.kBaseKeyFound },
  { id: Action.GrooveMade,      key: 'groove',    label: 'Grooves made',      base: econ.kBaseGrooveMade },
  { id: Action.HumCaught,       key: 'hum',       label: 'Hums caught',       base: econ.kBaseHumCaught },
  { id: Action.GrainGrown,      key: 'grain',     label: 'Grains grown',      base: econ.kBaseGrainGrown },
  { id: Action.VersionRestored, key: 'restore',   label: 'Versions restored', base: econ.kBaseVersionRestored },
  { id: Action.Export,          key: 'export',    label: 'Exports',           base: econ.kBaseExport },
  { id: Action.ChallengeDone,   key: 'daily',     label: 'Daily dares',       base: econ.kBaseChallengeDone },
];
export const ACTION_COUNT = CATALOG.length;

export function actionInfo(a) { return CATALOG[a]; }
export function actionKey(a) { return CATALOG[a].key; }
export function actionForKey(key) {
  for (const ai of CATALOG) if (ai.key === key) return ai.id;
  return -1;
}

// f(n) = 1 + (kMaxMult-1) * n^P / (n^P + kHalf^P). Super-linear for small n (grows like
// (n/kHalf)^P), saturating toward kMaxMult (the soft cap). n<=0 -> the identity 1.0.
// Mirrors native cyclo::game::codeEditMultiplier EXACTLY.
export function codeEditMultiplier(n) {
  if (n <= 0) return 1.0;
  const np = Math.pow(n, econ.kCurveP);
  const hp = Math.pow(econ.kHalf, econ.kCurveP);
  return 1.0 + (econ.kMaxMult - 1.0) * (np / (np + hp));
}

// 1.0 at streak 0 or 1; +kStreakStep per consecutive day beyond the first, capped low.
// Mirrors native cyclo::game::streakMultiplier EXACTLY.
export function streakMultiplier(streak) {
  const days = Math.min(Math.max(streak - 1, 0), econ.kStreakDayCap);
  return 1.0 + econ.kStreakStep * days;
}

// The running Maker Score: totals, the current session, the daily streak, per-action stats.
// A faithful port of cyclo::game::MakerScore.
export class MakerScore {
  constructor() {
    this.total_ = 0;          // cumulative lifetime score (persisted)
    this.bestSession_ = 0;    // best single-session score ever (persisted)
    this.session_ = 0;        // this session's score (ephemeral)
    this.streak_ = 0;         // consecutive days making (persisted)
    this.lastActiveDay_ = -1; // day index of the last earn (persisted; drives the streak)
    this.codeEdits_ = 0;      // code edits THIS session (ephemeral; drives the curve)
    this.sessionDay_ = -1;    // the day passed to beginSession (ephemeral)
    this.dayCounted_ = false; // has the streak been reconciled this session? (ephemeral)
    this.medalStrikes_ = 0;   // how many medal bonuses ever awarded (persisted)
    this.medalBonusPoints_ = 0;
    this.points_ = new Array(ACTION_COUNT).fill(0); // lifetime points per action (persisted)
    this.counts_ = new Array(ACTION_COUNT).fill(0); // lifetime count per action  (persisted)
  }

  // Start a session (call at app launch). Resets the ephemeral session score + code-edit count.
  // dayIndex advances the daily streak on the first earn of a new day; pass negative to skip.
  beginSession(dayIndex) {
    this.session_ = 0;
    this.codeEdits_ = 0;
    this.sessionDay_ = dayIndex;
    this.dayCounted_ = false;
  }

  // Reconcile the daily streak on the FIRST earn of a session (so the streak only advances when
  // the maker actually MAKES something, not merely by launching). Duolingo-style.
  countDayIfNeeded_() {
    if (this.dayCounted_) return;
    this.dayCounted_ = true;
    const day = this.sessionDay_;
    if (day < 0) return; // no day info — leave the streak as loaded

    if (this.lastActiveDay_ < 0) this.streak_ = 1;                          // first ever earn
    else if (day === this.lastActiveDay_) this.streak_ = Math.max(this.streak_, 1); // same day
    else if (day === this.lastActiveDay_ + 1) this.streak_ += 1;            // consecutive day
    else if (day > this.lastActiveDay_ + 1) this.streak_ = 1;               // missed a day — reset
    // day < lastActiveDay_ (clock rolled back): leave the streak untouched.

    if (day > this.lastActiveDay_) this.lastActiveDay_ = day;
  }

  addPoints_(idx, earned) {
    this.total_ += earned;
    this.session_ += earned;
    this.points_[idx] += earned;
    this.counts_[idx] += 1;
    if (this.session_ > this.bestSession_) this.bestSession_ = this.session_;
  }

  // Award one making action. Returns the points earned (for the "+N" pop feedback). Code edits
  // multiply by the session curve; every action scales by the streak bonus. Never returns < 1.
  award(a) {
    this.countDayIfNeeded_();
    let pts = CATALOG[a].base;
    if (a === Action.CodeEdit) {
      ++this.codeEdits_;                          // the ordinal of THIS edit in the session
      pts *= codeEditMultiplier(this.codeEdits_); // the super-linear, soft-capped premium
    }
    pts *= streakMultiplier(this.streak_);        // mild global daily-streak bonus
    let earned = Math.round(pts);                 // native std::llround (== round-half-up for +ve)
    if (earned < 1) earned = 1;                   // every making action earns at least 1
    this.addPoints_(a, earned);
    return earned;
  }

  // A Maker Medal was struck — add the chunky one-off bonus. Returns the points added.
  awardMedalStrike() {
    this.countDayIfNeeded_();
    const earned = econ.kMedalBonus;              // flat + chunky (legible, not multiplied)
    this.total_ += earned;
    this.session_ += earned;
    this.medalStrikes_ += 1;
    this.medalBonusPoints_ += earned;
    if (this.session_ > this.bestSession_) this.bestSession_ = this.session_;
    return earned;
  }

  // ---- readouts ----
  total() { return this.total_; }
  sessionScore() { return this.session_; }
  bestSession() { return this.bestSession_; }
  streak() { return this.streak_; }
  codeEditsThisSession() { return this.codeEdits_; }
  medalStrikes() { return this.medalStrikes_; }
  medalBonusPoints() { return this.medalBonusPoints_; }
  // The multiplier the NEXT code edit of this session would earn (for a live "x3.4" HUD read).
  nextCodeMultiplier() { return codeEditMultiplier(this.codeEdits_ + 1); }

  actionPoints(a) { return this.points_[a]; }
  actionCount(a) { return this.counts_[a]; }

  // ---- persistence — a byte-compatible `key=value` line list (parity with native serialize) ----
  // The session score + code-edit count are EPHEMERAL and never persisted (they reset each launch).
  serialize() {
    let out = '';
    out += 'total=' + this.total_ + '\n';
    out += 'best=' + this.bestSession_ + '\n';
    out += 'streak=' + this.streak_ + '\n';
    out += 'lastday=' + this.lastActiveDay_ + '\n';
    out += 'medal_strikes=' + this.medalStrikes_ + '\n';
    out += 'medal_points=' + this.medalBonusPoints_ + '\n';
    for (const ai of CATALOG)
      out += 'a.' + ai.key + '=' + this.points_[ai.id] + '/' + this.counts_[ai.id] + '\n';
    return out;
  }

  // Replace state from serialized text. Tolerant: ignores blank lines, trims, skips unknown keys
  // (forward-compatible). Mirrors native deserialize; the ephemeral session state stays reset.
  deserialize(text) {
    this.total_ = 0; this.bestSession_ = 0; this.streak_ = 0; this.lastActiveDay_ = -1;
    this.medalStrikes_ = 0; this.medalBonusPoints_ = 0;
    this.points_.fill(0); this.counts_.fill(0);
    if (typeof text !== 'string') return;

    for (const rawLine of text.split('\n')) {
      const eq = rawLine.indexOf('=');
      if (eq < 0) continue;
      const key = rawLine.slice(0, eq).trim();
      const val = rawLine.slice(eq + 1).trim();
      if (!key) continue;
      try {
        if (key === 'total') this.total_ = parseIntSafe(val);
        else if (key === 'best') this.bestSession_ = parseIntSafe(val);
        else if (key === 'streak') this.streak_ = parseIntSafe(val);
        else if (key === 'lastday') this.lastActiveDay_ = parseIntSafe(val);
        else if (key === 'medal_strikes') this.medalStrikes_ = parseIntSafe(val);
        else if (key === 'medal_points') this.medalBonusPoints_ = parseIntSafe(val);
        else if (key.startsWith('a.')) {
          const a = actionForKey(key.slice(2));
          if (a >= 0) {
            const slash = val.indexOf('/');
            const p = slash < 0 ? val : val.slice(0, slash);
            const c = slash < 0 ? '0' : val.slice(slash + 1);
            this.points_[a] = parseIntSafe(p.trim());
            this.counts_[a] = parseIntSafe(c.trim());
          }
        }
        // unknown keys are ignored (forward-compatible)
      } catch (_) { /* a malformed number on one line never corrupts the rest of the load */ }
    }
  }
}

function parseIntSafe(s) {
  const n = parseInt(s, 10);
  return Number.isFinite(n) ? n : 0;
}

// The day number (days since the Unix epoch) driving the daily streak — matches native
// MainComponent::todayIndex (UTC-day granularity; no timezone handling needed for a streak).
export function todayIndex() {
  return Math.floor(Date.now() / 86400000);
}
