// ===========================================================================
//  Cyclo language support for CodeMirror 6 — syntax highlighting + inline error
//  underlines, at parity with the native JUCE editor (CycloTokeniser + CodeErrorEditor).
//
//  TWO pieces, both driven by the SHARED C++ core (never a hand-maintained JS copy):
//
//  1. SYNTAX HIGHLIGHTING. A StreamLanguage tokeniser that mirrors native CycloTokeniser
//     (strings, numbers, comments, `## NAME` headers, operators, identifiers) but colours
//     identifiers by CATEGORY. The categories are DERIVED FROM THE CORE Reference via the
//     WASM bridge (`Module.languageTokens()` -> languageReference()), the single source of
//     truth the compiler is kept in sync with (test_reference.cpp) — so the highlighter can
//     never drift from what the language accepts. Themed to the LOCKED phosphor-LCD palette
//     (the exact native col:: tokens: amber strings, cyan numbers, phosphor-green methods).
//     StreamLanguage relexes incrementally (line-resumable, viewport-only) so it stays cheap
//     on mobile — the whole doc is never re-tokenised per keystroke.
//
//  2. INLINE ERROR UNDERLINES. A decoration StateField that draws a red wavy squiggle under
//     the offending span + floats the compiler's message at the line end — the web twin of
//     native CodeErrorEditor. The spans come from the REAL core diagnostic position
//     (`Module.diagnoseDoc()` -> the per-section Diagnostic {offset,length,message} mapped to
//     document coordinates, byte-identical to native MainComponent::showLayerErrors). Pushed
//     imperatively via setCycloDiagnostics() as the user types (debounced by the caller) and
//     mapped through edits so it stays glued to the glyphs; cleared when the doc compiles clean.
// ===========================================================================

import { StreamLanguage, HighlightStyle, syntaxHighlighting } from '@codemirror/language';
import { tags as t, Tag } from '@lezer/highlight';
import { StateField, StateEffect, Compartment } from '@codemirror/state';
import { EditorView, Decoration, WidgetType } from '@codemirror/view';

// ---------------------------------------------------------------------------
//  1. SYNTAX HIGHLIGHTING
// ---------------------------------------------------------------------------

// Custom highlight tags for the three Cyclo-specific identifier categories; the rest reuse
// the standard lezer tags. Every name the tokeniser returns is mapped here (tokenTable), so
// StreamLanguage never falls back to an unstyled token.
const sourceTag = Tag.define();
const transformTag = Tag.define();
const signalTag = Tag.define();

const tokenTable = {
  comment: t.lineComment,
  string: t.string,
  number: t.number,
  heading: t.heading,
  operator: t.operator,
  keyword: t.keyword,
  source: sourceTag,
  transform: transformTag,
  signal: signalTag,
};

// The phosphor-LCD palette — the exact native col:: tokens (src/app/laf/Tokens.h):
//   amber #e0b45c strings · cyan #58c4e0 numbers · phosphor #4ade80 methods · red #ff4d45 errors
//   textDim #84948d comments · operator violet #9d7bff (native CycloTokeniser Operator colour).
// The three semantic buckets stay inside that family: the s() source is the brightest mint (the
// star of every line), transforms the signal green, signals a calmer teal-green, keywords a
// lighter sibling of the operator violet — distinguishable but coherent on the dark screen.
const cycloHighlightStyle = HighlightStyle.define([
  { tag: t.lineComment, color: '#84948d', fontStyle: 'italic' },
  { tag: t.string,      color: '#e0b45c' },
  { tag: t.number,      color: '#58c4e0' },
  { tag: t.heading,     color: '#8bffc6', fontWeight: '700' },
  { tag: t.operator,    color: '#9d7bff' },
  { tag: t.keyword,     color: '#c9a6ff', fontWeight: '700' },
  { tag: sourceTag,     color: '#eafff4', fontWeight: '700' },
  { tag: transformTag,  color: '#4ade80' },
  { tag: signalTag,     color: '#5fd0a8' },
]);

// The empty classifier (before the WASM core has handed over its Reference-derived categories):
// everything is still lexed (strings/numbers/comments/headers/operators colour immediately), only
// identifier CATEGORY colouring waits for the reconfigure. Keeps the editor usable during boot.
const EMPTY_CLASSES = { sources: new Set(), transforms: new Set(), signals: new Set(), keywords: new Set() };

// The tokeniser — a faithful port of native CycloTokeniser::readNextToken.
function makeCycloStreamLanguage(classes) {
  const c = classes || EMPTY_CLASSES;
  return StreamLanguage.define({
    name: 'cyclo',
    tokenTable,
    startState() { return {}; },
    token(stream) {
      if (stream.eatSpace()) return null;
      const ch = stream.peek();

      // `#...` to end of line -> section header (`## NAME`) — native Header
      if (ch === '#') { stream.skipToEnd(); return 'heading'; }

      // `//` line comment, else a lone `/` is an operator
      if (ch === '/') {
        stream.next();
        if (stream.peek() === '/') { stream.skipToEnd(); return 'comment'; }
        return 'operator';
      }

      // "quoted string" — the mini-notation pattern
      if (ch === '"') {
        stream.next();
        let q;
        while ((q = stream.next()) != null) { if (q === '"') break; }
        return 'string';
      }

      // number (incl. decimals) — a leading digit
      if (ch >= '0' && ch <= '9') { stream.match(/^[0-9.]+/); return 'number'; }

      // `.` — a decimal `.5`, else the method-access dot operator
      if (ch === '.') {
        const nxt = stream.string.charAt(stream.pos + 1);
        if (nxt >= '0' && nxt <= '9') { stream.match(/^\.[0-9.]*/); return 'number'; }
        stream.next();
        return 'operator';
      }

      // identifier: classify by CATEGORY (derived from the core Reference)
      if (/[A-Za-z_]/.test(ch)) {
        const m = stream.match(/^[A-Za-z_][A-Za-z0-9_]*/);
        const id = m ? m[0] : (stream.next(), ch);
        if (c.keywords.has(id)) return 'keyword';
        if (c.sources.has(id)) return 'source';
        if (c.transforms.has(id)) return 'transform';
        if (c.signals.has(id)) return 'signal';
        return null;                       // an unknown word (e.g. a sound name) stays default ink
      }

      // punctuation / operators of the language (`.` handled above)
      if ('~*<>[],:()@+-/'.indexOf(ch) >= 0) { stream.next(); return 'operator'; }

      stream.next();
      return null;
    },
  });
}

// A Compartment so main.js can reconfigure the highlighter once the WASM core has loaded and
// handed over the Reference-derived categories (the editor is created before the WASM module).
export const cycloLangCompartment = new Compartment();

// The full highlighter extension for a given classifier — the language + its highlight style.
export function cycloHighlightExtension(classes) {
  return [makeCycloStreamLanguage(classes), syntaxHighlighting(cycloHighlightStyle)];
}

// ---------------------------------------------------------------------------
//  2. INLINE ERROR UNDERLINES
// ---------------------------------------------------------------------------

// Push a fresh set of diagnostics (from Module.diagnoseDoc()): [{start,length,message}] in
// document character coordinates. An empty array clears the underlines.
const setCycloDiagsEffect = StateEffect.define();

// The floating message widget — the web twin of native CodeErrorEditor's right-aligned pill.
class ErrMsgWidget extends WidgetType {
  constructor(msg) { super(); this.msg = msg; }
  eq(other) { return other.msg === this.msg; }
  toDOM() {
    const s = document.createElement('span');
    s.className = 'cm-cyclo-errmsg';
    s.textContent = '⚠ ' + this.msg;   // ⚠ message
    return s;
  }
  ignoreEvent() { return true; }
}

function buildDiagDeco(state, marks) {
  const doc = state.doc;
  const len = doc.length;
  const ranges = [];
  const labelledLines = new Set();          // one message per line, like native
  for (const mk of (marks || [])) {
    let from = Math.max(0, Math.min(len, mk.start | 0));
    let to = Math.min(len, from + Math.max(1, mk.length | 0));
    if (to <= from) { if (from > 0) from -= 1; else to = Math.min(len, from + 1); }
    if (to <= from) continue;               // empty document — nothing to mark
    ranges.push(
      Decoration.mark({
        class: 'cm-cyclo-error',
        attributes: { title: mk.message },  // hover tooltip (desktop bonus; message also floats)
      }).range(from, to)
    );
    const line = doc.lineAt(from);
    if (!labelledLines.has(line.number)) {
      labelledLines.add(line.number);
      ranges.push(
        Decoration.widget({ widget: new ErrMsgWidget(mk.message), side: 1 }).range(line.to)
      );
    }
  }
  return Decoration.set(ranges, true);      // true = let CM sort the mixed mark/widget ranges
}

const cycloDiagField = StateField.define({
  create() { return Decoration.none; },
  update(deco, tr) {
    let next = deco.map(tr.changes);        // keep marks glued to the glyphs through edits
    for (const e of tr.effects) if (e.is(setCycloDiagsEffect)) next = buildDiagDeco(tr.state, e.value);
    return next;
  },
  provide: (f) => EditorView.decorations.from(f),
});

const cycloDiagTheme = EditorView.theme({
  '.cm-cyclo-error': {
    textDecoration: 'underline wavy #ff4d45',
    textDecorationSkipInk: 'none',
    textUnderlineOffset: '3px',
  },
  '.cm-cyclo-errmsg': {
    color: '#ff8079',
    fontFamily: 'var(--mono)',
    fontSize: '11px',
    marginLeft: '14px',
    padding: '1px 7px',
    borderRadius: '4px',
    background: 'rgba(255,77,69,.14)',
    whiteSpace: 'nowrap',
    verticalAlign: 'baseline',
  },
}, { dark: true });

// The inline-diagnostics extension (the decoration field + its phosphor-red theme).
export const cycloDiagnostics = [cycloDiagField, cycloDiagTheme];

// Imperatively set the editor's diagnostics from a marks array (call after compile, debounced).
export function setCycloDiagnostics(view, marks) {
  if (view) view.dispatch({ effects: setCycloDiagsEffect.of(marks || []) });
}
