// call-name -> the descriptor that owns it (filter owns lpf/hpf/bpf)
export const FX_CALL_NAMES = (() => {
  const m = {};
  for (const d of Object.values(FX_DESCRIPTORS)) {
    if (d.variants) for (const v of d.variants) m[v] = d;
    else m[d.id] = d;
  }
  return m;
})();

const clampf = (x, a = 0, b = 1) => Math.max(a, Math.min(b, x));

// normalized 0..1 <-> the param's real value (linear, or log for a cutoff).
export function paramNorm(p, value) {
  if (p.log) return clampf(Math.log(Math.max(p.min, value) / p.min) / Math.log(p.max / p.min));
  const min = p.min ?? 0, max = p.max ?? 1;
  return clampf((value - min) / (max - min));
}
export function paramDenorm(p, t) {
  t = clampf(t);
  if (p.log) return p.min * Math.pow(p.max / p.min, t);
  const min = p.min ?? 0, max = p.max ?? 1;
  return min + t * (max - min);
}
export function paramFormat(p, value) {
  if (p.int) return String(Math.round(value));
  return Number(value).toFixed(p.fmt ?? 2);
}

// ---- find the effect call under a document offset ------------------------------
// Scans for `.<fxname>(` calls with a balanced-paren body and returns the one whose
// span [callStart .. callEnd) contains `offset` (callStart is the '.'; callEnd is one
// past the ')'). Prefers the tightest span when calls nest. Returns null if none.
export function findEffectCall(doc, offset) {
  const re = /\.([A-Za-z_][A-Za-z0-9_]*)\s*\(/g;
  let best = null, m;
  while ((m = re.exec(doc)) !== null) {
    const name = m[1];
    const desc = FX_CALL_NAMES[name];
    if (!desc) continue;
    // find the matching ')'
    let depth = 0, j = m.index + m[0].length - 1, close = -1;
    for (; j < doc.length; j++) {
      const c = doc[j];
      if (c === '(') depth++;
      else if (c === ')') { if (--depth === 0) { close = j; break; } }
    }
    if (close < 0) continue;
    const callStart = m.index, callEnd = close + 1;
    // hit test: inside the whole call span, OR right on the name token
    if (offset >= callStart && offset <= callEnd) {
      const span = callEnd - callStart;
      if (!best || span < best.span)
        best = { descriptor: desc, callName: name, callStart, callEnd, span,
                 argStr: doc.slice(m.index + m[0].length, close) };
    }
  }
  if (!best) return null;
  const { span, ...out } = best;
  return out;
}

// Split an arg list on TOP-LEVEL commas only (respect nested () and "" '' strings).
function splitTopLevel(s) {
  const out = []; let depth = 0, cur = '', q = 0;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (q) { cur += c; if (c === q) q = 0; continue; }
    if (c === '"' || c === "'") { q = c; cur += c; continue; }
    if (c === '(') depth++;
    else if (c === ')') depth--;
    if (c === ',' && depth === 0) { out.push(cur); cur = ''; }
    else cur += c;
  }
  if (cur.trim().length || out.length) out.push(cur);
  return out;
}

// Parse an arg list into per-param state, mirroring the native readClause: named args
// (`mix: .5`) win; bare args fill positionally. A param the doc didn't give keeps its
// default (untouched). A non-numeric arg (e.g. `hz: sine.slow(4)…`) is kept RAW so a
// drag on a *different* param never clobbers the automation — only a dragged param is
// rewritten to a number. Returns [{ key, value, norm, raw, touched }] aligned to params.
export function parseArgs(descriptor, argStr) {
  const toks = splitTopLevel(argStr || '');
  const byName = {}; const positional = [];
  for (let t of toks) {
    t = t.trim(); if (!t) { positional.push(null); continue; }
    const colon = topLevelColon(t);
    if (colon >= 0) byName[t.slice(0, colon).trim()] = t.slice(colon + 1).trim();
    else positional.push(t);
  }
  let pos = 0;
  return descriptor.params.map((p) => {
    let rawTok = null;
    if (p.key in byName) rawTok = byName[p.key];
    else { rawTok = positional[pos] ?? null; pos++; }
    const st = { key: p.key, value: p.def, norm: paramNorm(p, p.def), raw: null, touched: false };
    if (rawTok != null) {
      const num = parseFloat(rawTok);
      if (isFinite(num) && /^[-+]?[0-9.]+$/.test(rawTok)) {
        st.value = num; st.norm = paramNorm(p, num);
      } else {
        st.raw = rawTok;   // a non-numeric expression — preserve verbatim unless dragged
      }
    }
    return st;
  });
}
function topLevelColon(t) {
  let depth = 0, q = 0;
  for (let i = 0; i < t.length; i++) {
    const c = t[i];
    if (q) { if (c === q) q = 0; continue; }
    if (c === '"' || c === "'") { q = c; continue; }
    if (c === '(') depth++;
    else if (c === ')') depth--;
    else if (c === ':' && depth === 0) return i;
  }
  return -1;
}

// Build the clause text `.name(k: v, …)` from param state, faithful to each native
// view's clause(): ALWAYS named args, native number format. Touched params emit their
// number; untouched params re-emit their original RAW expression when they had one,
// else the (formatted) default — so an untouched `.lpf(sine…)` keeps its automation.
export function buildClause(descriptor, callName, states) {
  const args = descriptor.params.map((p, i) => {
    const st = states[i];
    const val = (!st.touched && st.raw != null) ? st.raw : paramFormat(p, st.value);
    return `${p.key}: ${val}`;
  });
  return `.${callName}(${args.join(', ')})`;
}

// Splice a fresh clause into the document in place of the call at [callStart,callEnd),
// preserving everything else byte-for-byte. Returns { doc, callEnd } (the new end so the
// caller can keep editing the same call as its length changes).
export function rewriteCall(doc, callStart, callEnd, clause) {
  return { doc: doc.slice(0, callStart) + clause + doc.slice(callEnd), callEnd: callStart + clause.length };
}

// =============================================================================
//  DOM editor (browser only). Renders a design-bar overlay bound to one call.
//  `opts`: { host, doc, call (from findEffectCall), onChange(newDoc), onClose }.
//  onChange fires on every drag with the FULL rewritten document; the app dispatches
//  it into CodeMirror + hot-swaps the engine so the change is heard immediately.
// =============================================================================
export function createFxEditor(opts) {
  const { host } = opts;
  const desc = opts.call.descriptor;
  let callStart = opts.call.callStart;
  let callEnd = opts.call.callEnd;
  let callName = opts.call.callName;
  let states = parseArgs(desc, opts.call.argStr);

  const scrim = el('div', 'fx-scrim');
  const card = el('div', 'fx-card');
  card.style.setProperty('--fx', desc.color);
  scrim.appendChild(card);

  // header: colour dot + title + subtitle + close
  const head = el('div', 'fx-head');
  const dot = el('span', 'fx-dot');
  const titles = el('div', 'fx-titles');
  const h = el('div', 'fx-title'); h.textContent = desc.title;
  const s = el('div', 'fx-sub'); s.textContent = desc.sub;
  titles.appendChild(h); titles.appendChild(s);
  const close = el('button', 'fx-close'); close.type = 'button'; close.textContent = '×';
  close.setAttribute('aria-label', 'close');
  head.appendChild(dot); head.appendChild(titles); head.appendChild(close);
  card.appendChild(head);

  // the world motif canvas (the playful character of each native minigame)
  const canvas = document.createElement('canvas');
  canvas.className = 'fx-canvas';
  card.appendChild(canvas);

  // filter's LP/HP/BP variant pills
  let pills = null;
  if (desc.variants) {
    pills = el('div', 'fx-pills');
    desc.variants.forEach((v, i) => {
      const b = el('button', 'fx-pill'); b.type = 'button'; b.textContent = desc.variantLabels[i];
      b.classList.toggle('on', v === callName);
      // click = the universal activation (mouse + touch + keyboard Enter/Space on a <button>)
      b.addEventListener('click', (e) => { e.preventDefault(); setVariant(v); });
      pills.appendChild(b);
    });
    card.appendChild(pills);
  }

  // one drag-row fader per param (big touch target — the whole row drags)
  const rowsWrap = el('div', 'fx-rows');
  const rows = desc.params.map((p, i) => makeRow(p, i));
  rows.forEach((r) => rowsWrap.appendChild(r.el));
  card.appendChild(rowsWrap);

  // the coin readout: the live clause text this editor writes
  const coin = el('div', 'fx-coin');
  card.appendChild(coin);

  // a visible affordance hint: every input works (never hover-only), stated plainly
  const hint = el('div', 'fx-hint');
  hint.textContent = 'drag · scroll · arrow keys — pull away to fine-tune';
  card.appendChild(hint);

  host.appendChild(scrim);

  let raf = 0; const t0 = performance.now();   // declared before startAnim() runs (no TDZ)

  // Open/close/scrim/Escape all come from the ONE shared overlay manager (overlay.js): header ×,
  // release-close scrim-tap (press-vs-release guarded), and the central Escape stack. No bespoke
  // wiring here anymore.
  const overlay = registerOverlay(scrim, {
    panel: card,
    closeButtons: [close],
    label: desc.title,
    onClose: () => { teardown(); if (opts.onClose) opts.onClose(); },
  });
  overlay.open();

  refreshAll();
  startAnim();

  function makeRow(p, i) {
    const row = el('div', 'fx-row');
    row.setAttribute('role', 'slider');
    row.setAttribute('aria-label', p.label);
    row.setAttribute('aria-valuemin', '0'); row.setAttribute('aria-valuemax', '1');
    row.tabIndex = 0;
    // desktop hover affordance hint (a bonus; every action also has a non-hover path)
    row.title = 'drag · scroll · arrow keys — pull away while dragging for fine control';
    const label = el('span', 'fx-row-label'); label.textContent = p.label;
    const fill = el('div', 'fx-row-fill');
    const val = el('span', 'fx-row-val');
    row.appendChild(fill); row.appendChild(label); row.appendChild(val);
    // the effective normalized value (source of truth is `value` once touched)
    const getNorm = () => (states[i].touched ? paramNorm(p, states[i].value) : states[i].norm);
    const setNorm = (t) => {
      t = clampf(t);
      states[i].norm = t; states[i].value = paramDenorm(p, t); states[i].touched = true;
      row.setAttribute('aria-valuenow', paramFormat(p, states[i].value));
      row.setAttribute('aria-valuetext', paramFormat(p, states[i].value) + (p.unit === 'hz' ? ' hertz' : ''));
      emit();
    };
    // ONE input-agnostic gesture drives the row: pointer drag (mouse/touch/pen + capture) with an
    // occlusion-safe floating bubble + "pull away = finer", plus wheel + arrow-key fine-tune.
    attachValueDrag(row, {
      getNorm, setNorm,
      width: () => row.getBoundingClientRect().width,
      format: (t) => paramFormat(p, paramDenorm(p, t)) + (p.unit === 'hz' ? ' Hz' : '')
    });
    return { el: row, label, fill, val, param: p };
  }

  function setVariant(v) {
    if (v === callName) return;
    callName = v;
    if (pills) Array.from(pills.children).forEach((b, i) => b.classList.toggle('on', desc.variants[i] === v));
    emit();
  }

  function emit() {
    const clause = buildClause(desc, callName, states);
    const r = rewriteCall(opts.doc, callStart, callEnd, clause);
    opts.doc = r.doc; callEnd = r.callEnd;   // keep editing the same call as it grows/shrinks
    refreshAll();
    if (opts.onChange) opts.onChange(r.doc);
  }

  function refreshAll() {
    rows.forEach((r, i) => {
      const p = r.param, st = states[i];
      const t = st.touched ? paramNorm(p, st.value) : st.norm;
      r.fill.style.width = (t * 100).toFixed(1) + '%';
      if (!st.touched && st.raw != null) r.val.textContent = 'expr';
      else r.val.textContent = paramFormat(p, st.value) + (p.unit === 'hz' ? ' Hz' : '');
    });
    coin.textContent = buildClause(desc, callName, states);
  }

  // ---- the world motif: a small animated canvas echoing the native minigame ----
  function startAnim() { const loop = () => { drawWorld(); raf = requestAnimationFrame(loop); }; loop(); }
  function drawWorld() {
    const dpr = Math.min(2, window.devicePixelRatio || 1);
    const w = canvas.clientWidth, hgt = canvas.clientHeight;
    if (!w || !hgt) return;
    if (canvas.width !== w * dpr || canvas.height !== hgt * dpr) { canvas.width = w * dpr; canvas.height = hgt * dpr; }
    const ctx = canvas.getContext('2d');
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, w, hgt);
    const time = (performance.now() - t0) / 1000;
    const P = {}; desc.params.forEach((p, i) => { P[p.key] = states[i].touched ? paramNorm(p, states[i].value) : states[i].norm; });
    WORLDS[desc.world](ctx, w, hgt, P, desc.color, time, callName);
  }

  let torn = false;
  function teardown() {
    if (torn) return; torn = true;
    cancelAnimationFrame(raf);
    if (scrim.parentNode) scrim.parentNode.removeChild(scrim);
  }
  // Public close routes through the overlay manager (pops the stack + fires onClose->teardown), so
  // a programmatic close (reopen / test hook) stays in lockstep with a user × / scrim / Escape.
  const destroy = () => overlay.close();

  return {
    destroy,
    doc: () => opts.doc,
    // test hook: set a param by key to a normalized [0,1] value, as a drag would
    setParam: (key, norm) => {
      const i = desc.params.findIndex((p) => p.key === key);
      if (i < 0) return null;
      states[i].norm = clampf(norm); states[i].value = paramDenorm(desc.params[i], states[i].norm); states[i].touched = true;
      emit(); return opts.doc;
    },
    // test hook: the current real value of a param (for both-modality outcome assertions)
    valueOf: (key) => { const i = desc.params.findIndex((p) => p.key === key); return i < 0 ? null : states[i].value; },
    setVariant, clause: () => buildClause(desc, callName, states)
  };
}

function el(tag, cls) { const e = document.createElement(tag); if (cls) e.className = cls; return e; }

// =============================================================================
//  The per-effect canvas "worlds" — compact echoes of the native minigames.
//  Each: (ctx, w, h, P {param->0..1}, color, time, callName). Presentation only.
//  Exported so the FX RACK console (src/fxrack.js) can draw the SAME per-effect world
//  glyph on each chain tile (native FxRackView's tile motif) — one source of truth.
// =============================================================================
export const WORLDS = {
  // ROOM · GOO — a source blob that sheds drifting droplets (the reverb tail)
  reverb(ctx, w, h, P, col, t) {
    const cx = w / 2, cy = h / 2;
    const rw = (0.32 + P.width * 0.34) * w, rh = (0.30 + P.size * 0.36) * h;
    ctx.strokeStyle = withA(col, 0.5); ctx.lineWidth = 1.6;
    roundRect(ctx, cx - rw / 2, cy - rh / 2, rw, rh, 12); ctx.stroke();
    const n = 5;
    for (let i = 0; i < n; i++) {
      const ph = t * (0.5 + P.decay) + i * (Math.PI * 2 / n);
      const rad = (0.15 + ((Math.sin(ph) + 1) / 2) * (0.35 + P.mix * 0.4)) * Math.min(rw, rh);
      const a = (0.5 - P.damp * 0.3) * (0.4 + 0.6 * (0.5 + 0.5 * Math.cos(ph)));
      ctx.beginPath();
      ctx.arc(cx + Math.cos(i * 1.7 + t) * rw * 0.18, cy + Math.sin(i * 2.1 + t) * rh * 0.18, rad, 0, Math.PI * 2);
      ctx.fillStyle = withA(col, clampf(a) * 0.4); ctx.fill();
    }
    ctx.beginPath(); ctx.arc(cx, cy, 6 + P.predelay * 8, 0, Math.PI * 2);
    ctx.fillStyle = '#f0f8ff'; ctx.fill();
  },
  // TAPE ECHO — a hit and its fading, alternating ping-pong repeats along the tape
  delay(ctx, w, h, P, col, t) {
    const y = h / 2, x0 = w * 0.12, x1 = w * 0.9;
    ctx.strokeStyle = withA(col, 0.25); ctx.lineWidth = 1.4;
    line(ctx, x0, y, x1, y);
    const gap = (0.12 + P.time * 0.16) * w, sep = (2 + P.width * 16);
    let amp = 1, x = x0 + (t * (0.4 + (1 - P.time)) * w * 0.3) % gap;
    for (let e = 0; e < 7 && x < x1; e++) {
      const lane = P.pingpong > 0.1 ? (e % 2 ? 1 : -1) : 0;
      const rr = 3 + 7 * amp;
      ctx.beginPath(); ctx.arc(x, y + lane * sep, rr, 0, Math.PI * 2);
      ctx.fillStyle = withA(e === 0 ? lighten(col) : col, clampf(amp) * (0.35 + P.mix * 0.5)); ctx.fill();
      amp *= (0.35 + P.feedback * 0.6); x += gap;
    }
  },
  // PAINT · HEAT — a sine driven into a flat-topped (clipped) wave
  drive(ctx, w, h, P, col, t) {
    const y = h / 2, amp = h * 0.32, x0 = w * 0.08, ww = w * 0.84;
    ctx.strokeStyle = lighten(col); ctx.lineWidth = 2.4; ctx.beginPath();
    const drive = 1 + P.amt * 6;
    for (let i = 0; i <= 64; i++) {
      const u = i / 64;
      let sig = Math.sin(u * Math.PI * 4 + t * 2) * drive;
      sig = clampf(sig, -1, 1) * (0.5 + P.out * 0.6);
      const x = x0 + ww * u, yy = y - sig * amp;
      if (i === 0) ctx.moveTo(x, yy); else ctx.lineTo(x, yy);
    }
    ctx.stroke();
  },
  // PIXEL · SHATTER — a blob rendered as chunky posterised cells (bit + rate crush)
  crush(ctx, w, h, P, col) {
    const cx = w / 2, cy = h / 2, R = Math.min(w, h) * 0.34;
    const px = Math.max(6, Math.round(6 + P.rate * 22));
    const shades = clampf(Math.round(4 - P.amt * 3), 1, 4);
    for (let y = cy - R; y < cy + R; y += px) for (let x = cx - R; x < cx + R; x += px) {
      const d2 = (x + px / 2 - cx) ** 2 + (y + px / 2 - cy) ** 2;
      const f = (R * R) / (d2 + 1);
      if (f <= 0.9) continue;
      const step = clampf(Math.floor(clampf((f - 0.9) * 4) * shades), 0, shades - 1);
      const bt = shades > 1 ? step / (shades - 1) : 0.55;
      ctx.fillStyle = withA(col, 0.35 + bt * 0.6 * (0.5 + P.mix * 0.5));
      ctx.fillRect(x, y, px - 1, px - 1);
    }
  },
  // THE CURVE — the filter's frequency response, with a resonant peak at cutoff
  filter(ctx, w, h, P, col, t, callName) {
    const top = h * 0.16, bot = h * 0.82, fc = P.hz;
    const wob = Math.sin(t * (1 + P.res * 2)) * P.res * 0.06;
    const lvl = (u) => {
      let base;
      if (callName === 'lpf') base = 1 / (1 + Math.exp((u - fc) * 13));
      else if (callName === 'hpf') base = 1 / (1 + Math.exp((fc - u) * 13));
      else base = Math.exp(-((u - fc) ** 2) / 0.012);
      const peak = P.res * Math.exp(-((u - fc) ** 2) / 0.0016) * (0.7 + wob);
      return clampf(base + peak, 0, 1.35);
    };
    ctx.strokeStyle = lighten(col); ctx.lineWidth = 2.2; ctx.beginPath();
    const N = Math.max(2, Math.floor(w));
    for (let i = 0; i <= N; i++) {
      const u = i / N, x = u * w, y = bot - (lvl(u) / 1.35) * (bot - top);
      if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
    }
    ctx.stroke();
    const hx = fc * w, hy = bot - (lvl(fc) / 1.35) * (bot - top);
    ctx.fillStyle = withA(col, 0.35); line2(ctx, hx, top, hx, bot);
    ctx.beginPath(); ctx.arc(hx, hy, 6, 0, Math.PI * 2); ctx.fillStyle = lighten(col); ctx.fill();
  },
  // THE FOLDER — a beam folded between two mirrors; the bright ribbon IS the folder output waveform
  fold(ctx, w, h, P, col, t) {
    const cy = h / 2, half = h * 0.36, x0 = w * 0.06, ww = w * 0.88, N = Math.max(2, Math.floor(w));
    const foldAt = (raw) => Math.sin(raw * (1 + P.amt * 6) * Math.PI * 0.5);
    ctx.strokeStyle = withA(col, 0.28);       // the two mirrors
    line(ctx, x0, cy - half, x0 + ww, cy - half); line(ctx, x0, cy + half, x0 + ww, cy + half);
    ctx.strokeStyle = withA('#9fb0c0', 0.22 * (1 - P.mix)); ctx.lineWidth = 1.4; ctx.beginPath();
    for (let i = 0; i <= N; i++) { const u = i / N, raw = Math.sin(u * 4 * Math.PI + t); const y = cy - raw * half;
      i === 0 ? ctx.moveTo(x0 + u * ww, y) : ctx.lineTo(x0 + u * ww, y); }
    ctx.stroke();
    ctx.strokeStyle = lighten(col); ctx.lineWidth = 2.4; ctx.beginPath();
    for (let i = 0; i <= N; i++) { const u = i / N, raw = Math.sin(u * 4 * Math.PI + t);
      const wet = raw * (1 - P.mix) + foldAt(raw) * P.mix; const y = cy - wet * half;
      i === 0 ? ctx.moveTo(x0 + u * ww, y) : ctx.lineTo(x0 + u * ww, y); }
    ctx.stroke();
  },
  // RADIO — metallic bars warbling at the carrier + a tuning needle sweeping the dial
  ring(ctx, w, h, P, col, t) {
    const top = h * 0.10, sigH = h * 0.5, nb = 20, bw = w / nb, warble = 0.6 + 3.4 * P.hz;
    for (let i = 0; i < nb; i++) {
      const ph = t * warble * 3 + i * 0.7;
      const amp = (0.3 + 0.7 * (0.5 + 0.5 * Math.sin(ph))) * (0.3 + 0.7 * P.mix);
      const bh = sigH * clampf(amp, 0.05, 1);
      ctx.fillStyle = withA(col, 0.5 + 0.4 * P.mix);
      ctx.fillRect(w * 0.02 + i * bw + 1.5, top + sigH - bh, bw - 3, bh);
    }
    const baseY = h * 0.82, nx = w * 0.08 + P.hz * w * 0.84;
    ctx.strokeStyle = withA(col, 0.5); line(ctx, w * 0.06, baseY, w * 0.94, baseY);
    for (let i = 0; i <= 20; i++) { const x = w * 0.08 + (i / 20) * w * 0.84, mj = i % 5 === 0;
      ctx.strokeStyle = withA(col, mj ? 0.7 : 0.3); ctx.lineWidth = mj ? 1.4 : 1; line(ctx, x, baseY - (mj ? 8 : 4), x, baseY); }
    ctx.strokeStyle = 'rgba(255,255,255,0.9)'; ctx.lineWidth = 2.2; line(ctx, nx, h * 0.62, nx, baseY);
    ctx.fillStyle = lighten(col); ctx.beginPath(); ctx.arc(nx, h * 0.60, 5, 0, Math.PI * 2); ctx.fill();
  },
  // THE SWIRL — spectral bars with dark notches sweeping across (deeper = more mix/depth carve)
  phaser(ctx, w, h, P, col, t) {
    const baseY = h * 0.86, H = h * 0.72, N = 40, bw = w / N, M = 4;
    const sweep = (t * (0.05 + P.rate) * 0.4) % 1, notchW = 0.035 + 0.05 * P.depth;
    for (let i = 0; i < N; i++) {
      const bx = (i + 0.5) / N, base = 0.35 + 0.5 * Math.sin(bx * Math.PI);
      let atten = 1;
      for (let j = 0; j < M; j++) { let np = sweep + j / M; np -= Math.floor(np);
        let dd = Math.abs(bx - np); dd = Math.min(dd, 1 - dd); atten = Math.min(atten, 1 - P.depth * Math.exp(-(dd * dd) / (notchW * notchW))); }
      const bh = base * atten * H;
      ctx.fillStyle = withA(lighten(col), (0.3 + 0.55 * P.mix) * (0.35 + 0.65 * atten));
      ctx.fillRect(i * bw + 1, baseY - bh, bw - 2, bh);
    }
  },
  // PULSE — a scrolling EKG amplitude-envelope trace; deeper dips = more depth, faster = higher rate
  trem(ctx, w, h, P, col, t) {
    const top = h * 0.14, bot = h * 0.9, N = Math.max(2, Math.floor(w)), span = 1.2 + P.rate * 6;
    const gainAt = (p) => 1 - P.depth * 0.5 * (1 - Math.cos(p));
    const phase = t * (0.5 + P.rate * 8);
    ctx.strokeStyle = lighten(col); ctx.lineWidth = 2.2; ctx.beginPath();
    for (let i = 0; i <= N; i++) { const u = i / N;
      const p = phase - (1 - u) * span * 2 * Math.PI, g = gainAt(p), y = bot - g * (bot - top), x = u * w;
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y); }
    ctx.stroke();
    const yNow = bot - gainAt(phase) * (bot - top);
    ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.arc(w - 6, yNow, 4, 0, Math.PI * 2); ctx.fill();
  },
  // STEREO FIELD — a glowing dot flying L<->R between two speakers, trailing light
  autopan(ctx, w, h, P, col, t) {
    const cy = h / 2, cx = w / 2, reach = w * 0.5 - 34, s = Math.sin(t * (0.5 + P.rate * 8));
    const dotX = cx + s * P.depth * reach;
    ctx.strokeStyle = withA(col, 0.16); line(ctx, cx - reach, cy, cx + reach, cy);
    const spk = (x, glow) => { ctx.fillStyle = withA(col, 0.25 + 0.6 * glow); ctx.fillRect(x - 8, cy - 11, 16, 22);
      ctx.fillStyle = withA('#ffffff', 0.35 + 0.55 * glow); ctx.beginPath(); ctx.arc(x, cy, 4, 0, Math.PI * 2); ctx.fill(); };
    spk(cx - reach, clampf(-s * P.depth)); spk(cx + reach, clampf(s * P.depth));
    for (let i = 0; i < 8; i++) { const a = i / 8, tx = cx + Math.sin(t * (0.5 + P.rate * 8) - a * 0.5) * P.depth * reach;
      ctx.fillStyle = withA(col, 0.04 + 0.14 * a); const rr = 3 + 5 * a; ctx.beginPath(); ctx.arc(tx, cy, rr, 0, Math.PI * 2); ctx.fill(); }
    const dr = 10; ctx.fillStyle = lighten(col); ctx.beginPath(); ctx.arc(dotX, cy, dr, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = 'rgba(255,255,255,0.85)'; ctx.beginPath(); ctx.arc(dotX, cy, dr * 0.4, 0, Math.PI * 2); ctx.fill();
  },
  // THE SCULPTOR — a hit envelope: sharp attack spike then a decay to the sustain tail
  punch(ctx, w, h, P, col, t, name, hit) {
    const baseY = h * 0.84, H = h * 0.72, x0 = w * 0.04;
    const peakH = (0.32 + 0.66 * P.attack) * H, atkX = w * (0.06 + (1 - P.attack) * 0.14), peakY = baseY - peakH;
    const tailH = P.sustain * peakH * 0.72, sustX = w * 0.55, sustY = baseY - tailH;
    ctx.strokeStyle = withA(col, 0.14); line(ctx, 0, baseY, w, baseY);
    ctx.beginPath(); ctx.moveTo(x0, baseY); ctx.lineTo(atkX, peakY);
    ctx.quadraticCurveTo(atkX + w * 0.10, sustY, sustX, sustY); ctx.lineTo(w * 0.96, baseY - tailH * 0.4);
    const grad = ctx.createLinearGradient(0, peakY, 0, baseY);
    grad.addColorStop(0, withA(col, 0.3)); grad.addColorStop(1, withA(col, 0.03));
    ctx.save(); ctx.lineTo(w * 0.96, baseY); ctx.lineTo(x0, baseY); ctx.closePath(); ctx.fillStyle = grad; ctx.fill(); ctx.restore();
    ctx.strokeStyle = lighten(col); ctx.lineWidth = 2.4; ctx.beginPath(); ctx.moveTo(x0, baseY); ctx.lineTo(atkX, peakY);
    ctx.quadraticCurveTo(atkX + w * 0.10, sustY, sustX, sustY); ctx.lineTo(w * 0.96, baseY - tailH * 0.4); ctx.stroke();
    const dot = (x, y) => { ctx.fillStyle = lighten(col); ctx.beginPath(); ctx.arc(x, y, 5, 0, Math.PI * 2); ctx.fill(); };
    dot(atkX, peakY); dot(sustX, sustY);
  },
  // THE SEESAW — a beam tipping BRIGHT (left) vs WARM (right); a weight rolls to the low side
  tilt(ctx, w, h, P, col) {
    const cx = w / 2, pivotY = h * 0.62, beamW = w * 0.74, angle = (P.amount - 0.5) * 0.9;
    const cool = '#5ab0e0', warm = '#f0913f';
    ctx.save(); ctx.translate(cx, pivotY); ctx.rotate(angle);
    ctx.fillStyle = '#6b6f78'; roundRect(ctx, -beamW / 2, -6, beamW, 12, 6); ctx.fill();
    const ex = beamW * 0.42;
    const pan = (x, c) => { ctx.fillStyle = c; roundRect(ctx, x - 16, -22, 32, 12, 3); ctx.fill();
      ctx.strokeStyle = c; ctx.lineWidth = 1.6; line(ctx, x, -22, x, -32); };
    pan(-ex, cool); pan(ex, warm);
    const roll = clampf((P.amount - 0.5) * 3, -1, 1) * beamW * 0.34;
    ctx.fillStyle = lighten(col); ctx.beginPath(); ctx.arc(roll, -14, 8, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
    ctx.fillStyle = '#8a8f98'; ctx.beginPath(); ctx.moveTo(cx - 16, pivotY + 26); ctx.lineTo(cx + 16, pivotY + 26); ctx.lineTo(cx, pivotY + 2); ctx.closePath(); ctx.fill();
    ctx.fillStyle = withA(cool, P.amount < 0.5 ? 0.95 : 0.5); ctx.font = '11px monospace'; ctx.textAlign = 'left'; ctx.fillText('BRIGHT', 8, 16);
    ctx.fillStyle = withA(warm, P.amount > 0.5 ? 0.95 : 0.5); ctx.textAlign = 'right'; ctx.fillText('WARM', w - 8, 16); ctx.textAlign = 'left';
  },
  // THE CHOIR — several detuned wavy strands that fan apart (depth) and drift/beat against each other
  chorus(ctx, w, h, P, col, t) {
    const cy = h / 2, Nv = 5, spread = P.depth * h * 0.16, amp = h * 0.11, steps = Math.max(2, Math.floor(w));
    for (let v = 0; v < Nv; v++) {
      const rel = v - (Nv - 1) / 2, yoff = rel * spread, vph = t * (1 + rel * 0.1) * (1.2 + P.rate * 4) + rel * 0.7;
      const centre = v === (Nv - 1) / 2;
      ctx.strokeStyle = withA(centre ? lighten(col) : col, clampf((centre ? 0.55 : 0.3) * (0.4 + 0.6 * P.mix)));
      ctx.lineWidth = centre ? 2.4 : 1.6; ctx.beginPath();
      for (let i = 0; i <= steps; i++) { const u = i / steps, y = cy + yoff + Math.sin(u * 4 * Math.PI + vph) * amp;
        i === 0 ? ctx.moveTo(0, y) : ctx.lineTo(u * w, y); }
      ctx.stroke();
    }
  }
};

// ---- tiny canvas helpers -------------------------------------------------------
function withA(hex, a) {
  const c = hex.replace('#', '');
  const r = parseInt(c.slice(0, 2), 16), g = parseInt(c.slice(2, 4), 16), b = parseInt(c.slice(4, 6), 16);
  return `rgba(${r},${g},${b},${clampf(a)})`;
}
function lighten(hex) {
  const c = hex.replace('#', '');
  const r = Math.min(255, parseInt(c.slice(0, 2), 16) + 60);
  const g = Math.min(255, parseInt(c.slice(2, 4), 16) + 60);
  const b = Math.min(255, parseInt(c.slice(4, 6), 16) + 60);
  return `rgb(${r},${g},${b})`;
}
function roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y); ctx.arcTo(x + w, y, x + w, y + h, r); ctx.arcTo(x + w, y + h, x, y + h, r);
  ctx.arcTo(x, y + h, x, y, r); ctx.arcTo(x, y, x + w, y, r); ctx.closePath();
}
function line(ctx, x0, y0, x1, y1) { ctx.beginPath(); ctx.moveTo(x0, y0); ctx.lineTo(x1, y1); ctx.stroke(); }
function line2(ctx, x0, y0, x1, y1) { ctx.save(); ctx.strokeStyle = ctx.fillStyle; ctx.lineWidth = 1; line(ctx, x0, y0, x1, y1); ctx.restore(); }
