// ===========================================================================
//  cheatsheet.js — the discoverable KEYBOARD SHORTCUTS overlay (desktop).
//
//  Opened by pressing `?` (Shift+/). A design-bar dark-LCD "data screen" (the same phosphor
//  language as the language reference), listing every shortcut grouped by purpose, with the
//  modifier rendered platform-correct (⌘ on macOS, Ctrl elsewhere). This is a progressive
//  enhancement: mobile has no `?` key and never sees it, and every action it lists is also
//  reachable by pointer/touch — the sheet just makes the desktop keys discoverable.
//
//  The data is keymap.js SHORTCUT_GROUPS (the single source of truth for the bindings), so the
//  sheet can never drift from what actually fires. Input-agnostic close: the × button, a tap on
//  the dim scrim, or Esc.
// ===========================================================================
import { SHORTCUT_GROUPS, modLabel } from './keymap.js';
import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

// Render one key token as a phosphor keycap. 'Mod' expands to ⌘ / Ctrl for the platform.
function keycap(token, mac) {
  const k = document.createElement('kbd');
  k.className = 'cheat-key';
  k.textContent = token === 'Mod' ? modLabel(mac) : token;
  if (token === '…') k.classList.add('cheat-key-ellipsis');
  return k;
}

// Build the overlay once, hidden. `mac` picks the modifier glyph; `onClose` returns focus.
export function createCheatSheet({ host, mac, onClose }) {
  const scrim = document.createElement('div');
  scrim.className = 'cheat-scrim hidden';
  scrim.setAttribute('role', 'dialog');
  scrim.setAttribute('aria-modal', 'true');
  scrim.setAttribute('aria-label', 'keyboard shortcuts');

  const card = document.createElement('div');
  card.className = 'cheat-card';
  scrim.appendChild(card);

  // head: title + close
  const head = document.createElement('div');
  head.className = 'cheat-head';
  const titles = document.createElement('div');
  titles.className = 'cheat-titles';
  titles.innerHTML = '<div class="cheat-title">Keyboard shortcuts</div>' +
    '<div class="cheat-sub">DESKTOP — EVERY ACTION IS ALSO A TAP AWAY</div>';
  const closeBtn = document.createElement('button');
  closeBtn.type = 'button';
  closeBtn.className = 'cheat-close';
  closeBtn.setAttribute('aria-label', 'close');
  closeBtn.innerHTML = '&times;';
  head.appendChild(titles);
  head.appendChild(closeBtn);
  card.appendChild(head);

  // the grouped list
  const list = document.createElement('div');
  list.className = 'cheat-list';
  card.appendChild(list);

  for (const group of SHORTCUT_GROUPS) {
    const g = document.createElement('div');
    g.className = 'cheat-group';
    const gh = document.createElement('div');
    gh.className = 'cheat-grouphead';
    gh.textContent = group.title;
    g.appendChild(gh);
    for (const item of group.items) {
      const row = document.createElement('div');
      row.className = 'cheat-item';
      const keys = document.createElement('div');
      keys.className = 'cheat-keys';
      item.keys.forEach((tok, i) => {
        if (i > 0) { const plus = document.createElement('span'); plus.className = 'cheat-plus'; plus.textContent = '+'; keys.appendChild(plus); }
        keys.appendChild(keycap(tok, mac));
      });
      const desc = document.createElement('div');
      desc.className = 'cheat-desc';
      const lbl = document.createElement('span');
      lbl.className = 'cheat-label';
      lbl.textContent = item.label;
      desc.appendChild(lbl);
      if (item.note) {
        const note = document.createElement('span');
        note.className = 'cheat-note';
        note.textContent = item.note;
        desc.appendChild(note);
      }
      row.appendChild(keys);
      row.appendChild(desc);
      g.appendChild(row);
    }
    list.appendChild(g);
  }

  (host || document.body).appendChild(scrim);

  // Open/close/scrim/Escape via the ONE shared overlay manager (overlay.js): header ×, release-close
  // scrim-tap (press-vs-release guarded), the central Escape stack.
  const overlay = registerOverlay(scrim, {
    panel: card,
    closeButtons: [closeBtn],
    label: 'keyboard shortcuts',
    initialFocus: closeBtn,
    onClose: () => { if (onClose) onClose(); },
  });
  function show() { overlay.open(); }
  function hide() { overlay.close(); }
  function isOpen() { return overlay.isOpen(); }

  return {
    el: scrim,
    show, hide, isOpen,
    destroy: () => { try { scrim.remove(); } catch (e) {} },
  };
}
