// ===========================================================================
//  share.js — "every song is a link" (memory cyclo-platform-strategy).
//
//  A Cyclo song IS its `.cyclo` document text (the coin), so a whole song can ride
//  in a URL with ZERO server (honors cyclo-zero-hosting-cost): the link IS the data.
//  This module is the codec + a small samples-honesty analyzer. It is pure and
//  environment-agnostic (no `window`, no `btoa`, no `Buffer`) so the SAME code runs
//  in the browser bundle AND in Node (web/verify.js proves round-trip losslessness).
//
//  Scheme:  #s=<ver>.<base64url( deflate-raw( utf8(docText) ) )>
//    - ver is a tiny version tag ("1") so the format can evolve; decode rejects an
//      unknown version rather than mis-parsing it.
//    - deflate-raw via fflate (a solid, tiny, well-supported lib) — songs are small
//      text and compress well, landing comfortably under URL limits.
//    - base64url (RFC 4648 §5, no padding) so the payload is URL-hash safe as-is.
//  Round-trip is lossless: decodeSong(encodeSong(doc)) === doc, byte-for-byte.
// ===========================================================================
// fflate's deflateSync/inflateSync produce/consume a RAW DEFLATE stream (no zlib/gzip
// wrapper) — the smallest option, ideal for a URL. strToU8/strFromU8 do UTF-8.
import { deflateSync, inflateSync, strToU8, strFromU8 } from 'fflate';

export const SHARE_VERSION = '1';
export const HASH_KEY = 's';               // location.hash carries `#s=<payload>`

// URL-safe base64 alphabet (RFC 4648 §5). We emit WITHOUT padding ('=') and decode
// tolerantly (any '=' or standard +/ is still accepted), so links stay short + clean.
const B64 = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_';
let B64LUT = null;
function lut() {
  if (B64LUT) return B64LUT;
  B64LUT = Object.create(null);
  for (let i = 0; i < B64.length; i++) B64LUT[B64[i]] = i;
  B64LUT['+'] = 62; B64LUT['/'] = 63;      // accept standard base64 chars on decode too
  return B64LUT;
}

function bytesToB64url(bytes) {
  let out = '';
  const n = bytes.length;
  for (let i = 0; i < n; i += 3) {
    const b0 = bytes[i];
    const b1 = i + 1 < n ? bytes[i + 1] : 0;
    const b2 = i + 2 < n ? bytes[i + 2] : 0;
    out += B64[b0 >> 2];
    out += B64[((b0 & 3) << 4) | (b1 >> 4)];
    if (i + 1 < n) out += B64[((b1 & 15) << 2) | (b2 >> 6)];
    if (i + 2 < n) out += B64[b2 & 63];
  }
  return out;
}

function b64urlToBytes(str) {
  const L = lut();
  // strip padding + any stray whitespace a copy/paste may have introduced
  const s = str.replace(/[=\s]/g, '');
  const out = [];
  for (let i = 0; i < s.length; i += 4) {
    const c0 = L[s[i]], c1 = L[s[i + 1]];
    if (c0 === undefined || c1 === undefined) break;
    out.push((c0 << 2) | (c1 >> 4));
    const c2 = L[s[i + 2]];
    if (c2 === undefined) break;
    out.push(((c1 & 15) << 4) | (c2 >> 2));
    const c3 = L[s[i + 3]];
    if (c3 === undefined) break;
    out.push(((c2 & 3) << 6) | c3);
  }
  return new Uint8Array(out);
}

// Serialize a document to a hash payload string (the part after `#s=`).
export function encodeSong(text) {
  const bytes = strToU8(String(text));            // UTF-8
  const packed = deflateSync(bytes, { level: 9 }); // max compression; songs are tiny
  return SHARE_VERSION + '.' + bytesToB64url(packed);
}

// Inverse of encodeSong. Throws on an unknown version or corrupt payload.
export function decodeSong(payload) {
  if (!payload) throw new Error('empty share payload');
  const dot = payload.indexOf('.');
  const ver = dot >= 0 ? payload.slice(0, dot) : SHARE_VERSION;
  const body = dot >= 0 ? payload.slice(dot + 1) : payload;
  if (ver !== SHARE_VERSION) throw new Error('unsupported share version "' + ver + '"');
  const packed = b64urlToBytes(body);
  const bytes = inflateSync(packed);
  return strFromU8(bytes);                         // UTF-8
}

// Build the full shareable URL for a document, given the current page URL. Keeps the
// origin + path (+ any query) and replaces only the hash — so the link points back at
// THIS deployment (works on static GitHub Pages, no server).
export function buildShareUrl(text, baseHref) {
  const payload = encodeSong(text);
  const base = String(baseHref || '').split('#')[0];
  return base + '#' + HASH_KEY + '=' + payload;
}

// Pull the share payload out of a location.hash string (e.g. "#s=1.abc" -> "1.abc").
// Returns null when the hash carries no song. Tolerates other `&`-joined hash params.
export function songPayloadFromHash(hash) {
  if (!hash) return null;
  const h = hash.charAt(0) === '#' ? hash.slice(1) : hash;
  for (const part of h.split('&')) {
    const eq = part.indexOf('=');
    if (eq < 0) continue;
    if (part.slice(0, eq) === HASH_KEY) return part.slice(eq + 1);
  }
  return null;
}

// ---- samples honesty (memory cyclo-platform-strategy) --------------------------------
// The link carries CODE (synth recipes, patterns) + built-in sound NAMES (which travel
// fine — the recipient's build synthesizes them). The one thing a link cannot carry is
// the user's OWN recorded audio. So before sharing we check whether the song references
// any sound that ISN'T a shareable built-in / synth-recipe voice, and surface an honest
// note rather than silently producing a link that plays wrong on the other end.
//
//   knownNames — the recipient-reproducible sound names (the engine's real bank names:
//                built-in synth kit + any `voice NAME =` recipes defined IN this doc).
// Returns { unknown: [names], sharesClean: bool }.
export function analyzeSong(text, knownNames) {
  const known = new Set((knownNames || []).map((n) => String(n).toLowerCase()));
  // voices/aliases DEFINED in the doc travel as text, so they're always reproducible.
  for (const m of String(text).matchAll(/^\s*voice\s+([A-Za-z_][A-Za-z0-9_]*)\s*=/gm)) known.add(m[1].toLowerCase());
  for (const m of String(text).matchAll(/^\s*([A-Za-z_][A-Za-z0-9_]*)\s*=/gm)) known.add(m[1].toLowerCase());
  // `def NAME(p1, p2) = ...` parameters are locals, not sound names — don't flag them.
  for (const m of String(text).matchAll(/^\s*def\s+[A-Za-z_][A-Za-z0-9_]*\s*\(([^)]*)\)/gm))
    for (const p of m[1].split(',')) { const pn = p.trim(); if (pn) known.add(pn.toLowerCase()); }

  const unknown = new Set();
  // scan every s("...") literal and pull the bare sound tokens out of the mini-notation
  for (const m of String(text).matchAll(/s\(\s*"([^"]*)"/g)) {
    for (const raw of m[1].split(/[\s,()<>\[\]*!@/.]+/)) {
      const tok = raw.trim();
      if (!tok || tok === '-' || tok === '~') continue;   // rest
      if (/^[0-9]+$/.test(tok)) continue;                 // a count/index, not a name
      if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(tok)) continue; // not an identifier -> ignore
      if (!known.has(tok.toLowerCase())) unknown.add(tok);
    }
  }
  return { unknown: [...unknown], sharesClean: unknown.size === 0 };
}
