// ===========================================================================
//  history.js — LOCAL VERSION HISTORY on the web (the free rung of "git-for-music").
//
//  A FAITHFUL port of the native pure-logic model src/app/HistoryStore.h + UndoLabel.h:
//  a rolling shelf of document SNAPSHOTS (the code IS the state — text-only, so history is
//  nearly free) with the SAME capture policy:
//    - timed checkpoints ride the autosave tick, throttled to one per kMinGapMs (rapid edits
//      coalesce; the label names the changed section via changedSectionLabel);
//    - boundary captures (eval / save / doc-switch) always fire, unthrottled;
//    - identical-code captures are deduped, empty documents are never stored;
//    - the shelf is capped (oldest snapshots pruned) so storage stays bounded.
//  Restoring is safe: the browser snapshots the CURRENT state first, so a rewind is always
//  reversible (a navigable history, exactly like native HistoryBrowser).
//
//  PURE + DOM-FREE so it unit-tests in Node (web/verify.js asserts the capture/retention/
//  restore logic) and drives the web browser UI unchanged. Persistence is the caller's job
//  (main.js serializes the whole shelf into this build's OWN IndexedDB slot, like the
//  score/medals slots — text-only, so a full shelf is tiny). The native dev-box .history is
//  never touched.
//
//  Native cross-reference (do not drift): cyclo::ui::HistoryStore::{maybeCapture,capture,list,
//  relativeTime,kMinGapMs,kDefaultMax} + cyclo::ui::changedSectionLabel.
// ===========================================================================

// Timed checkpoints coalesce to one per this window; boundary captures ignore it (native kMinGapMs).
export const KMIN_GAP_MS = 120 * 1000;
// The shelf is capped (oldest pruned) so storage stays bounded (native kDefaultMax).
export const DEFAULT_MAX = 200;

// "just now" / "N min ago" / "N h ago" / "N days ago" — the row's time text (native relativeTime).
export function relativeTime(thenMs, nowMs) {
  const s = Math.max(0, Math.floor((nowMs - thenMs) / 1000));
  if (s < 90) return 'just now';
  if (s < 90 * 60) return Math.floor((s + 30) / 60) + ' min ago';
  if (s < 36 * 3600) return Math.floor((s + 1800) / 3600) + ' h ago';
  return Math.floor((s + 43200) / 86400) + ' days ago';
}

// The section name ("DRUMS") owning the first difference between two document texts, or
// "song" / "tempo" / "code" for changes in the globals above the first section. "" when they
// match. A faithful port of native cyclo::ui::changedSectionLabel (UndoLabel.h) — the VISIBLE
// UNDO helper that names what a step changed (an undo the user can't SEE is a usability failure).
export function changedSectionLabel(before, after) {
  if (before === after) return '';
  const a = String(before).split(/\r?\n/);
  const b = String(after).split(/\r?\n/);
  let i = 0;
  while (i < a.length && i < b.length && a[i] === b[i]) ++i;

  const lineAt = (lines, j) => (j < lines.length ? lines[j].replace(/^\s+/, '') : '');
  const la = lineAt(a, i), lb = lineAt(b, i);
  if (la.startsWith('## ')) return la.slice(3).trim();
  if (lb.startsWith('## ')) return lb.slice(3).trim();

  // otherwise the owning header is the nearest "## NAME" above the difference (part of the
  // common prefix, so either doc serves)
  for (let j = Math.min(i, a.length - 1); j >= 0; --j)
    if (a[j].replace(/^\s+/, '').startsWith('## ')) return a[j].replace(/^\s+/, '').slice(3).trim();

  // above the first section: a global line
  const g = la || lb;
  if (g.startsWith('song')) return 'song';
  if (g.startsWith('bpm')) return 'tempo';
  return 'code';
}

// Coerce a mix value to the stored shape { muted:[names], soloed:[names] } — tolerant of a missing
// or malformed value (a legacy snapshot, a bad blob) so history stays crash-proof. Names as-is
// (the caller lowercases on apply); duplicates/non-strings are dropped.
export function normalizeMix(mix) {
  const arr = (v) => (Array.isArray(v) ? v.filter((x) => typeof x === 'string' && x) : []);
  return { muted: arr(mix && mix.muted), soloed: arr(mix && mix.soloed) };
}

// The rolling shelf of snapshots (newest-first). A snapshot is:
//   { id, time, bpm, code, label, project, mix }
// where `code` is the whole document (the state — the coin), `id` is a stable, strictly
// increasing, chronological key.
export class HistoryStore {
  constructor(max = DEFAULT_MAX) {
    this.snaps = [];                     // newest-first
    this.max = Math.max(1, max | 0 || DEFAULT_MAX);
  }

  latest() { return this.snaps.length ? this.snaps[0] : null; }
  count() { return this.snaps.length; }
  list() { return this.snaps.slice(); }
  get(id) { return this.snaps.find((s) => s.id === id) || null; }
  clear() { this.snaps = []; }

  // Timed checkpoint (ride the autosave tick): capture only when the doc CHANGED since the newest
  // snapshot AND the throttle window has passed. Returns the new snapshot, or null (coalesced).
  // `mix` is the per-section mute/solo model ({muted:[],soloed:[]}) captured alongside the code —
  // native records mixState() in every history entry so a rewind restores the exact mix too.
  maybeCapture(code, bpm, project, nowMs, mix) {
    const last = this.latest();
    if (last && nowMs - last.time < KMIN_GAP_MS) return null;
    return this.capture(code, bpm, project, '', nowMs, mix);
  }

  // Boundary capture (eval / save / doc-switch): unthrottled, but still DEDUPED against the newest
  // snapshot and NEVER stores an empty document. An empty label auto-names the change ("changed
  // DRUMS") from the diff against the previous snapshot (native UndoLabel). Returns null if deduped.
  capture(code, bpm, project, label, nowMs, mix) {
    if (!code || !String(code).trim()) return null;     // empty documents are never stored
    const last = this.latest();
    if (last && last.code === code) return null;         // a no-change checkpoint is noise

    let lbl = label || '';
    if (!lbl) {
      const sec = last ? changedSectionLabel(last.code, code) : '';
      lbl = sec ? ('changed ' + sec) : 'checkpoint';
    }

    const snap = {
      id: this._nextId(nowMs),
      time: nowMs,
      bpm: Number(bpm) || 120,
      code: String(code),
      label: lbl,
      project: project || '',
      mix: normalizeMix(mix),            // per-snapshot mute/solo (native mixState per history entry)
    };
    this.snaps.unshift(snap);            // newest-first
    this._prune();
    return snap;
  }

  // A strictly-increasing, chronological id (a same-ms capture nudges past the newest — so name
  // order == time order, like native's zero-padded stamp filenames).
  _nextId(nowMs) {
    const top = this.snaps.length ? this.snaps[0].id : 0;
    return nowMs > top ? nowMs : top + 1;
  }

  _prune() { if (this.snaps.length > this.max) this.snaps.length = this.max; }   // drop the oldest (tail)

  // ---- persistence — a compact JSON of the whole shelf (text-only, so it stays tiny) ----
  serialize() { return JSON.stringify({ format: 1, snaps: this.snaps }); }

  // Replace the shelf from serialized text. Tolerant by design (mirrors the score/medals loaders):
  // a bad blob loads to an empty shelf rather than throwing; unknown/garbage entries are skipped;
  // entries are re-sorted newest-first and capped to `max` (forward-compatible).
  deserialize(text) {
    this.snaps = [];
    if (typeof text !== 'string' || !text.trim()) return;
    let obj;
    try { obj = JSON.parse(text); } catch (e) { return; }
    const arr = Array.isArray(obj) ? obj : (obj && Array.isArray(obj.snaps) ? obj.snaps : []);
    const out = [];
    for (const s of arr) {
      if (!s || typeof s.code !== 'string' || !s.code.trim()) continue;
      out.push({
        id: Number.isFinite(s.id) ? s.id : (Number(s.time) || 0),
        time: Number(s.time) || 0,
        bpm: Number(s.bpm) || 120,
        code: s.code,
        label: typeof s.label === 'string' && s.label ? s.label : 'checkpoint',
        project: typeof s.project === 'string' ? s.project : '',
        mix: normalizeMix(s.mix),          // tolerant: a legacy snapshot with no mix loads to empty
      });
    }
    out.sort((a, b) => b.id - a.id);      // newest-first
    if (out.length > this.max) out.length = this.max;
    this.snaps = out;
  }
}
