// ===========================================================================
//  Cyclo web — the shared SHEET/OVERLAY manager (the sheet-world twin of gesture.js).
//
//  Every sheet / overlay in the web build (there are ~17: FILES, sound picker, reference,
//  time-travel, the 13 FX editors, grain garden, record, cheat sheet, scoreboard, daily,
//  MORE overflow, name sheets, welcome, examples, …) MUST open/close through THIS ONE
//  helper, so the open/close/scrim/Escape mechanics are IDENTICAL everywhere. It is the
//  sheet analogue of gesture.js (which unified every value drag): dev speed is free, and
//  one solid helper pays off across every surface. See docs/web-interaction.md.
//
//  The ONE consistent contract this module owns:
//    - CLOSE AFFORDANCE: a header × in a consistent position is the canonical close (the
//      majority pattern); a footer Cancel/Done is kept ONLY where it is a real form action
//      (commit a name, abandon a recording), never as the sole way out.
//    - ESCAPE closes the TOP-MOST overlay, wired ONCE centrally through a STACK — so nested
//      / stacked sheets close in order (top first). There is exactly ONE Escape path in the
//      app (the keymap.js `escape` action calls closeTopOverlay()); no per-sheet listeners.
//    - SCRIM-TAP closes on RELEASE, not press: a press that starts inside the panel and
//      drags out to release on the scrim does NOT dismiss (the press-vs-release fix). Only a
//      press AND release that both land on the scrim itself closes it.
//    - FOCUS is moved into the panel on open and restored to the opener on close; the panel
//      is body-scroll-locked behind it; role="dialog" / aria-modal live here once.
//
//  Input-agnostic (docs/web-interaction.md): Escape (keyboard), scrim-tap (pointer/touch)
//  and a real focusable × <button> (pointer + keyboard Enter/Space) — a keyboard can ALWAYS
//  close a sheet, a fat fingertip can always tap the scrim or the ~44px ×.
//
//  The PURE overlay STACK (push/pop/top/depth) imports nothing and runs in Node, so
//  web/verify.js asserts the stack ordering + the top-of-stack close contract headlessly.
// ===========================================================================

// ---- the pure overlay stack (DOM-free, Node-testable) ----------------------------
// Models z-order: the last entry is the TOP-MOST overlay. Escape / closeTopOverlay act on it.
// An entry is an opaque token object ({ onEscape, close }); the stack never touches the DOM.
const _stack = [];

export function overlayDepth() { return _stack.length; }
export function overlayTop() { return _stack.length ? _stack[_stack.length - 1] : null; }
export function anyOverlayOpen() { return _stack.length > 0; }
export function overlayHas(entry) { return _stack.indexOf(entry) !== -1; }

// Subscribe to stack-depth changes. Fired (with the new depth) on every push/pop, so a host can
// react when the LAST modal closes — e.g. flush a celebration that was QUEUED because a sheet was
// up (P1-h: a celebration must never render beneath an open sheet; it plays when the sheet closes).
const _changeListeners = [];
export function onOverlayChange(cb) { if (typeof cb === 'function') _changeListeners.push(cb); }
function _notifyChange() { for (const cb of _changeListeners) { try { cb(_stack.length); } catch (_) {} } }

// Push an entry to the top. A re-open of an already-stacked entry moves it to the top (no dupes).
export function pushOverlay(entry) {
  const i = _stack.indexOf(entry);
  if (i !== -1) _stack.splice(i, 1);
  _stack.push(entry);
  _notifyChange();
  return _stack.length;
}

// Remove an entry from ANYWHERE in the stack (an inner sheet may close before an outer one).
export function popOverlay(entry) {
  const i = _stack.indexOf(entry);
  if (i === -1) return false;
  _stack.splice(i, 1);
  _notifyChange();
  return true;
}

// Close the TOP-MOST overlay (the ONE Escape target). An entry may intercept via onEscape()
// (returning true) to handle an internal sub-state first — e.g. the FX rack closes its add-
// picker before the rack, welcome steps back from examples to home. Returns true if it acted.
export function closeTopOverlay() {
  const top = overlayTop();
  if (!top) return false;
  if (top.onEscape && top.onEscape() === true) return true;
  if (top.close) top.close();
  return true;
}

// ---- body scroll-lock (browser only) --------------------------------------------
// One shared lock refcounted across stacked overlays: the background stops scrolling while any
// sheet is up, and scrolling returns only when the LAST overlay closes.
let _lockCount = 0;
function lockScroll() {
  if (typeof document === 'undefined') return;
  if (_lockCount++ === 0) document.body.classList.add('overlay-lock');
}
function unlockScroll() {
  if (typeof document === 'undefined') return;
  if (_lockCount > 0 && --_lockCount === 0) document.body.classList.remove('overlay-lock');
}

// ---- register a scrim as a managed overlay (browser only) ------------------------
//  scrim : the full-viewport dim layer (a `.sheet-scrim`/`.fx-scrim`/… element) whose direct
//          child is the panel/card. May already live in the DOM (index.html sheets) or be
//          freshly built (component overlays).
//  opts  :
//    panel        : the card element (defaults to scrim.firstElementChild) — focused on open.
//    closeButtons : [el,…] the header × (+ any real footer close) — each wired to close().
//    onOpen()     : after the sheet is shown + stacked.
//    onClose()    : after the sheet is hidden + unstacked (a module may re-focus the editor here).
//    onEscape()   : intercept Escape for an internal sub-state; return true if handled.
//    initialFocus : element (or ()=>element) to focus on open instead of the panel (e.g. an input).
//    label        : aria-label (only set if the scrim doesn't already carry one).
//    restoreFocus : false to skip restoring focus to the opener on close (default restores it).
//  Returns { el, open, close, isOpen, token }.
export function registerOverlay(scrim, opts = {}) {
  const panel = opts.panel || scrim.firstElementChild;
  if (!scrim.getAttribute('role')) scrim.setAttribute('role', 'dialog');
  if (!scrim.hasAttribute('aria-modal')) scrim.setAttribute('aria-modal', 'true');
  if (opts.label && !scrim.getAttribute('aria-label')) scrim.setAttribute('aria-label', opts.label);
  if (panel && !panel.hasAttribute('tabindex')) panel.tabIndex = -1;   // focusable on open, not tab-stop

  let opener = null;
  const entry = { onEscape: opts.onEscape || null, close: () => api.close() };
  const isOpen = () => !scrim.classList.contains('hidden');

  // SCRIM-TAP = release-close with the press-vs-release guard. Record whether the press landed on
  // the scrim itself; only close if the RELEASE also lands on the scrim. A press that begins inside
  // the panel (a drag on a fader/canvas that overshoots onto the scrim) never dismisses.
  let downOnScrim = false;
  scrim.addEventListener('pointerdown', (e) => { downOnScrim = (e.target === scrim); });
  scrim.addEventListener('pointerup', (e) => {
    const hit = downOnScrim && e.target === scrim;
    downOnScrim = false;
    if (hit && opts.dismissable !== false) api.close();
  });

  (opts.closeButtons || []).forEach((b) => {
    if (b) b.addEventListener('click', (e) => { e.preventDefault(); api.close(); });
  });

  const api = {
    el: scrim,
    isOpen,
    token: entry,
    open() {
      if (isOpen()) return;
      opener = (typeof document !== 'undefined') ? document.activeElement : null;
      scrim.classList.remove('hidden');
      pushOverlay(entry);
      lockScroll();
      const target = (typeof opts.initialFocus === 'function' ? opts.initialFocus() : opts.initialFocus) || panel;
      if (target) setTimeout(() => { try { target.focus(); } catch (_) {} }, opts.focusDelay == null ? 20 : opts.focusDelay);
      if (opts.onOpen) opts.onOpen();
    },
    close() {
      if (!isOpen()) return;
      popOverlay(entry);
      scrim.classList.add('hidden');
      unlockScroll();
      if (opts.restoreFocus !== false && opener && opener.isConnected) { try { opener.focus(); } catch (_) {} }
      if (opts.onClose) opts.onClose();
    },
  };
  return api;
}
