// ONE source of truth for the web app's shared accent palette + the pad-tint ramp.
//
// The semantic accents MIRROR the CSS :root tokens in web-app/public/styles.css and are read
// LIVE from the document (so the CSS stays authoritative — change a token there and JS follows),
// with a hex fallback that matches the token for any non-DOM context. This kills the "one accent,
// many near-miss hexes" drift the fable web review flagged (V2 / H3): five greens, five ambers,
// four blues and four cyans that had crept in across the 30 independently-built modules.
//
// The pad-tint ramp is the 8-colour colour-is-light sequence assigned to sounds / sections /
// tracks in order — it was copy-pasted verbatim into main.js, compose.js, fxrack.js and
// trackrack.js (H1, "the pad-tint palette is copy-pasted into four modules"); it now lives here.

const cssVar = (name, fallback) => {
  if (typeof document !== 'undefined' && document.documentElement) {
    const v = getComputedStyle(document.documentElement).getPropertyValue(name).trim();
    if (v) return v;
  }
  return fallback;
};

export const PHOS     = cssVar('--phos',     '#4ade80');   // the ONE phosphor — the native LCD green
export const PHOS_RGB = cssVar('--phos-rgb', '74,222,128'); // the phosphor as bare rgb triplet (for rgba() glows)
export const PHOS_INK = cssVar('--phos-ink', '#eafff4');   // bright phosphor ink (labels on the dark screen)
export const AMBER    = cssVar('--amber',    '#ffb454');   // the LCD amber (code-edit / sample tint)
export const BLUE     = cssVar('--blue',     '#5b8ed4');   // settings / reverb / "fader" blue
export const CYAN     = cssVar('--cyan',     '#58c4e0');   // the LCD cyan
export const SCR0     = cssVar('--scr0',     '#0a1310');   // dark phosphor screen ground (near)
export const SCR1     = cssVar('--scr1',     '#0b1712');   // dark phosphor screen ground (far)

// the pad-tint ramp — the colour-is-light hues, assigned to sounds/sections/tracks in order.
// Shared by PADS (main.js), COMPOSE (compose.js), the mixer (trackrack.js) and the FX rack (fxrack.js).
export const PAD_TINTS = ['#35d67a', '#23c9c9', '#4f9bff', '#b07cff', '#ff73b3', '#ff7a52', '#ffc23d', '#bfe04a'];
