// ===========================================================================
//  Cyclo web — THE GRAIN GARDEN (the chop world), the granular MINIGAME.
//
//  A faithful web port of native's grain surface: src/app/GardenView.h (the "4D
//  gardening" bioluminescent night bed you PLAY — sweep the soil to sow, drag up to
//  make it lusher, drag the moon for light, swipe the sky for wind) AND
//  src/app/GrainControls.h (the console tray of faders — GRAINS / DENSITY / PITCH /
//  PAN / FILTER / MOTION / HIGH-PASS / DRIVE / REVERB / DELAY / CRUSH / GAIN). Both
//  native views drive the SAME coin (GrainCode); on web they are one overlay — the
//  garden is the playful hero, the tray is the input-agnostic/keyboard console.
//
//  THE COIN (grain gestures -> real Cyclo code): every gesture maps to a shared
//  cyclo::GrainParams and the CLAUSE TEXT (`chop / fast / speed(rand) / pan(rand) /
//  lpf(sine.range) / spray / drive / reverb / delay / crush / gain`) is rewritten by the
//  SHARED pure-core generator via WASM (M.grainApply) — NOT reinvented in JS. The garden
//  reads a section's current grain clauses back via M.grainReadJson so the flowers reflect
//  the real code, and every change hot-swaps the shared engine so it is HEARD immediately.
//  This mirrors native GardenView::emitCode / GrainControls::paramsChanged exactly.
//
//  INPUT-AGNOSTIC (docs/web-interaction.md): the canvas is ONE Pointer-Events path
//  (mouse/touch/pen + setPointerCapture) with an occlusion-safe floating readout bubble
//  ABOVE the finger; the fader tray reuses the shared attachValueDrag (wheel + arrow-key
//  fine-tune, keyboard focus, pull-away=finer); the TONE LOCK chip + close are real
//  <button>s (pointer + keyboard). No action is gated behind hover/right-click/wheel.
// ===========================================================================
import { attachValueDrag, attachActivate, showValueBubble, hideValueBubble } from './gesture.js';
import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

const clampf = (x, a = 0, b = 1) => Math.max(a, Math.min(b, x));
const frac = (x) => x - Math.floor(x);

// ---- the state <-> the shared cyclo::GrainParams (the codec's fields) -----------
// All fields normalized 0..1 (fader space) except `lock`. The garden gestures and the
// faders BOTH write these, and buildCsv() maps them to the GrainParams CSV the shared
// GrainCode consumes. The slider<->value maps (density skew, filter/hpf Hz sweeps) are
// lifted verbatim from GrainControls.h so the written Hz/rate numbers match native.
const KHZ_TOP = 8000, KHZ_BOT = 150;         // FILTER slider (0 open .. 1 dark) <-> Hz
const HPF_BOT = 20, HPF_TOP = 2000;          // HIGH-PASS slider (0 off .. 1 thin) <-> Hz
function sliderToHz(v) { return v < 0.02 ? 0 : KHZ_TOP * Math.pow(KHZ_BOT / KHZ_TOP, v); }
function hzToSlider(hz) { return hz <= 0 ? 0 : clampf(Math.log(hz / KHZ_TOP) / Math.log(KHZ_BOT / KHZ_TOP)); }
function sliderToHpf(v) { return v < 0.02 ? 0 : HPF_BOT * Math.pow(HPF_TOP / HPF_BOT, v); }
function hpfToSlider(hz) { return hz <= 0 ? 0 : clampf(Math.log(hz / HPF_BOT) / Math.log(HPF_TOP / HPF_BOT)); }
// DENSITY slider (0..1) <-> rate (0.25..4), log so norm 0.5 == 1.0x (the "off" centre).
function sliderToRate(v) { return 0.25 * Math.pow(16, v); }
function rateToSlider(r) { return clampf(Math.log(r / 0.25) / Math.log(16)); }
// GAIN slider (0..1) <-> gainMul (0..1.5), unity at norm 2/3.
function sliderToGain(v) { return v * 1.5; }
function gainToSlider(g) { return clampf(g / 1.5); }

// A fresh garden's default state (a lush, inviting bed — mirrors GardenView::Params defaults).
export function defaultState() {
  return { lush: 0.5, density: 0.5, pitch: 0.5, pan: 0.55, filter: 0.35, motion: 0.35,
           spray: 0.0, hpf: 0.0, drive: 0.0, reverb: 0.0, delay: 0.0, crush: 0.0,
           gain: gainToSlider(1.0), lock: false };
}

// state -> the GrainParams CSV (fixed field order the C++ bridge parseGrainCsv expects):
//   grains, overlap, spread, rate, pitch, pan, filterHz, motion, hpf, drive, reverb, delay, crush, gain
export function buildCsv(s) {
  const grains  = s.lush < 0.04 ? 0 : 4 + Math.round(s.lush * 44);   // .chop(4..48)
  const overlap = grains >= 2 ? 1 + s.lush * 5 : 1;                  // lusher => an overlapping cloud
  let rate = sliderToRate(s.density);
  if (Math.abs(rate - 1) < 0.06) rate = 1;                          // snap to "off" near centre
  const pitch = s.lock ? 0 : s.pitch;                               // TONE LOCK drops the pitch spray
  const filterHz = sliderToHz(s.filter);
  const hpfHz = sliderToHpf(s.hpf);
  let gain = sliderToGain(s.gain);
  if (Math.abs(gain - 1) < 0.03) gain = 1;                          // snap to unity
  return [grains, overlap, s.spray, rate, pitch, s.pan, filterHz, s.motion,
          hpfHz, s.drive, s.reverb, s.delay, s.crush, gain].map((x) => +x.toFixed(4)).join(',');
}

// GrainParams (from M.grainReadJson) -> state, so the garden opens reflecting the real code.
export function stateFromParams(p) {
  const s = defaultState();
  if (!p) return s;
  s.lush   = p.grains <= 0 ? 0 : clampf((p.grains - 4) / 44);
  s.density = rateToSlider(clampf(p.rate, 0.25, 4));
  s.pitch  = clampf(p.pitchSpray);
  s.pan    = clampf(p.panSpray);
  s.filter = hzToSlider(p.filterHz);
  s.motion = clampf(p.filterMove);
  s.spray  = clampf(p.grainSpread);
  s.hpf    = hpfToSlider(p.hpfHz);
  s.drive  = clampf(p.driveAmt); s.reverb = clampf(p.reverbAmt);
  s.delay  = clampf(p.delayAmt); s.crush  = clampf(p.crushAmt);
  s.gain   = gainToSlider(clampf(p.gainMul, 0, 1.5));
  // reflect an existing "grains but no pitch spray" section as already tone-locked (truth on open)
  s.lock   = p.grains > 0 && p.pitchSpray <= 0;
  return s;
}

// The twelve console faders (GrainControls parity): label + the state key + a live readout format.
// GRAINS/DENSITY/PITCH/PAN drive the granular core; FILTER/MOTION/HIGH-PASS shape it; DRIVE/REVERB/
// DELAY/CRUSH/GAIN are the sends — the exact native GrainControls set + ranges.
const FADERS = [
  { key: 'lush',   label: 'GRAINS',    fmt: (s) => { const g = s.lush < 0.04 ? 0 : 4 + Math.round(s.lush * 44); return g < 2 ? 'Off' : String(g); } },
  { key: 'density',label: 'DENSITY',   fmt: (s) => { const r = sliderToRate(s.density); return Math.abs(r - 1) < 0.06 ? 'x1.0' : 'x' + r.toFixed(2); } },
  { key: 'pitch',  label: 'PITCH',     fmt: (s) => s.lock ? 'Lock' : (s.pitch <= 0 ? 'Off' : '±' + Math.round(s.pitch * 12) + ' st') },
  { key: 'pan',    label: 'PAN',       fmt: (s) => s.pan <= 0 ? 'Centre' : Math.round(s.pan * 100) + '%' },
  { key: 'filter', label: 'FILTER',    fmt: (s) => { const hz = sliderToHz(s.filter); return hz <= 0 ? 'Open' : hz >= 1000 ? (hz / 1000).toFixed(1) + ' kHz' : Math.round(hz) + ' Hz'; } },
  { key: 'motion', label: 'MOTION',    fmt: (s) => sliderToHz(s.filter) <= 0 ? '—' : (s.motion <= 0.01 ? 'Static' : 'sweep ' + Math.round(s.motion * 100) + '%') },
  { key: 'spray',  label: 'SPRAY',     fmt: (s) => s.spray <= 0.01 ? 'Off' : Math.round(s.spray * 100) + '%' },
  { key: 'hpf',    label: 'HIGH-PASS', fmt: (s) => { const hz = sliderToHpf(s.hpf); return hz <= 0 ? 'Off' : hz >= 1000 ? (hz / 1000).toFixed(1) + ' kHz' : Math.round(hz) + ' Hz'; } },
  { key: 'drive',  label: 'DRIVE',     fmt: (s) => s.drive <= 0.001 ? 'Off' : Math.round(s.drive * 100) + '%' },
  { key: 'reverb', label: 'REVERB',    fmt: (s) => s.reverb <= 0.001 ? 'Off' : Math.round(s.reverb * 100) + '%' },
  { key: 'delay',  label: 'DELAY',     fmt: (s) => s.delay <= 0.001 ? 'Off' : Math.round(s.delay * 100) + '%' },
  { key: 'crush',  label: 'CRUSH',     fmt: (s) => s.crush <= 0.001 ? 'Off' : Math.round(s.crush * 100) + '%' },
  { key: 'gain',   label: 'GAIN',      fmt: (s) => { const g = sliderToGain(s.gain); if (Math.abs(g - 1) < 0.03) return '0 dB'; const db = 20 * Math.log10(Math.max(1e-4, g)); return (db >= 0 ? '+' : '') + db.toFixed(1) + ' dB'; } }
];

const HUES = [0.30, 0.42, 0.50, 0.76, 0.88, 0.26];   // green/teal/cyan/violet/pink/lime (native palette)
const LOCK_HUE = 0.40;

// =============================================================================
//  Find the s(...) grain chain (a chain containing a .chop(...) clause) around a doc
//  offset — the section the tapped .chop lives in. Returns { start, end, body } or null.
//  Single-line-safe: a chain is one logical line (web sections are one-line chains), so
//  clause continuation stops at a newline (never merges across `## NAME` sections).
// =============================================================================
export function findGrainChain(doc, offset) {
  const re = /s\s*\(/g;
  let m, best = null;
  while ((m = re.exec(doc)) !== null) {
    const prev = m.index > 0 ? doc[m.index - 1] : '';
    if (/[A-Za-z0-9_]/.test(prev)) continue;            // not the head of a real s(...) (part of a word)
    const start = m.index;
    const end = scanChainEnd(doc, start);
    if (end < 0) continue;
    if (offset >= start && offset <= end) {
      const body = doc.slice(start, end);
      if (/\.chop\s*\(/.test(body)) best = { start, end, body };
    }
  }
  return best;
}

// Scan one s(...) chain from `start`, returning the offset one past its last clause, or -1 if the
// head is malformed. Stops at a newline (single-line chain) so it never spans sections.
function scanChainEnd(doc, start) {
  let i = start + 1;
  i = skipInline(doc, i);
  if (doc[i] !== '(') return -1;
  i++;
  // head: s("...") or s(alias) — skip a quoted string or a bare identifier, then ')'
  i = skipInline(doc, i);
  if (doc[i] === '"') { i++; while (i < doc.length && doc[i] !== '"') i++; if (doc[i] !== '"') return -1; i++; }
  else { const s0 = i; while (i < doc.length && /[A-Za-z0-9_]/.test(doc[i])) i++; if (i === s0) return -1; }
  i = skipInline(doc, i);
  if (doc[i] !== ')') return -1;
  i++;
  // clauses: `.name` optionally `(...)`, separated by inline whitespace only
  while (true) {
    const j = skipInline(doc, i);
    if (doc[j] !== '.') break;
    let k = j + 1, n0 = k;
    while (k < doc.length && /[A-Za-z0-9_]/.test(doc[k])) k++;
    if (k === n0) break;
    k = skipInline(doc, k);
    if (doc[k] === '(') {
      let depth = 1; k++;
      while (k < doc.length && depth > 0) { if (doc[k] === '(') depth++; else if (doc[k] === ')') depth--; k++; }
      if (depth !== 0) return -1;
    }
    i = k;
  }
  return i;
}
function skipInline(doc, i) { while (i < doc.length && (doc[i] === ' ' || doc[i] === '\t')) i++; return i; }

// =============================================================================
//  The DOM/canvas garden (browser only). `opts`: { module (WASM M), host, doc (full),
//  chain ({start,end,body} from findGrainChain), onChange(newFullDoc), onClose, onGrow }.
//  onChange fires the FULL rewritten document on every gesture; onGrow fires ONCE the first
//  time a gesture actually grows grain code (the Grain Gardener medal trigger).
// =============================================================================
export function createGarden(opts) {
  const M = opts.module;
  let doc = opts.doc;
  const chainStart = opts.chain.start;
  let chainEnd = opts.chain.end;
  let body = opts.chain.body;

  // read the real grain clauses (the coin) into the garden state
  let params = null;
  try { params = JSON.parse(M.grainReadJson(body)); } catch (_) { params = null; }
  const hasCoin = !!params;
  const state = stateFromParams(params);
  let grew = false;

  // ---- DOM shell (design-bar overlay, same pattern as the FX editor) ----
  const scrim = el('div', 'garden-scrim');
  const card = el('div', 'garden-card');
  scrim.appendChild(card);

  const head = el('div', 'garden-head');
  const titles = el('div', 'garden-titles');
  const h = el('div', 'garden-title'); h.textContent = 'Grain';
  const sub = el('div', 'garden-sub'); sub.textContent = 'GARDEN';
  titles.appendChild(h); titles.appendChild(sub);
  const lockChip = el('button', 'garden-lock'); lockChip.type = 'button';
  lockChip.setAttribute('aria-pressed', String(state.lock));
  const close = el('button', 'garden-close'); close.type = 'button'; close.textContent = '×';
  close.setAttribute('aria-label', 'close');
  head.appendChild(titles); head.appendChild(lockChip); head.appendChild(close);
  card.appendChild(head);

  const canvas = document.createElement('canvas');
  canvas.className = 'garden-canvas';
  canvas.setAttribute('role', 'application');
  canvas.setAttribute('aria-label', 'Grain garden — sweep the soil to sow, drag up to grow lusher, drag the moon for light, swipe the sky for wind');
  card.appendChild(canvas);

  const coin = el('div', 'garden-coin');
  card.appendChild(coin);

  // the console tray — the GrainControls faders (input-agnostic / keyboard path)
  const tray = el('div', 'garden-rows');
  const rows = FADERS.map((f) => makeRow(f));
  rows.forEach((r) => tray.appendChild(r.el));
  card.appendChild(tray);

  const hint = el('div', 'garden-hint');
  hint.textContent = 'play the garden · or drag the faders — scroll · arrow keys — pull away to fine-tune';
  card.appendChild(hint);

  opts.host.appendChild(scrim);

  // ---- close: × / scrim tap / Escape — all via the ONE shared overlay manager (overlay.js) ----
  const overlay = registerOverlay(scrim, {
    panel: card,
    closeButtons: [close],
    label: 'grain garden',
    onClose: () => { teardown(); if (opts.onClose) opts.onClose(); },
  });
  overlay.open();

  // ---- TONE LOCK chip ----
  attachActivate(lockChip, () => { state.lock = !state.lock; lockChip.setAttribute('aria-pressed', String(state.lock)); flowers.length = 0; scatter(); emit(); refreshChip(); });

  // ---- the coin: state -> shared GrainCode -> doc, hot-swapped live ----
  function emit() {
    refreshRows();
    if (!hasCoin || !M) { refreshCoin(); return; }
    const next = M.grainApply(body, buildCsv(state));
    if (next !== body) {
      body = next;
      doc = doc.slice(0, chainStart) + next + doc.slice(chainEnd);
      chainEnd = chainStart + next.length;
      if (opts.onChange) opts.onChange(doc);
      if (!grew && /\.chop\s*\(/.test(next)) { grew = true; if (opts.onGrow) opts.onGrow(); }
    }
    refreshCoin();
  }
  function refreshCoin() { coin.textContent = (hasCoin ? body : 's("seed").chop(…)') .split('\n')[0].trim(); }
  function refreshChip() {
    lockChip.textContent = state.lock ? '🔒 TONE LOCK' : '🔓 TONE FREE';
    lockChip.classList.toggle('on', state.lock);
  }
  function refreshRows() { rows.forEach((r) => r.refresh()); }

  // ---- a fader row (GrainControls strip) via the shared input-agnostic gesture ----
  function makeRow(f) {
    const row = el('div', 'garden-row');
    row.setAttribute('role', 'slider'); row.setAttribute('aria-label', f.label);
    row.setAttribute('aria-valuemin', '0'); row.setAttribute('aria-valuemax', '1'); row.tabIndex = 0;
    row.title = 'drag · scroll · arrow keys — pull away while dragging for fine control';
    const fill = el('div', 'garden-row-fill');
    const label = el('span', 'garden-row-label'); label.textContent = f.label;
    const val = el('span', 'garden-row-val');
    row.appendChild(fill); row.appendChild(label); row.appendChild(val);
    attachValueDrag(row, {
      getNorm: () => state[f.key],
      setNorm: (t) => { state[f.key] = clampf(t); row.setAttribute('aria-valuenow', t.toFixed(3)); emit(); },
      width: () => row.getBoundingClientRect().width,
      format: () => f.fmt(state)
    });
    const refresh = () => {
      const t = clampf(state[f.key]);
      fill.style.width = (t * 100).toFixed(1) + '%';
      const txt = f.fmt(state);
      val.textContent = txt;
      // dim a row at its neutral/"off" default so a glance shows which params are doing something
      row.classList.toggle('off', /^(Off|Open|Centre|—|x1\.0|0 dB)$/.test(txt));
    };
    return { el: row, refresh };
  }

  // ================= the bioluminescent night garden (canvas) =================
  const flowers = [];
  let moonX = 0.72, moonY = 0.26, clock = 0, windDir = 1;
  let stageR = { x: 0, y: 0, w: 0, h: 0 };
  let mode = 'none', lastX = 0, lastY = 0, activeId = -1;

  function rand() { return Math.random(); }
  function viz() {
    // normalized viz values the paint needs (inverse of the state maps)
    const filterOpen = sliderToHz(state.filter) <= 0;
    const filterN = filterOpen ? 1 : clampf(1 - state.filter);   // bright when open/low cutoff-dark
    return { grains: state.lush, pan: state.pan, pitch: state.lock ? 0 : state.pitch,
             filter: filterN, motion: state.motion, spray: state.spray };
  }

  function plant(x, hueOverride) {
    const V = viz();
    const variety = state.lock ? 0 : V.pitch;
    const wide = V.pan * 0.5 + V.spray * 0.35;
    const fx = clampf(x + (rand() - 0.5) * (0.06 + V.spray * 0.5),
                      clampf(0.5 - wide, 0.02, 0.5), clampf(0.5 + wide, 0.5, 0.98));
    const hue = hueOverride != null ? hueOverride
              : state.lock ? LOCK_HUE
              : clampf(HUES[(Math.random() * HUES.length) | 0] + (rand() - 0.5) * 0.1 * variety, 0, 1);
    flowers.push({ x: fx, h: 0.35 + (1 - variety) * 0.3 + rand() * variety * 0.55, grow: 0,
                   hue, size: 5 + rand() * 6 * (0.6 + variety), phase: rand() * 6.28, petals: 5 + ((rand() * 4) | 0) });
    const cap = 6 + Math.round(V.grains * 26);
    while (flowers.length > cap) flowers.shift();
  }
  function scatter() { const V = viz(); const n = 6 + Math.round(V.grains * 10); for (let i = 0; i < n; i++) plant(0.5 + (rand() - 0.5) * V.pan); }

  // ---- one Pointer-Events path for the whole canvas (mouse/touch/pen + capture) ----
  function localNx(clientX) { const r = canvas.getBoundingClientRect(); return clampf((clientX - r.left) / Math.max(1, r.width)); }
  function localPt(e) { const r = canvas.getBoundingClientRect(); return { x: e.clientX - r.left, y: e.clientY - r.top }; }
  function onDown(e) {
    if (e.button != null && e.button !== 0) return;
    e.preventDefault();
    try { canvas.setPointerCapture(e.pointerId); } catch (_) {}
    activeId = e.pointerId;
    const p = localPt(e); lastX = p.x; lastY = p.y;
    const mx = stageR.x + moonX * stageR.w, my = stageR.y + moonY * stageR.h;
    const soil = stageR.y + stageR.h * 0.82, sky = stageR.y + stageR.h * 0.40;
    const d = Math.hypot(p.x - mx, p.y - my);
    if (d < 44) mode = 'moon';
    else if (p.y > soil - 20) { mode = 'sow'; plant(localNx(e.clientX)); }
    else if (p.y < sky) mode = 'wind';
    else mode = 'lush';
    applyGesture(e, true);
  }
  function onMove(e) { if (mode !== 'none' && e.pointerId === activeId) applyGesture(e, false); }
  function onUp(e) { if (e.pointerId !== activeId) return; mode = 'none'; activeId = -1; hideValueBubble(); try { canvas.releasePointerCapture(e.pointerId); } catch (_) {} }

  function applyGesture(e, first) {
    const p = localPt(e);
    let bubble = null;
    if (mode === 'moon') {
      moonX = clampf((p.x - stageR.x) / stageR.w, 0.05, 0.95);
      moonY = clampf((p.y - stageR.y) / stageR.h, 0.05, 0.5);
      // moon high in the sky = more light = filter OPEN (bright); map to the FILTER slider
      const light = clampf(1 - moonY / 0.5 * 0.8);
      state.filter = clampf(1 - light);   // slider: 0 open(bright) .. 1 dark
      bubble = FADERS[4].fmt(state);
    } else if (mode === 'sow') {
      if (!first) { plant(localNx(e.clientX)); state.pan = clampf(state.pan + Math.abs(p.x - lastX) / stageR.w * 0.5); }
      bubble = 'sow · pan ' + Math.round(state.pan * 100) + '%';
    } else if (mode === 'lush') {
      if (!first) {
        state.lush = clampf(state.lush + (lastY - p.y) / 300);
        if (!state.lock) state.pitch = clampf(state.pitch + (p.x - lastX) / 400);
        if (rand() < 0.4) plant(0.5 + (rand() - 0.5) * state.pan);
      }
      const g = state.lush < 0.04 ? 0 : 4 + Math.round(state.lush * 44);
      bubble = 'grains ' + (g < 2 ? 'off' : g);
    } else if (mode === 'wind') {
      if (!first) { state.spray = clampf(state.spray + Math.abs(p.x - lastX) / stageR.w * 1.2); windDir = p.x >= lastX ? 1 : -1; }
      bubble = 'wind · spray ' + Math.round(state.spray * 100) + '%';
    }
    lastX = p.x; lastY = p.y;
    if (bubble != null) showValueBubble(e.clientX, e.clientY, bubble);   // occlusion-safe readout above the finger
    emit();
  }
  canvas.addEventListener('pointerdown', onDown);
  canvas.addEventListener('pointermove', onMove);
  canvas.addEventListener('pointerup', onUp);
  canvas.addEventListener('pointercancel', onUp);
  // keyboard path for the canvas hero (arrows grow/light it; the faders carry the precise per-param path)
  canvas.tabIndex = 0;
  canvas.addEventListener('keydown', (e) => {
    let d = 0; if (e.key === 'ArrowUp') d = 1; else if (e.key === 'ArrowDown') d = -1; else return;
    e.preventDefault(); state.lush = clampf(state.lush + d * 0.05); emit();
  });

  // ---- render loop ----
  let raf = 0;
  function layout() {
    const dpr = Math.min(2, window.devicePixelRatio || 1);
    const w = canvas.clientWidth, hgt = canvas.clientHeight;
    if (!w || !hgt) return null;
    if (canvas.width !== w * dpr || canvas.height !== hgt * dpr) { canvas.width = w * dpr; canvas.height = hgt * dpr; }
    stageR = { x: 0, y: 0, w, h: hgt };
    const ctx = canvas.getContext('2d');
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    return { ctx, w, h: hgt };
  }
  function tick() {
    clock++;
    for (const f of flowers) if (f.grow < 1) f.grow = Math.min(1, f.grow + 0.02);
    const V = viz();
    if (Math.random() < 0.06 && flowers.length < 6 + Math.round(V.grains * 26)) plant(0.5 + (rand() - 0.5) * state.pan);
    draw();
    raf = requestAnimationFrame(tick);
  }
  function draw() {
    const L = layout(); if (!L) return;
    const { ctx, w, h: H } = L;
    const V = viz();
    ctx.clearRect(0, 0, w, H);
    const X = 0, Y = 0, sy = Y + H * 0.82;

    // night-garden sky (lift with the light)
    const lift = V.filter;
    const sky = ctx.createLinearGradient(0, Y, 0, Y + H);
    sky.addColorStop(0, `rgb(${(0.03 + lift * 0.09) * 255 | 0},${(0.06 + lift * 0.08) * 255 | 0},${(0.08 + lift * 0.09) * 255 | 0})`);
    sky.addColorStop(0.7, `rgb(${(0.02 + lift * 0.04) * 255 | 0},${0.05 * 255 | 0},${0.05 * 255 | 0})`);
    sky.addColorStop(1, '#040806');
    ctx.fillStyle = sky; ctx.fillRect(X, Y, w, H);

    // the moon (the light)
    const mx = X + moonX * w, my = Y + moonY * H, mr = 90 + V.filter * 70;
    const glow = ctx.createRadialGradient(mx, my, 0, mx, my, mr);
    glow.addColorStop(0, `rgba(199,240,209,${0.16 + V.filter * 0.45})`);
    glow.addColorStop(1, 'rgba(199,240,209,0)');
    ctx.fillStyle = glow; ctx.beginPath(); ctx.arc(mx, my, mr, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = `rgba(219,245,224,${0.6 + V.filter * 0.4})`;
    ctx.beginPath(); ctx.arc(mx, my, 9 + V.filter * 5, 0, Math.PI * 2); ctx.fill();

    // soil
    const soil = ctx.createLinearGradient(0, sy, 0, Y + H);
    soil.addColorStop(0, '#14100c'); soil.addColorStop(1, '#0a0705');
    ctx.fillStyle = soil; ctx.fillRect(X, sy, w, Y + H - sy);
    ctx.strokeStyle = 'rgba(120,90,60,0.25)'; ctx.lineWidth = 1; line(ctx, X, sy, X + w, sy);

    const wind = Math.sin(clock * 0.02) * V.motion + windDir * V.spray * 0.4;

    // flowers (back to front by height)
    const order = flowers.slice().sort((a, b) => a.h - b.h);
    for (const f of order) {
      const gx = X + f.x * w;
      const stalkH = f.h * (H * 0.5) * f.grow;
      const sway = (wind * 22 + Math.sin(clock * 0.026 + f.phase) * 8 * V.motion) * (stalkH / (H * 0.5));
      const topx = gx + sway, topy = sy - stalkH;
      ctx.strokeStyle = hsva(0.36, 0.55, 0.28 + V.filter * 0.12, 0.85); ctx.lineWidth = 2;
      ctx.beginPath(); ctx.moveTo(gx, sy); ctx.quadraticCurveTo(gx + sway * 0.5, sy - stalkH * 0.5, topx, topy); ctx.stroke();
      const bs = f.size * f.grow * (0.8 + V.filter * 0.5);
      const bloom = ctx.createRadialGradient(topx, topy, 0, topx, topy, bs * 3);
      bloom.addColorStop(0, hsva(f.hue, 0.8, 0.9, 0.5 + V.filter * 0.3));
      bloom.addColorStop(1, hsva(f.hue, 0.8, 0.9, 0));
      ctx.fillStyle = bloom; ctx.beginPath(); ctx.arc(topx, topy, bs * 3, 0, Math.PI * 2); ctx.fill();
      for (let p = 0; p < f.petals; p++) {
        const a = clock * 0.003 + f.phase + p / f.petals * Math.PI * 2;
        const px = topx + Math.cos(a) * bs, py = topy + Math.sin(a) * bs;
        ctx.fillStyle = hsva(f.hue, 0.8, 0.9, 0.9); ctx.beginPath(); ctx.arc(px, py, bs * 0.6, 0, Math.PI * 2); ctx.fill();
      }
      ctx.fillStyle = hsva(clampf(f.hue + 0.08), 0.7, 1, 0.95); ctx.beginPath(); ctx.arc(topx, topy, bs * 0.5, 0, Math.PI * 2); ctx.fill();
    }

    // WIND pollen — spray blows glowing pollen across the sky (the scatter/decorrelation visual)
    if (V.spray > 0.02) {
      const np = (V.spray * 46) | 0, drift = clock * (0.7 + V.spray * 2.4) * windDir;
      for (let i = 0; i < np; i++) {
        const h1 = frac(Math.sin(i * 12.9898) * 43758.5), h2 = frac(Math.sin(i * 78.233) * 12543.7);
        const px = X + (((h1 * w + drift) % w) + w) % w, py = Y + (0.06 + h2 * 0.70) * H;
        const tw = 0.4 + 0.6 * Math.sin(clock * 0.05 + i), r = 1.3 + h2 * 1.5;
        ctx.fillStyle = hsva(0.15, 0.35, 1, 0.10 + V.spray * 0.4 * tw);
        ctx.beginPath(); ctx.arc(px, py, r, 0, Math.PI * 2); ctx.fill();
      }
    }
  }

  // init
  scatter();
  refreshChip(); refreshRows(); refreshCoin();
  tick();

  let torn = false;
  function teardown() {
    if (torn) return; torn = true;
    cancelAnimationFrame(raf);
    if (scrim.parentNode) scrim.parentNode.removeChild(scrim);
  }
  const destroy = () => overlay.close();

  return {
    destroy,
    doc: () => doc,
    body: () => body,
    // test hooks (mirror the FX editor's setParam/valueOf so shoot.mjs can drive it headlessly)
    setParam: (key, norm) => { if (!(key in state)) return null; state[key] = clampf(norm); emit(); return doc; },
    valueOf: (key) => state[key],
    toggleLock: () => { state.lock = !state.lock; emit(); refreshChip(); return doc; },
    // simulate a garden gesture: 'lush' grows grains, 'moon' opens the filter, 'wind' sprays, 'sow' pans
    gesture: (kind, amount = 0.3) => {
      if (kind === 'lush') state.lush = clampf(state.lush + amount);
      else if (kind === 'moon') state.filter = clampf(state.filter - amount);
      else if (kind === 'wind') state.spray = clampf(state.spray + amount);
      else if (kind === 'sow') state.pan = clampf(state.pan + amount);
      emit(); return doc;
    },
    coin: () => body,
    hasCoin: () => hasCoin
  };
}

function el(tag, cls) { const e = document.createElement(tag); if (cls) e.className = cls; return e; }
function line(ctx, x0, y0, x1, y1) { ctx.beginPath(); ctx.moveTo(x0, y0); ctx.lineTo(x1, y1); ctx.stroke(); }
// HSV (h,s,v in 0..1) + alpha -> an rgba() string (matches JUCE Colour::fromHSV usage in GardenView)
function hsva(h, s, v, a) {
  h = ((h % 1) + 1) % 1; const i = Math.floor(h * 6), f = h * 6 - i;
  const p = v * (1 - s), q = v * (1 - f * s), t = v * (1 - (1 - f) * s);
  let r, g, b;
  switch (i % 6) {
    case 0: r = v; g = t; b = p; break; case 1: r = q; g = v; b = p; break;
    case 2: r = p; g = v; b = t; break; case 3: r = p; g = q; b = v; break;
    case 4: r = t; g = p; b = v; break; default: r = v; g = p; b = q;
  }
  return `rgba(${r * 255 | 0},${g * 255 | 0},${b * 255 | 0},${clampf(a)})`;
}
