// ===========================================================================
//  automation.js — the AUTOMATION LANE (the web twin of native src/app/AutomationLane.h +
//  AutomationStrip.h). Docked in COMPOSE, below the arrangement timeline (native hosts the strip
//  IN the COMPOSE timeline). You pick a `## SECTION` and an effect PARAM, then DRAW a per-cycle
//  curve; the drawn shape becomes a Signal that lands INLINE as that param's value —
//  `.reverb(mix: env(0:.15, 1:.32, ...))`, `.lpf(hz: sine.slow(8).range(200, 2000))`. The coin,
//  over TIME. No `~name` indirection (the shape lives right in the effect it drives).
//
//  The coin / mapping (follows native EXACTLY): every draw/shape gesture mutates the SHARED
//  pure-core AutomationCoin (WASM bridge: autoParamsJson / autoSignalExpr / autoFillShape /
//  setSectionAutomation / readSectionAutomationJson / autoSignalToCurveJson). The curve -> Signal
//  string and the named-arg setClauseArg splice are byte-identical to native src/app/AutomationCoin.h;
//  the write byte-preserves every OTHER section (coin::spliceSection) and the engine hot-swaps so the
//  automation is HEARD moving the param over time. The palette + signature hues come from the core.
//  Merely opening / selecting a param never writes — the document is written only on the user's first
//  gesture (draw / shape), exactly like native AutomationLane.
//
//  Input-agnostic (docs/web-interaction.md — a drawn curve IS a touch-draw surface): ONE Pointer-
//  Events path (down/move/up + setPointerCapture) draws the curve for mouse/touch/pen; the shared
//  occlusion-safe readout bubble floats ABOVE the finger; the plot is a focusable surface with a
//  visible ring and a KEYBOARD fallback (Left/Right pick a handle, Up/Down set its value, Shift =
//  coarse); handle columns are full-height (forgiving > 44px draw targets); touch-action:none +
//  overscroll-behavior:contain so a draw never scrolls/zooms/pulls-to-refresh. Shape presets +
//  the SECTION / PARAM chips are real focusable buttons (pointer + keyboard).
// ===========================================================================
import { showValueBubble, hideValueBubble } from './gesture.js';
import { PHOS, PHOS_RGB, PHOS_INK, SCR1 } from './palette.js';

const SHAPES = ['DRAW', 'LFO', 'RAMP', 'PERLIN', 'STEP'];   // native AutomationStrip shape order
const SHAPE_MAP = [0, 1, 2, 3, 4];                          // -> curveToSignal shape ids
const PADL = 10, PADR = 10, PADT = 12, PADB = 20;           // plot insets (bottom holds cycle numbers)

// Build the automation lane into one host element. `opts`:
//   module()        -> the WASM module M (the SHARED AutomationCoin bridge)
//   engine()        -> the live WebEngine (currentCycle for the playhead)
//   getDoc()        -> current editor document text
//   applyDoc(text)  -> write the new doc (dispatch into CM + hot-swap when playing) — main.js owns it
//   ensurePlaying() -> Promise; start audio + transport so a fresh curve is HEARD (on gesture end)
//   isPlaying()     -> transport running? (drives the playhead)
//   setStatus(s)    -> a status line
export function createAutomation(opts) {
  const M = opts.module;
  const el = document.createElement('div');
  el.className = 'autolane';

  let params = [];        // the 12 AutoParams from the SHARED core (autoParamsJson)
  let sections = [];      // [{name, editable}] from composeModel (in doc order)
  let secIdx = 0;         // selected section
  let p = 0;              // selected param
  let shape = 0;          // 0 DRAW / 1 LFO / 2 RAMP / 3 PERLIN / 4 STEP
  let N = 8;              // handles = song length (2..16), default 8
  let vals = [0.15, 0.32, 0.55, 0.72, 0.68, 0.5, 0.32, 0.2];   // native AutomationStrip default
  let autoSet = [];       // which params the selected section already automates (chip dots)
  let active = 0;         // keyboard-focused handle index
  let openMenu = null;    // 'section' | 'param' | null

  function loadParams() {
    if (params.length) return;
    try { params = JSON.parse(M().autoParamsJson()); } catch (e) { params = []; }
  }

  // ---- read the section list + song length from the SHARED core (same parse the engine uses) ----
  function readModel() {
    let model = { length: 0, sections: [] };
    try { model = JSON.parse(M().composeModel(opts.getDoc())); } catch (e) {}
    sections = (model.sections || []).filter((s) => s.editable);
    if (secIdx >= sections.length) secIdx = 0;
    const want = Math.max(2, Math.min(16, model.length > 0 ? model.length : 8));
    if (want !== N) { resampleTo(want); N = want; if (active >= N) active = N - 1; }
  }

  // resample the current curve to a new handle count (native AutomationStrip::setCycles) so changing
  // the song length keeps the drawn SHAPE rather than resetting it.
  function resampleTo(n) {
    const m = vals.length;
    const out = new Array(n);
    for (let i = 0; i < n; i++) {
      const x = n > 1 ? (i * (m - 1)) / (n - 1) : 0;
      const i0 = Math.max(0, Math.min(m - 1, Math.floor(x))), i1 = Math.min(m - 1, i0 + 1);
      out[i] = vals[i0] + (x - i0) * (vals[i1] - vals[i0]);
    }
    vals = out;
  }

  const curSection = () => (sections[secIdx] ? sections[secIdx].name : '');
  const curParam = () => params[p] || { label: '—', clause: '', arg: '', col: PHOS };

  // ---- reflect: load the selected section+param's existing curve (if it automates it), else keep
  // the current shape — selecting must NOT clobber (native: the write happens on the first draw). ----
  function reflect() {
    autoSet = [];
    const name = curSection();
    if (!name) return;
    try {
      const r = JSON.parse(M().readSectionAutomationJson(opts.getDoc(), name, p, N));
      autoSet = r.auto || [];
      if (r.selected && r.selected.automated && Array.isArray(r.selected.vals) && r.selected.vals.length === N) {
        vals = r.selected.vals.slice();
        shape = r.selected.shape | 0;
      }
    } catch (e) {}
  }

  // ========================================================================
  //  The coin write — only on a real gesture (draw / shape), never on open/select.
  // ========================================================================
  function writeCoin() {
    const name = curSection();
    if (!name) return;
    const csv = vals.map((v) => (Math.round(v * 1e4) / 1e4)).join(',');
    try {
      const next = M().setSectionAutomation(opts.getDoc(), name, p, csv, SHAPE_MAP[shape]);
      opts.applyDoc(next);
    } catch (e) {}
    if (!autoSet.includes(p)) autoSet.push(p);   // drawing on a param makes it automated (dots)
  }

  // the live Signal string the curve writes (the coin readout) — from the SHARED core
  function signalExpr() {
    const csv = vals.map((v) => (Math.round(v * 1e4) / 1e4)).join(',');
    try { return M().autoSignalExpr(csv, SHAPE_MAP[shape], p) || ''; } catch (e) { return ''; }
  }

  // ========================================================================
  //  DOM
  // ========================================================================
  let bar, chips, secChip, paramChip, plot, canvas, shapesRow, codeEl, emptyEl, menuEl;

  function build() {
    el.innerHTML = '';

    bar = document.createElement('div'); bar.className = 'autolane-bar';
    const t = document.createElement('div'); t.className = 'autolane-titles';
    const title = document.createElement('div'); title.className = 'autolane-title'; title.textContent = 'Automation';
    const sub = document.createElement('div'); sub.className = 'autolane-sub'; sub.textContent = 'MOVES OVER TIME';
    t.appendChild(title); t.appendChild(sub);
    bar.appendChild(t);
    el.appendChild(bar);

    emptyEl = document.createElement('div'); emptyEl.className = 'autolane-empty';
    emptyEl.textContent = 'add a section in CODE — then draw an effect curve for it here';
    el.appendChild(emptyEl);

    chips = document.createElement('div'); chips.className = 'autolane-chips';
    secChip = chipButton('autolane-secchip', () => toggleMenu('section'));
    paramChip = chipButton('autolane-paramchip', () => toggleMenu('param'));
    chips.appendChild(secChip); chips.appendChild(paramChip);
    el.appendChild(chips);

    // the popover menu (section / param picker) — real focusable buttons, Escape closes
    menuEl = document.createElement('div'); menuEl.className = 'autolane-menu hidden';
    el.appendChild(menuEl);

    // the curve plot — a focusable touch-draw surface (canvas)
    plot = document.createElement('div'); plot.className = 'autolane-plot';
    plot.tabIndex = 0;
    plot.setAttribute('role', 'application');
    plot.setAttribute('aria-label', 'automation curve — draw with a pointer, or arrow keys to set points');
    canvas = document.createElement('canvas'); canvas.className = 'autolane-canvas';
    plot.appendChild(canvas);
    el.appendChild(plot);

    plot.addEventListener('pointerdown', onDown);
    plot.addEventListener('pointermove', onMove);
    plot.addEventListener('pointerup', onUp);
    plot.addEventListener('pointercancel', onUp);
    plot.addEventListener('keydown', onKey);

    // shape presets
    shapesRow = document.createElement('div'); shapesRow.className = 'autolane-shapes';
    SHAPES.forEach((lab, s) => {
      const b = document.createElement('button'); b.type = 'button'; b.className = 'autolane-shape';
      b.textContent = lab; b.dataset.shape = String(s);
      b.setAttribute('aria-label', 'shape ' + lab);
      const pick = () => { shape = s; if (s !== 0) applyPreset(s); else { writeCoin(); paint(); paintCode(); } markShapes(); };
      b.addEventListener('pointerdown', (e) => { if (e.button != null && e.button !== 0) return; e.preventDefault(); pick(); });
      b.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); pick(); } });
      shapesRow.appendChild(b);
    });
    el.appendChild(shapesRow);

    // the code the curve writes (the coin), dimmed prefix + phosphor value
    codeEl = document.createElement('div'); codeEl.className = 'autolane-code';
    el.appendChild(codeEl);

    const hint = document.createElement('div'); hint.className = 'autolane-hint';
    hint.textContent = 'pick a section + param · draw the curve over the cycles · or a shape preset · arrows set points';
    el.appendChild(hint);
  }

  function chipButton(cls, fn) {
    const b = document.createElement('button'); b.type = 'button'; b.className = 'autolane-chip ' + cls;
    b.addEventListener('pointerdown', (e) => { if (e.button != null && e.button !== 0) return; e.preventDefault(); fn(); });
    b.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); fn(); } });
    return b;
  }

  function applyPreset(s) {
    try {
      const csv = M().autoFillShape(SHAPE_MAP[s], N);
      const arr = csv.split(',').map(Number);
      if (arr.length === N && arr.every((x) => isFinite(x))) vals = arr;
    } catch (e) {}
    shape = s;
    writeCoin(); paint(); paintCode();
    opts.ensurePlaying().catch(() => {});
  }

  // ---- the popover section/param menu ----
  function toggleMenu(which) {
    if (openMenu === which) { closeMenu(); return; }
    openMenu = which;
    menuEl.innerHTML = '';
    menuEl.classList.remove('hidden');
    const items = which === 'section'
      ? sections.map((s, i) => ({ label: s.name, on: i === secIdx, dot: false, pick: () => selectSection(i) }))
      : params.map((pp, i) => ({ label: pp.label, on: i === p, dot: autoSet.includes(i), col: pp.col, pick: () => selectParam(i) }));
    items.forEach((it) => {
      const b = document.createElement('button'); b.type = 'button'; b.className = 'autolane-menuitem' + (it.on ? ' on' : '');
      if (it.col) b.style.setProperty('--tint', it.col);
      const dot = document.createElement('span'); dot.className = 'autolane-menudot' + (it.dot ? ' auto' : '');
      const lbl = document.createElement('span'); lbl.textContent = it.label + (it.dot ? '  · auto' : '');
      b.appendChild(dot); b.appendChild(lbl);
      b.addEventListener('pointerdown', (e) => { if (e.button != null && e.button !== 0) return; e.preventDefault(); it.pick(); closeMenu(); });
      b.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); it.pick(); closeMenu(); } else if (e.key === 'Escape') { closeMenu(); } });
      menuEl.appendChild(b);
    });
    const first = menuEl.querySelector('.autolane-menuitem'); if (first) first.focus();
  }
  function closeMenu() { openMenu = null; menuEl.classList.add('hidden'); menuEl.innerHTML = ''; }

  function selectSection(i) { secIdx = Math.max(0, Math.min(sections.length - 1, i)); reflect(); paintAll(); }
  function selectParam(i) { p = Math.max(0, Math.min(params.length - 1, i)); reflect(); paintAll(); }

  // ========================================================================
  //  Pointer draw (ONE path for mouse / touch / pen) — draw the curve per cycle column.
  // ========================================================================
  let drawing = false;
  function plotXY(e) {
    const r = canvas.getBoundingClientRect();
    return { x: e.clientX - r.left, y: e.clientY - r.top, w: r.width, h: r.height };
  }
  function setPoint(px, py, w, h) {
    const span = Math.max(1, w - PADL - PADR);
    const i = Math.max(0, Math.min(N - 1, Math.floor((px - PADL) / (span / N))));
    const v = clamp01(1 - (py - PADT) / Math.max(1, h - PADT - PADB));
    vals[i] = v; active = i;
    if (shape !== 0 && shape !== 4) shape = 0;   // a freehand edit drops back to DRAW (native)
    return i;
  }
  function onDown(e) {
    if (e.button != null && e.button !== 0) return;
    if (!curSection()) return;
    drawing = true;
    try { plot.setPointerCapture(e.pointerId); } catch (_) {}
    plot.focus();
    e.preventDefault();
    const { x, y, w, h } = plotXY(e);
    setPoint(x, y, w, h);
    writeCoin(); paint(); paintCode(); markShapes();
    showValueBubble(e.clientX, e.clientY, readout());
  }
  function onMove(e) {
    if (!drawing) return;
    const { x, y, w, h } = plotXY(e);
    setPoint(x, y, w, h);
    writeCoin(); paint(); paintCode();
    showValueBubble(e.clientX, e.clientY, readout());
  }
  function onUp(e) {
    if (!drawing) return;
    drawing = false;
    try { plot.releasePointerCapture(e.pointerId); } catch (_) {}
    hideValueBubble();
    markShapes();
    opts.ensurePlaying().catch(() => {});   // hear the curve move the param (start once if stopped)
  }

  // ---- keyboard fallback: pick a handle + set its value (input-agnostic point setting) ----
  function onKey(e) {
    if (!curSection()) return;
    let handled = true;
    if (e.key === 'ArrowLeft') active = Math.max(0, active - 1);
    else if (e.key === 'ArrowRight') active = Math.min(N - 1, active + 1);
    else if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
      const d = (e.key === 'ArrowUp' ? 1 : -1) * (e.shiftKey ? 0.15 : 0.05);
      vals[active] = clamp01(vals[active] + d);
      if (shape !== 0 && shape !== 4) shape = 0;
      writeCoin(); paintCode(); markShapes();
      opts.ensurePlaying().catch(() => {});
    } else handled = false;
    if (handled) { e.preventDefault(); paint(); }
  }

  const readout = () => `${curSection()} · ${curParam().label} · ${signalExpr()}`;

  // ========================================================================
  //  Rendering
  // ========================================================================
  function paintAll() { paintChips(); paint(); paintCode(); markShapes(); }

  function paintChips() {
    const P = curParam();
    secChip.innerHTML = '';
    const sd = document.createElement('span'); sd.className = 'autolane-chipdot';
    const sl = document.createElement('span'); sl.textContent = curSection() || '—';
    secChip.appendChild(sd); secChip.appendChild(sl);
    secChip.setAttribute('aria-label', 'section ' + (curSection() || 'none'));

    paramChip.innerHTML = '';
    paramChip.style.setProperty('--tint', P.col);
    const pd = document.createElement('span'); pd.className = 'autolane-chipdot tint';
    const pl = document.createElement('span'); pl.textContent = P.label;
    paramChip.appendChild(pd); paramChip.appendChild(pl);
    // little indicator dots: which params this section automates
    const dots = document.createElement('span'); dots.className = 'autolane-autodots';
    autoSet.forEach((i) => { const d = document.createElement('span'); d.className = 'autolane-autodot';
      if (params[i]) d.style.background = params[i].col; dots.appendChild(d); });
    paramChip.appendChild(dots);
    paramChip.setAttribute('aria-label', 'parameter ' + P.label);
  }

  function markShapes() {
    shapesRow && shapesRow.querySelectorAll('.autolane-shape').forEach((b) => {
      b.classList.toggle('on', +b.dataset.shape === shape);
    });
  }

  let phCol = -1;
  function paint() {
    const has = sections.length > 0;
    emptyEl.classList.toggle('hidden', has);
    chips.classList.toggle('hidden', !has);
    plot.classList.toggle('hidden', !has);
    shapesRow.classList.toggle('hidden', !has);
    codeEl.classList.toggle('hidden', !has);
    if (!has) return;

    const dpr = Math.max(1, Math.min(3, window.devicePixelRatio || 1));
    const rect = canvas.getBoundingClientRect();
    const w = Math.max(60, rect.width), h = Math.max(60, rect.height);
    if (canvas.width !== Math.round(w * dpr) || canvas.height !== Math.round(h * dpr)) {
      canvas.width = Math.round(w * dpr); canvas.height = Math.round(h * dpr);
    }
    const g = canvas.getContext('2d');
    g.setTransform(dpr, 0, 0, dpr, 0, 0);
    g.clearRect(0, 0, w, h);

    const P = curParam();
    const tint = P.col;
    const phos = PHOS;
    const span = w - PADL - PADR;
    const colX = (i) => PADL + span * (i + 0.5) / N;
    const valY = (v) => (h - PADB) - v * (h - PADT - PADB);

    // recessed screen
    g.fillStyle = SCR1; roundRect(g, 0.5, 0.5, w - 1, h - 1, 10); g.fill();
    g.strokeStyle = `rgba(${PHOS_RGB},.10)`; g.lineWidth = 1; g.stroke();

    // cycle columns + numbers
    g.font = '9px ui-monospace, monospace'; g.textAlign = 'center';
    for (let i = 0; i <= N; i++) {
      const x = PADL + span * i / N;
      g.strokeStyle = hexA(tint, (i === 0 || i === N) ? 0.30 : 0.10); g.lineWidth = 1;
      g.beginPath(); g.moveTo(x, PADT - 2); g.lineTo(x, h - PADB + 2); g.stroke();
    }
    g.fillStyle = 'rgba(141,185,166,.6)';
    for (let i = 0; i < N; i++) g.fillText(String(i + 1), colX(i), h - 6);
    // horizontal grid
    for (let gg = 1; gg < 4; gg++) { const y = PADT + (h - PADT - PADB) * gg / 4;
      g.strokeStyle = hexA(tint, 0.06); g.beginPath(); g.moveTo(PADL, y); g.lineTo(w - PADR, y); g.stroke(); }

    // playhead sweep (audible cycle)
    if (phCol >= 0 && phCol < N) {
      const x0 = PADL + span * phCol / N, x1 = PADL + span * (phCol + 1) / N;
      g.fillStyle = `rgba(${PHOS_RGB},.10)`; g.fillRect(x0, PADT - 2, x1 - x0, h - PADT - PADB + 4);
      g.strokeStyle = hexA(phos, 0.55); g.lineWidth = 2;
      g.beginPath(); g.moveTo(x0, PADT - 2); g.lineTo(x0, h - PADB + 2); g.stroke();
    }

    // area fill + curve
    g.beginPath(); g.moveTo(colX(0), h - PADB);
    for (let i = 0; i < N; i++) g.lineTo(colX(i), valY(vals[i]));
    g.lineTo(colX(N - 1), h - PADB); g.closePath();
    const grad = g.createLinearGradient(0, PADT, 0, h - PADB);
    grad.addColorStop(0, hexA(phos, 0.30)); grad.addColorStop(1, hexA(phos, 0.03));
    g.fillStyle = grad; g.fill();

    g.beginPath();
    for (let i = 0; i < N; i++) { const x = colX(i), y = valY(vals[i]); if (i === 0) g.moveTo(x, y); else g.lineTo(x, y); }
    g.strokeStyle = phos; g.lineWidth = 2.2; g.lineJoin = 'round'; g.stroke();

    // handles (param-coloured; the keyboard-active one ringed)
    for (let i = 0; i < N; i++) {
      const x = colX(i), y = valY(vals[i]);
      g.fillStyle = tint; g.beginPath(); g.arc(x, y, 6, 0, Math.PI * 2); g.fill();
      g.fillStyle = 'rgba(255,255,255,.85)'; g.beginPath(); g.arc(x, y, 2.4, 0, Math.PI * 2); g.fill();
      if (i === active) { g.strokeStyle = PHOS_INK; g.lineWidth = 1.6; g.beginPath(); g.arc(x, y, 9, 0, Math.PI * 2); g.stroke(); }
    }
  }

  function paintCode() {
    if (!curSection()) { codeEl.textContent = ''; return; }
    const P = curParam();
    const pre = `s("${curSection().toLowerCase()}").${P.clause}(${P.arg}: `;
    codeEl.innerHTML = '';
    const a = document.createElement('span'); a.className = 'autolane-code-dim'; a.textContent = pre;
    const b = document.createElement('span'); b.className = 'autolane-code-val'; b.textContent = signalExpr();
    const c = document.createElement('span'); c.className = 'autolane-code-dim'; c.textContent = ')';
    codeEl.appendChild(a); codeEl.appendChild(b); codeEl.appendChild(c);
  }

  // ---- playhead tick ----
  let phTimer = null;
  function tick() {
    const eng = opts.engine();
    let col = -1;
    if (eng && opts.isPlaying() && N > 0) col = ((Math.floor(eng.currentCycle()) % N) + N) % N;
    if (col !== phCol) { phCol = col; paint(); }
  }

  function refresh() { loadParams(); readModel(); reflect(); paintAll(); }
  function start() { if (!phTimer) phTimer = setInterval(tick, 90); }
  function stop() { if (phTimer) { clearInterval(phTimer); phTimer = null; } phCol = -1; }

  build();
  refresh();

  return {
    el, refresh, start, stop,
    // verification hooks (headless drive)
    _sections: () => sections.map((s) => s.name),
    _selectSection: (name) => { const i = sections.findIndex((s) => s.name === name); if (i >= 0) selectSection(i); },
    _selectParam: (i) => selectParam(i),
    _drawCurve: (arr, sh) => { vals = arr.slice(); N = vals.length; active = Math.min(active, N - 1); if (sh != null) shape = sh; writeCoin(); paintAll(); return opts.getDoc(); },
    _signalExpr: () => signalExpr(),
    _plotEl: () => plot, _canvasEl: () => canvas,
    _state: () => ({ section: curSection(), param: p, shape, N, vals: vals.slice(), auto: autoSet.slice() }),
  };
}

function clamp01(x) { return Math.max(0, Math.min(1, x)); }
function roundRect(g, x, y, w, h, r) {
  g.beginPath();
  g.moveTo(x + r, y); g.arcTo(x + w, y, x + w, y + h, r); g.arcTo(x + w, y + h, x, y + h, r);
  g.arcTo(x, y + h, x, y, r); g.arcTo(x, y, x + w, y, r); g.closePath();
}
// "#rrggbb" + alpha -> rgba() string
function hexA(hex, a) {
  const h = hex.replace('#', '');
  const r = parseInt(h.slice(0, 2), 16), gg = parseInt(h.slice(2, 4), 16), b = parseInt(h.slice(4, 6), 16);
  return `rgba(${r},${gg},${b},${a})`;
}
