// ===========================================================================
//  fxrack.js — the FX RACK CONSOLE (the web twin of native src/app/FxRackView.h).
//
//  Native's FxRackView is the in-app door to every effect world for the SELECTED track:
//  a grid of gooey tiles, one per effect, lit in its signature colour. Tap a tile → its
//  minigame opens. On web we go one better and make it a CHAIN console: the tiles ARE the
//  effect chain on the current `## SECTION` (`.reverb(...).delay(...)...`), shown IN ORDER,
//  each a signature-coloured tile with the fx.js per-effect world glyph + its live first-param
//  readout. You can TAP a tile to edit it, ADD an effect (appends a defaulted call), REMOVE a
//  tile (deletes that call), and REORDER tiles (reorders the calls) — every op REWRITES the
//  document text (the coin) byte-preserving the rest, then the engine hot-swaps so it's HEARD.
//
//  THE COIN (round-trip safe): all edits reuse the fx.js splice machinery — findEffectCall's
//  balanced-paren scan, buildClause (named-arg, native number format) for a defaulted add, and
//  a byte-preserving splice for add/remove/reorder. The chain is always DERIVED from the doc, so
//  a hand-edited section reads back correctly and nothing else in the file is touched.
//
//  The PURE half (parseSections / parseChain / addEffect / removeEffect / moveEffect /
//  reorderChain / defaultClauseFor) imports nothing DOM-y and runs in Node, so web/verify.js can
//  assert the chain parse + add/remove/reorder rewrites headlessly. The DOM half (createFxRack)
//  is browser-only.
//
//  INPUT-AGNOSTIC (docs/web-interaction.md): tiles are focusable buttons (tap = edit, keyboard
//  Enter/Space too); REORDER works via a pointer/touch drag (Pointer Events + setPointerCapture,
//  occlusion-safe bubble ABOVE the finger) AND a keyboard/no-drag path (explicit ◀ ▶ move buttons
//  on every tile, plus Ctrl+Arrow on a focused tile); ADD + REMOVE are always-visible real buttons
//  (never hover-gated); every target is ~44px.
// ===========================================================================
import { FX_DESCRIPTORS, FX_CALL_NAMES, WORLDS, parseArgs, buildClause, paramNorm, paramFormat } from './fx.js';
import { attachActivate, showValueBubble, hideValueBubble } from './gesture.js';
import { PHOS, PAD_TINTS as TINTS } from './palette.js';
import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

// A synthetic descriptor for the grain/chop tile — native's FxRackView carries a "grain" tile
// whose world is the Grain Garden. We show a chop chain as a tile too, but route its EDIT to the
// garden (createGarden), not the fx editor. It is not ADDable here (the garden owns chop authoring).
export const GRAIN_DESC = { id: 'grain', title: 'Grain', sub: 'THE GARDEN', color: PHOS, world: null };

// name of a chain call -> its descriptor (fx.js effects + chop).
function descFor(name) { return name === 'chop' ? GRAIN_DESC : (FX_CALL_NAMES[name] || null); }

// The effects the ADD menu offers, in native FxRackView's tile order (grain excluded — it is
// authored in the Grain Garden). Each: { id, title, color }.
export const ADDABLE = ['reverb', 'delay', 'drive', 'filter', 'crush', 'trem', 'ring', 'autopan',
                        'fold', 'chorus', 'punch', 'phaser', 'tilt']
  .filter((id) => FX_DESCRIPTORS[id])
  .map((id) => ({ id, title: FX_DESCRIPTORS[id].title, sub: FX_DESCRIPTORS[id].sub, color: FX_DESCRIPTORS[id].color }));

// ---- parse the `## NAME` sections into [{ name, headerStart, bodyStart, bodyEnd }] ------------
// A section body runs from just after its header line to the start of the next `## ` header (or EOF).
// The globals preamble (before the first `##`) is not a section (native's rack only lists tracks).
export function parseSections(doc) {
  const out = [];
  const re = /^##[ \t]+(\S[^\n]*?)[ \t]*$/gm;
  let m, prev = null;
  while ((m = re.exec(doc)) !== null) {
    if (prev) prev.bodyEnd = m.index;
    prev = { name: m[1].trim(), headerStart: m.index, bodyStart: m.index + m[0].length, bodyEnd: doc.length };
    out.push(prev);
  }
  return out;
}

function findSection(doc, sectionName) {
  const secs = parseSections(doc);
  const want = String(sectionName);
  return secs.find((s) => s.name === want) || secs.find((s) => s.name.toLowerCase() === want.toLowerCase()) || null;
}

// ---- parse the effect chain on a section: the ordered TOP-LEVEL fx (+ chop) calls in its body ----
// Returns { section, calls: [{ id, callName, callStart, callEnd, argStr, descriptor, isGrain }] } (calls
// in document order), or null if the section isn't found. Nested calls inside an fx's args (e.g. the
// sine.slow(4).range(...) inside .lpf(...)) are NOT chain tiles — the containment filter drops them.
export function parseChain(doc, sectionName) {
  const section = findSection(doc, sectionName);
  if (!section) return null;
  const calls = [];
  const re = /\.([A-Za-z_][A-Za-z0-9_]*)\s*\(/g;
  re.lastIndex = section.bodyStart;
  let m, lastKeptEnd = section.bodyStart;
  while ((m = re.exec(doc)) !== null) {
    if (m.index >= section.bodyEnd) break;
    const name = m[1];
    const desc = descFor(name);
    if (!desc) continue;
    // find the matching ')'
    let depth = 0, j = m.index + m[0].length - 1, close = -1;
    for (; j < doc.length; j++) {
      const c = doc[j];
      if (c === '(') depth++;
      else if (c === ')') { if (--depth === 0) { close = j; break; } }
    }
    if (close < 0) continue;
    const callStart = m.index, callEnd = close + 1;
    if (callStart < lastKeptEnd) continue;        // nested inside a kept call's args — not a chain tile
    if (callEnd > section.bodyEnd) continue;       // runs past the section — ignore
    calls.push({ id: desc.id, callName: name, callStart, callEnd,
                 argStr: doc.slice(m.index + m[0].length, close), descriptor: desc, isGrain: name === 'chop' });
    lastKeptEnd = callEnd;
  }
  return { section, calls };
}

// The default clause for an ADD: fx.js buildClause with the descriptor's defaults (named args,
// native number format), e.g. `.reverb(mix: 0.50, size: 0.72, …)`. Immediately editable + audible.
export function defaultClauseFor(fxId) {
  const desc = FX_DESCRIPTORS[fxId];
  if (!desc) return '';
  const callName = desc.variants ? desc.defaultVariant : desc.id;
  return buildClause(desc, callName, parseArgs(desc, ''));
}

// ADD an effect to the section's chain: append `.fx(defaults)` after the last chain call (or, if the
// chain is empty, after the last non-whitespace char of the section body — i.e. right after the
// source expression). Byte-preserves everything else. Returns the new doc (unchanged if impossible).
export function addEffect(doc, sectionName, fxId) {
  const ch = parseChain(doc, sectionName);
  if (!ch) return doc;
  const clause = defaultClauseFor(fxId);
  if (!clause) return doc;
  let insertAt;
  if (ch.calls.length) insertAt = ch.calls[ch.calls.length - 1].callEnd;
  else {
    let e = ch.section.bodyEnd;
    while (e > ch.section.bodyStart && /\s/.test(doc[e - 1])) e--;
    if (e <= ch.section.bodyStart) return doc;   // empty body — nothing to chain onto
    insertAt = e;
  }
  return doc.slice(0, insertAt) + clause + doc.slice(insertAt);
}

// REMOVE a chain call: delete its [callStart, callEnd) span, byte-preserving the rest.
export function removeEffect(doc, call) {
  if (!call) return doc;
  return doc.slice(0, call.callStart) + doc.slice(call.callEnd);
}

// REORDER: rebuild the chain slots so slot k holds the call-text of calls[order[k]]. Slots are the
// existing call spans (their positions, incl. any inter-call transform like `.fast(2)`, are kept);
// only WHICH call-text sits in each slot changes. Splicing right-to-left keeps earlier offsets valid,
// so everything outside the chain is byte-preserved. `order` is a permutation of 0..N-1.
export function reorderChain(doc, calls, order) {
  const texts = calls.map((c) => doc.slice(c.callStart, c.callEnd));
  let out = doc;
  for (let k = calls.length - 1; k >= 0; k--) {
    const slot = calls[k];
    out = out.slice(0, slot.callStart) + texts[order[k]] + out.slice(slot.callEnd);
  }
  return out;
}

// MOVE the call at index fromIdx to index toIdx (0-based, within the chain). Returns the new doc.
export function moveEffect(doc, calls, fromIdx, toIdx) {
  const n = calls.length;
  if (fromIdx < 0 || fromIdx >= n || toIdx < 0 || toIdx >= n || fromIdx === toIdx) return doc;
  const order = [];
  for (let i = 0; i < n; i++) order.push(i);
  const [f] = order.splice(fromIdx, 1);
  order.splice(toIdx, 0, f);
  return reorderChain(doc, calls, order);
}

// =============================================================================
//  DOM console (browser only). A design-bar overlay: header + section chips + the tile grid
//  (chain in order) + an ADD tile. `opts`:
//    host, getDoc(), applyDoc(text), sectionName, sectionNames()  (the ## sections, for the chips)
//    onEditCall({ callStart, isGrain })  — open the tapped tile's editor (fx editor / garden)
//    onClose(), setStatus(s)
// =============================================================================
export function createFxRack(opts) {
  let sectionName = opts.sectionName;

  const scrim = el('div', 'fx-scrim fxrack-scrim');
  const card = el('div', 'fx-card fxrack-card');
  scrim.appendChild(card);

  // header
  const head = el('div', 'fx-head');
  const dot = el('span', 'fx-dot'); dot.style.background = '#7fe0b0';
  const titles = el('div', 'fx-titles');
  const h = el('div', 'fx-title'); h.textContent = 'FX rack';
  const sub = el('div', 'fx-sub');
  titles.appendChild(h); titles.appendChild(sub);
  const close = el('button', 'fx-close'); close.type = 'button'; close.textContent = '×';
  close.setAttribute('aria-label', 'close');
  head.appendChild(dot); head.appendChild(titles); head.appendChild(close);
  card.appendChild(head);

  // section chips (pick which ## section's chain to manage — the track-select surface)
  const chips = el('div', 'fxrack-chips');
  card.appendChild(chips);

  // the tile grid (chain in order + an ADD tile)
  const grid = el('div', 'fxrack-grid');
  card.appendChild(grid);

  // the ADD picker (a menu of addable effects), toggled by the ADD tile
  const picker = el('div', 'fxrack-picker hidden');
  card.appendChild(picker);

  // affordance hint (every action reachable without hover)
  const hint = el('div', 'fx-hint');
  hint.textContent = 'tap a tile to edit · drag or ◀ ▶ to reorder · + to add · × to remove';
  card.appendChild(hint);

  opts.host.appendChild(scrim);

  let pickerOpen = false;

  // close on × / scrim / Escape — all via the ONE shared overlay manager (overlay.js). Escape first
  // closes the ADD-picker sub-state (onEscape returns true = handled) before it closes the rack.
  const overlay = registerOverlay(scrim, {
    panel: card,
    closeButtons: [close],
    label: 'FX rack',
    onEscape: () => { if (pickerOpen) { closePicker(); return true; } return false; },
    onClose: () => { teardown(); if (opts.onClose) opts.onClose(); },
  });
  overlay.open();

  render();

  // ------- section chips -------
  function renderChips() {
    chips.innerHTML = '';
    const names = (opts.sectionNames && opts.sectionNames()) || [];
    if (names.length <= 1) { chips.classList.add('hidden'); return; }
    chips.classList.remove('hidden');
    names.forEach((nm, i) => {
      const c = el('button', 'fxrack-chip' + (nm === sectionName ? ' on' : ''));
      c.type = 'button'; c.textContent = nm; c.title = nm;
      c.style.setProperty('--tint', TINTS[i % TINTS.length]);
      attachActivate(c, () => { if (nm !== sectionName) { sectionName = nm; closePicker(); render(); } });
      chips.appendChild(c);
    });
  }

  // ------- the tile grid -------
  function render() {
    renderChips();
    const ch = parseChain(opts.getDoc(), sectionName);
    const calls = ch ? ch.calls : [];
    sub.textContent = 'SECTION · ' + String(sectionName || '').toUpperCase();
    grid.innerHTML = '';
    if (!calls.length) {
      const empty = el('div', 'fxrack-empty');
      empty.textContent = 'no effects on this section yet — tap + to add one';
      grid.appendChild(empty);
    }
    calls.forEach((call, i) => grid.appendChild(tile(call, i, calls.length)));
    grid.appendChild(addTile());
  }

  function tile(call, i, total) {
    const desc = call.descriptor;
    const row = el('div', 'fxrack-tile');
    row.style.setProperty('--fx', desc.color);
    row.dataset.idx = String(i);

    // the tap-to-edit FACE (name + world glyph + first-param readout). A tap edits; a drag reorders.
    const face = el('button', 'fxrack-face'); face.type = 'button';
    face.setAttribute('aria-label', desc.title + ' — tap to edit, drag to reorder');
    const cv = document.createElement('canvas'); cv.className = 'fxrack-glyph';
    const meta = el('div', 'fxrack-meta');
    const nm = el('div', 'fxrack-name'); nm.textContent = desc.title;
    const st = el('div', 'fxrack-state'); st.textContent = tileReadout(desc, call.argStr);
    meta.appendChild(nm); meta.appendChild(st);
    face.appendChild(cv); face.appendChild(meta);
    drawGlyph(cv, desc, call.argStr);

    // reorder + remove bar (real focusable buttons — the keyboard/no-drag path, always visible)
    const bar = el('div', 'fxrack-bar');
    const left = iconBtn('◀', 'move ' + desc.title + ' left', i === 0);
    const right = iconBtn('▶', 'move ' + desc.title + ' right', i === total - 1);
    const del = iconBtn('×', 'remove ' + desc.title, false, 'fxrack-del');
    if (i > 0) attachActivate(left, () => doMove(i, i - 1));
    if (i < total - 1) attachActivate(right, () => doMove(i, i + 1));
    attachActivate(del, () => doRemove(i));
    bar.appendChild(left); bar.appendChild(right); bar.appendChild(del);

    row.appendChild(face);
    row.appendChild(bar);

    // TAP = edit, DRAG = reorder (one Pointer-Events path with a movement threshold + capture)
    wireTileGesture(face, row, i);
    // keyboard reorder on the focused face: Ctrl+Arrow moves the tile (belt-and-suspenders with ◀ ▶)
    face.addEventListener('keydown', (e) => {
      if (!(e.ctrlKey || e.metaKey)) return;
      if (e.key === 'ArrowLeft' && i > 0) { e.preventDefault(); doMove(i, i - 1); }
      else if (e.key === 'ArrowRight' && i < total - 1) { e.preventDefault(); doMove(i, i + 1); }
    });
    return row;
  }

  function addTile() {
    const t = el('button', 'fxrack-tile fxrack-add'); t.type = 'button';
    t.setAttribute('aria-label', 'add an effect');
    const plus = el('div', 'fxrack-plus'); plus.textContent = '+';
    const lbl = el('div', 'fxrack-addlbl'); lbl.textContent = 'ADD FX';
    t.appendChild(plus); t.appendChild(lbl);
    attachActivate(t, () => togglePicker());
    return t;
  }

  // ------- the ADD picker -------
  function togglePicker() { pickerOpen ? closePicker() : openPicker(); }
  function openPicker() {
    pickerOpen = true;
    picker.classList.remove('hidden');
    picker.innerHTML = '';
    const cap = el('div', 'fxrack-picker-cap'); cap.textContent = 'ADD AN EFFECT';
    picker.appendChild(cap);
    const wrap = el('div', 'fxrack-picker-grid');
    ADDABLE.forEach((a) => {
      const b = el('button', 'fxrack-pick'); b.type = 'button'; b.title = a.sub;
      b.style.setProperty('--fx', a.color);
      const d = el('span', 'fxrack-pick-dot');
      const n = el('span', 'fxrack-pick-name'); n.textContent = a.title;
      b.appendChild(d); b.appendChild(n);
      attachActivate(b, () => { doAdd(a.id); });
      wrap.appendChild(b);
    });
    picker.appendChild(wrap);
  }
  function closePicker() { pickerOpen = false; picker.classList.add('hidden'); }

  // ------- the ops (the coin): each rewrites the doc + hot-swaps, then re-renders from the doc -------
  function doAdd(fxId) {
    const nd = addEffect(opts.getDoc(), sectionName, fxId);
    if (nd !== opts.getDoc()) { opts.applyDoc(nd); if (opts.setStatus) opts.setStatus('added ' + fxId + ' to ' + sectionName); }
    closePicker(); render();
  }
  function doRemove(i) {
    const ch = parseChain(opts.getDoc(), sectionName);
    if (!ch || !ch.calls[i]) return;
    const name = ch.calls[i].callName;
    opts.applyDoc(removeEffect(opts.getDoc(), ch.calls[i]));
    if (opts.setStatus) opts.setStatus('removed ' + name + ' from ' + sectionName);
    render();
  }
  function doMove(from, to) {
    const ch = parseChain(opts.getDoc(), sectionName);
    if (!ch) return;
    const nd = moveEffect(opts.getDoc(), ch.calls, from, to);
    if (nd !== opts.getDoc()) { opts.applyDoc(nd); if (opts.setStatus) opts.setStatus('reordered ' + sectionName + ' chain'); }
    render();
    // keep focus near the moved tile for keyboard users
    const faces = grid.querySelectorAll('.fxrack-face');
    if (faces[to]) faces[to].focus();
  }
  function doEdit(i) {
    const ch = parseChain(opts.getDoc(), sectionName);
    if (!ch || !ch.calls[i]) return;
    if (opts.onEditCall) opts.onEditCall({ callStart: ch.calls[i].callStart, isGrain: ch.calls[i].isGrain });
  }

  // ------- tile pointer gesture: tap = edit, drag = reorder (occlusion-safe, capture) -------
  function wireTileGesture(face, row, index) {
    let downX = 0, downY = 0, dragging = false, pid = null;
    const THRESH = 8;
    const onDown = (e) => {
      if (e.button != null && e.button !== 0) return;
      pid = e.pointerId; downX = e.clientX; downY = e.clientY; dragging = false;
      try { face.setPointerCapture(pid); } catch (_) {}
    };
    const onMove = (e) => {
      if (pid == null) return;
      if (!dragging && Math.abs(e.clientX - downX) + Math.abs(e.clientY - downY) < THRESH) return;
      dragging = true;
      row.classList.add('dragging');
      showValueBubble(e.clientX, e.clientY, 'move');
      showDropMarker(e.clientX);
    };
    const onUp = (e) => {
      if (pid == null) return;
      try { face.releasePointerCapture(pid); } catch (_) {}
      pid = null;
      if (dragging) {
        row.classList.remove('dragging');
        hideValueBubble();
        const ins = dropIndex(e.clientX);           // desired insert slot 0..N
        const to = ins > index ? ins - 1 : ins;
        clearDropMarker();
        doMove(index, Math.max(0, Math.min(to, tileCount() - 1)));
      } else {
        doEdit(index);                               // a plain tap edits
      }
    };
    face.addEventListener('pointerdown', onDown);
    face.addEventListener('pointermove', onMove);
    face.addEventListener('pointerup', onUp);
    face.addEventListener('pointercancel', () => { pid = null; dragging = false; row.classList.remove('dragging'); hideValueBubble(); clearDropMarker(); });
    // keyboard activate (Enter/Space) = edit — a tile is a real button
    face.addEventListener('keydown', (e) => {
      if ((e.key === 'Enter' || e.key === ' ' || e.key === 'Spacebar') && !e.ctrlKey && !e.metaKey) { e.preventDefault(); doEdit(index); }
    });
  }

  function tiles() { return Array.from(grid.querySelectorAll('.fxrack-tile:not(.fxrack-add)')); }
  function tileCount() { return tiles().length; }
  // the insert slot (0..N) for a pointer X: the first tile whose horizontal centre the pointer is left of.
  function dropIndex(clientX) {
    const ts = tiles();
    for (let i = 0; i < ts.length; i++) {
      const r = ts[i].getBoundingClientRect();
      if (clientX < r.left + r.width / 2) return i;
    }
    return ts.length;
  }
  let marker = null;
  function showDropMarker(clientX) {
    const ts = tiles();
    const ins = dropIndex(clientX);
    if (!marker) { marker = el('div', 'fxrack-drop'); grid.appendChild(marker); }
    const ref = ts[ins];
    const gridR = grid.getBoundingClientRect();
    if (ref) { const r = ref.getBoundingClientRect(); marker.style.left = (r.left - gridR.left - 4) + 'px'; marker.style.top = (r.top - gridR.top) + 'px'; marker.style.height = r.height + 'px'; }
    else if (ts.length) { const r = ts[ts.length - 1].getBoundingClientRect(); marker.style.left = (r.right - gridR.left + 2) + 'px'; marker.style.top = (r.top - gridR.top) + 'px'; marker.style.height = r.height + 'px'; }
    marker.classList.add('show');
  }
  function clearDropMarker() { if (marker) marker.classList.remove('show'); }

  let torn = false;
  function teardown() {
    if (torn) return; torn = true;
    if (scrim.parentNode) scrim.parentNode.removeChild(scrim);
  }
  const destroy = () => overlay.close();

  return {
    el: scrim,
    destroy,
    refresh: () => render(),
    // verification hooks (headless drive)
    _section: () => sectionName,
    _setSection: (nm) => { sectionName = nm; render(); },
    _tiles: () => { const ch = parseChain(opts.getDoc(), sectionName); return ch ? ch.calls.map((c) => ({ id: c.id, callName: c.callName, isGrain: c.isGrain })) : []; },
    _add: (id) => { doAdd(id); return opts.getDoc(); },
    _remove: (i) => { doRemove(i); return opts.getDoc(); },
    _move: (a, b) => { doMove(a, b); return opts.getDoc(); },
    _edit: (i) => { doEdit(i); },
    _tapAdd: () => { togglePicker(); return pickerOpen; },
    _pickerIds: () => ADDABLE.map((a) => a.id),
  };
}

// ---- tile presentation helpers -------------------------------------------------
// TINTS is the ONE shared pad-tint ramp (./palette.js), matched to PADS / COMPOSE / the mixer.

// a compact readout of the tile's first param (the "mini state glyph" text), e.g. "MIX 0.35".
function tileReadout(desc, argStr) {
  if (!desc.id || !FX_DESCRIPTORS[desc.id]) return desc.sub || '';
  const d = FX_DESCRIPTORS[desc.id];
  const st = parseArgs(d, argStr);
  const p = d.params[0], s = st[0];
  if (!p || !s) return desc.sub || '';
  if (!s.touched && s.raw != null) return p.label + ' env';
  return p.label + ' ' + paramFormat(p, s.value) + (p.unit === 'hz' ? ' Hz' : '');
}

// draw one STATIC frame of the effect's fx.js world onto the tile glyph canvas (native tile motif).
function drawGlyph(canvas, desc, argStr) {
  const world = desc.world && WORLDS[desc.world] ? WORLDS[desc.world] : null;
  const dpr = Math.min(2, (typeof window !== 'undefined' && window.devicePixelRatio) || 1);
  const w = 48, hgt = 40;
  canvas.width = w * dpr; canvas.height = hgt * dpr;
  canvas.style.width = w + 'px'; canvas.style.height = hgt + 'px';
  const ctx = canvas.getContext('2d');
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, w, hgt);
  if (world) {
    const d = FX_DESCRIPTORS[desc.id];
    const P = {};
    const st = parseArgs(d, argStr);
    d.params.forEach((p, i) => { P[p.key] = st[i].touched ? paramNorm(p, st[i].value) : st[i].norm; });
    try { world(ctx, w, hgt, P, desc.color, 0.6, d.variants ? d.defaultVariant : d.id); } catch (_) {}
  } else {
    // grain/chop fallback: a soft signature blob
    ctx.fillStyle = desc.color;
    ctx.globalAlpha = 0.85; ctx.beginPath(); ctx.arc(w / 2, hgt / 2, 8, 0, Math.PI * 2); ctx.fill();
    ctx.globalAlpha = 0.3; ctx.beginPath(); ctx.arc(w / 2, hgt / 2, 15, 0, Math.PI * 2); ctx.fill();
    ctx.globalAlpha = 1;
  }
}

function iconBtn(txt, aria, disabled, extra) {
  const b = document.createElement('button');
  b.type = 'button'; b.className = 'fxrack-icon' + (extra ? ' ' + extra : '') + (disabled ? ' disabled' : '');
  b.textContent = txt; b.title = aria; b.setAttribute('aria-label', aria);
  if (disabled) { b.disabled = true; b.tabIndex = -1; }
  return b;
}

function el(tag, cls) { const e = document.createElement(tag); if (cls) e.className = cls; return e; }
