// CompKind (src/core/lang/CompletionProvider.h) -> a CM icon type + a short glyph label.
const KIND = ['source', 'keyword', 'transform', 'signal', 'sound', 'scale', 'voice', 'method'];
function kindType(k) {
  switch (k) {
    case 0: return 'variable';   // source s
    case 1: return 'keyword';
    case 2: return 'function';   // transform
    case 3: return 'function';   // signal
    case 4: return 'text';       // sound name
    case 5: return 'enum';       // scale
    case 6: return 'class';      // voice source
    case 7: return 'method';
    default: return 'text';
  }
}

