// ---- the channel-strip MIX model (native RackModel::muted/soloed) — mute/solo is a SEPARATE model
// (not code; the LEVEL/PAN half lives in the doc as .gain/.pan). Lowercased section-name sets, fed
// to the engine's WebEngine::setMix (filters which sections compile; solo overrides the arrangement),
// persisted with the session (autosave/projects) and captured in each history snapshot — parity with
// native mixState() / applyMixState(). ----
const mix = { muted: new Set(), soloed: new Set() };
function mixCsv(set) { return Array.from(set).join(','); }
// Push the current mute/solo to the engine + re-eval so it's HEARD (hot-swap while playing).
function applyMixToEngine() {
  if (!eng) return;
  eng.setMix(mixCsv(mix.muted), mixCsv(mix.soloed));
  if (playing) reflectError(eng.updateDocument(docText()));   // click-free recompile with the new mix
}
// Serialize / restore the mix as name arrays (persisted in snapshots + history). Native mixState().
function serializeMix() { return { muted: Array.from(mix.muted), soloed: Array.from(mix.soloed) }; }
function applyMix(saved) {
  mix.muted.clear(); mix.soloed.clear();
  if (saved) {
    for (const n of saved.muted || []) mix.muted.add(String(n).toLowerCase());
    for (const n of saved.soloed || []) mix.soloed.add(String(n).toLowerCase());
  }
  applyMixToEngine();
  if (trackrack) trackrack.refresh();
}
function toggleMute(name) {
  const k = String(name).toLowerCase();
  if (mix.muted.has(k)) mix.muted.delete(k); else mix.muted.add(k);
  applyMixToEngine();
  if (trackrack) trackrack.refresh();
  scheduleAutosave();
  setStatus((mix.muted.has(k) ? 'muted ' : 'unmuted ') + escapeHtml(name), '');
}
function toggleSolo(name) {
  const k = String(name).toLowerCase();
  if (mix.soloed.has(k)) mix.soloed.delete(k); else mix.soloed.add(k);
  applyMixToEngine();
  if (trackrack) trackrack.refresh();
  scheduleAutosave();
  setStatus((mix.soloed.has(k) ? 'soloed ' : 'unsoloed ') + escapeHtml(name), '');
}
