function cycloCompletionSource(context) {
  if (!eng) return null;
  const doc = context.state.doc.toString();
  const caret = context.pos;
  let res;
  try { res = JSON.parse(eng.complete(doc, caret)); } catch (e) { return null; }
  if (!res.items.length && !res.showOnEmpty) return null;
  // Only auto-open on an explicit trigger (dot / string / non-empty prefix); avoid noise.
  if (!context.explicit && !res.showOnEmpty && res.prefix.length === 0) return null;

  const from = caret - res.prefix.length;
  const options = res.items.map((it) => ({
    label: it.label,
    detail: it.signature || undefined,
    info: it.doc || undefined,
    type: kindType(it.kind),
    boost: 0,
    apply: (v, comp, fromPos, toPos) => {
      const insert = it.insert;
      v.dispatch({
        changes: { from: fromPos, to: toPos, insert },
        selection: { anchor: fromPos + insert.length - (it.caretBack || 0) }
      });
      // chain-friendly: after a '.' completion the popup can re-open on next keystroke
    }
  }));
  // filter:false -> show EXACTLY the core's ranked list (do not let CM re-rank/drop items)
  return { from, to: caret, options, filter: false };
}

