// ===========================================================================
//  LOCAL VERSION HISTORY + TIME TRAVEL (native src/app/HistoryStore + HistoryBrowser + UndoLabel).
//  A rolling shelf of document snapshots (the coin/text IS the state — text-only, near-free). The
//  capture policy mirrors native: timed checkpoints ride the autosave tick (throttled to one per
//  kMinGapMs so rapid edits coalesce), boundary captures (eval / save) fire unthrottled, identical
//  code is deduped, empty docs are never stored, and the shelf is capped. The time-travel BROWSER
//  (src/history-browser.js) scrubs/lists the checkpoints; restoring loads that document (the coin,
//  via loadDocument/hot-swap) after snapshotting the CURRENT state first, so it's always reversible.
//  Restoring strikes the Time Traveler medal + its VHS-rewind celebration → 8/8 medals auto-earn.
// ===========================================================================

// The project name at capture time (native records which project a snapshot belonged to).
function currentProjectName() {
  return (($('projName') && $('projName').value) || '').trim() || 'Untitled';
}

// Load the persisted shelf (this build's OWN IndexedDB slot — never the native dev-box .history).
async function loadHistoryState() {
  let text = null;
  if (idbAvailable()) { try { text = await loadHistory(); } catch (e) { text = null; } }
  if (text) histStore.deserialize(text);
  historyReady = true;
  updateHistoryCount();
}

function scheduleHistorySave() {
  if (!idbAvailable()) return;
  if (historySaveTimer) clearTimeout(historySaveTimer);
  historySaveTimer = setTimeout(() => { saveHistory(histStore.serialize()).catch(() => {}); }, 500);
}

function updateHistoryCount() {
  const d = $('historyCount'); if (d) d.textContent = String(histStore.count());
}

function afterHistoryChanged(snap) {
  if (!snap) return;
  updateHistoryCount();
  scheduleHistorySave();
  if (historyBrowser && !$('historySheet').classList.contains('hidden')) historyBrowser.refresh();
}

// Timed checkpoint — ride the autosave tick (throttled to one per kMinGapMs; rapid edits coalesce).
function maybeHistoryCheckpoint() {
  if (!historyReady || !view) return null;
  const snap = histStore.maybeCapture(docText(), snapshotBpm(), currentProjectName(), Date.now(), serializeMix());
  afterHistoryChanged(snap);
  return snap;
}

// Boundary capture — unthrottled (still deduped + never-empty). Fired on eval (PLAY) + project save,
// and to snapshot the CURRENT state before a rewind so restoring never loses work (native parity).
function historyBoundary(label) {
  if (!historyReady || !view) return null;
  const snap = histStore.capture(docText(), snapshotBpm(), currentProjectName(), label || '', Date.now(), serializeMix());
  afterHistoryChanged(snap);
  return snap;
}

// Rewind to a snapshot (the coin): snapshot the current state first (reversible), then LOAD that
// document (text + BPM) and hot-swap the engine so it's HEARD. History is TEXT-ONLY (native model —
// sounds live in the bank / project saves), so the session's samples are kept; only the doc changes.
// Restoring strikes the Time Traveler medal + its VHS-rewind celebration + scores the restore.
function restoreSnapshot(snap) {
  if (!snap || !historyReady) return false;
  const cur = docText();
  if (snap.code === cur) {                          // already on that version — nothing to rewind
    showToast('already on this version', '');
    closeSheet('historySheet');
    return false;
  }
  // 1) snapshot the CURRENT state so the rewind is reversible (native snapshots-before-restore)
  historyBoundary('');
  // 2) load the past document + BPM + MIX (samples untouched — history is the text coin + mute/solo)
  restoreDocText(snap.code, snap.bpm);
  applyMix(snap.mix);                                // restore the snapshot's mute/solo (native parity)
  // 3) UndoLabel feedback: name what the rewind changed (native "undid DRUMS")
  const changed = changedSectionLabel(cur, snap.code);
  showToast('rewound to “' + (snap.label || 'a checkpoint') + '”', changed ? 'changed ' + changed : 'back in time');
  setStatus('rewound to “' + escapeHtml(snap.label || 'a checkpoint') + '”' + (changed ? ' · ' + escapeHtml(changed) : ''), '');
  // 4) Gamification: Time Traveler auto-earns (+ VHS rewind celebration); the restore scores too
  noteScore(Action.VersionRestored);
  awardMedal(Medal.TimeTraveler);
  closeSheet('historySheet');
  scheduleAutosave();
  return true;
}

// Swap the editor document (+ BPM) to a restored version, rebuild the pads, and hot-swap the live
// engine so the rewind is audible. Does NOT touch the sample bank (history is text-only).
function restoreDocText(doc, bpm) {
  if (view && typeof doc === 'string')
    view.dispatch({ changes: { from: 0, to: view.state.doc.length, insert: doc } });
  if (bpm) { $('bpm').value = Math.round(Number(bpm)) || 124; if (eng) eng.setBpm(parseFloat($('bpm').value) || 124); }
  buildPadGrid();
  syncGrooveBaseline();                             // a programmatic doc swap sets the baseline WITHOUT awarding
  if (playing && eng) reflectError(eng.updateDocument(docText()));   // hear the restored state live
}

function setupHistoryBrowser() {
  if (historyBrowser) return;
  historyBrowser = createHistoryBrowser({
    list: () => histStore.list(),
    currentDoc: () => docText(),
    now: () => Date.now(),
    onRestore: (snap) => restoreSnapshot(snap),
    onClose: () => closeSheet('historySheet'),
  });
  const sheet = document.createElement('div');
  sheet.className = 'sheet history-sheet';
  sheet.appendChild(historyBrowser.el);
  $('historySheet').appendChild(sheet);
}

function openHistorySheet() {
  setupHistoryBrowser();
  historyBrowser.refresh();
  openSheet('historySheet');
}

