// ===========================================================================
//  step.js — the STEP grid (the groovebox step-sequencer + mini piano-roll front door).
//
//  The web twin of native src/app/PadGrid STEP mode (MainComponent stepEnter / refreshStepGrid /
//  stepEdit). A labelled matrix: ROWS are your sounds (BEAT source) or pitches (NOTES piano-roll),
//  COLUMNS are the 16 steps of a cycle. Tap/paint a cell to place a hit/note on that step, drag to
//  paint a run along the row, tap a lit cell to clear it. A phosphor playhead column tracks the
//  audible step (currentCycle). Two sources, exactly like native's BEAT | KEYS step toggle:
//    BEAT  : rows = bank sounds  <-> the ## LIVE beat  s("bd - - - , - sn - - , ...")
//    NOTES : rows = scale pitches <-> the ## KEYS melody s("guitar").note("0 - [0,4,7] ...")
//
//  Nothing musical lives in JS. The touch<->code codec is the SHARED pure-core Coin.h, reached
//  through the WASM bridge: the BEAT grid uses liveBodyFor / parseLiveBodyJson (formatLiveBody /
//  parseLiveBody), the NOTES roll reuses the EXACT KEYS coin (keysBodyFor / parseKeysBodyJson) that
//  the KEYS strip writes — so the roll and the strip are two views of ONE ## KEYS section. The
//  grid is always DERIVED from the document (read back before every render), so a hand-edited
//  section that isn't our managed shape becomes read-only (auditions only, never clobbered) — the
//  same "graphics and code are two views of one document" contract as compose.js / melodic.js.
//
//  Input-agnostic (docs/web-interaction.md): ONE Pointer-Events path (down/move/up + capture) on
//  the grid — tap places, drag paints a run within the start row, tap-lit clears — with the shared
//  occlusion-safe readout bubble ABOVE the finger. Every cell is a real focusable <button> so the
//  whole grid is keyboard-operable (Enter/Space toggles, Delete clears, arrows move focus). 44px+
//  cells, touch-action:none, overscroll-behavior:contain.
// ===========================================================================
import { attachActivate, showValueBubble, hideValueBubble } from './gesture.js';

const STEPS = 16;                 // steps per cycle (must match coin::kLiveSteps)
// Row-tint palettes (colour-is-light). BEAT rows use the pad palette; NOTES rows a pitch rainbow.
const BEAT_TINTS = ['#e5573f', '#e0913f', '#d9c04a', '#57c06a', '#33b3ac', '#5b8ed4', '#8a6fd6', '#d46a9e',
                    '#c96a5a', '#c0a04a', '#6ab86a', '#4aa6c9', '#7a86d6', '#c97ab0', '#9aa04a', '#5ac0a0'];
const NOTE_NAMES = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
const noteName = (pc) => NOTE_NAMES[((pc % 12) + 12) % 12];
const noteHue = (pc) => `hsl(${(((pc % 12) + 12) % 12) / 12 * 360}, 62%, 58%)`;

// The NOTES scale cycle (matches melodic.js SCALES / native keysScale) — "" = chromatic.
const SCALES = [
  { value: '', label: 'CHRM' },
  { value: 'major', label: 'MAJ' },
  { value: 'minor', label: 'MIN' },
  { value: 'majpent', label: 'PENT' },
];

// Build the STEP surface into one host element. `opts` (mirrors compose.js / melodic.js):
//   module()        -> the WASM module M (the SHARED coin: liveBodyFor/parseLiveBodyJson/keysBodyFor/…)
//   engine()        -> the live WebEngine (triggerPad / triggerPadPitched / currentCycle)
//   getDoc()        -> current editor document text
//   applyDoc(text)  -> write the new doc (dispatch into CM + hot-swap/play) — main.js owns it
//   ensurePlaying() -> Promise; start audio + transport so a painted beat is HEARD
//   isPlaying()     -> transport running? (drives the playhead)
//   padNames()      -> the ordered bank sound names (BEAT rows)
//   setStatus(s)    -> a status line
export function createStep(opts) {
  const M = opts.module;

  const el = document.createElement('div');
  el.className = 'step-surface';

  const state = {
    source: 'beat',              // 'beat' (## LIVE) | 'notes' (## KEYS piano-roll)
    scaleIdx: 1,                 // NOTES scale (MAJ) — read back from the ## KEYS section on entry
    octave: 0,                   // NOTES octave window (-2..+2)
    sound: 'guitar',             // NOTES instrument (read back from ## KEYS)
  };
  // last-read model: { editable, rows:[{key,label,tint,noteVal?,semi?}], lit:(row,step)->bool, underlay:[bool] }
  let model = { editable: true, rows: [], lit: () => false, underlay: [], sound: '', scale: '' };

  // ---- scale geometry (mirror of melodic.js, shared-core note->semitone) ---------------------
  function scaleValue() { return SCALES[state.scaleIdx].value; }
  function stepsPerOctave() {
    const sc = scaleValue();
    if (!sc) return 12;
    for (let d = 1; d <= 12; d++) if (M().noteToSemitone(sc, d) >= 12) return d;
    return 12;
  }
  function noteRowCount() { return stepsPerOctave() + 1; }       // one octave + the root above
  function octaveBase() { return state.octave * stepsPerOctave(); }
  function semiOf(noteVal) { const sc = scaleValue(); return sc ? M().noteToSemitone(sc, noteVal) : noteVal; }

  // grid <-> the coin wire "step=note,note;step=note" (see bridge parseGridSpec) — NOTES source only.
  function gridObjFromSpec(spec) {
    const g = {};
    if (!spec) return g;
    for (const entry of spec.split(';')) {
      if (!entry) continue;
      const eq = entry.indexOf('='); if (eq < 0) continue;
      const step = parseInt(entry.slice(0, eq), 10);
      const notes = entry.slice(eq + 1).split(',').filter((t) => t.length).map((t) => parseInt(t, 10));
      if (notes.length) g[step] = notes;
    }
    return g;
  }
  function gridSpecFromObj(g) {
    return Object.keys(g).map((k) => parseInt(k, 10)).filter((k) => g[k] && g[k].length).sort((a, b) => a - b)
      .map((k) => k + '=' + g[k].slice().sort((a, b) => a - b).join(',')).join(';');
  }
  // BEAT wire "name=step,step;name=step" (bridge parseLiveSpec) — sound-keyed rows.
  function liveSpecFromObj(g) {
    return Object.keys(g).filter((n) => g[n] && g[n].length)
      .map((n) => n + '=' + g[n].slice().sort((a, b) => a - b).join(',')).join(';');
  }

  // ---- read the current source's section back out of the doc (the single source of truth) ----
  function beatLiveGrid() {
    const body = M().sectionBodyOf(opts.getDoc(), 'LIVE');
    if (!body) return { grid: {}, editable: true };
    const js = M().parseLiveBodyJson(body);
    if (js === 'null') return { grid: {}, editable: false };     // hand-edited: audition only
    const o = JSON.parse(js);
    const grid = {};
    for (const entry of (o.grid || '').split(';')) {
      if (!entry) continue;
      const eq = entry.indexOf('='); if (eq < 0) continue;
      const name = entry.slice(0, eq);
      grid[name] = new Set(entry.slice(eq + 1).split(',').filter((t) => t.length).map((t) => parseInt(t, 10)));
    }
    return { grid, editable: true };
  }
  function keysContent() {
    const body = M().sectionBodyOf(opts.getDoc(), 'KEYS');
    if (!body) return { sound: state.sound, scale: '', grid: {}, editable: true };
    const js = M().parseKeysBodyJson(body);
    if (js === 'null') return { sound: state.sound, scale: '', grid: {}, editable: false };
    const o = JSON.parse(js);
    return { sound: o.sound || state.sound, scale: o.scale || '', grid: gridObjFromSpec(o.grid), editable: true };
  }

  // ---- the coin write: mutate the section, splice it into the doc (bodies elsewhere preserved) ----
  function writeBeat(grid) {
    const spec = liveSpecFromObj(grid);
    const body = M().liveBodyFor(spec);
    opts.applyDoc(M().spliceDocSection(opts.getDoc(), 'LIVE', body));
  }
  function writeKeys(sound, scale, gridObj) {
    const spec = gridSpecFromObj(gridObj);
    const body = M().keysBodyFor(sound, scale, spec);
    opts.applyDoc(M().spliceDocSection(opts.getDoc(), 'KEYS', body));
  }

  // ---- (re)derive the render model from the doc for the active source ----
  function readModel() {
    if (state.source === 'beat') {
      const { grid, editable } = beatLiveGrid();
      const names = opts.padNames();
      const rows = names.map((name, i) => ({ key: name, label: name.toUpperCase(), tint: BEAT_TINTS[i % BEAT_TINTS.length] }));
      model = {
        editable, rows, underlay: [], sound: '', scale: '',
        lit: (r, s) => { const set = grid[rows[r] && rows[r].key]; return !!(set && set.has(s)); },
        _grid: grid,
      };
    } else {
      const kc = keysContent();
      // reflect the section's own sound/scale back onto the chips so the roll matches the code
      state.sound = kc.sound;
      const si = SCALES.findIndex((x) => x.value === kc.scale);
      if (si >= 0) state.scaleIdx = si;
      const n = noteRowCount(), base = octaveBase();
      const rows = [];
      for (let r = 0; r < n; r++) {
        const keyIndex = n - 1 - r;                 // high pitch on top (native roll)
        const noteVal = keyIndex + base;
        const semi = semiOf(noteVal);
        rows.push({ key: String(noteVal), noteVal, semi, label: noteName(semi), tint: noteHue(semi) });
      }
      // underlay: any drum hit per step (place notes ON the beat you already made — native stepUnderlay)
      const under = new Array(STEPS).fill(false);
      const beat = beatLiveGrid().grid;
      for (const name in beat) for (const s of beat[name]) if (s >= 0 && s < STEPS) under[s] = true;
      model = {
        editable: kc.editable, rows, underlay: under, sound: kc.sound, scale: kc.scale,
        lit: (r, s) => { const notes = kc.grid[s]; return !!(notes && rows[r] && notes.includes(rows[r].noteVal)); },
        _grid: kc.grid,
      };
    }
    return model;
  }

  // ---- a cell toggle (paint): trigger the sound now + rewrite the coin, then re-derive + re-render ----
  function paintCell(row, step, on) {
    const rowMeta = model.rows[row];
    if (!rowMeta) return;
    if (state.source === 'beat') {
      if (on && opts.engine()) opts.engine().triggerPad(rowMeta.key);
      if (!model.editable) return;                  // hand-edited: audition only (never clobber)
      const grid = {};
      for (const name in model._grid) grid[name] = new Set(model._grid[name]);
      if (!grid[rowMeta.key]) grid[rowMeta.key] = new Set();
      if (on) grid[rowMeta.key].add(step); else grid[rowMeta.key].delete(step);
      const asArr = {}; for (const n in grid) if (grid[n].size) asArr[n] = Array.from(grid[n]);
      writeBeat(asArr);
    } else {
      if (on && opts.engine()) opts.engine().triggerPadPitched(state.sound, Math.pow(2, rowMeta.semi / 12));
      if (!model.editable) return;
      const grid = {};
      for (const s in model._grid) grid[s] = model._grid[s].slice();
      const arr = grid[step] ? grid[step] : (grid[step] = []);
      const idx = arr.indexOf(rowMeta.noteVal);
      if (on && idx < 0) arr.push(rowMeta.noteVal);
      else if (!on && idx >= 0) arr.splice(idx, 1);
      if (!arr.length) delete grid[step];
      writeKeys(state.sound, scaleValue(), grid);
    }
    readModel(); render();
  }

  // ========================================================================
  //  The pointer gesture — ONE path (mouse / touch / pen), drag paints within the start row.
  // ========================================================================
  let g = null;
  function cellFromPoint(x, y) {
    const el2 = document.elementFromPoint(x, y);
    const c = el2 && el2.closest ? el2.closest('.scell') : null;
    return c && grid.contains(c) ? c : null;
  }
  function onGridDown(e) {
    if (e.button != null && e.button !== 0) return;
    const cell = e.target.closest && e.target.closest('.scell');
    if (!cell || !grid.contains(cell)) return;
    const row = +cell.dataset.row, step = +cell.dataset.step;
    const on = !model.lit(row, step);
    g = { row, on, cy: cell.getBoundingClientRect().top + cell.getBoundingClientRect().height / 2, last: step };
    try { grid.setPointerCapture(e.pointerId); } catch (_) {}
    e.preventDefault();
    paintCell(row, step, on);
    bubble(e.clientX, row, step);
  }
  function onGridMove(e) {
    if (!g) return;
    const cell = cellFromPoint(e.clientX, e.clientY);
    if (!cell) return;
    const row = +cell.dataset.row, step = +cell.dataset.step;
    if (row !== g.row || step === g.last) return;   // stay on the start row (paint a fill); skip repeats
    g.last = step;
    if (model.lit(row, step) !== g.on) paintCell(row, step, g.on);
    bubble(e.clientX, row, step);
  }
  function onGridUp(e) {
    if (!g) return;
    try { grid.releasePointerCapture(e.pointerId); } catch (_) {}
    hideValueBubble();
    g = null;
    opts.ensurePlaying().catch(() => {});           // hear the pattern (start once if stopped)
  }
  function bubble(clientX, row, step) {
    const rm = model.rows[row]; if (!rm || !g) return;
    showValueBubble(clientX, g.cy, `${rm.label} · step ${step + 1}`);
  }

  // ---- keyboard on a focused cell (the whole grid is operable by key) ----
  function onCellKey(e) {
    const cell = e.currentTarget;
    const row = +cell.dataset.row, step = +cell.dataset.step;
    if (e.key === 'Enter' || e.key === ' ' || e.key === 'Spacebar') {
      e.preventDefault(); paintCell(row, step, !model.lit(row, step)); focusCell(row, step); opts.ensurePlaying().catch(() => {});
    } else if (e.key === 'Delete' || e.key === 'Backspace') {
      e.preventDefault(); paintCell(row, step, false); focusCell(row, step);
    } else if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') {
      e.preventDefault(); focusCell(row, Math.max(0, Math.min(STEPS - 1, step + (e.key === 'ArrowRight' ? 1 : -1))));
    } else if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
      e.preventDefault(); focusCell(Math.max(0, Math.min(model.rows.length - 1, row + (e.key === 'ArrowDown' ? 1 : -1))), step);
    }
  }
  function focusCell(row, step) { const c = grid.querySelector(`.scell[data-row="${row}"][data-step="${step}"]`); if (c) c.focus(); }

  // ========================================================================
  //  Rendering
  // ========================================================================
  let bar, scroll, grid, playhead, srcToggle, chipsRow, note;

  function build() {
    el.innerHTML = '';
    bar = document.createElement('div'); bar.className = 'step-bar';
    const title = document.createElement('div'); title.className = 'step-title'; title.textContent = 'Step';
    bar.appendChild(title);

    // BEAT | NOTES source toggle (native's stepSource BEAT|KEYS)
    srcToggle = document.createElement('div'); srcToggle.className = 'step-srctoggle'; srcToggle.setAttribute('role', 'tablist');
    for (const [val, lbl] of [['beat', 'BEAT'], ['notes', 'NOTES']]) {
      const b = document.createElement('button'); b.type = 'button'; b.className = 'step-src'; b.dataset.src = val;
      b.textContent = lbl; b.setAttribute('role', 'tab');
      attachActivate(b, () => setSource(val));
      srcToggle.appendChild(b);
    }
    bar.appendChild(srcToggle);
    el.appendChild(bar);

    // NOTES chips (SOUND / SCALE / OCT) — only shown for the piano-roll source
    chipsRow = document.createElement('div'); chipsRow.className = 'step-chips';
    el.appendChild(chipsRow);

    note = document.createElement('div'); note.className = 'step-note'; note.setAttribute('aria-live', 'polite');
    el.appendChild(note);

    scroll = document.createElement('div'); scroll.className = 'step-scroll';
    grid = document.createElement('div'); grid.className = 'step-grid';
    playhead = document.createElement('div'); playhead.className = 'step-playhead'; playhead.setAttribute('aria-hidden', 'true');
    grid.appendChild(playhead);
    scroll.appendChild(grid);
    el.appendChild(scroll);
    grid.addEventListener('pointerdown', onGridDown);
    grid.addEventListener('pointermove', onGridMove);
    grid.addEventListener('pointerup', onGridUp);
    grid.addEventListener('pointercancel', onGridUp);

    const hint = document.createElement('div'); hint.className = 'step-hint';
    hint.textContent = 'tap a cell to place a hit · drag along a row to paint a run · tap a lit cell to clear · arrows + Enter work too';
    el.appendChild(hint);
  }

  function chip(cap, valueFn, onTap, extraClass) {
    const b = document.createElement('button'); b.type = 'button'; b.className = 'mchip' + (extraClass ? ' ' + extraClass : ''); b.tabIndex = 0;
    const c = document.createElement('span'); c.className = 'mchip-cap'; c.textContent = cap;
    const v = document.createElement('span'); v.className = 'mchip-val'; v.textContent = valueFn();
    b.appendChild(c); b.appendChild(v);
    attachActivate(b, () => onTap());
    return b;
  }
  function buildChips() {
    chipsRow.innerHTML = '';
    if (state.source !== 'notes') { chipsRow.classList.add('hidden'); return; }
    chipsRow.classList.remove('hidden');
    const names = opts.padNames();
    const cycleSound = () => { let i = names.indexOf(state.sound); state.sound = names.length ? names[(i + 1) % names.length] : state.sound; };
    chipsRow.appendChild(chip('SOUND', () => state.sound.toUpperCase(),
      () => { cycleSound(); writeKeys(state.sound, scaleValue(), model._grid); readModel(); render(); }, 'wide'));
    chipsRow.appendChild(chip('SCALE', () => SCALES[state.scaleIdx].label,
      () => { state.scaleIdx = (state.scaleIdx + 1) % SCALES.length; writeKeys(state.sound, scaleValue(), model._grid); readModel(); render(); }));
    chipsRow.appendChild(chip('OCT', () => '−', () => { state.octave = Math.max(-2, state.octave - 1); readModel(); render(); }, 'oct'));
    chipsRow.appendChild(chip('', () => (state.octave > 0 ? '+' : '') + state.octave, () => {}, 'octval'));
    chipsRow.appendChild(chip('OCT', () => '+', () => { state.octave = Math.min(2, state.octave + 1); readModel(); render(); }, 'oct'));
  }

  function setSource(src) {
    if (src === state.source) return;
    state.source = src;
    // if NOTES has no sound yet, seed from the bank (native seeds keysSound from the last pad / bank[0])
    if (src === 'notes') { const n = opts.padNames(); if (!n.includes(state.sound)) state.sound = n.length ? n[0] : 'guitar'; }
    readModel(); render();
  }

  function render() {
    for (const b of srcToggle.querySelectorAll('.step-src')) {
      const on = b.dataset.src === state.source;
      b.classList.toggle('on', on); b.setAttribute('aria-selected', String(on));
    }
    buildChips();
    // the read-only note when the section is hand-edited beyond our managed grid shape
    if (!model.editable) {
      note.classList.remove('hidden');
      note.textContent = state.source === 'beat'
        ? 'LIVE is hand-edited in code — the grid auditions only'
        : 'KEYS is hand-edited in code — the grid auditions only';
    } else if (!model.rows.length) {
      note.classList.remove('hidden');
      note.textContent = state.source === 'beat' ? 'add a sound, then tap steps to build a beat' : 'no notes yet — tap a cell to place one';
    } else { note.classList.add('hidden'); }

    renderGrid();
  }

  function renderGrid() {
    Array.from(grid.children).forEach((c) => { if (c !== playhead) grid.removeChild(c); });
    const rows = model.rows;
    grid.style.gridTemplateColumns = `var(--step-gutter) repeat(${STEPS}, var(--step-col))`;
    grid.style.gridTemplateRows = `repeat(${rows.length}, var(--step-rowh))`;

    rows.forEach((rm, r) => {
      const lbl = document.createElement('div'); lbl.className = 'step-rowlbl';
      lbl.style.setProperty('--tint', rm.tint); lbl.textContent = rm.label; lbl.title = rm.label;
      grid.appendChild(lbl);
      for (let s = 0; s < STEPS; s++) {
        const cell = document.createElement('button');
        cell.type = 'button';
        const lit = model.lit(r, s);
        cell.className = 'scell' + (lit ? ' lit' : ' empty') + (s % 4 === 0 ? ' beat1' : '')
          + (!lit && model.underlay[s] ? ' under' : '');
        cell.dataset.row = String(r); cell.dataset.step = String(s);
        cell.style.setProperty('--tint', rm.tint);
        cell.tabIndex = 0;
        cell.setAttribute('aria-label', `${rm.label} step ${s + 1} ${lit ? 'on' : 'off'}`);
        cell.setAttribute('aria-pressed', String(lit));
        cell.addEventListener('keydown', onCellKey);
        grid.appendChild(cell);
      }
    });
    positionPlayhead();
  }

  // ---- the phosphor playhead: the audible step column while playing ----
  let playStep = -1;
  function positionPlayhead() {
    const show = playStep >= 0 && playStep < STEPS && model.rows.length > 0;
    playhead.style.display = show ? 'block' : 'none';
    if (show) {
      playhead.style.left = `calc(var(--step-gutter) + ${playStep} * var(--step-col))`;
      playhead.style.width = 'var(--step-col)';
    }
    grid.querySelectorAll('.scell.playing').forEach((c) => c.classList.remove('playing'));
    if (show) grid.querySelectorAll(`.scell[data-step="${playStep}"]`).forEach((c) => c.classList.add('playing'));
  }
  let phTimer = null;
  function tick() {
    const eng = opts.engine();
    let s = -1;
    if (eng && opts.isPlaying()) { const cyc = eng.currentCycle(); s = ((Math.floor((cyc - Math.floor(cyc)) * STEPS) % STEPS) + STEPS) % STEPS; }
    if (s !== playStep) { playStep = s; positionPlayhead(); }
  }

  // Public: (re)read the doc + rebuild (called when STEP is shown or the doc changes).
  function refresh() { readModel(); render(); }
  function start() { if (!phTimer) phTimer = setInterval(tick, 60); }
  function stop() { if (phTimer) { clearInterval(phTimer); phTimer = null; } playStep = -1; positionPlayhead(); }

  build();
  refresh();

  return {
    el, refresh, start, stop, state,
    // ---- verification hooks (headless drive) ----
    _model: () => ({ editable: model.editable, rows: model.rows.map((r) => r.label), source: state.source }),
    _setSource: (s) => setSource(s),
    _paint: (row, step, on) => paintCell(row, step, on),   // programmatic paint (writes the coin)
    _lit: (row, step) => model.lit(row, step),
    _rowCount: () => model.rows.length,
  };
}
