// ===========================================================================
//  feed.js — the LIVE FEED (Gamification): a running activity ticker of the maker's
//  real making events (scored actions, medal strikes, celebrations, key-finds…).
//
//  Native cross-reference / honesty note: native src/app/LiveFeed.h is actually the effect-
//  minigame LIVE PULSE (output loudness / cycle phase / note onsets fed to whichever effect
//  world is on screen). The gamification "running activity feed" the web-parity checklist calls
//  for has no native model to port byte-for-byte, so this is a purpose-built web surface that
//  matches native's STYLE + CADENCE (design-bar phosphor, colour-is-light per event, non-
//  intrusive). It is wired ONLY to real events the web already emits (every noteScore award +
//  every Maker Medal strike) — nothing is faked; a feed entry means a making thing actually
//  happened.
//
//  PURE + DOM-FREE + framework-free so it unit-tests in Node (web/verify.js) and drives the UI
//  unchanged. The bounded ring keeps storage tiny; it persists (serialized JSON) in this build's
//  OWN IndexedDB slot so the recent stream survives a reload.
// ===========================================================================
import { Action, actionInfo } from './score.js';
import { PHOS, AMBER, CYAN } from './palette.js';   // shared accent tokens (node-safe: hex fallbacks)

// A short, present-tense headline per scored action (what the maker just DID) — reads as a
// living feed, not a stat table. Order matches the native Action enum (score.js Action).
const ACTION_VERB = {
  [Action.PadTap]: 'finger-drummed a pad',
  [Action.CodeEdit]: 'shaped the code',
  [Action.KeyFound]: 'found the key',
  [Action.GrooveMade]: 'made it groove',
  [Action.HumCaught]: 'caught a hummed tune',
  [Action.GrainGrown]: 'grew a cloud of grains',
  [Action.VersionRestored]: 'rewound time',
  [Action.Export]: 'shipped a track',
  [Action.ChallengeDone]: "took today's dare",
};

// The colour-is-light hue per action (a dim per-event LED tint, matching the design bar's
// colour-is-light language). Kept here so the feed is self-contained + node-testable.
const ACTION_COLOUR = {
  [Action.PadTap]: PHOS,             // phosphor
  [Action.CodeEdit]: AMBER,          // amber — the premium action
  [Action.KeyFound]: CYAN,           // cyan
  [Action.GrooveMade]: '#8fe36b',    // mint
  [Action.HumCaught]: '#ff73b3',     // pink
  [Action.GrainGrown]: '#b7ff5a',    // lime
  [Action.VersionRestored]: '#b07cff',// violet
  [Action.Export]: '#ff9d5c',        // ship orange
  [Action.ChallengeDone]: '#ffd24a', // daily gold
};

export const MEDAL_COLOUR = '#e9edf2'; // chrome-ish — a struck medal is the splash

// Build a feed entry for a scored making action. Pure — the caller supplies the points earned.
// { kind:'action', action, text, points, colour, time }
export function feedEntryForAction(action, points, now) {
  const info = actionInfo(action);
  return {
    kind: 'action',
    action,
    text: (ACTION_VERB[action] || (info ? info.label : 'made something')),
    points: points | 0,
    colour: ACTION_COLOUR[action] || PHOS,
    time: now == null ? Date.now() : now,
  };
}

// Build a feed entry for a Maker Medal strike. `name` is the medal's display name.
export function feedEntryForMedal(name, now) {
  return {
    kind: 'medal',
    text: 'earned the ' + String(name) + ' medal',
    points: 0,
    colour: MEDAL_COLOUR,
    time: now == null ? Date.now() : now,
  };
}

// The running LIVE FEED — a bounded ring of recent making events, newest-first on read.
export class LiveFeed {
  constructor(cap = 80) {
    this.cap_ = Math.max(1, cap | 0);
    this.entries_ = []; // chronological (oldest first); pruned from the front
    this.seq_ = 0;      // monotonic id so the UI can key rows stably
  }

  // Append an event. Assigns a stable monotonic id, prunes the oldest past `cap`. Returns the
  // stored entry (with its id).
  push(entry) {
    const e = Object.assign({ id: ++this.seq_ }, entry);
    if (e.time == null) e.time = Date.now();
    this.entries_.push(e);
    if (this.entries_.length > this.cap_) this.entries_.splice(0, this.entries_.length - this.cap_);
    return e;
  }

  // The stream NEWEST-FIRST (what the panel + rail render).
  list() { return this.entries_.slice().reverse(); }

  // The single most-recent entry (what the ambient rail shows), or null when empty.
  latest() { return this.entries_.length ? this.entries_[this.entries_.length - 1] : null; }

  count() { return this.entries_.length; }
  clear() { this.entries_ = []; }

  // ---- persistence — compact JSON (the ring is small; text-only, so tiny) ----
  serialize() {
    return JSON.stringify({ seq: this.seq_, entries: this.entries_ });
  }

  deserialize(text) {
    this.entries_ = [];
    this.seq_ = 0;
    if (typeof text !== 'string' || !text) return;
    let obj;
    try { obj = JSON.parse(text); } catch (_) { return; } // corrupt blob -> empty feed, never a crash
    if (!obj || !Array.isArray(obj.entries)) return;
    this.seq_ = Number.isFinite(obj.seq) ? obj.seq : 0;
    for (const e of obj.entries) {
      if (e && typeof e === 'object' && typeof e.text === 'string') {
        this.entries_.push(e);
        if (Number.isFinite(e.id) && e.id > this.seq_) this.seq_ = e.id;
      }
    }
    if (this.entries_.length > this.cap_) this.entries_.splice(0, this.entries_.length - this.cap_);
  }
}

// A friendly relative-time string for a feed row (mirrors history.js relativeTime cadence).
export function feedRelativeTime(then, now) {
  const ms = Math.max(0, (now == null ? Date.now() : now) - then);
  const s = Math.floor(ms / 1000);
  if (s < 5) return 'just now';
  if (s < 60) return s + 's ago';
  const m = Math.floor(s / 60);
  if (m < 60) return m + 'm ago';
  const h = Math.floor(m / 60);
  if (h < 24) return h + 'h ago';
  return Math.floor(h / 24) + 'd ago';
}
