// ===========================================================================
//  compose.js — the COMPOSE arrangement timeline (the song-lane / track-rack front door).
//
//  The web twin of native src/app/SongLane + src/app/TrackRack: a horizontal timeline whose
//  ROWS are the document's `## NAME` sections and whose COLUMNS are the looping cycles of the
//  `song = ...` global. Each lit run reads as a draggable BLOCK. Every place/reorder/repeat/
//  remove gesture mutates the SHARED pure-core cyclo::SongPlan (via the WASM bridge composeModel
//  / songSetCell / songSetRun / songMoveRun / songResize / songSeed) and writes the result back
//  into the ONE document's `song = ...` line (setSongLine), byte-preserving the section bodies —
//  the visual edit and the text are the SAME truth. Nothing about the arrangement is
//  re-implemented in JS; the model is the same SongPlan the engine gates sections with.
//
//  Input-agnostic (docs/web-interaction.md): ONE Pointer-Events path (down/move/up + capture) on
//  the grid, tap to place/remove, drag a block to move, drag an edge to resize, all with a shared
//  occlusion-safe readout bubble ABOVE the finger. Every cell is a real focusable <button> so the
//  whole arrangement is keyboard-operable (Enter toggles, Delete clears, arrows move focus,
//  Shift+Arrow extends a block). 44px+ targets, touch-action:none, momentum-safe scroll. A phosphor
//  playhead column tracks the audible cycle while playing.
// ===========================================================================
import { showValueBubble, hideValueBubble } from './gesture.js';
import { PAD_TINTS as TINTS } from './palette.js';

const COLW = 46;        // cycle column width (>= 44px touch target)
const GUTTER = 96;      // the section-label gutter (shared by the ruler + every lane)
const EDGE = 0.26;      // fraction of a block's width at each end that grabs a resize (not a move)
// The section tint palette — colour-is-light (native rack hues); tints the lit LED blocks per row.
// The ONE shared ramp (./palette.js), matched to the mixer / FX rack / PADS.

// Build the COMPOSE surface into one host element. `opts`:
//   module()        -> the WASM module M (the SHARED SongPlan bridge: composeModel / song* / setSongLine)
//   engine()        -> the live WebEngine (currentCycle for the playhead)
//   getDoc()        -> current editor document text
//   applyDoc(text)  -> write the new doc (dispatch into CM + hot-swap when playing) — main.js owns it
//   ensurePlaying() -> Promise; start audio + transport so a fresh arrangement is HEARD (on gesture end)
//   isPlaying()     -> transport running? (drives the playhead)
//   setStatus(s)    -> a status line
export function createCompose(opts) {
  const M = opts.module;

  const el = document.createElement('div');
  el.className = 'compose-surface';

  let model = { song: '', length: 0, sections: [] };   // last composeModel()
  let editableRows = [];                                // sections that can be arranged (row order)

  // ---- the coin write: mutate the SHARED SongPlan value, splice it into the doc's song= line ----
  // Preserves every section body byte-for-byte (only the globals `song = ...` line changes).
  function writeSong(value) {
    const newDoc = M().setSongLine(opts.getDoc(), value);
    opts.applyDoc(newDoc);
  }
  function readModel() {
    try { model = JSON.parse(M().composeModel(opts.getDoc())); }
    catch (e) { model = { song: '', length: 0, sections: [] }; }
    editableRows = model.sections.filter((s) => s.editable);
    return model;
  }

  // ---- geometry: pointer clientX -> a cycle column (scroll-aware, rebuild-safe) ----
  function colAtClientX(clientX) {
    const gridRect = grid.getBoundingClientRect();       // grid is the SCROLLED content
    const xLane = clientX - gridRect.left - GUTTER;
    return Math.max(0, Math.min(model.length - 1, Math.floor(xLane / COLW)));
  }
  function runContaining(mask, col) {
    if (!mask[col]) return null;
    let b = col; while (b > 0 && mask[b - 1]) b--;
    let e = col + 1; while (e < mask.length && mask[e]) e++;
    return { begin: b, end: e };
  }

  // ========================================================================
  //  The pointer gesture (ONE path for mouse / touch / pen) — TrackRack-style blocks.
  //   empty cell : tap places a 1-cycle block; drag paints a block across the crossed cycles.
  //   lit cell   : tap removes that cycle; drag from an edge RESIZES, from the middle MOVES.
  //  Each frame writes the SHARED SongPlan back to the song= line and re-renders the lane.
  // ========================================================================
  let g = null;   // active gesture state

  function onGridDown(e) {
    if (e.button != null && e.button !== 0) return;
    const cell = e.target.closest && e.target.closest('.ccell');
    if (!cell || cell.classList.contains('locked')) return;
    const row = +cell.dataset.row;
    const sec = editableRows[row];
    if (!sec) return;
    const col = colAtClientX(e.clientX);
    const mask = sec.mask.slice();
    const run = runContaining(mask, col);

    let mode, base;
    if (!run) {
      // empty: place now (a tap is a place), and a drag paints a block across the crossed cells
      mode = 'paint';
      base = M().songSetCell(model.song, sec.name, col, true);
    } else {
      // lit: decide edge-resize vs move from where inside the block the press landed
      const runW = (run.end - run.begin) * COLW;
      const gridRect = grid.getBoundingClientRect();
      const px = e.clientX - gridRect.left - GUTTER - run.begin * COLW;
      const frac = runW > 0 ? px / runW : 0.5;
      const len = run.end - run.begin;
      if (len >= 2 && frac < EDGE) mode = 'resizeL';
      else if (len >= 2 && frac > 1 - EDGE) mode = 'resizeR';
      else mode = 'move';
      // base = the plan with this run REMOVED (move/resize re-lay it each frame)
      base = M().songSetRun(model.song, sec.name, run.begin, run.end, false);
    }

    g = { sec: sec.name, row, mode, startCol: col, run, base, moved: false, lastCol: col,
          grabOffset: run ? col - run.begin : 0, cy: cell.getBoundingClientRect().top + cell.getBoundingClientRect().height / 2 };
    try { grid.setPointerCapture(e.pointerId); } catch (_) {}
    e.preventDefault();
    applyGesture(col, e.clientX, e.clientY);
  }

  function onGridMove(e) {
    if (!g) return;
    const col = colAtClientX(e.clientX);
    if (col !== g.lastCol) g.moved = true;
    g.lastCol = col;
    applyGesture(col, e.clientX, e.clientY);
  }

  function onGridUp(e) {
    if (!g) return;
    try { grid.releasePointerCapture(e.pointerId); } catch (_) {}
    hideValueBubble();
    const wasTap = !g.moved;
    const gg = g; g = null;
    if (wasTap) {
      // a tap: place (empty) is already done on down; a tap on a LIT cell REMOVES that cycle
      if (gg.run) writeSong(M().songSetCell(model.song, gg.sec, gg.startCol, false));
    }
    readModel(); render();
    opts.ensurePlaying().then(() => {}).catch(() => {});   // hear the new order (start once if stopped)
  }

  // Apply the active gesture for the pointer now over cycle `col`.
  function applyGesture(col, clientX, clientY) {
    const s = g; if (!s) return;
    const L = model.length;
    let value = s.base, readout = '';
    if (s.mode === 'paint') {
      const lo = Math.min(s.startCol, col), hi = Math.max(s.startCol, col) + 1;
      value = M().songSetRun(s.base, s.sec, lo, hi, true);
      readout = `${s.sec} · cyc ${lo + 1}–${hi}`;
    } else if (s.mode === 'move') {
      const len = s.run.end - s.run.begin;
      const begin = Math.max(0, Math.min(L - len, col - s.grabOffset));
      value = M().songSetRun(s.base, s.sec, begin, begin + len, true);
      readout = `${s.sec} → cyc ${begin + 1}`;
    } else if (s.mode === 'resizeL') {
      const begin = Math.max(0, Math.min(s.run.end - 1, col));
      value = M().songSetRun(s.base, s.sec, begin, s.run.end, true);
      readout = `${s.sec} · ${s.run.end - begin} cyc`;
    } else if (s.mode === 'resizeR') {
      const end = Math.max(s.run.begin + 1, Math.min(L, col + 1));
      value = M().songSetRun(s.base, s.sec, s.run.begin, end, true);
      readout = `${s.sec} · ${end - s.run.begin} cyc`;
    }
    writeSong(value);
    readModel(); renderLanes();
    if (clientX != null) showValueBubble(clientX, s.cy, readout);
  }

  // ---- keyboard on a focused cell (input-agnostic: the whole arrangement is operable by key) ----
  function onCellKey(e) {
    const cell = e.currentTarget;
    const row = +cell.dataset.row, col = +cell.dataset.col;
    const sec = editableRows[row]; if (!sec) return;
    if (e.key === 'Enter' || e.key === ' ' || e.key === 'Spacebar') {
      e.preventDefault();
      writeSong(M().songSetCell(model.song, sec.name, col, !sec.mask[col]));
      after(row, col); opts.ensurePlaying().catch(() => {});
    } else if (e.key === 'Delete' || e.key === 'Backspace') {
      e.preventDefault();
      writeSong(M().songSetCell(model.song, sec.name, col, false));
      after(row, col);
    } else if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') {
      e.preventDefault();
      const dir = e.key === 'ArrowRight' ? 1 : -1;
      if (e.shiftKey && sec.mask[col]) {          // extend the block by one cycle (repeat)
        const run = runContaining(sec.mask.slice(), col);
        if (dir > 0) writeSong(M().songSetRun(model.song, sec.name, run.begin, Math.min(model.length, run.end + 1), true));
        else writeSong(M().songSetRun(model.song, sec.name, Math.max(0, run.begin - 1), run.end, true));
        after(row, Math.max(0, Math.min(model.length - 1, col + dir)));
        opts.ensurePlaying().catch(() => {});
      } else {                                     // move focus along the timeline
        focusCell(row, Math.max(0, Math.min(model.length - 1, col + dir)));
      }
    } else if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
      e.preventDefault();
      const dir = e.key === 'ArrowDown' ? 1 : -1;
      focusCell(Math.max(0, Math.min(editableRows.length - 1, row + dir)), col);
    }
  }
  function after(row, col) { readModel(); render(); focusCell(row, col); opts.ensurePlaying().catch(() => {}); }
  function focusCell(row, col) {
    const c = grid.querySelector(`.ccell[data-row="${row}"][data-col="${col}"]`);
    if (c) c.focus();
  }

  // ========================================================================
  //  Rendering
  // ========================================================================
  let bar, scroll, grid, playhead, emptyState, stepLabel;

  function build() {
    el.innerHTML = '';

    bar = document.createElement('div'); bar.className = 'compose-bar';
    const title = document.createElement('div'); title.className = 'compose-title'; title.textContent = 'Compose';
    bar.appendChild(title);

    const tools = document.createElement('div'); tools.className = 'compose-tools';
    const minus = toolBtn('−', 'shorten the song by a cycle', () => {
      if (model.length > 1) { writeSong(M().songResize(model.song, model.length - 1)); readModel(); render(); }
    });
    stepLabel = document.createElement('span'); stepLabel.className = 'compose-steplabel';
    const plus = toolBtn('+', 'add a cycle (repeat the last)', () => {
      writeSong(M().songResize(model.song, Math.max(1, model.length) + 1)); readModel(); render(); opts.ensurePlaying().catch(() => {});
    });
    const clear = toolBtn('CLEAR', 'clear the arrangement (sections stack again)', () => {
      writeSong(''); readModel(); render();
    });
    clear.classList.add('compose-clear');
    tools.appendChild(minus); tools.appendChild(stepLabel); tools.appendChild(plus); tools.appendChild(clear);
    bar.appendChild(tools);
    el.appendChild(bar);

    // empty state (no song yet): the MAKE SONG chip (native SongLane's seed-a-song button)
    emptyState = document.createElement('div'); emptyState.className = 'compose-empty';
    const make = document.createElement('button'); make.type = 'button'; make.className = 'compose-make';
    make.textContent = 'MAKE SONG';
    make.title = 'arrange your sections over cycles — a pop-song skeleton to edit';
    make.addEventListener('click', makeSong);
    make.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); makeSong(); } });
    const es = document.createElement('div'); es.className = 'compose-empty-sub';
    es.textContent = 'arrange sections over cycles — or tap MAKE SONG for a starting layout';
    emptyState.appendChild(make); emptyState.appendChild(es);
    el.appendChild(emptyState);

    scroll = document.createElement('div'); scroll.className = 'compose-scroll';
    grid = document.createElement('div'); grid.className = 'compose-grid';
    playhead = document.createElement('div'); playhead.className = 'compose-playhead'; playhead.setAttribute('aria-hidden', 'true');
    grid.appendChild(playhead);
    scroll.appendChild(grid);
    el.appendChild(scroll);

    grid.addEventListener('pointerdown', onGridDown);
    grid.addEventListener('pointermove', onGridMove);
    grid.addEventListener('pointerup', onGridUp);
    grid.addEventListener('pointercancel', onGridUp);

    const hint = document.createElement('div'); hint.className = 'compose-hint';
    hint.textContent = 'tap a cell to place · drag a block to move · drag its edge to grow · tap a lit cell to remove · arrows + Enter work too';
    el.appendChild(hint);
  }

  function toolBtn(txt, title, fn) {
    const b = document.createElement('button'); b.type = 'button'; b.className = 'compose-tool';
    b.textContent = txt; b.title = title; b.setAttribute('aria-label', title);
    b.addEventListener('click', fn);
    b.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); fn(); } });
    return b;
  }

  function makeSong() {
    readModel();
    const csv = editableRows.map((s) => s.name).join(',');
    writeSong(M().songSeed(csv));
    readModel(); render();
    opts.ensurePlaying().catch(() => {});
    opts.setStatus('made a starting arrangement — drag the blocks to shape it');
  }

  // Rebuild the whole grid (ruler + every lane) from the current model.
  function render() {
    const L = model.length;
    const hasSong = L > 0 && editableRows.length > 0;
    emptyState.classList.toggle('hidden', hasSong);
    scroll.classList.toggle('hidden', !hasSong);
    bar.querySelector('.compose-tools').classList.toggle('hidden', !hasSong);
    if (stepLabel) stepLabel.textContent = hasSong ? `${L} cyc` : '';
    if (!hasSong) return;
    grid.style.gridTemplateColumns = `${GUTTER}px repeat(${L}, ${COLW}px)`;
    renderLanes();
  }

  // Redraw the ruler + lane cells (called on every gesture frame — cheap, no layout thrash on the bar).
  function renderLanes() {
    const L = model.length;
    // remove everything except the persistent playhead
    Array.from(grid.children).forEach((c) => { if (c !== playhead) grid.removeChild(c); });

    // ruler row: gutter + cycle numbers
    const rg = document.createElement('div'); rg.className = 'compose-rulergutter'; rg.textContent = 'CYCLE';
    grid.appendChild(rg);
    for (let c = 0; c < L; c++) {
      const n = document.createElement('div'); n.className = 'compose-rulercell'; n.textContent = String(c + 1);
      grid.appendChild(n);
    }

    // one lane per editable section
    editableRows.forEach((sec, row) => {
      const lbl = document.createElement('div'); lbl.className = 'compose-label';
      lbl.style.setProperty('--tint', TINTS[row % TINTS.length]);
      lbl.textContent = sec.name;
      lbl.title = sec.name;
      grid.appendChild(lbl);
      const mask = sec.mask;
      for (let c = 0; c < L; c++) {
        const cell = document.createElement('button');
        cell.type = 'button'; cell.className = 'ccell' + (mask[c] ? ' lit' : ' empty');
        cell.dataset.row = String(row); cell.dataset.col = String(c);
        cell.style.setProperty('--tint', TINTS[row % TINTS.length]);
        cell.tabIndex = 0;
        if (mask[c]) {
          const runStart = c === 0 || !mask[c - 1];
          const runEnd = c === L - 1 || !mask[c + 1];
          if (runStart) cell.classList.add('run-start');
          if (runEnd) cell.classList.add('run-end');
          if (!runStart && !runEnd) cell.classList.add('run-mid');
        }
        cell.setAttribute('aria-label', `${sec.name} cycle ${c + 1} ${mask[c] ? 'on' : 'off'}`);
        cell.setAttribute('aria-pressed', String(!!mask[c]));
        cell.addEventListener('keydown', onCellKey);
        grid.appendChild(cell);
      }
    });
    positionPlayhead();
  }

  // ---- the phosphor playhead: the audible cycle column while playing ----
  let playCol = -1;
  function positionPlayhead() {
    const L = model.length;
    const show = playCol >= 0 && playCol < L;
    playhead.style.display = show ? 'block' : 'none';
    if (show) {
      playhead.style.left = (GUTTER + playCol * COLW) + 'px';
      playhead.style.width = COLW + 'px';
    }
    // highlight the live column's cells
    grid.querySelectorAll('.ccell.playing').forEach((c) => c.classList.remove('playing'));
    if (show) grid.querySelectorAll(`.ccell[data-col="${playCol}"]`).forEach((c) => c.classList.add('playing'));
  }

  let phTimer = null;
  function tick() {
    const eng = opts.engine();
    const L = model.length;
    let col = -1;
    if (eng && opts.isPlaying() && L > 0) col = ((Math.floor(eng.currentCycle()) % L) + L) % L;
    if (col !== playCol) { playCol = col; positionPlayhead(); }
  }

  // Public: (re)read the doc + rebuild (called when the COMPOSE view is shown or the doc changes).
  function refresh() { readModel(); render(); }
  function start() { if (!phTimer) phTimer = setInterval(tick, 70); }
  function stop() { if (phTimer) { clearInterval(phTimer); phTimer = null; } playCol = -1; positionPlayhead(); }

  build();
  refresh();

  return {
    el, refresh, start, stop,
    // verification hooks (headless drive): programmatic place / drive a run-set / read state
    _model: () => model,
    _tapCell: (row, col) => { const sec = editableRows[row]; if (!sec) return; writeSong(M().songSetCell(model.song, sec.name, col, !sec.mask[col])); readModel(); render(); },
    _sectionNames: () => editableRows.map((s) => s.name),
    _colw: COLW, _gutter: GUTTER,
  };
}
