// ===========================================================================
//  Cyclo web — DRAG-NUMBER: scrub a numeric literal in the CODE editor.
//
//  The web port of native src/app/DragNumber.h — "a number you change by dragging" — and
//  the sibling of the FX param drag-rows (src/fx.js). Native DragNumber is a standalone
//  field (the BPM display); on web the same gesture is brought INTO the code: a horizontal
//  drag that STARTS on a numeric literal scrubs its value live, rewrites it in place, and
//  hot-swaps the engine (WebEngine.updateDocument) so the change is HEARD immediately, with
//  an occlusion-safe floating readout (the shared gesture bubble). A plain TAP on a number
//  still just places the caret — a drag scrubs, a tap edits — so it never fights selection.
//
//  Step / precision follow native DragNumber: per-pixel step = the literal's own precision
//  unit (10^-decimals) * 0.5 (native `stp * 0.5`), and it gets FINER as you pull the pointer
//  away from the line (the shared fineFactor, docs/web-interaction.md R5). Keyboard users are
//  never gated behind the drag — they edit the number by typing, the natural CM path.
//
//  This module is PURE (imports only gesture.js's DOM-free fineFactor): numberTokenAt,
//  insideString, decimalsOf, scrubValue, formatScrub all run in Node, so web/verify.js
//  asserts the token detection + the step/round-trip maths headlessly. The pointer wiring
//  lives in main.js (which owns the CodeMirror view, the doc, and the hot-swap), reusing the
//  single onEditorPointerDown decision path (an FX call / grain chain still wins first).
// ===========================================================================
import { fineFactor } from './gesture.js';

const isNumCh = (c) => (c >= '0' && c <= '9') || c === '.';

// The number of decimal places a literal carries (its intrinsic precision) — the scrub
// re-formats to this so `0.95` stays 2dp, `124` stays an integer.
export function decimalsOf(text) {
  const dot = text.indexOf('.');
  return dot < 0 ? 0 : (text.length - dot - 1);
}

// Is `offset` inside a "double-quoted string" (the mini-notation pattern)? Numbers inside a
// pattern (e.g. `s("bd*4")`) belong to the STEP/pattern editors, never the scalar scrub, so
// the scrub skips them. Counts quotes before the offset; odd => inside.
export function insideString(doc, offset) {
  let inStr = false;
  const n = Math.min(offset, doc.length);
  for (let i = 0; i < n; i++) if (doc[i] === '"') inStr = !inStr;
  return inStr;
}

// The numeric literal covering `offset`, or null. A run of [0-9.] containing at least one
// digit; a caret sitting immediately AFTER a number still grabs it (so a tap on the trailing
// edge scrubs). A leading sign is intentionally NOT included — a preceding `-` (which in
// mini-notation is also a rest) is left untouched, and the magnitude scrubs beneath it.
// Returns { start, end, text, value, decimals }.
export function numberTokenAt(doc, offset) {
  if (!doc) return null;
  const n = doc.length;
  let i = Math.max(0, Math.min(n, offset));
  if (i >= n || !isNumCh(doc[i])) {
    if (i > 0 && isNumCh(doc[i - 1])) i -= 1;   // caret just past the number
    else return null;
  }
  let s = i, e = i;
  while (s > 0 && isNumCh(doc[s - 1])) s--;
  while (e < n && isNumCh(doc[e])) e++;
  const text = doc.slice(s, e);
  if (!/[0-9]/.test(text)) return null;         // a lone '.' / '...' is not a number
  const value = parseFloat(text);
  if (!isFinite(value)) return null;
  return { start: s, end: e, text, value, decimals: decimalsOf(text) };
}

// The scrubbed value for a horizontal pixel travel `dx` from the drag start, given the
// literal's `decimals` and the perpendicular `perp` (pull-away = finer). Mirrors native
// DragNumber: newVal = startVal + dx * step * 0.5 (here step = 10^-decimals), scaled by the
// shared fineFactor so far-off drags refine. Clamped at 0 so a positive literal never flips
// negative by over-dragging (native jlimits to its configured range; we floor at 0, the safe
// bound for gain/speed/hz/counts). Because it recomputes from startVal + total dx, a drag out
// and back to the origin returns EXACTLY to startVal (round-trip-safe).
export function scrubValue(startVal, dx, decimals, perp) {
  const step = Math.pow(10, -Math.max(0, decimals | 0));
  const v = startVal + dx * step * 0.5 * fineFactor(perp);
  return v < 0 ? 0 : v;
}

// Format a scrubbed value back to the literal's own precision (so it drops in cleanly).
export function formatScrub(value, decimals) {
  return (value < 0 ? 0 : value).toFixed(Math.max(0, decimals | 0));
}
