// ===========================================================================
//  Cyclo web — the SYMBOL / ACCESSORY ROW (the CODE view's key strip).
//
//  The web port of native src/app/SymbolRow.h + MainComponent::insertSymbol. The phone
//  software keyboard buries mini-notation's punctuation two taps deep (switch to the
//  symbol page, hunt, tap, switch back); this strip surfaces the whole managed vocabulary
//  of structural glyphs as one-tap keys right under the caret — exactly the native
//  accessory bar (owner directive touch-economy: count the taps, drive them down).
//
//  Parity with native SymbolRow.h:
//    - The EXACT same key SET + ORDER: the grouping brackets first (highest value), then
//      the lone operators. Every glyph the managed mini-notation vocabulary uses that is
//      not a letter, digit, or space. (Letters + `s(` stay on the normal keyboard / the
//      core autocomplete, as native intends — only the awkward glyphs move here.)
//    - Touch economy baked into the keys: a bracket pair `[]` `<>` `()` inserts the MATCHED
//      PAIR and parks the caret BETWEEN them (one tap opens a group, not two + a cursor
//      move). With a selection active it WRAPS it instead (select `bd sn`, tap `[ ]` ->
//      `[bd sn]`). The lone operators `- * : ,` insert one char. This is the identical
//      smart-caret mechanism the core completions use (`s("")` lands inside the quotes):
//      an insert string + a caretBack count.
//
//  The PURE half (SYMBOL_KEYS + symbolEdit) imports nothing DOM-y and runs in Node, so
//  web/verify.js asserts the insert strings + caret placement + selection-wrap headlessly.
//  The DOM half (createSymbolRow) is browser-only and reuses the shared input-agnostic
//  attachActivate (pointer mouse/touch/pen + keyboard Enter/Space, ghost-click suppressed).
// ===========================================================================
import { attachActivate } from './gesture.js';   // top-level pure in Node (DOM touched only when called)

// The managed symbol vocabulary — a byte-for-byte port of native SymbolRow.h kKeys
// (label, insert, caretBack, tip), SAME set + SAME order. caretBack 1 = a pair the caret
// lands inside (and that wraps a selection); 0 = a lone operator.
export const SYMBOL_KEYS = [
  { label: '[ ]', insert: '[]', caretBack: 1, tip: 'Group a sub-sequence: [bd sn]' },
  { label: '< >', insert: '<>', caretBack: 1, tip: 'Alternate per cycle: <bd sn>' },
  { label: '( )', insert: '()', caretBack: 1, tip: 'Euclid rhythm: bd(3,8)' },
  { label: '-',   insert: '-',  caretBack: 0, tip: 'Rest (a silent step)' },
  { label: '*',   insert: '*',  caretBack: 0, tip: 'Repeat / speed up: bd*2' },
  { label: ':',   insert: ':',  caretBack: 0, tip: 'Pick a slice: break:3' },
  { label: ',',   insert: ',',  caretBack: 0, tip: 'Stack in parallel: [bd, hh]' },
];

// The PURE edit for one key tap, given the current selection [selFrom, selTo). Returns a
// CodeMirror-shaped transaction spec { changes, selection } — a faithful port of native
// MainComponent::insertSymbol:
//   - A wrapping PAIR (caretBack 1, 2 chars) with a NON-EMPTY selection wraps it: insert the
//     opener at selFrom + the closer at selTo, and re-select the wrapped span [+1 .. +1]
//     (still one tap from wrapping again or editing inside).
//   - Otherwise insert the text at the caret (replacing any selection) and step the caret
//     BACK `caretBack` chars — so `[]`/`<>`/`()` land the caret between the brackets, and a
//     lone operator lands the caret after it.
export function symbolEdit(key, selFrom, selTo) {
  const from = Math.min(selFrom, selTo), to = Math.max(selFrom, selTo);
  const pair = key.caretBack === 1 && key.insert.length === 2;
  if (pair && to > from) {
    const open = key.insert[0], close = key.insert[1];
    return {
      // insert both ends; CM applies the change set atomically (indices are original-doc coords)
      changes: [{ from, insert: open }, { from: to, insert: close }],
      // re-select the wrapped inner span (shifted right by the inserted opener)
      selection: { anchor: from + 1, head: to + 1 },
    };
  }
  const anchor = from + key.insert.length - key.caretBack;
  return {
    changes: { from, to, insert: key.insert },
    selection: { anchor },
  };
}

// =============================================================================
//  DOM (browser only). Builds the accessory strip; each key is a real focusable
//  <button> activated input-agnostically (pointer + keyboard) via attachActivate.
//  `opts.onInsert(key)` is called with the tapped SYMBOL_KEYS entry — the caller
//  applies symbolEdit() to the live editor selection (so it owns the CM dispatch +
//  the userEvent tag + refocus). Returns { el }.
// =============================================================================
export function createSymbolRow(opts) {
  const el = document.createElement('div');
  el.className = 'symbolrow';
  el.setAttribute('role', 'toolbar');
  el.setAttribute('aria-label', 'insert a mini-notation symbol at the caret');
  for (const key of SYMBOL_KEYS) {
    const b = document.createElement('button');
    b.type = 'button';
    b.className = 'symkey';
    b.textContent = key.label;
    b.dataset.insert = key.insert;
    b.setAttribute('aria-label', key.tip);
    b.title = key.tip;                       // desktop hover hint (never the only affordance)
    // attachActivate: pointerdown fires it (mouse/touch/pen, on press) AND keyboard Enter/Space;
    // its pointerdown preventDefault keeps focus IN the editor (no focus theft = the caret/selection
    // and — on iOS — the soft keyboard stay put), exactly as native sets the keys non-focusable.
    attachActivate(b, () => { if (opts.onInsert) opts.onInsert(key); });
    el.appendChild(b);
  }
  return { el };
}
