// ===========================================================================
//  keymap.js — desktop keyboard shortcuts (a PROGRESSIVE ENHANCEMENT).
//
//  The web build serves BOTH touch (mobile) and mouse+keyboard (desktop) from ONE UI
//  (memory cyclo-web-input-agnostic, docs/web-interaction.md). A physical keyboard is a
//  desktop-only bonus, so NOTHING is gated behind it — every action here is ALSO reachable
//  by pointer/touch. Mobile users are completely unaffected.
//
//  The rules this module enforces (see docs/web-interaction.md "Keyboard shortcuts"):
//    - CONTEXT-AWARE FOCUS GUARD: single-key shortcuts (Space, 1/2/3, ?, QWERTY notes) must
//      NOT fire while the caret is in the CODE editor, a text <input>/<textarea>, or any
//      contenteditable — otherwise you couldn't type. They fire ONLY outside a text context.
//    - MODIFIER COMBOS respect the platform: ⌘ on macOS, Ctrl on Windows/Linux (never both).
//      Mod+Enter (evaluate) is allowed to work FROM the editor; the others are meta-level.
//    - NO CLOBBERING conventional browser shortcuts (Cmd/Ctrl+W/T/L/N/Q/R, Cmd+Z/redo which
//      CodeMirror owns inside the editor, …). We only claim keys the app needs, and we never
//      intercept undo/redo — CodeMirror's history keymap handles those inside the editor.
//
//  The PURE pieces (isMac / isTypingTarget / qwertyNoteIndex / resolveShortcut) import nothing
//  and take plain descriptors, so web/verify.js asserts the platform-mod detection, the
//  is-typing guard and the whole key->action table headlessly in Node.
// ===========================================================================

// ---- platform ------------------------------------------------------------------------------
// macOS uses ⌘ as the primary modifier; everywhere else it's Ctrl. Detect from the platform /
// userAgent (either signal is enough). `nav` is injectable so Node can test both branches.
export function isMac(nav) {
  const n = nav || (typeof navigator !== 'undefined' ? navigator : {});
  const p = String(n.platform || '').toLowerCase();
  const ua = String(n.userAgent || '').toLowerCase();
  return p.includes('mac') || /mac|iphone|ipad|ipod/.test(ua);
}

// The label for the primary modifier, for the cheat sheet + docs.
export function modLabel(mac) { return mac ? '⌘' : 'Ctrl'; }

// ---- the focus guard -----------------------------------------------------------------------
// True when `el` is a TEXT-ENTRY context — an <input>/<textarea>/<select>, a contenteditable, or
// the CodeMirror editor (its content is a contenteditable div). Single-key shortcuts are suppressed
// here so typing is never hijacked. Works on real DOM nodes AND on plain stubs (Node tests).
export function isTypingTarget(el) {
  if (!el) return false;
  if (el.isContentEditable) return true;
  const tag = String(el.tagName || '').toLowerCase();
  if (tag === 'input' || tag === 'textarea' || tag === 'select') return true;
  // belt-and-suspenders: any node inside the CM editor counts as typing
  if (typeof el.closest === 'function' && el.closest('.cm-editor')) return true;
  return false;
}

// True when `el` is an interactive control that CONSUMES Space/Enter itself (a <button>/pad/tab,
// a link, a role=button). We must not ALSO fire a single-key shortcut (e.g. Space -> transport)
// while such a control is focused, or a Space on a focused pad would both play the pad AND toggle
// the transport. Digit/`?`/note keys are NOT consumed by buttons, so they are unaffected.
export function isActivatableTarget(el) {
  if (!el) return false;
  const tag = String(el.tagName || '').toLowerCase();
  if (tag === 'button' || tag === 'a' || tag === 'summary' || tag === 'select') return true;
  const role = (typeof el.getAttribute === 'function') ? el.getAttribute('role') : null;
  if (role === 'button' || role === 'tab' || role === 'option') return true;
  return false;
}

// ---- QWERTY notes on the KEYS surface (Ableton-style) --------------------------------------
// Two orderings map physical keys to KEYS-strip cell indices:
//   - CHROMATIC strip (12 semitones + octave): the classic Ableton computer-MIDI layout, so the
//     home row plays the "white" notes and the row above plays the "black" ones — muscle memory.
//   - SCALE strip (major/minor/pentatonic degrees): the home row walks consecutive degrees.
const QWERTY_PIANO = ['a', 'w', 's', 'e', 'd', 'f', 't', 'g', 'y', 'h', 'u', 'j', 'k'];   // chromatic
const QWERTY_WHITE = ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';'];                  // scale degrees
const NOTE_KEY_SET = new Set([...QWERTY_PIANO, ...QWERTY_WHITE]);

// The KEYS-strip cell index a physical key maps to (or -1). `chromatic` picks the layout.
export function qwertyNoteIndex(key, chromatic) {
  const k = String(key || '').toLowerCase();
  const row = chromatic ? QWERTY_PIANO : QWERTY_WHITE;
  return row.indexOf(k);
}

// Is this key one of the QWERTY note keys at all (either layout)? Used by the resolver to CLAIM the
// key on the KEYS surface; the concrete index is resolved later against the live strip's layout.
export function isNoteKey(key) { return NOTE_KEY_SET.has(String(key || '').toLowerCase()); }

// ---- the key -> action table (pure, node-testable) -----------------------------------------
// `desc` is a normalized descriptor built from a real KeyboardEvent:
//   { key, mod, shift, alt, typing, surface, overlayOpen }
//     key         : the KeyboardEvent.key value ('a', ' ', '1', '?', 'Enter', 'Escape', …)
//     mod         : the PLATFORM primary modifier is held (metaKey on mac, ctrlKey elsewhere)
//     shift/alt   : those modifiers
//     typing      : the focus is in a text-entry context (isTypingTarget)
//     surface     : the active PLAY surface ('keys' when the KEYS strip is showing, else null)
//     overlayOpen : a modal sheet/overlay is up (only Esc is honoured then)
// Returns an ACTION id string, or null to let the key through (browser / CodeMirror / nothing).
export function resolveShortcut(desc) {
  const { key, mod, shift, alt, typing, surface, overlayOpen } = desc || {};

  // Esc is universal — it closes the top-most sheet/overlay regardless of focus or modifiers.
  if (key === 'Escape') return 'escape';

  // A modal is up: suppress every other shortcut (so a stray Space/1/2/3 can't drive the app
  // behind the sheet). Esc above still closes it.
  if (overlayOpen) return null;

  // ---- modifier combos (⌘/Ctrl). Some are safe WHILE typing (eval from the editor). ----
  if (mod && !alt) {
    const k = String(key).toLowerCase();
    if (key === 'Enter') return 'eval';          // ⌘/Ctrl+Enter — evaluate (works from the editor)
    if (k === 's' && !shift) return 'save';       // ⌘/Ctrl+S — download .cyclo (preventDefault the save)
    if (k === 'c' && shift) return 'copy-share';  // ⌘/Ctrl+Shift+C — copy the share link
    // ⌘/Ctrl+Z and ⌘/Ctrl+Shift+Z are DELIBERATELY not claimed — CodeMirror's history keymap
    // owns undo/redo inside the editor; claiming them here would double-fire. Same for W/T/L/N/…
    return null;
  }
  // any OTHER modifier combination (Alt-anything, the wrong platform's Ctrl on mac, …): pass through
  if (mod || alt) return null;

  // ---- single-key shortcuts: ONLY outside a text-entry context (the focus guard) ----
  if (typing) return null;

  if (key === ' ' || key === 'Spacebar') return 'toggle-transport';
  if (key === '1') return 'view-play';
  if (key === '2') return 'view-code';
  if (key === '3') return 'view-compose';
  if (key === '?') return 'cheatsheet';   // Shift+/ produces '?'

  // QWERTY notes only when the KEYS strip is the active surface, and not with Shift (a capital)
  if (surface === 'keys' && !shift && isNoteKey(key)) return 'note';

  return null;
}

