// ---- the wiring (browser only) -------------------------------------------------------------
// Attach ONE global keydown listener that turns a real KeyboardEvent into an action and calls the
// matching handler. `getContext()` supplies the live { surface, overlayOpen }; `actions` maps each
// action id to a function. Returns { detach }.
export function attachKeymap({ getContext, actions, mac }) {
  const isMacKb = mac == null ? isMac() : mac;
  const onKey = (e) => {
    const ctx = (getContext && getContext()) || {};
    const target = e.target;
    const desc = {
      key: e.key,
      mod: isMacKb ? e.metaKey : e.ctrlKey,
      shift: e.shiftKey,
      alt: e.altKey,
      typing: isTypingTarget(target),
      surface: ctx.surface || null,
      overlayOpen: !!ctx.overlayOpen,
    };
    const action = resolveShortcut(desc);
    if (!action) return;

    if (action === 'escape') { if (actions.escape) actions.escape(e); return; }   // no preventDefault
    // a focused button/pad/tab consumes Space itself — let it, don't ALSO toggle the transport
    if (action === 'toggle-transport' && isActivatableTarget(target)) return;

    e.preventDefault();                 // we own this key now (also suppresses the browser default)
    if (e.repeat) return;               // ignore key-autorepeat (no toggle/note spam on a held key)
    if (action === 'note') { if (actions.note) actions.note(e.key); return; }
    const fn = actions[action];
    if (fn) fn(e);
  };
  window.addEventListener('keydown', onKey);
  return { detach() { window.removeEventListener('keydown', onKey); } };
}
