// ===========================================================================
//  medalart.js — the chrome convex-mirror Maker Medal dome (Gamification Layer 1).
//
//  A FAITHFUL port of the LOCKED trophy material — the `ChromeDome` reflection model from
//  docs/design-lab/maker-medals.html (owner: "The maker medal is perfect", 2026-07-21):
//  a whole-neighbourhood convex-mirror fisheye (q^1.35 reach), diffusion (sharp/soft blend
//  rising to the rim), spectral rim diffraction, additive light-spray, and an oversaturated
//  hue-steal so the metal reads as COLOURED treasure. STATIC by design — the mirror is
//  rasterized ONCE on earn / shelf-open / resize, never on a timer (protects the zero-cost,
//  on-device, battery goals; chrome is REWARD-ONLY).
//
//  This is the same per-pixel canvas ray-map algorithm as the approved lab — NOT a flat fake
//  and NOT WebGL (the lab, the source of truth the owner signed off, is a 2D-canvas raymap;
//  reproducing it verbatim is the highest-fidelity path and renders truthfully in headless
//  Chrome without a GL backend). The one deliberate change vs the lab: each EARNED dome
//  reflects its OWN small coloured scene (a studio softbox + light floor + a radial halo in
//  the medal's identity hue behind the puck) rather than one shared page snapshot — this is
//  exactly what native MakerMedalsShelf does (per-medal scene isolation), because the fisheye
//  reach is far larger than the medal spacing, so a shared scene would bleed neighbours'
//  colours into every dome. LOCKED medals never call this — they show a matte blank slug.
// ===========================================================================

const DPR = () => Math.min((typeof window !== 'undefined' && window.devicePixelRatio) || 1, 2);

// The low-res scene each dome reflects (studio softbox + coloured belly-halo + light floor).
// Small + fixed: the ray map samples it with NORMALIZED offsets, so scene px are decoupled
// from dome px. Matches the lab's scene proportions (bright top, light floor, no black on metal).
const SCN = 72;

function hexToRgb(hex) {
  const s = hex.replace('#', '');
  return [parseInt(s.slice(0, 2), 16), parseInt(s.slice(2, 4), 16), parseInt(s.slice(4, 6), 16)];
}

// Build a per-medal scene (base + soft-blur + glow-blur ImageData), reflecting a studio-lit world
// tinted by the medal's identity colour. The convex mirror samples the CENTRE for the belly (the
// colour halo), the TOP rim for the white softbox bloom, and the BOTTOM rim for the light floor.
function buildScene(colorHex) {
  const cvs = document.createElement('canvas');
  cvs.width = SCN; cvs.height = SCN;
  const c = cvs.getContext('2d', { willReadFrequently: true });

  // porcelain-ish neutral ground (light — no black anywhere on the metal)
  c.fillStyle = '#c8ccd1';
  c.fillRect(0, 0, SCN, SCN);

  // top studio softbox — the white bloom the rim catches
  let g = c.createLinearGradient(0, 0, 0, SCN * 0.5);
  g.addColorStop(0, '#ffffff');
  g.addColorStop(0.55, 'rgba(255,255,255,.85)');
  g.addColorStop(1, 'rgba(255,255,255,0)');
  c.fillStyle = g; c.fillRect(0, 0, SCN, SCN * 0.5);

  // light studio floor at the bottom
  g = c.createLinearGradient(0, SCN * 0.62, 0, SCN);
  g.addColorStop(0, 'rgba(168,172,178,0)');
  g.addColorStop(0.5, 'rgba(168,172,178,.7)');
  g.addColorStop(1, '#a3a7ad');
  c.fillStyle = g; c.fillRect(0, SCN * 0.62, SCN, SCN * 0.38);

  // the medal's identity halo, bloomed at the centre so the convex belly samples that hue across
  // its middle (coloured metal) while the softbox still whitens the rim — the "coloured treasure"
  // read. Additive-ish: a vivid but semi-transparent radial so the world's luminance survives.
  const [r, gg, b] = hexToRgb(colorHex);
  const cx = SCN * 0.5, cy = SCN * 0.52;
  const halo = c.createRadialGradient(cx, cy, 0, cx, cy, SCN * 0.5);
  halo.addColorStop(0, `rgba(${r},${gg},${b},0.92)`);
  halo.addColorStop(0.45, `rgba(${r},${gg},${b},0.55)`);
  halo.addColorStop(1, `rgba(${r},${gg},${b},0)`);
  c.fillStyle = halo; c.fillRect(0, 0, SCN, SCN);

  const base = c.getImageData(0, 0, SCN, SCN).data;

  // blur variants for the diffusion (sharp->soft toward the rim) and the additive light-spray glow
  const soft = blurred(cvs, SCN * 0.055);
  const glow = blurred(cvs, SCN * 0.11);
  return { base, soft, glow };
}

function blurred(srcCanvas, radiusPx) {
  const cvs = document.createElement('canvas');
  cvs.width = SCN; cvs.height = SCN;
  const c = cvs.getContext('2d', { willReadFrequently: true });
  c.filter = `blur(${radiusPx}px)`;
  c.drawImage(srcCanvas, 0, 0);
  return c.getImageData(0, 0, SCN, SCN).data;
}

// One convex-mirror dome. Bound to a <canvas>; renders STATICally (call render() on earn / open /
// resize). The ray map (11 floats/px: normalized page offset + per-pixel shading terms) is the
// lab's buildMap; render() is the lab's render() sampling this medal's own scene.
export class MedalDome {
  constructor(canvas, colorHex) {
    this.cvs = canvas;
    this.ctx = canvas.getContext('2d');
    this.color = colorHex;
    this.W = 0; this.H = 0; this.map = null; this.img = null;
    this.scene = null;
  }

  // Recompute the ray map for the current canvas pixel size (idempotent for an unchanged size).
  buildMap() {
    const r = this.cvs.getBoundingClientRect();
    const dpr = DPR();
    const W = Math.max(2, Math.round((r.width || this.cvs.width / dpr) * dpr));
    const H = Math.max(2, Math.round((r.height || this.cvs.height / dpr) * dpr));
    if (W === this.W && H === this.H && this.map) return;
    this.W = W; this.H = H;
    this.cvs.width = W; this.cvs.height = H;
    this.img = this.ctx.createImageData(W, H);
    const map = this.map = new Float32Array(W * H * 11);
    const hw = W / 2, hh = H / 2, R = Math.min(hw, hh);

    for (let y = 0; y < H; y++) {
      const py = y + 0.5 - hh;
      for (let x = 0; x < W; x++) {
        const px = x + 0.5 - hw;
        const i = (y * W + x) * 11;
        const dEdge = R - Math.hypot(px, py);
        const alpha = Math.max(0, Math.min(1, dEdge + 0.5));
        if (alpha <= 0) { map[i + 6] = 0; continue; }

        // whole-neighbourhood convex mirror: every pixel looks outward from the centre; q^1.35 keeps
        // the near scene dominant mid-face, the far scene compressed toward the rim.
        const ex = px / hw, ey = py / hh;
        const q = Math.min(0.9999, Math.hypot(ex, ey));
        const ux = q > 1e-6 ? ex / q : 0;
        const uy = q > 1e-6 ? ey / q : 0;
        const gg = Math.pow(q, 1.35);

        const mm = Math.pow(q, 1.6) * 0.94;
        const nz = Math.sqrt(1 - mm * mm);
        const ry = uy;

        const skyW = Math.pow(q, 1.5);
        const sky = Math.pow(Math.max(0, Math.min(1, -ry * 2)), 1.35) * 0.82 * skyW;
        const t = (ry - 0.13) / 0.085;
        const horM = 1 - Math.exp(-t * t) * 0.30;
        const gnd = Math.max(0, Math.min(1, (ry - 0.42) * 1.5)) * 0.22;
        const edgeM = 1 - Math.pow(1 - nz, 2.2) * 0.12;

        const diffMix = Math.min(0.98, 0.62 + 0.36 * q);
        const band = Math.exp(-Math.pow((q - 0.86) / 0.10, 2));
        const phase = q * 46 + Math.atan2(uy, ux) * 2.5;

        map[i]      = ux * gg;
        map[i + 1]  = uy * gg;
        map[i + 2]  = sky;
        map[i + 3]  = horM;
        map[i + 4]  = gnd;
        map[i + 5]  = edgeM;
        map[i + 6]  = alpha;
        map[i + 7]  = diffMix;
        map[i + 8]  = band * (0.5 + 0.5 * Math.sin(phase)) * 62;
        map[i + 9]  = band * (0.5 + 0.5 * Math.sin(phase + 2.094)) * 62;
        map[i + 10] = band * (0.5 + 0.5 * Math.sin(phase + 4.189)) * 62;
      }
    }
  }

  render() {
    this.buildMap();
    if (!this.scene) this.scene = buildScene(this.color);
    const { base: sceneData, soft: sceneSoft, glow: sceneGlow } = this.scene;
    const { W, H, map } = this;
    const data = this.img.data;

    for (let p = 0, i = 0; p < W * H; p++, i += 11) {
      const o = p * 4;
      const alpha = map[i + 6];
      if (alpha <= 0) { data[o + 3] = 0; continue; }

      // normalized page reach -> a self-contained sample of THIS medal's scene (centre = belly
      // halo, top rim = softbox, bottom rim = floor). Isolated per medal (no neighbour bleed).
      let ox = map[i], oy = map[i + 1];
      let sx = (0.5 + 0.5 * ox) * SCN;
      let sy = (0.5 + 0.5 * oy) * SCN;
      sx = sx < 0 ? 0 : (sx >= SCN ? SCN - 1 : sx | 0);
      sy = sy < 0 ? 0 : (sy >= SCN ? SCN - 1 : sy | 0);
      const si = (sy * SCN + sx) * 4;

      const dm = map[i + 7];
      let er = sceneData[si]     + (sceneSoft[si]     - sceneData[si])     * dm;
      let eg = sceneData[si + 1] + (sceneSoft[si + 1] - sceneData[si + 1]) * dm;
      let eb = sceneData[si + 2] + (sceneSoft[si + 2] - sceneData[si + 2]) * dm;
      const mean = (er + eg + eb) / 3;
      er = mean + (er - mean) * 1.4;    // hue-steal: oversaturate so the belly reads as coloured metal
      eg = mean + (eg - mean) * 1.4;
      eb = mean + (eb - mean) * 1.4;

      const sky = map[i + 2], mul = map[i + 3] * map[i + 5], baseL = 0.78 + map[i + 4];
      let cr = er * baseL; cr = (cr + (255 - cr) * sky) * mul;
      let cg = eg * baseL; cg = (cg + (255 - cg) * sky) * mul;
      let cb = eb * baseL; cb = (cb + (255 - cb) * sky) * mul;

      const spray = 0.14 + 0.34 * sky;
      cr += sceneGlow[si] * spray;
      cg += sceneGlow[si + 1] * spray;
      cb += sceneGlow[si + 2] * spray;

      const lum = 0.35 + 0.65 * ((cr + cg + cb) / 765);
      cr += map[i + 8] * lum;           // spectral rim diffraction fringe (R/G/B out of phase)
      cg += map[i + 9] * lum;
      cb += map[i + 10] * lum;

      data[o]     = cr < 0 ? 0 : cr > 255 ? 255 : cr;
      data[o + 1] = cg < 0 ? 0 : cg > 255 ? 255 : cg;
      data[o + 2] = cb < 0 ? 0 : cb > 255 ? 255 : cb;
      data[o + 3] = alpha * 255;
    }
    this.ctx.putImageData(this.img, 0, 0);
  }
}
