// ===========================================================================
//  soundpicker.js — the sound picker / bank browser (native src/app/SoundPicker.h +
//  BankBrowser.h + the persistent src/engine/SoundLibrary).
//
//  ONE design-bar surface that lists EVERY available sound, grouped the way a maker thinks
//  about them:
//    • SYNTH KIT   — the built-in synth voices (bd/sn/hh/… + the alternates), always present.
//    • THIS SONG   — the user's own record/import samples in the current project.
//    • LIBRARY     — the persistent, CROSS-PROJECT keepers (native SoundLibrary): sounds you
//                    KEPT so they're available in every project.
//
//  Actions (all input-agnostic — every row + button is a real focusable <button>, pointer AND
//  keyboard, ~44px targets, touch-action off; a tap AUDITIONS through the SHARED engine,
//  never a JS re-synth):
//    • tap a row              -> AUDITION it (triggerPad; a library sound is added + heard, the
//                                native BankBrowser "tap = add AND hear" gesture).
//    • USE (kit / song)       -> PICK it: insert s("name") into the code at the caret (the coin).
//    • KEEP (song)            -> save this sound's PCM into the persistent LIBRARY (cross-project).
//    • ADD  (library)         -> rehydrate the keeper into THIS project (addSample), so it's on
//                                the pads + usable in code again.
//    • DEL  (library)         -> remove the keeper from the library (the project copy is untouched).
//
//  Searchable (a live substring filter) + scrollable. The GROUPING + FILTER are PURE functions
//  (groupSounds / filterGroups) so web/verify.js can node-test the library list/dedup logic with
//  no DOM; the view is a thin renderer over them.
// ===========================================================================
import { attachActivate } from './gesture.js';
import { registerOverlay } from './overlay.js';   // the ONE shared open/close/scrim/Escape manager

// PURE: assemble the three groups the browser shows. Node-testable (no DOM).
//   kitNames     : the built-in synth voice names present in the bank (ordered).
//   projectNames : the user's own record/import sample names in the current project (ordered).
//   libraryList  : [{ name, ... }] the persistent keepers.
// A library sound already present in the project is flagged `inProject` so the row shows an IN
// tag (and offers audition instead of a needless re-add), mirroring native BankBrowser's IN tag.
export function groupSounds(kitNames, projectNames, libraryList) {
  const inProj = new Set((projectNames || []).map((n) => String(n).toLowerCase()));
  return {
    kit: (kitNames || []).map((n) => ({ name: n })),
    project: (projectNames || []).map((n) => ({ name: n })),
    library: (libraryList || []).map((r) => ({ name: r.name, inProject: inProj.has(String(r.name).toLowerCase()) })),
  };
}

// PURE: filter every group by a case-insensitive substring on the sound name (the search box).
export function filterGroups(groups, q) {
  const s = String(q || '').trim().toLowerCase();
  if (!s) return groups;
  const f = (arr) => arr.filter((x) => x.name.toLowerCase().includes(s));
  return { kit: f(groups.kit), project: f(groups.project), library: f(groups.library) };
}

// Build the browser overlay. `opts`:
//   host           : parent element to append into (document.body)
//   getGroups()    : -> { kit, project, library } (the caller assembles from the engine + library)
//   tintFor(name)  : -> a css colour for the identity swatch (pad tint)
//   audition(name) : play the sound NOW (a kit/project sound; library uses onUseLibrary)
//   onPick(name)   : PICK — insert s("name") into the code (the coin)
//   onKeep(name)   : -> Promise, save a project sound to the persistent library
//   onUseLibrary(name) : -> Promise<finalName>, rehydrate a library keeper into the project (+ audition)
//   onRemoveLibrary(name) : -> Promise, remove a keeper from the library
//   setStatus(s)   : status-line hook
export function createSoundBrowser(opts) {
  const o = opts || {};
  let query = '';

  const scrim = document.createElement('div');
  scrim.className = 'sheet-scrim browser-scrim hidden';
  scrim.setAttribute('role', 'dialog');
  scrim.setAttribute('aria-modal', 'true');
  scrim.setAttribute('aria-label', 'sound library');

  const sheet = document.createElement('div');
  sheet.className = 'sheet browser-sheet';
  scrim.appendChild(sheet);

  const head = document.createElement('div');
  head.className = 'score-head';
  const title = document.createElement('div');
  title.className = 'sheet-title'; title.textContent = 'Sounds';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'fx-close'; closeBtn.type = 'button';
  closeBtn.setAttribute('aria-label', 'close'); closeBtn.innerHTML = '&times;';
  head.appendChild(title); head.appendChild(closeBtn);
  sheet.appendChild(head);

  const tag = document.createElement('div');
  tag.className = 'browser-tag';
  tag.textContent = 'Tap a sound to hear it. KEEP a sound to carry it into every song.';
  sheet.appendChild(tag);

  const search = document.createElement('input');
  search.className = 'browser-search'; search.type = 'search';
  search.setAttribute('autocomplete', 'off'); search.setAttribute('spellcheck', 'false');
  search.placeholder = 'search sounds…'; search.setAttribute('aria-label', 'search sounds');
  search.addEventListener('input', () => { query = search.value; renderList(); });
  sheet.appendChild(search);

  const list = document.createElement('div');
  list.className = 'browser-list'; list.setAttribute('aria-label', 'available sounds');
  sheet.appendChild(list);

  (o.host || document.body).appendChild(scrim);

  function auditionRow(name) {
    if (o.audition) o.audition(name);
    if (o.setStatus) o.setStatus('auditioning ' + name);
  }

  // Build one row: a swatch + name, a right-side action cluster, tap-to-audition.
  function makeRow(name, kind, extra) {
    const row = document.createElement('div');
    row.className = 'browser-row' + (kind === 'library' ? ' lib' : '');
    row.dataset.name = name; row.dataset.kind = kind;

    const audio = document.createElement('button');
    audio.className = 'browser-audio'; audio.type = 'button';
    audio.setAttribute('aria-label', 'play ' + name);
    audio.title = name + ' — tap to hear it';
    const swatch = document.createElement('span');
    swatch.className = 'browser-swatch';
    if (o.tintFor) swatch.style.background = o.tintFor(name);
    const label = document.createElement('span');
    label.className = 'browser-name'; label.textContent = name;
    audio.appendChild(swatch); audio.appendChild(label);
    if (extra && extra.tag) {
      const t = document.createElement('span');
      t.className = 'browser-intag'; t.textContent = extra.tag;
      audio.appendChild(t);
    }
    row.appendChild(audio);

    const actions = document.createElement('div');
    actions.className = 'browser-actions';
    row.appendChild(actions);

    const addAction = (cls, text, aria, fn) => {
      const b = document.createElement('button');
      b.className = 'browser-act ' + cls; b.type = 'button';
      b.textContent = text; b.setAttribute('aria-label', aria + ' ' + name);
      attachActivate(b, (e) => { if (e) { e.stopPropagation(); } fn(); });
      actions.appendChild(b);
      return b;
    };

    if (kind === 'library') {
      // tap = audition: an in-project keeper plays directly; otherwise ADD-and-hear (native gesture)
      attachActivate(audio, () => { if (extra && extra.inProject) auditionRow(name); else doUseLibrary(name); });
      if (!(extra && extra.inProject)) addAction('use', 'ADD', 'add to song', () => doUseLibrary(name));
      addAction('del', 'REMOVE', 'remove from library', () => doRemoveLibrary(name));
    } else {
      attachActivate(audio, () => auditionRow(name));
      if (kind === 'project') addAction('keep', 'KEEP', 'keep', () => doKeep(name));
      addAction('use', 'USE', 'use in code', () => doPick(name));
    }
    return row;
  }

  function groupHeader(text, count) {
    const h = document.createElement('div');
    h.className = 'browser-group';
    const cap = document.createElement('span'); cap.className = 'browser-group-cap'; cap.textContent = text;
    const n = document.createElement('span'); n.className = 'browser-group-count'; n.textContent = String(count);
    h.appendChild(cap); h.appendChild(n);
    return h;
  }

  function renderList() {
    const groups = filterGroups(o.getGroups ? o.getGroups() : { kit: [], project: [], library: [] }, query);
    list.innerHTML = '';
    const section = (capText, items, kind) => {
      if (!items.length) return;
      list.appendChild(groupHeader(capText, items.length));
      for (const it of items) list.appendChild(makeRow(it.name, kind, kind === 'library' ? { inProject: it.inProject, tag: it.inProject ? 'IN' : '' } : null));
    };
    section('SYNTH KIT', groups.kit, 'kit');
    section('THIS SONG', groups.project, 'project');
    section('LIBRARY', groups.library, 'library');
    if (!groups.kit.length && !groups.project.length && !groups.library.length) {
      const empty = document.createElement('div');
      empty.className = 'browser-empty';
      empty.textContent = query ? 'no sounds match "' + query + '"'
        : 'no sounds yet — record or import one, then KEEP it here';
      list.appendChild(empty);
    }
  }

  // ---- actions (async library ops re-render on completion) ----
  // CLOSE the sheet FIRST, then insert — so the result (the selected s("name") on CODE) is VISIBLE
  // and the editor keeps focus (close restores focus to the opener; onPick then focuses the editor).
  function doPick(name) { close(); if (o.onPick) o.onPick(name); }
  async function doKeep(name) {
    try { if (o.onKeep) await o.onKeep(name); if (o.setStatus) o.setStatus('kept ' + name + ' in your library'); }
    catch (e) { if (o.setStatus) o.setStatus("couldn't keep that sound"); }
    renderList();
  }
  async function doUseLibrary(name) {
    try { if (o.onUseLibrary) await o.onUseLibrary(name); }
    catch (e) { if (o.setStatus) o.setStatus("couldn't add that sound"); }
    renderList();
  }
  async function doRemoveLibrary(name) {
    try { if (o.onRemoveLibrary) await o.onRemoveLibrary(name); }
    catch (e) {}
    renderList();
  }

  // Open/close/scrim/Escape via the ONE shared overlay manager (overlay.js): header ×, release-close
  // scrim-tap (press-vs-release guarded), the central Escape stack. Focus lands in the search field.
  const overlay = registerOverlay(scrim, {
    panel: sheet,
    closeButtons: [closeBtn],
    label: 'sound library',
    initialFocus: search,
    focusDelay: 30,
    onOpen: () => renderList(),
    onClose: () => { if (o.onClose) o.onClose(); },
  });
  function open() { overlay.open(); }
  function close() { overlay.close(); }
  function isOpen() { return overlay.isOpen(); }
  function refresh() { if (isOpen()) renderList(); }

  return {
    el: scrim, open, close, isOpen, refresh,
    // ---- verification hooks (drive the REAL surface headlessly) ----
    _setSearch: (q) => { query = q; search.value = q; renderList(); },
    _rowNames: (kind) => Array.from(list.querySelectorAll('.browser-row' + (kind ? '[data-kind="' + kind + '"]' : ''))).map((r) => r.dataset.name),
    _groupCounts: () => {
      const c = {};
      list.querySelectorAll('.browser-group').forEach((h) => { c[h.querySelector('.browser-group-cap').textContent] = +h.querySelector('.browser-group-count').textContent; });
      return c;
    },
    _tapRow: (name) => { const r = list.querySelector('.browser-row[data-name="' + name + '"] .browser-audio'); if (r) r.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true, button: 0 })); },
    _clickAct: (name, cls) => {
      // a name can appear in two groups (project + library); click the row that actually has this key
      for (const r of list.querySelectorAll('.browser-row[data-name="' + name + '"]')) {
        const b = r.querySelector('.browser-act.' + cls);
        if (b) { b.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true, button: 0 })); return true; }
      }
      return false;
    },
  };
}
