// ===========================================================================
//  history-browser.js — the TIME-TRAVEL browser (the web twin of native HistoryBrowser.h).
//
//  A design-bar, input-agnostic surface over the HistoryStore: a SCRUBBABLE timeline of every
//  checkpoint the song has laid down PLUS a tappable list (newest-first). Scrub the timeline to
//  PREVIEW a past state (its label + UndoLabel "changed DRUMS" feedback + a code preview), then
//  RESTORE it — or tap a list row to rewind straight there (native's "tap a row = restore",
//  3 taps to any version). Restoring is safe: main.js snapshots the CURRENT state first, so a
//  rewind is always reversible (a navigable history, exactly like native).
//
//  Input-agnostic (docs/web-interaction.md): the scrubber uses the SHARED attachValueDrag gesture
//  (Pointer Events + capture, the occlusion-safe bubble ABOVE the finger, wheel + arrow-key nudge
//  with a visible focus ring, pull-away = finer); every list row + RESTORE is a real focusable
//  <button> (pointer + Enter/Space); 44px+ targets; touch-action handled in CSS.
//
//  The COIN: a snapshot is just the document text — restoring loads that text (main.js does the
//  loadDocument/hot-swap); nothing bespoke. This module is pure presentation — it never touches
//  the engine or storage; it calls opts.onRestore(snap) to commit.
// ===========================================================================
import { attachValueDrag } from './gesture.js';
import { relativeTime, changedSectionLabel } from './history.js';

// Build the time-travel browser into one host element. `opts`:
//   list()         -> the snapshots, NEWEST-first ([{ id, time, bpm, code, label, project }])
//   currentDoc()   -> the live editor document (for the UndoLabel "changed X" preview + no-op guard)
//   now()          -> current wall-clock ms (relative-time text); defaults to Date.now
//   onRestore(snap)-> commit a rewind to that snapshot (main.js owns the restore + Time Traveler medal)
//   onClose()      -> close the sheet
export function createHistoryBrowser(opts) {
  const nowMs = opts.now || (() => Date.now());

  const el = document.createElement('div');
  el.className = 'history-surface';

  let snaps = [];       // newest-first
  let selListIdx = 0;   // index INTO `snaps` (0 = newest) currently previewed on the scrubber

  // ---- geometry: scrubber norm [0,1] (left = OLDEST, right = NEWEST) <-> a list index ----
  const n = () => snaps.length;
  function normToIdx(t) {
    const N = n(); if (N <= 1) return 0;
    // t=0 -> oldest (last in the newest-first array); t=1 -> newest (index 0)
    return Math.max(0, Math.min(N - 1, Math.round((1 - t) * (N - 1))));
  }
  function idxToNorm(idx) {
    const N = n(); if (N <= 1) return 1;
    return 1 - idx / (N - 1);
  }

  // ========================================================================
  //  DOM
  // ========================================================================
  let scrub, scrubKnob, ticks, prevLabel, prevWhen, prevMeta, prevUndo, prevCode, restoreBtn, listHost, emptyEl, countEl;

  function build() {
    el.innerHTML = '';

    // head: title + live count + close
    const head = document.createElement('div'); head.className = 'score-head';
    const title = document.createElement('div'); title.className = 'sheet-title'; title.textContent = 'Time travel';
    countEl = document.createElement('span'); countEl.className = 'hist-head-count'; countEl.textContent = '0';
    const close = document.createElement('button'); close.className = 'fx-close'; close.type = 'button';
    close.setAttribute('aria-label', 'close'); close.innerHTML = '&times;';
    close.addEventListener('click', () => opts.onClose && opts.onClose());
    head.appendChild(title); head.appendChild(countEl); head.appendChild(close);
    el.appendChild(head);

    const tag = document.createElement('div'); tag.className = 'hist-tag';
    tag.textContent = 'Every checkpoint of this song. Scrub the timeline or tap a version to rewind — your current state is saved first, so it is always reversible.';
    el.appendChild(tag);

    // the recessed dark-LCD screen holding the scrubber + preview (native paintRecessedScreen)
    const screen = document.createElement('div'); screen.className = 'hist-screen';

    // --- the SCRUBBER: a phosphor timeline you drag through the checkpoints ---
    const scrubWrap = document.createElement('div'); scrubWrap.className = 'hist-scrub-wrap';
    const scrubCap = document.createElement('div'); scrubCap.className = 'hist-scrub-cap'; scrubCap.textContent = 'TIMELINE';
    scrubWrap.appendChild(scrubCap);
    scrub = document.createElement('div'); scrub.className = 'hist-scrub'; scrub.tabIndex = 0;
    scrub.setAttribute('role', 'slider'); scrub.setAttribute('aria-label', 'scrub the version timeline');
    ticks = document.createElement('div'); ticks.className = 'hist-ticks'; scrub.appendChild(ticks);
    scrubKnob = document.createElement('div'); scrubKnob.className = 'hist-knob'; scrub.appendChild(scrubKnob);
    scrubWrap.appendChild(scrub);
    const ends = document.createElement('div'); ends.className = 'hist-scrub-ends';
    ends.innerHTML = '<span>oldest</span><span>now</span>';
    scrubWrap.appendChild(ends);
    screen.appendChild(scrubWrap);

    // --- the PREVIEW: the selected version's label + UndoLabel feedback + a code preview ---
    const prev = document.createElement('div'); prev.className = 'hist-preview';
    const ph = document.createElement('div'); ph.className = 'hist-prev-head';
    prevLabel = document.createElement('span'); prevLabel.className = 'hist-prev-label';
    prevWhen = document.createElement('span'); prevWhen.className = 'hist-prev-when';
    ph.appendChild(prevLabel); ph.appendChild(prevWhen);
    prev.appendChild(ph);
    prevMeta = document.createElement('div'); prevMeta.className = 'hist-prev-meta';
    prev.appendChild(prevMeta);
    prevUndo = document.createElement('div'); prevUndo.className = 'hist-prev-undo';
    prev.appendChild(prevUndo);
    prevCode = document.createElement('pre'); prevCode.className = 'hist-prev-code';
    prev.appendChild(prevCode);
    restoreBtn = document.createElement('button'); restoreBtn.className = 'hist-restore'; restoreBtn.type = 'button';
    restoreBtn.textContent = 'REWIND TO THIS VERSION';
    restoreBtn.addEventListener('click', () => commitSelected());
    prev.appendChild(restoreBtn);
    screen.appendChild(prev);
    el.appendChild(screen);

    // --- the LIST: tappable rows, newest-first (native tap = restore) ---
    const listCap = document.createElement('div'); listCap.className = 'hist-list-cap'; listCap.textContent = 'ALL CHECKPOINTS';
    el.appendChild(listCap);
    listHost = document.createElement('div'); listHost.className = 'hist-list'; listHost.setAttribute('aria-label', 'checkpoints');
    el.appendChild(listHost);
    emptyEl = document.createElement('div'); emptyEl.className = 'hist-empty';
    emptyEl.textContent = 'no history yet — checkpoints record on their own as you edit and play';
    el.appendChild(emptyEl);

    // discrete keyboard stepping (one arrow press = one checkpoint) — registered BEFORE the drag so
    // it runs first and stops the drag's own (continuous) arrow handler, keeping the step exact.
    scrub.addEventListener('keydown', (e) => {
      if (e.key === 'ArrowRight' || e.key === 'ArrowUp') { e.preventDefault(); e.stopImmediatePropagation(); select(selListIdx - 1); }      // newer
      else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') { e.preventDefault(); e.stopImmediatePropagation(); select(selListIdx + 1); } // older
      else if (e.key === 'Enter' || e.key === ' ' || e.key === 'Spacebar') { e.preventDefault(); e.stopImmediatePropagation(); commitSelected(); }
    });
    // wire the scrubber to the SHARED input-agnostic gesture (mouse == touch == wheel; bubble above finger)
    attachValueDrag(scrub, {
      getNorm: () => idxToNorm(selListIdx),
      setNorm: (t) => selectByNorm(t),
      format: () => { const s = snaps[selListIdx]; return s ? s.label : ''; },
      width: () => scrub.getBoundingClientRect().width,
    });
  }

  // ---- selection / preview (no restore) ----
  function selectByNorm(t) { select(normToIdx(t)); }
  function select(listIdx) {
    if (!n()) return;
    selListIdx = Math.max(0, Math.min(n() - 1, listIdx | 0));
    renderPreview();
    positionKnob();
    markSelectedRow();
  }

  function positionKnob() {
    const t = idxToNorm(selListIdx);
    if (scrubKnob) scrubKnob.style.left = (t * 100) + '%';
    if (scrub) scrub.setAttribute('aria-valuetext', (snaps[selListIdx] && snaps[selListIdx].label) || '');
  }

  function renderPreview() {
    const s = snaps[selListIdx];
    const has = !!s;
    if (restoreBtn) restoreBtn.disabled = !has;
    if (!has) { prevLabel.textContent = ''; prevWhen.textContent = ''; prevMeta.textContent = ''; prevUndo.textContent = ''; prevCode.textContent = ''; return; }
    prevLabel.textContent = s.label || 'checkpoint';
    prevWhen.textContent = relativeTime(s.time, nowMs());
    const bpm = Math.round(Number(s.bpm) || 120);
    prevMeta.textContent = (s.project || 'Untitled') + '  ·  ' + bpm + ' bpm';
    // the UndoLabel feedback: what this version differs from the CURRENT doc by (native UndoLabel)
    const cur = opts.currentDoc ? opts.currentDoc() : '';
    if (s.code === cur) prevUndo.textContent = 'this is your current version';
    else { const chg = changedSectionLabel(s.code, cur); prevUndo.textContent = chg ? ('rewind changes: ' + chg) : 'a different version'; }
    prevCode.textContent = s.code;
  }

  function markSelectedRow() {
    if (!listHost) return;
    const rows = listHost.querySelectorAll('.hist-row');
    rows.forEach((r) => r.classList.toggle('sel', +r.dataset.idx === selListIdx));
  }

  function renderList() {
    listHost.innerHTML = '';
    const N = n();
    emptyEl.classList.toggle('hidden', N > 0);
    listHost.classList.toggle('hidden', N === 0);
    if (countEl) countEl.textContent = String(N);
    const now = nowMs();
    snaps.forEach((s, idx) => {
      const row = document.createElement('button'); row.type = 'button'; row.className = 'hist-row';
      row.dataset.idx = String(idx); row.dataset.id = String(s.id);
      row.setAttribute('aria-label', 'rewind to ' + (s.label || 'checkpoint') + ', ' + relativeTime(s.time, now));
      const top = document.createElement('div'); top.className = 'hist-row-top';
      const when = document.createElement('span'); when.className = 'hist-row-when'; when.textContent = relativeTime(s.time, now);
      const lbl = document.createElement('span'); lbl.className = 'hist-row-label'; lbl.textContent = s.label || 'checkpoint';
      top.appendChild(when); top.appendChild(lbl);
      const meta = document.createElement('div'); meta.className = 'hist-row-meta';
      meta.textContent = (s.project || 'Untitled') + '  ·  ' + Math.round(Number(s.bpm) || 120) + ' bpm';
      const rew = document.createElement('span'); rew.className = 'hist-row-rew'; rew.textContent = 'REWIND';
      row.appendChild(top); row.appendChild(meta); row.appendChild(rew);
      // tap a row = rewind straight to it (native tap = restore); it also previews it first
      row.addEventListener('click', () => { select(idx); commitSelected(); });
      row.addEventListener('pointerenter', () => select(idx));   // hover preview (a desktop bonus, never required)
      listHost.appendChild(row);
    });
    markSelectedRow();
  }

  function commitSelected() {
    const s = snaps[selListIdx];
    if (s && opts.onRestore) opts.onRestore(s);
  }

  // Public: (re)read the store + rebuild. Keeps the selection on the newest by default.
  function refresh() {
    snaps = (opts.list ? opts.list() : []) || [];
    if (selListIdx >= snaps.length) selListIdx = 0;
    renderList();
    select(selListIdx);
  }

  build();
  refresh();

  return {
    el, refresh,
    // verification hooks (headless drive)
    _count: () => n(),
    _selectIndex: (i) => { select(i); return snaps[selListIdx] || null; },
    _scrubTo: (t) => { selectByNorm(t); return snaps[selListIdx] || null; },
    _selectedCode: () => (snaps[selListIdx] ? snaps[selListIdx].code : ''),
    _selectedId: () => (snaps[selListIdx] ? snaps[selListIdx].id : null),
    _commit: () => commitSelected(),
    _tapRow: (i) => { const r = listHost.querySelector(`.hist-row[data-idx="${i | 0}"]`); if (r) r.click(); },
  };
}
